<template>
  <!-- 🚀 A. 前置微型加载检测锁 (在获取数据库协议签署状态之前呈现，彻底杜绝主界面瞬间闪现) -->
  <div
    v-if="isAgreementChecking"
    class="fixed inset-0 z-[999] flex flex-col items-center justify-center bg-background text-on-surface select-none animate-fade-in"
    :class="{ dark: isDark }"
  >
    <div class="flex flex-col items-center space-y-4">
      <div class="w-10 h-10 rounded-2xl bg-primary/10 flex items-center justify-center animate-pulse">
        <SparklesIcon class="w-5.5 h-5.5 text-primary animate-spin" />
      </div>
      <span class="text-xs font-bold text-on-surface-variant/60 tracking-wider">正在加载安全环境...</span>
    </div>
  </div>

  <!-- 🚀 B. 全屏高颜值磨砂用户协议卡片：在未同意且非检测中时强制锁死全屏 -->
  <div
    v-else-if="!hasAcceptedAgreement && showAgreementModal"
    class="fixed inset-0 z-[999] flex items-center justify-center p-4 bg-background text-on-surface select-text animate-fade-in"
    :class="{ dark: isDark }"
  >
    <div
      class="w-full max-w-[500px] h-[85vh] bg-surface rounded-[24px] border border-outline-variant shadow-2xl flex flex-col overflow-hidden animate-scale-in relative"
    >
      <header
        class="p-6 border-b border-outline-variant/30 flex items-center space-x-3 select-none flex-shrink-0 bg-surface"
      >
        <div class="w-8 h-8 rounded-xl bg-primary/10 flex items-center justify-center">
          <BookOpenIcon class="w-4.5 h-4.5 text-primary animate-pulse" />
        </div>
        <div>
          <h3 class="text-sm font-black text-on-surface tracking-wide">Echo-回音 用户协议与免责声明</h3>
          <p class="text-[9px] text-on-surface-variant/60 tracking-tighter mt-0.5">请在使用前仔细阅读并遵守以下条款</p>
        </div>
      </header>

      <!-- 🚀 纯 Markdown 条款排版区 -->
      <div
        class="flex-1 overflow-y-auto p-6 select-text bg-surface-low border-b border-outline-variant/20 mobile-select-text leading-relaxed markdown-body"
        v-html="renderMarkdown(agreementText)"
      ></div>

      <!-- 底部操作按钮 -->
      <footer
        class="p-5 flex flex-col space-y-3 bg-surface select-none flex-shrink-0 border-t border-outline-variant/20"
      >
        <div class="flex items-center space-x-3">
          <button
            @click="rejectAgreement"
            class="flex-1 py-3 rounded-xl bg-surface-high border border-outline-variant hover:bg-on-surface/5 active:scale-95 text-xs font-bold text-on-surface-variant transition-all cursor-pointer"
          >
            我不同意
          </button>

          <button
            :disabled="agreementCountdown > 0"
            @click="acceptAgreement"
            class="flex-[2] py-3 rounded-xl text-xs font-bold transition-all flex items-center justify-center space-x-2"
            :class="
              agreementCountdown > 0
                ? 'bg-outline-variant text-on-surface-variant/40 cursor-not-allowed shadow-inner'
                : 'bg-primary text-white hover:bg-primary-container active:scale-95 cursor-pointer shadow-md shadow-primary/10'
            "
          >
            <CheckIcon class="w-3.5 h-3.5" />
            <span v-if="agreementCountdown > 0">请仔细阅读并等待 ({{ agreementCountdown }}秒)</span>
            <span v-else>我同意并自愿遵守所有内容</span>
          </button>
        </div>
        <p class="text-[9px] text-center text-on-surface-variant/40 select-none">
          * 拒绝签署本协议将立刻自动物理退出程序所有进程
        </p>
      </footer>
    </div>
  </div>

  <!-- 精致跳秒时钟独立分流视图 -->
  <div v-else-if="isClockView" class="w-full h-full select-none overflow-hidden" :class="{ dark: isDark }">
    <ClockView />
  </div>

  <!-- 根容器，支持亮色/暗色模式 -->
  <div
    v-else
    class="w-full flex flex-col bg-background text-on-surface font-sans select-none overflow-hidden"
    :class="{ dark: isDark }"
    :style="isMobile ? { height: viewportHeight } : { height: '100%' }"
    @dragenter.prevent="handleDragEnter"
  >
    <!-- 顶部拖拽导航条 (兼顾 Windows 与 macOS，标题 100% 绝对水平居中) -->
    <div
      v-if="!isMobile"
      class="h-7 w-full flex-shrink-0 bg-surface border-b border-outline-variant/30 flex items-center justify-between select-none shadow-sm relative animate-in slide-in-from-top duration-200"
      style="-webkit-app-region: drag"
    >
      <!-- 🚀 绝对居中的标题：通过绝对定位绝对居中，保证在 Mac/Win 两端都对称处于正中间，且完全避免与两侧控件重叠 -->
      <div class="absolute inset-0 flex items-center justify-center pointer-events-none">
        <span class="text-[11px] font-semibold tracking-wide text-on-surface/60 font-sans">Echo-回音</span>
      </div>

      <!-- 左侧占位栏：主要用于在 macOS 下完美留出系统原生“交通灯”按钮的安全气隙，防止其他元素越界 -->
      <div class="h-full flex items-center pl-3 pointer-events-none" :class="{ 'w-20': !isWindows }">
        <!-- 保持空白以保护 macOS 的左侧控制区域 -->
      </div>

      <!-- Windows 专属精致窗口控制按钮组件 (设置 relative z-10 确保悬浮在绝对居中的容器上方) -->
      <div
        v-if="isWindows"
        class="h-full flex items-center flex-shrink-0 relative z-10"
        style="-webkit-app-region: no-drag"
      >
        <!-- 最小化 -->
        <button
          @click="handleWindowControl('minimize')"
          class="w-11 h-full flex items-center justify-center hover:bg-on-surface/10 active:bg-on-surface/20 transition-colors text-on-surface-variant cursor-pointer"
          title="最小化"
        >
          <svg class="w-[10px] h-[10px]" viewBox="0 0 1024 1024" fill="currentColor">
            <path d="M64 896h896v80H64z"></path>
          </svg>
        </button>
        <!-- 最大化 -->
        <button
          @click="handleWindowControl('maximize')"
          class="w-11 h-full flex items-center justify-center hover:bg-on-surface/10 active:bg-on-surface/20 transition-colors text-on-surface-variant cursor-pointer"
          title="最大化"
        >
          <svg class="w-[10px] h-[10px]" viewBox="0 0 1024 1024" fill="currentColor">
            <path d="M128 128h768v768H128V128zm80 80v608h608V208H208z"></path>
          </svg>
        </button>
        <!-- 关闭 -->
        <button
          @click="handleWindowControl('close')"
          class="w-11 h-full flex items-center justify-center hover:bg-[#e81123] hover:text-white active:bg-[#f1707a] transition-colors text-on-surface-variant cursor-pointer"
          title="关闭"
        >
          <svg class="w-[10px] h-[10px]" viewBox="0 0 1024 1024" fill="currentColor">
            <path
              d="M576 512l342.4-342.4c17.6-17.6 17.6-46.4 0-64s-46.4-17.6-64 0L512 448 169.6 105.6c-17.6-17.6-46.4-17.6-64 0s-17.6 46.4 0 64L448 512 105.6 854.4c-17.6 17.6-17.6 46.4 0 64s46.4 17.6 64 0L512 576l342.4 342.4c17.6 17.6 46.4 17.6 64 0s17.6-46.4 0-64L576 512z"
            ></path>
          </svg>
        </button>
      </div>
    </div>

    <!-- 三栏主体布局 -->
    <div class="flex-1 flex min-h-0 overflow-hidden" style="-webkit-app-region: no-drag">
      <!-- ====== 左侧极窄导航栏 (72px) ====== -->
      <nav
        class="w-[72px] h-full hidden md:flex flex-col items-center bg-nav-bar py-3 flex-shrink-0 border-r border-nav-border"
      >
        <!-- 用户头像（点击进入个人设置） -->
        <div
          class="w-10 h-10 rounded overflow-hidden border-2 border-nav-avatar-border hover:opacity-90 transition-all mb-5 flex-shrink-0 shadow-md cursor-pointer"
          @click="
            sideView = 'settings';
            activeSettingsTab = 'profile';
            userProfileActiveTab = 'profile';
            userMdEditing = false;
          "
        >
          <img
            v-if="userProfile.appAvatarUrl"
            :src="userProfile.appAvatarUrl"
            class="w-full h-full object-cover"
            @error="userProfile.appAvatarUrl = ''"
          />
          <img v-else :src="defaultAvatarSrc" class="w-full h-full object-cover" />
        </div>

        <!-- 导航功能图标组 -->
        <div class="flex flex-col items-center space-y-2 flex-1">
          <!-- 对话 -->
          <button
            @click="
              sideView = 'chat';
              activeView = 'chat';
            "
            class="nav-icon-btn relative"
            :class="{ 'nav-icon-btn-active': sideView === 'chat' }"
            title="对话"
          >
            <MessageSquareIcon class="w-5 h-5" />
            <span
              v-if="hasUnreadConversations"
              class="absolute top-1 right-1 w-2.5 h-2.5 bg-red-500 rounded-full shadow-sm scale-95 animate-pulse"
            ></span>
          </button>

          <!-- 通讯录 -->
          <button
            @click="sideView = 'contacts'"
            class="nav-icon-btn"
            :class="{ 'nav-icon-btn-active': sideView === 'contacts' }"
            title="通讯录"
          >
            <UsersIcon class="w-5 h-5" />
          </button>

          <!-- 朋友圈 -->
          <button
            @click="
              sideView = 'moments';
              loadMomentsList();
            "
            class="nav-icon-btn relative"
            :class="{ 'nav-icon-btn-active': sideView === 'moments' }"
            title="朋友圈"
          >
            <GlobeIcon class="w-5 h-5" />
            <span
              v-if="unreadMomentsCount > 0"
              class="absolute top-1 right-1 w-2.5 h-2.5 bg-red-500 rounded-full shadow-sm scale-95 animate-pulse"
            ></span>
          </button>

          <!-- 音乐 -->
          <button
            v-if="generalConfig.enable_music"
            @click="sideView = 'music'"
            class="nav-icon-btn"
            :class="{ 'nav-icon-btn-active': sideView === 'music' }"
            title="回音音乐"
          >
            <MusicIcon class="w-5 h-5" />
          </button>

          <!-- 论坛 -->
          <button
            @click="
              sideView = 'forum';
              selectBoard('all');
            "
            class="nav-icon-btn relative"
            :class="{ 'nav-icon-btn-active': sideView === 'forum' }"
            title="开发者论坛"
          >
            <ScrollIcon class="w-5 h-5" />
            <span
              v-if="unreadForumCount > 0"
              class="absolute top-1 right-1 w-2.5 h-2.5 bg-red-500 rounded-full shadow-sm scale-95 animate-pulse"
            ></span>
          </button>

          <!-- 收藏夹 -->
          <button
            @click="
              sideView = 'favorites';
              loadFavoritesList();
            "
            class="nav-icon-btn"
            :class="{ 'nav-icon-btn-active': sideView === 'favorites' }"
            title="收藏中心"
          >
            <BookmarkIcon class="w-5 h-5" />
          </button>

          <!-- 书架 (仅当存在任意小说时开启) -->
          <button
            @click="
              sideView = 'bookshelf';
              loadBookshelf();
            "
            class="nav-icon-btn transition-all duration-300 relative"
            :class="[sideView === 'bookshelf' ? 'nav-icon-btn-active' : '', 'opacity-100 cursor-pointer']"
            title="小说书架"
          >
            <LibraryIcon class="w-5 h-5" />
            <!-- 书架更新全局红点 -->
            <span
              v-if="Object.values(novelNewChapterBadges).reduce((a, b) => a + b, 0) > 0"
              class="absolute top-1.5 right-1.5 w-2 h-2 bg-red-500 rounded-full shadow-sm animate-pulse"
            ></span>
          </button>

          <!-- Echo家园 -->
          <button
            v-if="isDevMode"
            @click="sideView = 'home'"
            class="nav-icon-btn transition-all duration-300 relative"
            :class="{ 'nav-icon-btn-active': sideView === 'home' }"
            title="Echo家园"
          >
            <HomeIcon class="w-5 h-5" />
          </button>
        </div>

        <!-- 底部：数据统计 + 亮暗切换 + 设置 -->
        <div class="flex flex-col items-center space-y-2 flex-shrink-0">
          <button
            @click="openStatsPanel"
            class="nav-icon-btn"
            :class="{ 'nav-icon-btn-active': sideView === 'stats' }"
            title="数据面板"
          >
            <BarChart3Icon class="w-5 h-5" />
          </button>

          <button @click="toggleTheme()" class="nav-icon-btn" :title="isDark ? '切换为亮色' : '切换为暗色'">
            <MoonIcon v-if="isDark" class="w-5 h-5" />
            <SunIcon v-else class="w-5 h-5" />
          </button>

          <button
            @click="openSettingsPage"
            class="nav-icon-btn relative"
            :class="{ 'nav-icon-btn-active': sideView === 'settings' }"
            title="设置"
          >
            <SettingsIcon class="w-5 h-5" />
            <span
              v-if="hasNewVersion"
              class="absolute top-1.5 right-1.5 w-2.5 h-2.5 bg-red-500 rounded-full shadow-sm scale-95 animate-pulse"
            ></span>
          </button>
        </div>
      </nav>

      <!-- ====== 中间会话/联系人列表 ====== -->
      <aside
        v-if="
          sideView !== 'stats' &&
          sideView !== 'moments' &&
          sideView !== 'forum' &&
          sideView !== 'favorites' &&
          sideView !== 'home' &&
          (sideView !== 'bookshelf' || selectedBookId)
        "
        :style="!isMobile ? { width: sidebarWidth + 'px' } : {}"
        class="h-full flex flex-col bg-sidebar backdrop-blur-md flex-shrink-0 overflow-hidden relative"
        :class="{
          'hidden md:flex': isRightPanelActive || (sideView === 'bookshelf' && selectedBookId),
          'w-full': isMobile,
        }"
      >
        <!-- ── 对话列表视图 ── -->
        <template v-if="sideView === 'chat'">
          <!-- 顶部标题与搜索 -->
          <div class="px-4 pt-4 pb-2 flex-shrink-0">
            <!-- 搜索框与加号下拉按钮 -->
            <div class="flex items-center space-x-2">
              <!-- 🚀 移动端专属用户头像：高圆角与搜索框完全平齐 (28px)，点击即可修改个人侧写画像 -->
              <div
                v-if="isMobile"
                class="w-[28px] h-[28px] rounded-md overflow-hidden border border-outline-variant bg-surface flex-shrink-0 cursor-pointer shadow-sm active:scale-95 transition-all"
                @click="
                  sideView = 'settings';
                  activeSettingsTab = 'profile';
                  userProfileActiveTab = 'profile';
                  userMdEditing = false;
                "
                title="点击修改个人信息"
              >
                <img
                  v-if="userProfile.appAvatarUrl"
                  :src="userProfile.appAvatarUrl"
                  class="w-full h-full object-cover"
                  @error="userProfile.appAvatarUrl = ''"
                />
                <img v-else :src="defaultAvatarSrc" class="w-full h-full object-cover" />
              </div>

              <div class="relative flex-1">
                <SearchIcon class="w-3.5 h-3.5 absolute left-2.5 top-1/2 -translate-y-1/2 text-on-surface-variant/50" />
                <input
                  v-model="searchQuery"
                  type="text"
                  placeholder="搜索"
                  class="w-full pl-8 pr-3 py-1.5 rounded-md text-xs bg-surface-high text-on-surface placeholder-on-surface-variant/40 focus:outline-none border border-transparent focus:border-outline-variant/40 transition-all"
                />
              </div>

              <!-- 精美加号按钮与级联菜单 -->
              <div class="relative flex-shrink-0">
                <button
                  @click.stop="toggleAddMenu"
                  class="w-7 h-7 rounded-md flex items-center justify-center hover:bg-surface-high/75 active:scale-90 transition-all text-on-surface-variant hover:text-primary cursor-pointer"
                  title="添加"
                >
                  <PlusCircleIcon class="w-4 h-4" stroke-width="1.5" />
                </button>

                <!-- 下拉扁平化菜单：AI创角 / 手动创角 / 导入角色卡 / 发起群聊 -->
                <div
                  v-if="showAddMenu"
                  class="absolute right-0 mt-1.5 w-36 bg-surface border border-outline-variant rounded-xl shadow-2xl py-1.5 z-50 overflow-hidden select-none animate-in fade-in duration-100"
                >
                  <button
                    @click.stop="triggerCreateNewCharacter"
                    class="w-full px-3 py-2 text-left text-xs text-on-surface hover:bg-surface-high/60 transition-colors flex items-center space-x-2 cursor-pointer font-medium"
                  >
                    <PenLineIcon class="w-4 h-4 text-secondary" stroke-width="1.5" />
                    <span>使用AI创建角色</span>
                  </button>
                  <button
                    @click.stop="triggerManualCreateCharacter"
                    class="w-full px-3 py-2 text-left text-xs text-on-surface hover:bg-surface-high/60 transition-colors flex items-center space-x-2 cursor-pointer font-medium"
                  >
                    <UserPlusIcon class="w-4 h-4 text-primary" stroke-width="1.5" />
                    <span>手动录入角色</span>
                  </button>
                  <button
                    @click.stop="triggerImportCharacterCard"
                    class="w-full px-3 py-2 text-left text-xs text-on-surface hover:bg-surface-high/60 transition-colors flex items-center space-x-2 cursor-pointer font-medium"
                  >
                    <UploadIcon class="w-4 h-4 text-primary" stroke-width="1.5" />
                    <span>导入角色卡</span>
                  </button>
                  <button
                    @click.stop="
                      showCreateGroupModal = true;
                      showAddMenu = false;
                    "
                    class="w-full px-3 py-2 text-left text-xs text-on-surface hover:bg-surface-high/60 transition-colors flex items-center space-x-2 cursor-pointer font-medium"
                  >
                    <UsersIcon class="w-4 h-4 text-secondary" stroke-width="1.5" />
                    <span>群聊 (beta)</span>
                  </button>
                </div>
              </div>
            </div>
          </div>

          <!-- 角色对话列表 -->
          <div class="flex-1 overflow-y-auto" ref="chatListRef">
            <!-- 置顶的角色 -->
            <div v-if="pinnedCharacters.length > 0">
              <div class="px-4 py-1 text-[10px] text-on-surface-variant/40 font-bold uppercase tracking-wider">
                置顶
              </div>
              <ConversationItem
                v-for="char in pinnedCharacters"
                :key="char.id"
                :character="char"
                :avatar="characterAvatars[char.id]"
                :is-selected="selectedCharacterId === char.id"
                :unread="conversationMeta[char.id]?.unread || 0"
                :last-message="getLastMessage(char.id)"
                :is-muted="conversationMeta[char.id]?.muted"
                :is-hidden="conversationMeta[char.id]?.hidden"
                :is-pinned="conversationMeta[char.id]?.pinned"
                @click="selectCharacter(char.id)"
                @contextmenu.prevent="openContextMenu($event, char)"
                @touchstart="onLongPressStart($event, char, 'chat')"
                @touchend="onLongPressEnd"
                @touchmove="onLongPressMove"
              />
            </div>

            <!-- 普通角色列表 -->
            <div v-if="visibleCharacters.length > 0 || searchQuery">
              <template v-if="!searchQuery">
                <ConversationItem
                  v-for="char in visibleCharacters"
                  :key="char.id"
                  :character="char"
                  :avatar="characterAvatars[char.id]"
                  :is-selected="selectedCharacterId === char.id"
                  :unread="conversationMeta[char.id]?.unread || 0"
                  :last-message="getLastMessage(char.id)"
                  :is-muted="conversationMeta[char.id]?.muted"
                  :is-hidden="conversationMeta[char.id]?.hidden"
                  :is-pinned="conversationMeta[char.id]?.pinned"
                  @click="selectCharacter(char.id)"
                  @contextmenu.prevent="openContextMenu($event, char)"
                  @touchstart="onLongPressStart($event, char, 'chat')"
                  @touchend="onLongPressEnd"
                  @touchmove="onLongPressMove"
                />
              </template>
              <template v-else>
                <!-- 搜索结果：联系人区块 -->
                <div v-if="searchContactResults.length > 0">
                  <div class="px-4 py-1 text-[10px] text-on-surface-variant/40 font-bold uppercase tracking-wider">
                    联系人
                  </div>
                  <ConversationItem
                    v-for="char in searchContactResults"
                    :key="char.id"
                    :character="char"
                    :avatar="characterAvatars[char.id]"
                    :is-selected="selectedCharacterId === char.id"
                    :unread="0"
                    :last-message="null"
                    :is-pinned="conversationMeta[char.id]?.pinned"
                    @click="selectCharacter(char.id)"
                  />
                </div>
                <!-- 搜索结果：聊天记录区块 -->
                <div v-if="searchMessageResults.length > 0">
                  <div class="px-4 py-1 text-[10px] text-on-surface-variant/40 font-bold uppercase tracking-wider">
                    聊天记录
                  </div>
                  <div
                    v-for="result in searchMessageResults"
                    :key="result.id"
                    class="px-4 py-2.5 hover:bg-surface-high/60 cursor-pointer transition-colors flex items-center space-x-2.5"
                    @click="selectCharacter(result.characterId)"
                  >
                    <div
                      class="w-9 h-9 rounded-md overflow-hidden flex-shrink-0 bg-surface-high border border-outline-variant"
                    >
                      <img
                        v-if="characterAvatars[result.characterId]"
                        :src="characterAvatars[result.characterId]"
                        class="w-full h-full object-cover"
                      />
                    </div>
                    <div class="flex-1 min-w-0">
                      <div class="text-xs font-bold text-on-surface">{{ result.charName }}</div>
                      <div
                        class="text-[10px] text-on-surface-variant truncate"
                        v-html="highlightSearch(result.content)"
                      ></div>
                    </div>
                  </div>
                </div>
                <div
                  v-if="searchContactResults.length === 0 && searchMessageResults.length === 0"
                  class="text-center text-xs text-on-surface-variant/50 py-8"
                >
                  无搜索结果
                </div>
              </template>
            </div>

            <!-- 没有角色时的提示 -->
            <div
              v-if="characterList.length === 0 && !searchQuery"
              class="flex flex-col items-center justify-center py-12 px-6 text-center"
            >
              <PlusCircleIcon class="w-7 h-7 text-on-surface-variant/20 mb-2.5" stroke-width="1.5" />
              <p class="text-xs text-on-surface-variant/50">暂无角色，请选择</p>
              <div class="flex items-center space-x-3 mt-2">
                <button @click="triggerImportCharacterCard" class="text-xs text-primary font-bold hover:underline">
                  导入角色卡
                </button>
                <span class="text-on-surface-variant/20 text-xs">|</span>
                <button @click="triggerCreateNewCharacter" class="text-xs text-primary font-bold hover:underline">
                  创建角色
                </button>
              </div>
            </div>
          </div>
        </template>

        <!-- ── 通讯录视图 ── -->
        <template v-else-if="sideView === 'contacts'">
          <div class="px-4 pt-4 pb-2 flex-shrink-0">
            <div class="text-sm font-bold text-on-surface">通讯录</div>
          </div>
          <div class="flex-1 overflow-y-auto">
            <div v-if="characterList.length === 0" class="text-center text-xs text-on-surface-variant/50 py-12">
