            </div>
            <div
              v-for="char in characterList"
              :key="char.id"
              class="px-4 py-3 hover:bg-surface-high/60 cursor-pointer transition-colors flex items-center space-x-3 group"
              :class="{ 'bg-surface-high/80': selectedContactId === char.id }"
              @click="selectCharacterForContactDetails(char.id)"
              @dblclick="doubleClickStartChat(char.id)"
              @contextmenu.prevent="openContactContextMenu($event, char)"
              @touchstart="onLongPressStart($event, char, 'contact')"
              @touchend="onLongPressEnd"
              @touchmove="onLongPressMove"
            >
              <div
                class="w-10 h-10 rounded overflow-hidden flex-shrink-0 bg-surface-high border border-outline-variant"
              >
                <template v-if="char.id === 'character_creator_bot'">
                  <img :src="creatorBotAvatarUrl" class="w-full h-full object-cover" />
                </template>
                <template v-else>
                  <img
                    v-if="characterAvatars[char.id]"
                    :src="characterAvatars[char.id]"
                    class="w-full h-full object-cover"
                  />
                  <UserIcon v-else class="w-5 h-5 text-on-surface-variant m-auto mt-2.5" />
                </template>
              </div>
              <div class="flex-1 min-w-0">
                <div class="text-sm font-semibold text-on-surface truncate">{{ char.name }}</div>
                <div class="text-[10px] text-on-surface-variant truncate opacity-70">角色</div>
              </div>
            </div>
          </div>
        </template>

        <!-- ── 系统设置导航视图 ── -->
        <template v-else-if="sideView === 'settings'">
          <div class="px-4 pt-4 pb-2 flex-shrink-0">
            <div class="text-sm font-bold text-on-surface">系统设置</div>
          </div>
          <div class="flex-1 overflow-y-auto py-2">
            <div
              v-for="menu in settingsMenus"
              :key="menu.id"
              class="mx-2 px-3.5 py-2.5 rounded-xl hover:bg-surface-high/50 cursor-pointer transition-all flex items-center space-x-3 group"
              :style="activeSettingsTab === menu.id ? 'background-color: rgba(59, 130, 246, 0.12)' : ''"
              @click="
                activeSettingsTab = menu.id;
                isMobileSettingsActive = true;
              "
            >
              <component
                :is="menu.icon"
                class="w-4 h-4 text-on-surface-variant flex-shrink-0 transition-all group-hover:scale-110"
                stroke-width="1.5"
              />
              <div class="flex-1 min-w-0 flex items-center justify-between">
                <div
                  class="text-xs font-semibold text-on-surface truncate"
                  :class="{ 'font-bold': activeSettingsTab === menu.id }"
                >
                  {{ menu.label }}
                </div>
                <span
                  v-if="menu.id === 'about' && hasNewVersion"
                  class="w-2 h-2 bg-red-500 rounded-full shadow-sm scale-95 animate-pulse mr-1.5 shrink-0"
                ></span>
              </div>
            </div>
          </div>
          <!-- 底部所在地与天气 -->
          <div
            class="px-4 py-3 border-t border-sidebar-border/30 text-[10px] text-on-surface-variant/60 font-sans flex-shrink-0 select-none flex items-center space-x-2.5 cursor-pointer hover:bg-surface-high/30 active:scale-[0.98] transition-all"
            title="点击强制刷新天气信息"
            @click="fetchRealtimeWeather(true)"
          >
            <CloudIcon class="w-3.5 h-3.5 text-primary/75 shrink-0" stroke-width="1.8" />
            <div class="flex-1 min-w-0">
              <div class="font-bold text-on-surface truncate">{{ userProfile.location || '未设置所在地' }}</div>
              <div class="text-[9px] text-on-surface-variant/60 truncate mt-0.5">
                {{ userWeatherText || '正在加载天气...' }}
              </div>
            </div>
          </div>
        </template>

        <!-- ── 音乐菜单列表视图 ── -->
        <template v-else-if="sideView === 'music'">
          <div class="px-4 pt-4 pb-2 flex-shrink-0 flex items-center justify-between select-none">
            <div class="text-sm font-bold text-on-surface">回音音乐</div>
            <button
              v-if="activeMusicTab === 'playlist'"
              @click="showCreatePlaylistModal = true"
              class="px-2 py-0.5 rounded bg-primary/10 hover:bg-primary/20 text-primary cursor-pointer active:scale-95 transition-all text-[9.5px] font-bold"
              title="新建列表"
            >
              新建列表
            </button>
          </div>
          <div class="flex-1 overflow-y-auto py-2 space-y-1 select-none">
            <!-- 歌单推荐 -->
            <button
              @click="
                showMusicSearchResultsView = false;
                activeMusicTab = 'recommend';
                loadRecommendPlaylists();
                currentDetailPlaylistSongs = [];
              "
              class="w-full px-4 py-3 hover:bg-surface-high/60 cursor-pointer transition-colors flex items-center space-x-3 group"
              :class="{
                'bg-surface-high/80 text-primary font-bold':
                  activeMusicTab === 'recommend' || activeMusicTab === 'playlist_detail',
              }"
            >
              <GlobeIcon
                class="w-4 h-4 text-on-surface-variant group-hover:scale-110 transition-transform"
                :class="{ '!text-primary': activeMusicTab === 'recommend' || activeMusicTab === 'playlist_detail' }"
              />
              <span class="text-xs text-on-surface font-semibold text-left flex-1 truncate">歌单推荐</span>
            </button>

            <!-- 排行榜 -->
            <button
              @click="
                showMusicSearchResultsView = false;
                activeMusicTab = 'leaderboard';
                loadLeaderboardList(activeBangId);
              "
              class="w-full px-4 py-3 hover:bg-surface-high/60 cursor-pointer transition-colors flex items-center space-x-3 group"
              :class="{ 'bg-surface-high/80 text-primary font-bold': activeMusicTab === 'leaderboard' }"
            >
              <ActivityIcon
                class="w-4 h-4 text-on-surface-variant group-hover:scale-110 transition-transform"
                :class="{ '!text-primary': activeMusicTab === 'leaderboard' }"
              />
              <span class="text-xs text-on-surface font-semibold text-left flex-1 truncate">排行榜</span>
            </button>

            <!-- 播放列表 -->
            <button
              @click="
                showMusicSearchResultsView = false;
                activeMusicTab = 'playlist';
                musicStore.loadPlaylistSongs(musicStore.state.activePlaylistId);
                currentDetailPlaylistSongs = [];
              "
              class="w-full px-4 py-3 hover:bg-surface-high/60 cursor-pointer transition-colors flex items-center space-x-3 group"
              :class="{ 'bg-surface-high/80 text-primary font-bold': activeMusicTab === 'playlist' }"
            >
              <MusicIcon
                class="w-4 h-4 text-on-surface-variant group-hover:scale-110 transition-transform"
                :class="{ '!text-primary': activeMusicTab === 'playlist' }"
              />
              <span class="text-xs text-on-surface font-semibold text-left flex-1 truncate">自建播放列表</span>
            </button>

            <!-- 自建列表展开项 -->
            <div v-if="activeMusicTab === 'playlist' && !currentDetailPlaylistSongs.length" class="pl-6 pr-2 space-y-1">
              <!-- “我的收藏”列表 -->
              <button
                @click="
                  showMusicSearchResultsView = false;
                  musicStore.loadPlaylistSongs('love');
                "
                class="w-full px-3 py-2 rounded-xl hover:bg-surface-high text-[11px] flex items-center justify-between text-left"
                :class="
                  musicStore.state.activePlaylistId === 'love'
                    ? 'text-primary font-bold bg-primary/5'
                    : 'text-on-surface-variant'
                "
              >
                <span class="truncate">❤️ 我的收藏</span>
                <span class="text-[9px] font-mono opacity-50">({{ musicStore.state.favoriteSongs.length }})</span>
              </button>

              <!-- 其他自建列表 -->
              <div
                v-for="lst in musicStore.state.playlists"
                :key="lst.id"
                class="w-full flex items-center justify-between group/lst px-3 py-1.5 rounded-xl hover:bg-surface-high text-[11px]"
                :class="
                  musicStore.state.activePlaylistId === lst.id
                    ? 'text-primary font-bold bg-primary/5'
                    : 'text-on-surface-variant'
                "
              >
                <button
                  @click="
                    showMusicSearchResultsView = false;
                    musicStore.loadPlaylistSongs(lst.id);
                  "
                  class="flex-1 text-left truncate cursor-pointer"
                >
                  📁 {{ lst.name }}
                </button>
                <button
                  @click="musicStore.deletePlaylist(lst.id)"
                  class="opacity-0 group-hover/lst:opacity-100 p-0.5 text-on-surface-variant/40 hover:text-red-500 active:scale-90 transition-all cursor-pointer font-sans"
                  title="删除列表"
                >
                  ✕
                </button>
              </div>
            </div>

            <!-- 下载 -->
            <button
              @click="
                showMusicSearchResultsView = false;
                activeMusicTab = 'download';
              "
              class="w-full px-4 py-3 hover:bg-surface-high/60 cursor-pointer transition-colors flex items-center space-x-3 group"
              :class="{ 'bg-surface-high/80 text-primary font-bold': activeMusicTab === 'download' }"
            >
              <DownloadIcon
                class="w-4 h-4 text-on-surface-variant group-hover:scale-110 transition-transform"
                :class="{ '!text-primary': activeMusicTab === 'download' }"
              />
              <span class="text-xs text-on-surface font-semibold text-left flex-1 truncate">下载中心</span>
            </button>

            <!-- 设置 -->
            <button
              @click="
                showMusicSearchResultsView = false;
                activeMusicTab = 'settings';
              "
              class="w-full px-4 py-3 hover:bg-surface-high/60 cursor-pointer transition-colors flex items-center space-x-3 group"
              :class="{ 'bg-surface-high/80 text-primary font-bold': activeMusicTab === 'settings' }"
            >
              <SettingsIcon
                class="w-4 h-4 text-on-surface-variant group-hover:scale-110 transition-transform"
                :class="{ '!text-primary': activeMusicTab === 'settings' }"
              />
              <span class="text-xs text-on-surface font-semibold text-left flex-1 truncate">音乐设置</span>
            </button>
          </div>
        </template>

        <!-- ── 小说阅读器目录左栏 ── -->
        <template v-else-if="sideView === 'bookshelf' && selectedBookId">
          <div class="h-full flex flex-col min-h-0 bg-sidebar border-r border-sidebar-border/30">
            <!-- 顶部操作栏：返回书架 -->
            <div class="h-14 px-4 flex items-center justify-between border-b border-outline-variant/30 flex-shrink-0">
              <button
                @click="closeBook"
                class="flex items-center space-x-1.5 text-xs text-on-surface-variant hover:text-primary transition-all"
              >
                <ChevronLeftIcon class="w-4 h-4" />
                <span class="font-bold">返回书架</span>
              </button>
              <button
                @click="triggerBookExportTxt(selectedBookId)"
                class="text-[10px] font-bold text-primary hover:underline"
              >
                导出整书
              </button>
            </div>

            <!-- 目录列表 -->
            <div class="flex-1 overflow-y-auto p-3 space-y-1.5 min-h-0">
              <div v-if="bookChapters.length === 0" class="text-xs text-on-surface-variant/40 text-center py-10">
                暂无章节内容
              </div>
              <button
                v-for="ch in bookChapters"
                :key="ch.id"
                @click="loadChapterContent(ch.id)"
                class="w-full text-left px-3.5 py-2.5 rounded-xl border text-xs flex items-center justify-between transition-all"
                :class="
                  selectedBookChapterId === ch.id
                    ? 'border-primary bg-primary/5 font-bold text-primary animate-in fade-in duration-200'
                    : 'border-transparent bg-surface-low/30 hover:bg-surface-high/30 text-on-surface'
                "
              >
                <span class="truncate pr-2">第{{ ch.chapter_index }}章 {{ ch.title }}</span>
                <span v-if="ch.rating > 0" class="text-[9px] text-amber-500 shrink-0 font-normal"
                  >★ {{ ch.rating }}</span
                >
              </button>
            </div>
          </div>
        </template>
      </aside>

      <!-- 会话列表与聊天视窗之间的可拖拽分割线 -->
      <div
        v-if="
          sideView !== 'stats' &&
          sideView !== 'moments' &&
          sideView !== 'forum' &&
          sideView !== 'favorites' &&
          sideView !== 'home' &&
          (sideView !== 'bookshelf' || selectedBookId)
        "
        @mousedown="startResize"
        class="hidden md:block w-[1px] hover:w-[2px] bg-sidebar-border hover:bg-primary cursor-col-resize transition-all h-full z-20 flex-shrink-0"
        title="拖动调整宽度"
      ></div>

      <!-- ====== 右侧主区域 ====== -->
      <main
        class="flex-1 h-full flex flex-col min-w-0 bg-chat-bg overflow-hidden relative"
        :class="{
          'hidden md:flex':
            !['stats', 'moments', 'forum', 'favorites', 'bookshelf', 'home'].includes(sideView) && !isRightPanelActive,
          'w-full': isMobile,
        }"
      >
        <!-- 唯美梦境睡眠进化动画遮罩 -->
        <div
          v-if="isDreaming"
          class="absolute inset-0 z-40 bg-black/60 backdrop-blur-md flex flex-col items-center justify-center text-white p-8 select-none"
        >
          <div class="relative w-20 h-20 mb-5 flex items-center justify-center">
            <div class="absolute inset-0 rounded-full bg-indigo-500/20 animate-ping"></div>
            <div class="absolute inset-2 rounded-full bg-indigo-500/40 animate-pulse"></div>
            <MoonIcon class="w-8 h-8 text-indigo-200 relative z-10 animate-bounce" />
          </div>
          <h3 class="text-sm font-bold tracking-wider mb-1.5 text-indigo-200">正在进入梦境睡眠反思...</h3>
          <p class="text-[10px] text-zinc-400 max-w-xs text-center leading-relaxed">
            AI 角色正在深睡自省中，深度剖析最近对话历史以捕获您的挫败信号，并 Patch 避坑技能，请稍后...
          </p>
        </div>

        <!-- ── 大模型数据统计详情页 ── -->
        <template v-if="sideView === 'stats'">
          <div class="flex-1 flex flex-col min-h-0 bg-surface overflow-hidden">
            <!-- 顶部 Header -->
            <header
              class="h-14 px-6 border-b border-outline-variant/20 bg-surface flex items-center justify-between flex-shrink-0"
            >
              <div class="text-sm font-bold text-on-surface flex items-center space-x-2 select-none">
                <BarChart3Icon class="w-4 h-4 text-primary animate-pulse" />
                <span>数据面板</span>
              </div>

              <!-- 主/辅助大模型数据切换开关 (当且仅当启用辅助模型时智能展示) -->
              <div
                v-if="statsData.hasSecondary"
                class="flex rounded-xl bg-surface-high border border-outline-variant/60 p-0.5 shadow-inner select-none"
              >
                <button
                  @click="currentStatsModelRole = 'primary'"
                  class="px-3.5 py-1 text-[11px] font-bold rounded-lg transition-all select-none cursor-pointer focus:outline-none flex items-center space-x-1.5 active:scale-95"
                  :class="
                    currentStatsModelRole === 'primary'
                      ? 'bg-primary text-white shadow-sm font-black'
                      : 'text-on-surface-variant hover:text-on-surface'
                  "
                >
                  <CpuIcon class="w-3.5 h-3.5" />
                  <span>主模型数据</span>
                </button>
                <button
                  @click="currentStatsModelRole = 'secondary'"
                  class="px-3.5 py-1 text-[11px] font-bold rounded-lg transition-all select-none cursor-pointer focus:outline-none flex items-center space-x-1.5 active:scale-95"
                  :class="
                    currentStatsModelRole === 'secondary'
                      ? 'bg-secondary text-white shadow-sm font-black'
                      : 'text-on-surface-variant hover:text-on-surface'
                  "
                >
                  <SparklesIcon class="w-3.5 h-3.5 text-pink-300" />
                  <span>辅助模型数据</span>
                </button>
              </div>
            </header>

            <!-- 主滚动页面 -->
            <div
              class="flex-1 overflow-y-auto p-6 space-y-6 min-h-0 select-text max-w-4xl w-full mx-auto flex flex-col"
            >
              <!-- 第一部分：总览数据卡片 -->
              <div class="grid grid-cols-1 md:grid-cols-2 gap-4 flex-shrink-0 select-none">
                <!-- 1. AI累计调用次数卡片 -->
                <div
                  class="p-6 rounded-3xl border border-outline-variant/30 bg-surface-lowest/70 backdrop-blur-md shadow-sm relative overflow-hidden group hover:-translate-y-1.5 hover:shadow-xl transition-all duration-300 flex flex-col justify-between min-h-[155px]"
                  :class="
                    statsData.hasSecondary && currentStatsModelRole === 'secondary'
                      ? 'hover:border-secondary/40 hover:shadow-secondary/5'
                      : 'hover:border-primary/40 hover:shadow-primary/5'
                  "
                >
                  <!-- 背景装饰超大 Icon (Hover 缩放) -->
                  <div
                    class="absolute -right-4 -bottom-4 opacity-[0.03] group-hover:scale-110 transition-all duration-300"
                    :class="
                      statsData.hasSecondary && currentStatsModelRole === 'secondary'
                        ? 'text-secondary'
                        : 'text-primary'
                    "
                  >
                    <BarChart3Icon class="w-32 h-32" />
                  </div>

                  <!-- 1. 卡片首行：图标盒 + 角标徽章 -->
                  <div class="flex items-center justify-between w-full select-none mb-3.5">
                    <div
                      class="p-2.5 rounded-2xl flex-shrink-0 shadow-sm"
                      :class="
                        statsData.hasSecondary && currentStatsModelRole === 'secondary'
                          ? 'bg-secondary/15 text-secondary'
                          : 'bg-primary/15 text-primary'
                      "
                    >
                      <CpuIcon class="w-6 h-6 animate-pulse" />
                    </div>
                    <span
                      v-if="statsData.hasSecondary"
                      class="text-[9px] font-black uppercase tracking-widest px-2.5 py-0.5 rounded-lg border shadow-sm backdrop-blur-sm"
                      :class="
                        currentStatsModelRole === 'secondary'
                          ? 'text-secondary bg-secondary/10 border-secondary/20'
                          : 'text-primary bg-primary/10 border-primary/20'
                      "
                    >
                      {{ currentStatsModelRole === 'secondary' ? '辅助模型' : '主模型' }}
                    </span>
                    <span
                      v-else
                      class="text-[9px] font-black uppercase tracking-widest px-2.5 py-0.5 rounded-lg border border-primary/20 text-primary bg-primary/10 shadow-sm"
                    >
                      主模型
                    </span>
                  </div>

                  <!-- 2. 卡片二行：说明文本 -->
                  <div
                    class="text-[10px] font-bold text-on-surface-variant/80 font-sans tracking-widest uppercase mb-1 flex items-center space-x-1"
                  >
                    <span
                      class="w-1 h-1 rounded-full"
                      :class="
                        statsData.hasSecondary && currentStatsModelRole === 'secondary' ? 'bg-secondary' : 'bg-primary'
                      "
                    ></span>
                    <span>AI累计调用次数 (Calls)</span>
                  </div>

                  <!-- 3. 卡片三行：超大数值 -->
                  <div class="text-3xl font-black text-on-surface font-sans tracking-tight flex items-baseline mt-auto">
                    <span
                      :class="
                        statsData.hasSecondary && currentStatsModelRole === 'secondary'
                          ? 'text-secondary'
                          : 'text-primary'
                      "
                    >
                      {{
                        statsData.hasSecondary
                          ? currentStatsModelRole === 'secondary'
                            ? statsData.secondaryCalls
                            : statsData.primaryCalls
                          : statsData.totalCalls
                      }}
                    </span>
                    <span class="text-xs font-normal text-on-surface-variant ml-1.5">次</span>
                  </div>

                  <!-- 底部发光彩虹渐变线 -->
                  <div
                    class="absolute bottom-0 left-0 right-0 h-[3px] transition-all duration-300"
                    :class="
                      statsData.hasSecondary && currentStatsModelRole === 'secondary'
                        ? 'bg-gradient-to-r from-purple-500 via-fuchsia-500 to-pink-500'
                        : 'bg-gradient-to-r from-blue-500 via-indigo-500 to-violet-600'
                    "
                  ></div>
                </div>

                <!-- 2. 算力消耗总计卡片 -->
                <div
                  class="p-6 rounded-3xl border border-outline-variant/30 bg-surface-lowest/70 backdrop-blur-md shadow-sm relative overflow-hidden group hover:-translate-y-1.5 hover:shadow-xl transition-all duration-300 flex flex-col justify-between min-h-[155px]"
                  :class="
                    statsData.hasSecondary && currentStatsModelRole === 'secondary'
                      ? 'hover:border-pink-500/40 hover:shadow-pink-500/5'
                      : 'hover:border-emerald-500/40 hover:shadow-emerald-500/5'
                  "
                >
                  <!-- 背景装饰超大 Icon -->
                  <div
                    class="absolute -right-4 -bottom-4 opacity-[0.03] group-hover:scale-110 transition-all duration-300"
                    :class="
                      statsData.hasSecondary && currentStatsModelRole === 'secondary'
                        ? 'text-secondary'
                        : 'text-primary'
                    "
                  >
                    <BrainIcon class="w-32 h-32" />
                  </div>

                  <!-- 1. 卡片首行：图标盒 + 角标徽章 -->
                  <div class="flex items-center justify-between w-full select-none mb-3.5">
                    <div
                      class="p-2.5 rounded-2xl flex-shrink-0 shadow-sm"
                      :class="
                        statsData.hasSecondary && currentStatsModelRole === 'secondary'
                          ? 'bg-secondary/15 text-secondary'
                          : 'bg-primary/15 text-primary'
                      "
                    >
                      <ActivityIcon class="w-6 h-6 animate-pulse" />
                    </div>
                    <span
                      v-if="statsData.hasSecondary"
                      class="text-[9px] font-black uppercase tracking-widest px-2.5 py-0.5 rounded-lg border shadow-sm backdrop-blur-sm"
                      :class="
                        currentStatsModelRole === 'secondary'
                          ? 'text-secondary bg-secondary/10 border-secondary/20'
                          : 'text-primary bg-primary/10 border-primary/20'
                      "
                    >
                      {{ currentStatsModelRole === 'secondary' ? '辅助模型' : '主模型' }}
                    </span>
                    <span
                      v-else
                      class="text-[9px] font-black uppercase tracking-widest px-2.5 py-0.5 rounded-lg border border-primary/20 text-primary bg-primary/10 shadow-sm"
                    >
                      主模型
                    </span>
                  </div>

                  <!-- 2. 卡片二行：说明文本 -->
                  <div
                    class="text-[10px] font-bold text-on-surface-variant/80 font-sans tracking-widest uppercase mb-1 flex items-center space-x-1"
                  >
                    <span
                      class="w-1 h-1 rounded-full"
                      :class="
                        statsData.hasSecondary && currentStatsModelRole === 'secondary' ? 'bg-secondary' : 'bg-primary'
                      "
                    ></span>
                    <span>算力消耗总计 (Tokens)</span>
                  </div>

                  <!-- 3. 卡片三行：超大数值 -->
                  <div class="text-3xl font-black text-on-surface font-sans tracking-tight flex items-baseline mt-auto">
                    <span
                      :class="
                        statsData.hasSecondary && currentStatsModelRole === 'secondary'
                          ? 'text-secondary'
                          : 'text-primary'
                      "
                    >
                      {{
                        statsData.hasSecondary
                          ? (currentStatsModelRole === 'secondary'
                              ? statsData.secondaryTokens
                              : statsData.primaryTokens
                            ).toLocaleString()
                          : statsData.totalTokens.toLocaleString()
                      }}
                    </span>
                    <span class="text-xs font-normal text-on-surface-variant ml-1.5">Tokens</span>
                  </div>

                  <!-- 底部发光彩虹渐变线 -->
                  <div
                    class="absolute bottom-0 left-0 right-0 h-[3px] transition-all duration-300"
                    :class="
                      statsData.hasSecondary && currentStatsModelRole === 'secondary'
                        ? 'bg-gradient-to-r from-pink-500 via-rose-500 to-red-500'
                        : 'bg-gradient-to-r from-cyan-500 via-teal-500 to-emerald-500'
                    "
                  ></div>
                </div>
              </div>

              <!-- 第二部分：图表区（带天/周胶囊切换） -->
              <div
                class="flex-1 min-h-[340px] flex flex-col p-5 rounded-2xl border border-outline-variant/60 bg-surface-lowest shadow-sm"
              >
                <!-- 胶囊页签切换 -->
                <div class="flex items-center justify-between mb-6 flex-shrink-0 select-none">
                  <span class="text-xs font-bold text-on-surface font-sans">大模型调用与消耗走势分析</span>
                  <div class="flex rounded-xl bg-surface-high border border-outline-variant p-0.5">
                    <button
                      @click="statsViewMode = 'day'"
                      class="px-3.5 py-1 text-[11px] font-bold rounded-lg transition-all select-none cursor-pointer focus:outline-none"
                      :class="
                        statsViewMode === 'day'
                          ? 'bg-primary text-white shadow-sm font-black'
                          : 'text-on-surface-variant hover:text-on-surface'
                      "
                    >
                      按天统计 (7天)
                    </button>
                    <button
                      @click="statsViewMode = 'week'"
                      class="px-3.5 py-1 text-[11px] font-bold rounded-lg transition-all select-none cursor-pointer focus:outline-none"
                      :class="
                        statsViewMode === 'week'
                          ? 'bg-primary text-white shadow-sm font-black'
                          : 'text-on-surface-variant hover:text-on-surface'
                      "
                    >
                      按周统计 (8周)
                    </button>
                  </div>
                </div>

                <!-- 图表主要区域 -->
                <div
                  v-if="isStatsLoading"
                  class="flex-1 flex flex-col items-center justify-center space-y-2 select-none"
                >
                  <Loader2Icon class="w-8 h-8 text-primary animate-spin" />
                  <span class="text-xs text-on-surface-variant font-bold">算力统计提取中...</span>
                </div>
                <div v-else class="flex-1 grid grid-cols-1 md:grid-cols-2 gap-8 min-h-0">
                  <!-- 1. 调用频次柱状图 -->
                  <div class="flex flex-col h-full">
                    <div
                      class="text-[10px] font-bold text-primary mb-3 flex items-center space-x-1.5 flex-shrink-0 select-none"
                    >
                      <span
                        :class="
                          statsData.hasSecondary && currentStatsModelRole === 'secondary'
                            ? 'text-secondary'
                            : 'text-primary'
                        "
                        >●</span
                      >
                      <span
                        >{{
                          statsData.hasSecondary
                            ? currentStatsModelRole === 'secondary'
                              ? '辅助模型 AI调用次数'
                              : '主模型 AI调用次数'
                            : 'AI累计调用次数'
                        }}
                        (Calls)</span
                      >
                    </div>
                    <!-- 天/周图表主体列组 -->
                    <div class="flex-1 flex items-end space-x-3.5 px-3 min-h-0">
                      <div
                        v-for="item in statsViewMode === 'day' ? statsData.statsDays : statsData.statsWeeks"
                        :key="item.label"
                        class="flex-1 h-full flex flex-col justify-end items-center min-w-0 group relative"
                      >
                        <!-- 极具高级磨砂玻璃感与清晰对比度的高级 Tooltip 悬浮框 -->
                        <div
                          class="absolute bottom-full mb-2 opacity-0 group-hover:opacity-100 scale-95 group-hover:scale-100 bg-white/90 dark:bg-slate-950/90 backdrop-blur-md text-slate-800 dark:text-slate-200 text-[10px] font-bold font-mono px-3 py-2 rounded-2xl shadow-xl border border-slate-200/50 dark:border-slate-800/40 pointer-events-none transition-all duration-200 z-10 whitespace-nowrap flex flex-col space-y-1.5 leading-tight"
                        >
                          <span
                            class="text-slate-500 dark:text-slate-400 border-b border-slate-200/60 dark:border-slate-800/60 pb-1 text-center font-sans font-medium"
                            >{{ item.fullLabel }}</span
                          >

                          <!-- 分模型展示，采用高对比度鲜明配色 -->
                          <template v-if="statsData.hasSecondary">
                            <span
                              v-if="currentStatsModelRole === 'secondary'"
                              class="text-pink-600 dark:text-pink-400 font-extrabold font-sans flex items-center space-x-1 justify-center"
                            >
                              <span>●</span>
                              <span>辅助模型: {{ item.secondaryCalls }} 次</span>
                            </span>
                            <span
                              v-else
                              class="text-blue-600 dark:text-blue-400 font-extrabold font-sans flex items-center space-x-1 justify-center"
                            >
                              <span>●</span>
                              <span>主模型: {{ item.primaryCalls }} 次</span>
                            </span>
                          </template>
                          <template v-else>
                            <span
                              class="text-blue-600 dark:text-blue-400 font-extrabold font-sans flex items-center space-x-1 justify-center"
                            >
                              <span>●</span>
                              <span>AI调用次数: {{ item.calls }} 次</span>
                            </span>
                          </template>
                        </div>

                        <!-- 柱子展示容器 -->
                        <div
                          class="w-full flex-1 flex items-end justify-center pb-2 border-b border-outline-variant/40 min-h-0"
                        >
                          <!-- 辅助模型柱子 (紫粉色) -->
                          <div
                            v-if="statsData.hasSecondary && currentStatsModelRole === 'secondary'"
                            class="w-7 rounded-t-md bg-gradient-to-t from-purple-500/80 to-pink-600/95 group-hover:from-purple-400 group-hover:to-pink-500 group-hover:shadow-[0_0_8px_rgba(236,72,153,0.5)] transition-all duration-300"
                            :style="{
                              height: getBarHeightPercent(
                                item.secondaryCalls,
                                statsViewMode === 'day' ? statsData.statsDays : statsData.statsWeeks,
                                'calls',
                              ),
                            }"
                            :title="'辅助模型: ' + item.secondaryCalls + '次'"
                          ></div>
                          <!-- 主模型柱子 (蓝靛色) -->
                          <div
                            v-else
                            class="w-7 rounded-t-md bg-gradient-to-t from-blue-500/80 to-indigo-600/95 group-hover:from-blue-400 group-hover:to-indigo-500 group-hover:shadow-[0_0_8px_rgba(59,130,246,0.5)] transition-all duration-300"
                            :style="{
                              height: getBarHeightPercent(
                                statsData.hasSecondary ? item.primaryCalls : item.calls,
                                statsViewMode === 'day' ? statsData.statsDays : statsData.statsWeeks,
                                'calls',
                              ),
                            }"
                            :title="
                              (statsData.hasSecondary ? '主模型: ' : 'AI调用: ') +
                              (statsData.hasSecondary ? item.primaryCalls : item.calls) +
                              '次'
                            "
                          ></div>
                        </div>

                        <!-- 底部 Label 日期，直接绑定在同一列中，绝对完美中轴对齐，文字水平舒展 -->
                        <div
                          class="w-full text-center pt-2 pb-1.5 text-[9px] font-bold text-on-surface-variant/75 font-mono truncate select-none"
                          :title="item.fullLabel"
                        >
                          {{ item.label }}
                        </div>
                      </div>
                    </div>
                  </div>

                  <!-- 2. Token 消耗柱状图 -->
                  <div class="flex flex-col h-full">
                    <div
                      class="text-[10px] font-bold text-secondary mb-3 flex items-center space-x-1.5 flex-shrink-0 select-none"
                    >
                      <span
                        :class="
                          statsData.hasSecondary && currentStatsModelRole === 'secondary'
                            ? 'text-secondary'
                            : 'text-secondary'
                        "
                        >●</span
                      >
                      <span
                        >{{
                          statsData.hasSecondary
                            ? currentStatsModelRole === 'secondary'
                              ? '辅助模型 算力消耗总计'
                              : '主模型 算力消耗总计'
                            : '算力消耗总计'
                        }}
                        (Tokens)</span
                      >
                    </div>
                    <!-- 天/周图表主体列组 -->
                    <div class="flex-1 flex items-end space-x-3.5 px-3 min-h-0">
                      <div
                        v-for="item in statsViewMode === 'day' ? statsData.statsDays : statsData.statsWeeks"
                        :key="item.label"
                        class="flex-1 h-full flex flex-col justify-end items-center min-w-0 group relative"
                      >
                        <!-- 极具高级磨砂玻璃感与清晰对比度的高级 Tooltip 悬浮框 -->
                        <div
                          class="absolute bottom-full mb-2 opacity-0 group-hover:opacity-100 scale-95 group-hover:scale-100 bg-white/90 dark:bg-slate-950/90 backdrop-blur-md text-slate-800 dark:text-slate-200 text-[10px] font-bold font-mono px-3 py-2 rounded-2xl shadow-xl border border-slate-200/50 dark:border-slate-800/40 pointer-events-none transition-all duration-200 z-10 whitespace-nowrap flex flex-col space-y-1.5 leading-tight"
                        >
                          <span
                            class="text-slate-500 dark:text-slate-400 border-b border-slate-200/60 dark:border-slate-800/60 pb-1 text-center font-sans font-medium"
                            >{{ item.fullLabel }}</span
                          >

                          <!-- 分模型展示，采用高对比度鲜明配色 -->
                          <template v-if="statsData.hasSecondary">
                            <span
                              v-if="currentStatsModelRole === 'secondary'"
                              class="text-pink-600 dark:text-pink-400 font-extrabold font-sans flex items-center space-x-1 justify-center"
                            >
                              <span>●</span>
                              <span>辅助模型: {{ item.secondaryTokens.toLocaleString() }} T</span>
                            </span>
                            <span
                              v-else
                              class="text-blue-600 dark:text-blue-400 font-extrabold font-sans flex items-center space-x-1 justify-center"
                            >
                              <span>●</span>
                              <span>主模型: {{ item.primaryTokens.toLocaleString() }} T</span>
                            </span>
                          </template>
                          <template v-else>
                            <span
                              class="text-pink-600 dark:text-pink-400 font-extrabold font-sans flex items-center space-x-1 justify-center"
                            >
                              <span>●</span>
                              <span>算力消耗: {{ item.tokens.toLocaleString() }} T</span>
                            </span>
                          </template>
                        </div>

                        <!-- 柱子展示容器 -->
                        <div
                          class="w-full flex-1 flex items-end justify-center pb-2 border-b border-outline-variant/40 min-h-0"
                        >
                          <!-- 辅助模型柱子 (琥珀橙) -->
                          <div
                            class="w-7 rounded-t-md bg-gradient-to-t from-amber-500/80 to-orange-600/95 group-hover:from-amber-400 group-hover:to-orange-500 group-hover:shadow-[0_0_8px_rgba(245,158,11,0.5)] transition-all duration-300"
                            v-if="statsData.hasSecondary && currentStatsModelRole === 'secondary'"
                            :style="{
                              height: getBarHeightPercent(
                                item.secondaryTokens,
                                statsViewMode === 'day' ? statsData.statsDays : statsData.statsWeeks,
                                'tokens',
                              ),
                            }"
                            :title="'辅助模型: ' + item.secondaryTokens + ' Tokens'"
                          ></div>
                          <!-- 主模型/单模型柱子 (青绿/翠绿) -->
                          <div
                            v-else
                            class="w-7 rounded-t-md bg-gradient-to-t from-cyan-500/80 to-emerald-600/95 group-hover:from-cyan-400 group-hover:to-emerald-500 group-hover:shadow-[0_0_8px_rgba(34,211,238,0.5)] transition-all duration-300"
                            :style="{
                              height: getBarHeightPercent(
                                statsData.hasSecondary ? item.primaryTokens : item.tokens,
                                statsViewMode === 'day' ? statsData.statsDays : statsData.statsWeeks,
                                'tokens',
                              ),
                            }"
                            :title="
                              (statsData.hasSecondary ? '主模型: ' : '算力消耗: ') +
                              (statsData.hasSecondary ? item.primaryTokens : item.tokens) +
                              ' Tokens'
                            "
                          ></div>
                        </div>

                        <!-- 底部 Label 日期 -->
                        <div
                          class="w-full text-center pt-2 pb-1.5 text-[9px] font-bold text-on-surface-variant/75 font-mono truncate select-none"
                          :title="item.fullLabel"
                        >
                          {{ item.label }}
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              <!-- 第三部分：DeepSeek 专属余额卡片（按需展示） -->
              <!-- 第三部分：DeepSeek 专属余额卡片（仅在主/辅助模型配置了 DeepSeek 时展现并获取） -->
              <div
                v-if="hasDeepSeek"
                class="p-5 rounded-xl border border-[#d97706]/20 bg-gradient-to-r from-amber-500/5 to-orange-500/5 flex items-center justify-between flex-shrink-0 relative overflow-hidden shadow-sm"
              >
                <div class="flex items-start space-x-4">
                  <div class="p-2.5 rounded-lg bg-amber-500/10 text-amber-600 dark:text-amber-500 mt-0.5 flex-shrink-0">
                    <BanknoteIcon class="w-5.5 h-5.5" />
                  </div>
                  <div class="flex flex-col">
                    <span class="text-xs font-bold text-on-surface font-sans">DeepSeek 官方大模型可用余额</span>
                    <span class="text-[10px] text-on-surface-variant font-bold mt-0.5"
                      >直连 DeepSeek 官方 API 资产账户 (CNY/USD)</span
                    >

                    <!-- 首次获取余额骨架占位屏（彻底消除卡片闪烁） -->
                    <div v-if="!deepseekBalance" class="flex items-center space-x-2 mt-3 animate-pulse">
                      <div class="h-5 w-20 bg-amber-500/20 rounded"></div>
                      <span class="text-[10px] text-on-surface-variant/40 font-bold">算力额度查询中...</span>
                    </div>

                    <!-- 获取成功后展示 -->
                    <div v-else class="flex items-baseline space-x-3 mt-2">
                      <div
                        v-for="info in deepseekBalance.balance.balance_infos"
                        :key="info.currency"
                        class="flex items-baseline space-x-1"
                      >
                        <span class="text-lg font-black text-amber-600 dark:text-amber-500 font-mono">{{
                          Number(info.total_balance).toFixed(2)
                        }}</span>
                        <span class="text-[10px] font-bold text-on-surface-variant">{{ info.currency }}</span>
                      </div>
                    </div>
                  </div>
                </div>

                <button
                  @click="refreshDeepSeekBalance"
                  :disabled="isBalanceLoading"
                  class="px-3.5 py-2 rounded-lg bg-surface hover:bg-surface-high border border-outline-variant text-[11px] font-bold text-on-surface hover:shadow-sm cursor-pointer select-none transition-all flex items-center space-x-1 disabled:opacity-40"
                >
                  <Loader2Icon v-if="isBalanceLoading" class="w-3 h-3 animate-spin text-on-surface-variant" />
                  <SparklesIcon v-else class="w-3 h-3 text-amber-500" />
                  <span>一键刷新</span>
                </button>
              </div>
            </div>
          </div>
        </template>

        <!-- ── 朋友圈动态列表区 ── -->
        <template v-else-if="sideView === 'moments'">
          <div class="flex-1 flex flex-col min-h-0 bg-surface overflow-hidden">
            <!-- 顶部 Header -->
            <header
              class="h-14 px-6 border-b border-outline-variant/20 bg-surface flex items-center justify-between flex-shrink-0 select-none"
            >
              <div class="text-sm font-bold text-on-surface flex items-center space-x-2">
                <GlobeIcon class="w-4 h-4 text-primary animate-pulse" />
                <span>回音朋友圈</span>
              </div>

              <button
                @click="refreshMoments"
                :disabled="isRefreshingMoments"
                class="px-3.5 py-1.5 rounded-xl border border-outline-variant bg-surface hover:bg-surface-high hover:shadow-sm text-[11px] font-bold text-on-surface flex items-center space-x-1.5 disabled:opacity-50 cursor-pointer transition-all active:scale-95"
              >
                <Loader2Icon v-if="isRefreshingMoments" class="w-3.5 h-3.5 animate-spin text-primary" />
                <RefreshCwIcon v-else class="w-3.5 h-3.5 text-on-surface-variant" />
                <span>{{ momentsCooldownText || '手动刷新' }}</span>
              </button>
            </header>

            <!-- 主滚动列表 -->
            <div
              class="flex-1 overflow-y-auto p-4 md:p-6 space-y-4 md:space-y-6 max-w-2xl w-full mx-auto min-h-0 select-text"
            >
              <!-- 有新动态提示状态文字条 -->
              <div
                v-if="hasNewMomentNotification"
                @click="scrollToNewMoment"
                class="mb-4 mx-auto max-w-sm p-2.5 rounded-xl bg-primary/10 border border-primary/20 hover:bg-primary/20 text-primary text-xs font-bold text-center transition-all cursor-pointer shadow-sm animate-bounce flex items-center justify-center space-x-2 select-none"
              >
                <MessageSquareIcon class="w-3.5 h-3.5 animate-pulse text-primary" />
                <span>有新的动态，点击查看</span>
                <SparklesIcon class="w-3.5 h-3.5 text-primary" />
              </div>

              <!-- 用户发表新鲜事面板 -->
              <div
                class="p-5 rounded-2xl bg-surface border border-outline-variant/60 shadow-sm space-y-3.5 flex-shrink-0 select-none"
              >
                <div class="text-xs font-black text-on-surface flex items-center space-x-1.5">
                  <PenLineIcon class="w-3.5 h-3.5 text-primary" />
                  <span>记录今日新鲜事</span>
                </div>
                <textarea
                  v-model="newMomentContent"
                  placeholder="今天有什么所思所想？发表在朋友圈，角色们会为你点赞与评论哦"
                  class="w-full h-20 p-3 rounded-xl border border-outline-variant bg-surface-low text-xs text-on-surface placeholder-on-surface-variant/40 focus:outline-none focus:border-primary resize-none transition-all leading-relaxed"
                ></textarea>
                <div class="flex justify-between items-center">
                  <button
                    @click.stop="openStickersPanel($event, 'newMomentContent')"
                    class="p-1.5 rounded-lg text-on-surface-variant/70 hover:text-primary hover:bg-surface-high transition-all cursor-pointer active:scale-95 flex-shrink-0"
                    title="表情与表情包"
                  >
                    <SmileIcon class="w-4.5 h-4.5" />
                  </button>
                  <button
                    @click="publishUserMoment"
                    :disabled="!newMomentContent.trim()"
                    class="px-4 py-1.5 rounded-xl bg-primary hover:bg-primary-high text-xs font-bold text-white shadow-md transition-all cursor-pointer flex items-center space-x-1.5 disabled:opacity-40 disabled:cursor-not-allowed"
                  >
                    <span>发表动态</span>
                  </button>
                </div>
              </div>

              <!-- 空状态 -->
              <div
                v-if="momentsList.length === 0"
                class="flex flex-col items-center justify-center py-16 text-center select-none text-on-surface-variant/40"
              >
                <GlobeIcon class="w-16 h-16 opacity-25 mb-4 animate-pulse" />
                <p class="text-xs font-bold">朋友圈空荡荡的...</p>
                <p class="text-[10px] mt-1.5 opacity-80 max-w-xs leading-relaxed">
                  数字生命目前还在酝酿新鲜事。与角色进行对话后，她们会在这里发表精彩的个人动态，你也可以发表你的首条动态！
                </p>
              </div>

              <!-- 朋友圈流 -->
              <div
                v-for="moment in momentsList"
                :key="moment.id"
                :id="'moment-item-' + moment.id"
                class="p-5 rounded-2xl bg-surface border border-outline-variant/70 shadow-sm hover:shadow-md hover:border-primary/10 transition-all duration-500 space-y-4 relative overflow-hidden group"
              >
                <!-- 作者卡片 -->
                <div class="flex items-center justify-between select-none flex-shrink-0">
                  <div class="flex items-center space-x-3.5">
                    <div
                      class="w-10 h-10 rounded-xl overflow-hidden border border-outline-variant bg-surface-low flex-shrink-0 shadow-sm"
                    >
                      <img
                        v-if="moment.character_id === 'user'"
                        :src="userProfile.appAvatarUrl || defaultAvatarSrc"
                        class="w-full h-full object-cover"
                      />
                      <img
                        v-else-if="characterAvatars[moment.character_id]"
                        :src="characterAvatars[moment.character_id]"
                        class="w-full h-full object-cover"
                      />
                      <UserIcon v-else class="w-5 h-5 text-on-surface-variant m-auto mt-2.5" />
                    </div>
                    <div>
                      <h4 class="text-xs font-bold text-on-surface leading-tight">{{ moment.author_name }}</h4>
                      <p class="text-[9px] text-on-surface-variant/60 mt-1 font-mono tracking-wider">
                        {{ formatTime(moment.timestamp) }}
                      </p>
                    </div>
                  </div>

                  <!-- 手动删除该朋友圈动态 -->
                  <button
                    @click="deleteUserMomentItem(moment)"
                    class="p-1 rounded-lg text-on-surface-variant/40 hover:text-red-500 hover:bg-red-50 transition-all cursor-pointer active:scale-95 flex-shrink-0"
                    title="物理删除此动态"
                  >
                    <TrashIcon class="w-3.5 h-3.5" />
                  </button>
                </div>

                <!-- 朋友圈文案正文 -->
                <p
                  class="text-[11.5px] text-on-surface leading-relaxed whitespace-pre-wrap pl-1 pr-2 font-medium select-text"
                  v-html="renderTextWithStickers(moment.content)"
                ></p>
                <!-- 朋友圈配图异步加载渲染 [NEW] -->
                <div
                  v-if="moment.imageBase64"
                  class="mt-2.5 max-w-xs md:max-w-sm w-fit rounded-2xl overflow-hidden border border-outline-variant/30 active:scale-[0.99] transition-all cursor-zoom-in"
                  @click="openSocialImagePreview(moment)"
                >
                  <img
                    :src="moment.imageBase64"
                    class="max-w-full h-auto max-h-[500px] block hover:scale-[1.01] transition-transform duration-300 rounded-2xl"
                  />
                </div>

                <!-- 动作条：点赞、评论展开、收藏 -->
                <div
                  class="flex items-center justify-between border-t border-outline-variant/10 pt-2.5 select-none flex-shrink-0"
                >
                  <div class="flex items-center space-x-4 min-w-0">
                    <!-- 点赞区域：头像堆叠 + 点赞按钮 -->
                    <div class="flex items-center space-x-2 min-w-0">
                      <!-- ❤️ 点赞/取消点赞按钮 -->
                      <button
                        @click="toggleLikeMoment(moment)"
                        class="flex items-center space-x-1 text-[10px] font-bold transition-all active:scale-95 flex-shrink-0"
                        :class="moment.liked === 1 ? 'text-red-500' : 'text-on-surface-variant hover:text-red-500'"
                        :title="moment.liked === 1 ? '取消点赞' : '点赞'"
                      >
                        <HeartIcon
                          class="w-3.5 h-3.5 transition-transform"
                          :class="moment.liked === 1 ? 'fill-red-500 scale-110' : 'scale-100'"
                        />
                      </button>

                      <!-- 点赞者头像堆叠（最多显示6个，之后显示+N） -->
                      <div v-if="moment.likes_list && moment.likes_list.length > 0" class="flex items-center min-w-0">
                        <!-- 头像组 -->
                        <div class="flex -space-x-1.5">
                          <template
                            v-for="(liker, idx) in (moment.likes_list || []).slice(0, 6)"
                            :key="liker.character_id"
                          >
                            <div
                              class="w-5 h-5 rounded-full border-2 border-surface overflow-hidden flex-shrink-0 shadow-sm transition-transform hover:scale-110 hover:z-10 relative"
                              :title="liker.author_name"
                            >
                              <!-- 用户（我）头像 -->
                              <img
                                v-if="liker.character_id === 'user'"
                                :src="userProfile.appAvatarUrl || defaultAvatarSrc"
                                class="w-full h-full object-cover"
                              />
                              <!-- 角色头像 -->
                              <img
                                v-else-if="characterAvatars[liker.character_id]"
                                :src="characterAvatars[liker.character_id]"
                                class="w-full h-full object-cover"
                              />
                              <!-- 无头像时用名字首字 -->
                              <div
                                v-else
                                class="w-full h-full bg-primary/20 flex items-center justify-center text-[7px] font-black text-primary"
                              >
                                {{ liker.author_name?.[0] || '?' }}
                              </div>
                            </div>
                          </template>
                        </div>
                        <!-- 超出6个显示 +N -->
                        <span
                          v-if="(moment.likes_list || []).length > 6"
                          class="ml-1 text-[9px] font-bold text-on-surface-variant/60"
                          >+{{ moment.likes_list.length - 6 }}</span
                        >
                        <!-- 点赞者名字列表 tooltip hover区域 -->
                        <span class="ml-1.5 text-[9px] text-on-surface-variant/50 truncate max-w-[90px]">
                          {{ (moment.likes_list || []).map((l: any) => l.author_name).join('、') }}觉得很赞
                        </span>
                      </div>
                      <!-- 无点赞时显示灰色空态 -->
                      <span v-else class="text-[9px] text-on-surface-variant/30 font-mono">暂无点赞</span>
                    </div>

                    <!-- 收藏 -->
                    <button
                      @click="toggleFavoriteMoment(moment)"
                      class="flex items-center space-x-1 text-[10px] font-bold transition-all active:scale-95 flex-shrink-0"
                      :class="moment.isFavorited ? 'text-yellow-500' : 'text-on-surface-variant hover:text-yellow-500'"
                    >
                      <BookmarkIcon class="w-3.5 h-3.5" :class="{ 'fill-yellow-500': moment.isFavorited }" />
                      <span>{{ moment.isFavorited ? '已收藏' : '收藏' }}</span>
                    </button>
                  </div>

                  <span class="text-[8px] text-on-surface-variant/30 font-mono tracking-wider scale-90 flex-shrink-0"
                    >Moment ID: {{ moment.id.split('_').slice(-1)[0] }}</span
                  >
                </div>

                <!-- 💬 朋友圈真实互动评论区 (多端楼中楼) -->
                <div class="mt-3.5 pt-3 border-t border-outline-variant/10 space-y-3.5 select-text pl-1 pr-2">
                  <!-- 评论列表 -->
                  <div
                    v-if="moment.comments && moment.comments.length > 0"
                    class="space-y-2.5 text-xs bg-surface-low/55 p-3 rounded-xl border border-outline-variant/30"
                  >
                    <div
                      v-for="c in moment.comments"
                      :key="c.id"
                      class="leading-relaxed text-[11px] group/item text-on-surface"
                    >
                      <span class="font-bold text-primary">{{ c.author_name }}</span>
                      <span v-if="c.reply_to_name" class="text-on-surface-variant/70 font-normal">
                        回复 <span class="font-bold text-primary">{{ c.reply_to_name }}</span></span
                      >
                      <span class="text-on-surface-variant">: </span>
                      <span
                        class="text-on-surface font-medium select-text"
                        v-html="renderTextWithStickers(c.content)"
                      ></span>
                      <!-- 回复小图标 -->
                      <button
                        @click="startMomentReply(moment, c)"
                        class="ml-2 opacity-0 group-hover/item:opacity-100 text-[9px] text-primary hover:underline font-bold transition-all select-none cursor-pointer"
                      >
                        回复
                      </button>
                      <!-- 删除小图标 -->
                      <button
                        @click="deleteMomentCommentItem(moment, c)"
                        class="ml-2 opacity-0 group-hover/item:opacity-100 text-[9px] text-red-500 hover:underline font-bold transition-all select-none cursor-pointer"
                      >
                        删除
                      </button>
                    </div>
                  </div>

                  <!-- 输入框 -->
                  <div class="flex items-center space-x-1.5 select-none relative">
                    <!-- 评论@联想角色浮窗 -->
                    <div
                      v-if="showMomentAtList && activeMomentForAt?.id === moment.id"
                      class="absolute bottom-full left-0 right-0 mb-2 z-50 rounded-xl border border-outline-variant/60 shadow-lg max-h-[160px] overflow-y-auto animate-scale-in p-1 select-none flex flex-col min-w-[200px] bg-surface"
                    >
                      <div
                        class="text-[9px] font-bold text-on-surface-variant/40 px-2.5 py-1.5 border-b border-outline-variant/10 uppercase tracking-wider font-mono"
                      >
                        选择提及的角色 (@提及)
                      </div>
                      <div
                        v-if="filteredMomentAtCharacters.length === 0"
                        class="text-center py-4 text-[10px] text-on-surface-variant/40"
                      >
                        未找到匹配的角色 🐾
                      </div>
                      <div
                        v-else
                        v-for="char in filteredMomentAtCharacters"
                        :key="char.id"
                        @click="selectMomentAtCharacter(char)"
                        class="flex items-center space-x-2 px-2.5 py-1.5 rounded-lg hover:bg-primary/5 active:bg-primary/10 transition-colors cursor-pointer select-none"
                      >
                        <div
                          class="w-5 h-5 rounded-md overflow-hidden border border-outline-variant bg-surface-low flex-shrink-0 shadow-sm flex items-center justify-center"
                        >
                          <img
                            v-if="characterAvatars[char.id]"
                            :src="characterAvatars[char.id]"
                            class="w-full h-full object-cover"
                          />
                          <UserIcon v-else class="w-3.5 h-3.5 text-on-surface-variant" />
                        </div>
                        <span class="text-xs font-bold text-on-surface truncate">{{ char.name }}</span>
                      </div>
                    </div>

                    <button
                      @click.stop="openStickersPanel($event, 'momentComment', moment)"
                      class="p-1 rounded-lg text-on-surface-variant/60 hover:text-primary hover:bg-surface-high transition-all cursor-pointer active:scale-95 flex-shrink-0"
                      title="表情与表情包"
                    >
                      <SmileIcon class="w-4 h-4" />
                    </button>
                    <input
                      :id="'moment-comment-input-el-' + moment.id"
                      v-model="moment.inputComment"
                      :placeholder="moment.replyPlaceholder || '留下你的评论...'"
                      @keyup.enter="submitMomentComment(moment)"
                      @input="handleMomentCommentInput($event, moment)"
                      class="flex-1 bg-surface-low border border-outline-variant/80 rounded-xl px-3 py-1.5 text-xs text-on-surface focus:outline-none focus:border-primary placeholder-on-surface-variant/40"
                    />
                    <button
                      @click="submitMomentComment(moment)"
                      :disabled="!moment.inputComment || !moment.inputComment.trim()"
                      class="px-3.5 py-1.5 rounded-xl bg-primary text-white text-xs font-bold shadow hover:bg-primary-high disabled:opacity-40 transition-all select-none cursor-pointer"
                    >
                      发送
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </template>

        <!-- ── 开发者论坛发帖区 (极高品质三栏重构) ── -->
        <template v-else-if="sideView === 'forum'">
          <div class="flex-1 flex min-h-0 bg-surface divide-x divide-outline-variant/15 overflow-hidden">
            <!-- 【三栏论坛 - 中间板块/帖子列表栏】 w-[340px] -->
            <div
              class="w-[340px] flex flex-col min-h-0 bg-surface flex-shrink-0 select-none"
              :class="{ 'hidden md:flex': selectedForumPost, 'w-full': isMobile }"
            >
              <!-- 顶部 Header -->
              <header
                class="h-14 px-4 border-b border-outline-variant/20 flex items-center justify-between flex-shrink-0"
              >
                <div class="text-xs font-black text-on-surface flex items-center space-x-1.5">
                  <ScrollIcon class="w-4 h-4 text-primary animate-pulse" />
                  <span>回音社区</span>
                </div>
                <div class="flex items-center space-x-2">
                  <button
                    @click="refreshForum"
                    :disabled="isRefreshingForum"
                    class="px-2.5 py-1 rounded-lg border border-outline-variant/60 bg-surface hover:bg-surface-high hover:shadow-sm text-[10px] font-bold text-on-surface flex items-center space-x-1.5 disabled:opacity-50 cursor-pointer transition-all active:scale-95"
                  >
                    <Loader2Icon v-if="isRefreshingForum" class="w-3 h-3 animate-spin text-primary" />
                    <RefreshCwIcon v-else class="w-3 h-3 text-on-surface-variant" />
                    <span>{{ forumCooldownText || '刷新' }}</span>
                  </button>
                  <button
                    @click="openPublishForumModal"
                    class="px-2.5 py-1 rounded-lg bg-primary hover:bg-primary-high text-[10px] font-bold text-white shadow transition-all cursor-pointer select-none active:scale-95"
                  >
                    + 发帖
                  </button>
                </div>
              </header>

              <!-- 中间板块标签筛选 (科技前沿、灌水日常、灵感脑洞、异世界探讨、情感树洞、暗夜私语) -->
              <div class="p-3 bg-surface-low border-b border-outline-variant/10 grid grid-cols-2 gap-2 flex-shrink-0">
                <button
                  v-for="b in boards"
                  :key="b.id"
                  @click="selectBoard(b.id)"
                  class="px-3 py-2 rounded-xl border text-[11px] font-black text-center transition-all cursor-pointer truncate shadow-sm hover:scale-[1.02] active:scale-[0.98] flex items-center justify-center space-x-1.5"
                  :class="[
                    selectedBoardId === b.id
                      ? b.id === 'nsfw'
                        ? 'bg-red-600 text-white border-red-600 shadow-sm font-black'
                        : 'bg-primary text-white border-primary shadow-sm font-black'
                      : b.id === 'nsfw'
                        ? 'bg-red-500/5 border-red-500/20 text-red-500 hover:bg-red-500/10'
                        : 'bg-surface border-outline-variant/60 text-on-surface-variant hover:bg-surface-high',
                  ]"
                >
                  <component
                    :is="b.icon"
                    class="w-3.5 h-3.5"
                    :class="[
                      selectedBoardId === b.id
                        ? 'text-white'
                        : b.id === 'nsfw'
                          ? 'text-red-500 animate-pulse'
                          : 'text-on-surface-variant/70',
                    ]"
                  />
                  <span>{{ b.name }}</span>
                </button>
              </div>

              <!-- 帖子列表滚动流 -->
              <div class="flex-1 overflow-y-auto p-3.5 space-y-3 min-h-0">
                <div
                  v-if="forumPostsList.length === 0"
                  class="text-center py-16 text-[10px] text-on-surface-variant/40"
                >
                  当前板块空无一帖
                </div>
                <div
                  v-for="post in forumPostsList"
                  :key="post.id"
                  @click="selectForumPostDetail(post)"
                  class="p-4 rounded-2xl border transition-all cursor-pointer space-y-2.5 select-none hover:shadow-md hover:scale-[1.01] active:scale-[0.99]"
                  :class="
                    selectedForumPost?.id === post.id
                      ? 'bg-primary/5 border-primary shadow-sm'
                      : 'bg-surface border-outline-variant/50 hover:bg-surface-low hover:border-outline-variant'
                  "
                >
                  <div class="flex items-center justify-between text-[9px] text-on-surface-variant/60 font-mono">
                    <span class="truncate max-w-[120px] font-bold">{{ post.author_name }}</span>
                    <div class="flex items-center space-x-1.5">
                      <span
                        v-if="unreadForumPostIds.includes(post.id)"
                        class="w-2 h-2 bg-red-500 rounded-full shadow-sm animate-pulse"
                      ></span>
                      <span>{{ formatTime(post.timestamp) }}</span>
                    </div>
                  </div>
                  <h3
                    class="text-xs font-black text-on-surface leading-tight line-clamp-1"
                    :class="{ 'text-primary': selectedForumPost?.id === post.id }"
                  >
                    {{ post.title }}
                  </h3>
                  <p class="text-[10px] text-on-surface-variant line-clamp-2 leading-relaxed">
                    {{ post.content }}
                  </p>
                  <div class="flex items-center space-x-3 text-[9px] text-on-surface-variant/50 font-mono">
                    <span class="flex items-center space-x-0.5">
                      <EyeIcon class="w-3 h-3 text-on-surface-variant/40" />
                      <span>{{ post.views || 0 }}</span>
                    </span>
                    <span class="flex items-center space-x-0.5">
                      <MessageSquareIcon class="w-3 h-3 text-on-surface-variant/40" />
                      <span>{{ post.replies_count || 0 }}</span>
                    </span>
                  </div>
                </div>
              </div>
            </div>

            <!-- 【三栏论坛 - 右侧详情与互动回复区】 flex-1 -->
            <div
              class="flex-1 flex flex-col min-h-0 bg-surface-low overflow-hidden"
              :class="{ 'hidden md:flex': !selectedForumPost, 'w-full': isMobile }"
            >
              <template v-if="selectedForumPost">
                <!-- 详情 Header -->
                <header
                  class="h-14 px-6 border-b border-outline-variant/20 bg-surface flex items-center justify-between flex-shrink-0 select-none"
                >
                  <div class="flex items-center space-x-2.5">
                    <button
                      v-if="isMobile"
                      @click="selectedForumPost = null"
                      class="mr-1 p-1.5 rounded-xl hover:bg-surface-high text-on-surface-variant active:scale-95 transition-all flex items-center justify-center cursor-pointer"
                      title="返回列表"
                    >
                      <ChevronLeftIcon class="w-5 h-5" />
                    </button>
                    <div class="w-7 h-7 rounded-lg overflow-hidden border border-outline-variant">
                      <img
                        v-if="selectedForumPost.character_id === 'user'"
                        :src="userProfile.appAvatarUrl || defaultAvatarSrc"
                        class="w-full h-full object-cover"
                      />
                      <img
                        v-else-if="characterAvatars[selectedForumPost.character_id]"
                        :src="characterAvatars[selectedForumPost.character_id]"
                        class="w-full h-full object-cover"
                      />
                      <UserIcon v-else class="w-4 h-4 text-on-surface-variant m-auto mt-1.5" />
                    </div>
                    <div>
                      <h4 class="text-xs font-black text-on-surface leading-tight">
                        {{ selectedForumPost.author_name }}
                      </h4>
                      <p class="text-[9px] text-on-surface-variant/50 font-mono mt-0.5">
                        {{ formatTime(selectedForumPost.timestamp) }}
                      </p>
                    </div>
                  </div>

                  <div class="flex items-center space-x-3">
                    <!-- 收藏帖子 -->
                    <button
                      @click="toggleFavoriteForumPost(selectedForumPost)"
                      class="px-3 py-1.5 rounded-lg border text-[10px] font-bold flex items-center space-x-1.5 transition-all active:scale-95 cursor-pointer"
                      :class="
                        selectedForumPost.isFavorited
                          ? 'bg-yellow-500/10 border-yellow-500/30 text-yellow-600'
                          : 'bg-surface border-outline-variant text-on-surface-variant hover:text-yellow-500'
                      "
                    >
                      <BookmarkIcon class="w-3.5 h-3.5" :class="{ 'fill-yellow-500': selectedForumPost.isFavorited }" />
                      <span>{{ selectedForumPost.isFavorited ? '已收藏' : '收藏帖子' }}</span>
                    </button>

                    <!-- 删除帖子 -->
                    <button
                      @click="deleteForumPostItem(selectedForumPost)"
                      class="px-3 py-1.5 rounded-lg border border-red-200 text-[10px] font-bold text-red-600 bg-red-50/50 hover:bg-red-50 transition-all cursor-pointer active:scale-95 flex items-center space-x-1.5"
                      title="物理删除此帖子"
                    >
                      <TrashIcon class="w-3.5 h-3.5" />
                      <span>删除帖子</span>
                    </button>

                    <span
                      class="px-2 py-0.5 rounded text-[8px] font-mono tracking-wider uppercase font-bold scale-90 select-none flex items-center space-x-1 border"
                      :class="[
                        selectedForumPost.board_id === 'nsfw'
                          ? 'bg-red-500/10 text-red-500 border-red-500/20'
                          : 'bg-primary/5 text-primary border-transparent',
                      ]"
                    >
                      <component
                        :is="boards.find(b => b.id === selectedForumPost.board_id)?.icon || 'ScrollIcon'"
                        class="w-2.5 h-2.5"
                      />
                      <span>{{ boards.find(b => b.id === selectedForumPost.board_id)?.name || '开发者论坛' }}</span>
                    </span>
                  </div>
                </header>

                <!-- 详情与评论流 -->
                <div class="flex-1 overflow-y-auto p-6 space-y-6 min-h-0 select-text">
                  <!-- 帖子标题与内容 -->
                  <div class="p-5 rounded-2xl bg-surface border border-outline-variant/60 shadow-sm space-y-4">
                    <h2 class="text-sm font-black text-on-surface leading-snug">{{ selectedForumPost.title }}</h2>

                    <!-- 论坛贴子配图异步加载渲染 [NEW] -->
                    <div
                      v-if="selectedForumPost.imageBase64"
                      class="my-3 max-w-xl w-fit rounded-2xl overflow-hidden border border-outline-variant/30 active:scale-[0.99] transition-all cursor-zoom-in"
                      @click="openForumImagePreview(selectedForumPost)"
                    >
                      <img
                        :src="selectedForumPost.imageBase64"
                        class="max-w-full h-auto max-h-[600px] block hover:scale-[1.01] transition-transform duration-300 rounded-2xl"
                      />
                    </div>

                    <div
                      class="text-[11.5px] leading-relaxed text-on-surface pl-0.5 font-medium select-text font-sans markdown-body"
                      v-html="replaceStickersOnly(renderMarkdown(selectedForumPost.content))"
                    ></div>
                  </div>

                  <!-- 楼中楼互动回复列表 -->
                  <div class="space-y-4">
                    <div class="text-xs font-black text-on-surface select-none flex items-center space-x-1.5">
                      <MessageSquareIcon class="w-3.5 h-3.5 text-primary" />
                      <span>互动回复 ({{ forumCommentsList.length }})</span>
                    </div>

                    <div
                      v-if="forumCommentsList.length === 0"
                      class="text-center py-10 text-[10.5px] text-on-surface-variant/40 bg-surface/50 border border-outline-variant/20 rounded-xl"
                    >
                      暂无评论，留下第一个回音印记吧
                    </div>

                    <div v-else class="space-y-3">
                      <div
                        v-for="c in forumCommentsList"
                        :key="c.id"
                        class="p-4 rounded-xl bg-surface border border-outline-variant/50 shadow-sm space-y-2 select-text group/forum-comment"
                      >
                        <div class="flex items-center justify-between select-none">
                          <div class="flex items-center space-x-2">
                            <div class="w-6 h-6 rounded-md overflow-hidden border border-outline-variant">
                              <img
                                v-if="c.character_id === 'user'"
                                :src="userProfile.appAvatarUrl || defaultAvatarSrc"
                                class="w-full h-full object-cover"
                              />
                              <img
                                v-else-if="characterAvatars[c.character_id]"
                                :src="characterAvatars[c.character_id]"
                                class="w-full h-full object-cover"
                              />
                              <UserIcon v-else class="w-3.5 h-3.5 text-on-surface-variant m-auto mt-1" />
                            </div>
                            <span class="text-xs font-bold text-on-surface">{{ c.author_name }}</span>
                            <span v-if="c.reply_to_name" class="text-[10px] text-on-surface-variant/70 font-normal">
                              回复 <span class="font-bold text-primary">{{ c.reply_to_name }}</span></span
                            >
                          </div>
                          <div class="flex items-center space-x-2">
                            <span class="text-[9px] text-on-surface-variant/40 font-mono">{{
                              formatTime(c.timestamp)
                            }}</span>
                            <button
                              @click="startForumReply(c)"
                              class="opacity-0 group-hover/forum-comment:opacity-100 text-[9px] text-primary hover:underline font-bold transition-all cursor-pointer"
                            >
                              回复
                            </button>
                            <!-- 删除小图标 -->
                            <button
                              @click="deleteForumCommentItem(c)"
                              class="ml-2 opacity-0 group-hover/forum-comment:opacity-100 text-[9px] text-red-500 hover:underline font-bold transition-all cursor-pointer"
                            >
                              删除
                            </button>
                          </div>
                        </div>
                        <p
                          class="text-xs text-on-surface font-medium pl-8 select-text"
                          v-html="renderTextWithStickers(c.content)"
                        ></p>
                      </div>
                    </div>
                  </div>
                </div>

                <!-- 评论发表框 -->
                <footer
                  class="p-4 bg-surface border-t border-outline-variant/20 flex items-center space-x-1.5 flex-shrink-0 select-none relative"
                >
                  <!-- 评论@联想角色浮窗 -->
                  <div
                    v-if="showForumAtList"
                    class="absolute bottom-full left-4 right-4 mb-2 z-50 rounded-xl border border-outline-variant/60 shadow-lg max-h-[160px] overflow-y-auto animate-scale-in p-1 select-none flex flex-col min-w-[200px] bg-surface"
                  >
                    <div
                      class="text-[9px] font-bold text-on-surface-variant/40 px-2.5 py-1.5 border-b border-outline-variant/10 uppercase tracking-wider font-mono"
                    >
                      选择提及的角色 (@提及)
                    </div>
                    <div
                      v-if="filteredForumAtCharacters.length === 0"
                      class="text-center py-4 text-[10px] text-on-surface-variant/40"
                    >
                      未找到匹配的角色 🐾
                    </div>
                    <div
                      v-else
                      v-for="char in filteredForumAtCharacters"
                      :key="char.id"
                      @click="selectForumAtCharacter(char)"
                      class="flex items-center space-x-2 px-2.5 py-1.5 rounded-lg hover:bg-primary/5 active:bg-primary/10 transition-colors cursor-pointer select-none"
                    >
                      <div
                        class="w-5 h-5 rounded-md overflow-hidden border border-outline-variant bg-surface-low flex-shrink-0 shadow-sm flex items-center justify-center"
                      >
                        <img
                          v-if="characterAvatars[char.id]"
                          :src="characterAvatars[char.id]"
                          class="w-full h-full object-cover"
                        />
                        <UserIcon v-else class="w-3.5 h-3.5 text-on-surface-variant" />
                      </div>
                      <span class="text-xs font-bold text-on-surface truncate">{{ char.name }}</span>
                    </div>
                  </div>

                  <button
                    @click.stop="openStickersPanel($event, 'forumCommentInput')"
                    class="p-1.5 rounded-lg text-on-surface-variant/60 hover:text-primary hover:bg-surface-high transition-all cursor-pointer active:scale-95 flex-shrink-0"
                    title="表情与表情包"
                  >
                    <SmileIcon class="w-4.5 h-4.5" />
                  </button>
                  <input
                    id="forum-comment-input-el"
                    v-model="forumCommentInput"
                    :placeholder="forumReplyPlaceholder || '留下你的评论...'"
                    @keyup.enter="submitForumComment"
                    @input="handleForumCommentInput"
                    class="flex-1 bg-surface-low border border-outline-variant/80 rounded-xl px-4 py-2 text-xs text-on-surface focus:outline-none focus:border-primary placeholder-on-surface-variant/40"
                  />
                  <button
                    @click="submitForumComment"
                    :disabled="!forumCommentInput.trim()"
                    class="px-4 py-2 rounded-xl bg-primary text-white text-xs font-bold shadow hover:bg-primary-high disabled:opacity-40 transition-all select-none cursor-pointer"
                  >
                    发送
                  </button>
                </footer>
              </template>

              <div
                v-else
                class="flex-1 flex flex-col items-center justify-center text-center p-12 text-on-surface-variant/40 select-none"
              >
                <ScrollIcon class="w-14 h-14 opacity-25 mb-3 animate-pulse" />
                <p class="text-xs font-bold">请在左侧选择一篇帖子进行阅读</p>
                <p class="text-[10px] opacity-75 mt-1">支持按板块分类快捷筛选，用户或角色的发帖都将在此集结</p>
              </div>
            </div>
          </div>
        </template>

        <!-- ── 统一收藏中心区 (极高品质三栏重构) ── -->
        <template v-else-if="sideView === 'favorites'">
          <div class="flex-1 flex min-h-0 bg-surface divide-x divide-outline-variant/15 overflow-hidden">
            <!-- 【三栏收藏 - 中间筛选栏】 w-[280px] -->
            <div
              class="w-[280px] flex flex-col min-h-0 bg-surface flex-shrink-0 select-none"
              :class="{ 'hidden md:flex': selectedFavorite, 'w-full': isMobile }"
            >
              <!-- 顶部 Header -->
              <header
                class="h-14 px-4 border-b border-outline-variant/20 flex items-center justify-between flex-shrink-0"
              >
                <div class="text-xs font-black text-on-surface flex items-center space-x-1.5">
                  <BookmarkIcon class="w-4 h-4 text-primary animate-pulse" />
                  <span>收藏夹</span>
                </div>
              </header>

              <!-- 筛选过滤器：全部、对话、朋友圈、论坛、日记 -->
              <div class="p-3 bg-surface-low border-b border-outline-variant/10 grid grid-cols-2 gap-1.5 flex-shrink-0">
                <button
                  v-for="filter in favFilters"
                  :key="filter.type"
                  @click="selectFavoriteType(filter.type)"
                  class="px-2 py-1.5 rounded-lg border text-[10.5px] font-black text-center transition-all cursor-pointer truncate flex items-center justify-center space-x-1.5"
                  :class="
                    selectedFavType === filter.type
                      ? 'bg-primary text-white border-primary shadow-sm'
                      : 'bg-surface border-outline-variant/60 text-on-surface-variant hover:bg-surface-high'
                  "
                >
                  <component
                    :is="filter.icon"
                    class="w-3.5 h-3.5"
                    :class="[selectedFavType === filter.type ? 'text-white' : 'text-on-surface-variant/70']"
                  />
                  <span>{{ filter.name }}</span>
                </button>
              </div>

              <!-- 收藏列表 -->
              <div class="flex-1 overflow-y-auto p-3 space-y-3 min-h-0">
                <div v-if="favoritesList.length === 0" class="text-center py-16 text-[10px] text-on-surface-variant/40">
                  当前无收藏内容
                </div>
                <div
                  v-for="fav in favoritesList"
                  :key="fav.id"
                  @click="selectFavoriteDetail(fav)"
                  class="p-3.5 rounded-xl border transition-all cursor-pointer space-y-2 select-none"
                  :class="
                    selectedFavorite?.id === fav.id
                      ? 'bg-primary/5 border-primary shadow-sm'
                      : 'bg-surface border-outline-variant/50 hover:bg-surface-low hover:border-outline-variant'
                  "
                >
                  <!-- 精美微标：标注收藏自哪个角色 -->
                  <div
                    class="flex items-center space-x-1.5 text-[8.5px] font-bold text-primary font-mono bg-primary/5 px-2 py-0.5 rounded-md border border-primary/10 max-w-max"
                  >
                    <span>【{{ fav.author_name }}】</span>
                    <span class="opacity-70 font-sans font-normal">{{
                      favFilters.find(f => f.type === fav.type)?.name
                    }}</span>
                  </div>

                  <h3 class="text-xs font-black text-on-surface leading-tight line-clamp-1">
                    {{ fav.title || '无标题内容' }}
                  </h3>
                  <p class="text-[10px] text-on-surface-variant line-clamp-2 leading-relaxed">
                    {{ fav.content }}
                  </p>
                  <span class="text-[8.5px] text-on-surface-variant/40 font-mono block text-right">{{
                    formatTime(fav.timestamp)
                  }}</span>
                </div>
              </div>
            </div>

            <!-- 【三栏收藏 - 右侧内容大卡片区】 flex-1 -->
            <div
              class="flex-1 flex flex-col min-h-0 bg-surface-low overflow-hidden"
              :class="{ 'hidden md:flex': !selectedFavorite, 'w-full': isMobile }"
            >
              <template v-if="selectedFavorite">
                <!-- Header -->
                <header
                  class="h-14 px-6 border-b border-outline-variant/20 bg-surface flex items-center justify-between flex-shrink-0 select-none"
                >
                  <div class="flex items-center space-x-2.5">
                    <button
                      v-if="isMobile"
                      @click="selectedFavorite = null"
                      class="mr-1 p-1.5 rounded-xl hover:bg-surface-high text-on-surface-variant active:scale-95 transition-all flex items-center justify-center cursor-pointer"
                      title="返回列表"
                    >
                      <ChevronLeftIcon class="w-5 h-5" />
                    </button>
                    <div class="w-7 h-7 rounded-lg overflow-hidden border border-outline-variant">
                      <img
                        v-if="selectedFavorite.character_id === 'user'"
                        :src="userProfile.appAvatarUrl || defaultAvatarSrc"
                        class="w-full h-full object-cover"
                      />
                      <img
                        v-else-if="characterAvatars[selectedFavorite.character_id]"
                        :src="characterAvatars[selectedFavorite.character_id]"
                        class="w-full h-full object-cover"
                      />
                      <UserIcon v-else class="w-4 h-4 text-on-surface-variant m-auto mt-1.5" />
                    </div>
                    <div>
                      <h4 class="text-xs font-black text-on-surface leading-tight">
                        {{ selectedFavorite.author_name }}
                      </h4>
                      <p class="text-[9px] text-on-surface-variant/50 font-mono mt-0.5">
                        收藏于：{{ formatTime(selectedFavorite.timestamp) }}
                      </p>
                    </div>
                  </div>

                  <button
                    @click="deleteFavoriteItem(selectedFavorite)"
                    class="px-3 py-1.5 rounded-lg border border-red-200 text-[10px] font-bold text-red-600 bg-red-50/50 hover:bg-red-50 transition-all cursor-pointer active:scale-95 flex items-center space-x-1"
                  >
                    <span>🗑️ 取消收藏</span>
                  </button>
                </header>

                <!-- 收藏项内容详情 -->
                <div class="flex-1 overflow-y-auto p-6 space-y-5 min-h-0 select-text">
                  <div class="p-6 rounded-2xl bg-surface border border-outline-variant/60 shadow-sm space-y-4">
                    <h2 class="text-sm font-black text-on-surface leading-snug border-b border-outline-variant/10 pb-3">
                      {{ selectedFavorite.title || '收藏内容预览' }}
                    </h2>

                    <div
                      class="text-[11.5px] leading-relaxed text-on-surface pl-0.5 select-text font-sans whitespace-pre-wrap"
                    >
                      <template v-if="selectedFavorite.type === 'moment'">
                        <div v-html="renderTextWithStickers(selectedFavorite.content)"></div>
                      </template>
                      <template v-else-if="selectedFavorite.type === 'forum'">
                        <div
                          class="markdown-body font-medium"
                          v-html="replaceStickersOnly(renderMarkdown(selectedFavorite.content))"
                        ></div>
                      </template>
                      <template v-else>
                        {{ selectedFavorite.content }}
                      </template>
                    </div>

                    <!-- 配图区：若检测到配图，则显示精美大图，支持无缝大图卡片预览 -->
                    <div
                      v-if="selectedFavorite.imageBase64"
                      class="mt-4 max-w-md w-fit rounded-2xl overflow-hidden border border-outline-variant/30 active:scale-[0.99] transition-all cursor-zoom-in shadow-sm"
                      @click="
                        selectedFavorite.type === 'moment'
                          ? openSocialImagePreview(selectedFavorite)
                          : openForumImagePreview(selectedFavorite)
                      "
                    >
                      <img
                        :src="selectedFavorite.imageBase64"
                        class="max-w-full h-auto max-h-[500px] block hover:scale-[1.01] transition-transform duration-300 rounded-2xl"
                      />
                    </div>
                  </div>

                  <!-- 🚀 互动区域补齐（只在 moment 和 forum 类型下显示，直接渲染注入的实时数据） -->

                  <!-- A. 朋友圈点赞与评论互动面板 -->
                  <div v-if="selectedFavorite.type === 'moment'" class="space-y-4 select-text">
                    <div class="text-xs font-black text-on-surface flex items-center space-x-1.5 pl-1 select-none">
                      <HeartIcon class="w-3.5 h-3.5 text-red-500 fill-red-500 animate-pulse" />
                      <span>朋友圈动态互动数据</span>
                    </div>

                    <!-- 点赞者头像与名单堆叠 -->
                    <div
                      v-if="selectedFavorite.likes_list && selectedFavorite.likes_list.length > 0"
                      class="flex items-center p-3.5 bg-surface border border-outline-variant/50 rounded-2xl shadow-sm select-none"
                    >
                      <div class="flex -space-x-1.5 mr-2">
                        <template
                          v-for="(liker, idx) in selectedFavorite.likes_list.slice(0, 6)"
                          :key="liker.character_id"
                        >
                          <div
                            class="w-5 h-5 rounded-full border-2 border-surface overflow-hidden flex-shrink-0 shadow-sm relative transition-transform hover:scale-110 hover:z-10"
                            :title="liker.author_name"
                          >
                            <img
                              v-if="liker.character_id === 'user'"
                              :src="userProfile.appAvatarUrl || defaultAvatarSrc"
                              class="w-full h-full object-cover"
                            />
                            <img
                              v-else-if="characterAvatars[liker.character_id]"
                              :src="characterAvatars[liker.character_id]"
                              class="w-full h-full object-cover"
                            />
                            <div
                              v-else
                              class="w-full h-full bg-primary/20 flex items-center justify-center text-[7px] font-black text-primary"
                            >
                              {{ liker.author_name?.[0] || '?' }}
                            </div>
                          </div>
                        </template>
                      </div>
                      <span
                        v-if="selectedFavorite.likes_list.length > 6"
                        class="text-[9px] font-bold text-on-surface-variant/60 mr-1.5"
                        >+{{ selectedFavorite.likes_list.length - 6 }}</span
                      >
                      <span class="text-[9px] text-on-surface-variant/60 truncate flex-1">
                        {{ selectedFavorite.likes_list.map((l: any) => l.author_name).join('、') }} 觉得很赞
                      </span>
                    </div>

                    <!-- 评论流列表 -->
                    <div class="space-y-3">
                      <div
                        v-if="!selectedFavorite.comments || selectedFavorite.comments.length === 0"
                        class="text-center py-6 text-[10.5px] text-on-surface-variant/40 bg-surface/40 border border-outline-variant/20 rounded-xl"
                      >
                        暂无互动评论数据 🐾
                      </div>
                      <div v-else class="space-y-2.5">
                        <div
                          v-for="c in selectedFavorite.comments"
                          :key="c.id"
                          class="p-3.5 rounded-xl bg-surface border border-outline-variant/50 shadow-sm space-y-1.5 flex items-start space-x-3"
                        >
                          <div class="w-6 h-6 rounded-md overflow-hidden border border-outline-variant flex-shrink-0">
                            <img
                              v-if="c.character_id === 'user'"
                              :src="userProfile.appAvatarUrl || defaultAvatarSrc"
                              class="w-full h-full object-cover"
                            />
                            <img
                              v-else-if="characterAvatars[c.character_id]"
                              :src="characterAvatars[c.character_id]"
                              class="w-full h-full object-cover"
                            />
                            <UserIcon v-else class="w-3.5 h-3.5 text-on-surface-variant m-auto mt-1" />
                          </div>
                          <div class="flex-1 min-w-0">
                            <div class="flex items-center justify-between select-none">
                              <span class="text-xs font-bold text-on-surface">{{ c.author_name }}</span>
                              <span class="text-[8px] text-on-surface-variant/40 font-mono">{{
                                formatTime(c.timestamp)
                              }}</span>
                            </div>
                            <p class="text-[11px] text-on-surface-variant mt-1 leading-relaxed select-text">
                              <span v-if="c.reply_to_name" class="text-on-surface-variant/70 font-normal"
                                >回复 <span class="font-bold text-primary">{{ c.reply_to_name }}</span
                                >：</span
                              >
                              <span v-html="renderTextWithStickers(c.content)"></span>
                            </p>
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>

                  <!-- B. 论坛帖子互动与浏览面板 -->
                  <div v-else-if="selectedFavorite.type === 'forum'" class="space-y-4 select-text">
                    <div class="text-xs font-black text-on-surface flex items-center justify-between pl-1 select-none">
                      <div class="flex items-center space-x-1.5">
                        <MessageSquareIcon class="w-3.5 h-3.5 text-primary" />
                        <span>论坛帖子互动评论 ({{ selectedFavorite.comments?.length || 0 }})</span>
                      </div>
                      <!-- 阅读数显示 -->
                      <div
                        class="flex items-center space-x-1 text-[10px] text-on-surface-variant/50 font-mono font-normal"
                      >
                        <EyeIcon class="w-3 h-3 text-on-surface-variant/40" />
                        <span>总围观浏览量：{{ selectedFavorite.views || 0 }} 次</span>
                      </div>
                    </div>

                    <!-- 楼中楼回复流 -->
                    <div class="space-y-3">
                      <div
                        v-if="!selectedFavorite.comments || selectedFavorite.comments.length === 0"
                        class="text-center py-6 text-[10.5px] text-on-surface-variant/40 bg-surface/40 border border-outline-variant/20 rounded-xl"
                      >
                        此帖子暂无评论回复，静候角色互动吧 🐾
                      </div>
                      <div v-else class="space-y-2.5">
                        <div
                          v-for="c in selectedFavorite.comments"
                          :key="c.id"
                          class="p-3.5 rounded-xl bg-surface border border-outline-variant/50 shadow-sm space-y-1.5 flex items-start space-x-3"
                        >
                          <div class="w-6 h-6 rounded-md overflow-hidden border border-outline-variant flex-shrink-0">
                            <img
                              v-if="c.character_id === 'user'"
                              :src="userProfile.appAvatarUrl || defaultAvatarSrc"
                              class="w-full h-full object-cover"
                            />
                            <img
                              v-else-if="characterAvatars[c.character_id]"
                              :src="characterAvatars[c.character_id]"
                              class="w-full h-full object-cover"
                            />
                            <UserIcon v-else class="w-3.5 h-3.5 text-on-surface-variant m-auto mt-1" />
                          </div>
                          <div class="flex-1 min-w-0">
                            <div class="flex items-center justify-between select-none">
                              <span class="text-xs font-bold text-on-surface">{{ c.author_name }}</span>
                              <span class="text-[8px] text-on-surface-variant/40 font-mono">{{
                                formatTime(c.timestamp)
                              }}</span>
                            </div>
                            <p class="text-[11px] text-on-surface-variant mt-1 leading-relaxed select-text">
                              <span v-if="c.reply_to_name" class="text-on-surface-variant/70 font-normal"
                                >回复 <span class="font-bold text-primary">{{ c.reply_to_name }}</span
                                >：</span
                              >
                              <span v-html="renderTextWithStickers(c.content)"></span>
                            </p>
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </template>

              <div
                v-else
                class="flex-1 flex flex-col items-center justify-center text-center p-12 text-on-surface-variant/40 select-none"
              >
                <BookmarkIcon class="w-14 h-14 opacity-25 mb-3 animate-pulse" />
                <p class="text-xs font-bold">请在左侧选择一篇收藏进行阅读 🐾</p>
                <p class="text-[10px] opacity-75 mt-1">
                  对话、朋友圈、论坛、日记等一切灵光，都可以被安全存放并支持筛选
                </p>
              </div>
            </div>
          </div>
        </template>

        <!-- ── 小说书架与内嵌阅读器 ── -->
        <template v-else-if="sideView === 'bookshelf'">
          <!-- 状态 A：PC 端大网格书架展示（!selectedBookId 且非移动端） -->
          <div v-if="!isMobile && !selectedBookId" class="flex-1 flex flex-col min-h-0 bg-surface overflow-hidden">
            <header
              class="h-14 px-6 border-b border-outline-variant/20 bg-surface flex items-center justify-between flex-shrink-0 select-none"
            >
              <div class="text-sm font-bold text-on-surface flex items-center space-x-2">
                <LibraryIcon class="w-4 h-4 text-primary" />
                <span>小说书架</span>
              </div>
            </header>

            <div class="flex-1 overflow-y-auto p-8 min-h-0">
              <div class="max-w-6xl mx-auto w-full">
                <!-- 空状态 -->
                <div
                  v-if="bookshelfList.length === 0"
                  class="flex flex-col items-center justify-center text-center py-24 text-on-surface-variant/40 select-none animate-in fade-in duration-300"
                >
                  <LibraryIcon class="w-16 h-16 opacity-25 mb-4 text-primary animate-pulse" />
                  <p class="text-sm font-bold text-on-surface">书架空空如也 🐾</p>
                  <p class="text-xs opacity-75 mt-2 max-w-sm leading-relaxed">
                    在角色配置中开启「AI写手」后，系统会根据你们的聊天对话自动改编为小说并收录于此。
                  </p>
                  <button
                    @click="sideView = 'chat'"
                    class="mt-6 px-5 py-2 bg-primary text-white rounded-xl text-xs font-bold shadow-md hover:bg-primary/95 active:scale-95 transition-all"
                  >
                    前去对话生成
                  </button>
                </div>

                <div v-else class="flex flex-col space-y-6">
                  <div v-for="(row, rowIndex) in bookshelfRows" :key="rowIndex" class="w-full flex flex-col">
                    <!-- 每一行之间使用横线隔开，与网格容器同宽并居中 -->
                    <hr
                      v-if="rowIndex > 0"
                      class="border-t border-outline-variant/20 mb-6 w-full max-w-[720px] mx-auto"
                    />

                    <!-- 每行固定 4 个，限制最大宽度并水平居中 -->
                    <div class="grid grid-cols-4 gap-6 w-full max-w-[720px] mx-auto">
                      <div
                        v-for="book in row"
                        :key="book.novelId"
                        class="group flex flex-col space-y-3 cursor-pointer bg-surface-low/20 hover:bg-surface-high/30 p-3 rounded-2xl transition-all duration-300 hover:shadow-lg hover:-translate-y-0.5"
                        @click="openBook(book.novelId, book.characterId)"
                      >
                        <!-- 2:3 竖图封面，无外边框，点击直接阅读 -->
                        <div class="aspect-[2/3] w-full rounded-lg overflow-hidden bg-surface relative shadow-md">
                          <img
                            :src="book.coverUrl"
                            class="w-full h-full object-cover select-none pointer-events-none"
                          />
                          <!-- 小说封面未读红点角标 -->
                          <span
                            v-if="novelNewChapterBadges[book.novelId]"
                            class="absolute top-2 right-2 w-2.5 h-2.5 bg-red-500 rounded-full border border-surface shadow-sm animate-pulse"
                          ></span>
                        </div>
                        <!-- 小说书名 -->
                        <div
                          class="text-xs font-bold text-on-surface truncate text-center group-hover:text-primary transition-all"
                        >
                          {{ book.novelTitle }}
                        </div>
                        <!-- 操作工具区，Hover 时优雅淡入，点击阻止冒泡以防止触发阅读 -->
                        <div
                          class="flex items-center justify-center space-x-2.5 text-[10px] font-semibold text-on-surface-variant/40 opacity-0 group-hover:opacity-100 transition-opacity duration-300 h-4"
                          @click.stop
                        >
                          <button @click="openEditBookModal(book)" class="hover:text-primary transition-colors">
                            改名
                          </button>
                          <span class="text-on-surface-variant/15 select-none">|</span>
                          <button @click="changeBookCover(book.novelId)" class="hover:text-primary transition-colors">
                            换图
                          </button>
                          <span class="text-on-surface-variant/15 select-none">|</span>
                          <button @click="confirmDeleteBook(book)" class="hover:text-red-500 transition-colors">
                            删除
                          </button>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>

          <!-- 状态 B：PC 端双栏阅读器的右侧正文区（selectedBookId 且非移动端） -->
          <div v-else-if="!isMobile && selectedBookId" class="flex-1 flex flex-col min-h-0 bg-surface overflow-hidden">
            <!-- 顶部正文操作 Header -->
            <header
              class="h-14 px-6 border-b border-outline-variant/20 bg-surface flex items-center justify-between flex-shrink-0 select-none"
            >
              <div class="text-xs font-bold text-on-surface flex items-center space-x-2">
                <span>正文阅读</span>
                <span class="text-on-surface-variant/40 font-normal">|</span>
                <span class="text-primary">{{
                  bookshelfList.find(b => b.novelId === selectedBookId)?.novelTitle
                }}</span>
              </div>

              <!-- 单章操作按钮组 -->
              <div v-if="selectedBookChapterId && bookChapters.length > 0" class="flex items-center space-x-3.5">
                <!-- 字号微调 -->
                <div
                  class="flex items-center space-x-1 border border-outline-variant/20 bg-surface-low/30 px-1.5 py-0.5 rounded-lg text-xs mr-1 select-none"
                >
                  <button
                    @click="decreaseFontSize"
                    class="w-6 h-6 flex items-center justify-center font-bold hover:text-primary transition-colors text-on-surface-variant/70 active:scale-95"
                    title="减小字号"
                  >
                    A-
                  </button>
                  <span
                    class="text-[10px] font-bold px-1 select-none border-x border-outline-variant/10 text-on-surface-variant/60"
                    >{{ readerFontSize }}px</span
                  >
                  <button
                    @click="increaseFontSize"
                    class="w-6 h-6 flex items-center justify-center font-bold hover:text-primary transition-colors text-on-surface-variant/70 active:scale-95"
                    title="增大字号"
                  >
                    A+
                  </button>
                </div>

                <!-- 评分星级 -->
                <div
                  class="flex items-center space-x-1 border border-outline-variant/20 bg-surface-low/30 px-2 py-1 rounded-lg text-xs"
                >
                  <span class="text-[10px] text-on-surface-variant/70 pr-0.5">本章评分:</span>
                  <button
                    v-for="star in 5"
                    :key="star"
                    @click="rateChapter(selectedBookChapterId, star)"
                    class="text-xs hover:scale-115 transition-transform"
                  >
                    <span
                      :class="
                        star <= (bookChapters.find(c => c.id === selectedBookChapterId)?.rating || 0)
                          ? 'text-amber-500'
                          : 'text-gray-300 dark:text-gray-600 opacity-40'
                      "
                      >★</span
                    >
                  </button>
                </div>

                <button
                  @click="triggerBookChapterRewrite(selectedBookChapterId)"
                  class="text-xs font-semibold text-primary hover:underline flex items-center space-x-1"
                >
                  <span>重写此章</span>
