                          />
                          <span class="text-[10px] text-on-surface-variant/40">字</span>
                        </div>
                      </div>
                      <p class="text-[9px] text-on-surface-variant/60 leading-relaxed">
                        设置 AI
                        单次输出的最低字数（默认500，不做上限限制）。大模型会严格遵守此铁律，进行多层次的动作神态与心理细节白描。
                      </p>
                    </div>

                    <div class="p-3 bg-surface-low border border-outline-variant/60 rounded-2xl space-y-2 select-none">
                      <div class="flex items-center justify-between">
                        <span class="text-xs font-bold text-on-surface flex items-center space-x-1.5">
                          <SlidersHorizontalIcon class="w-3.5 h-3.5 text-primary" />
                          <span>导演模式最低字数限制</span>
                        </span>
                        <div
                          class="flex items-center space-x-1 border border-outline-variant rounded-xl bg-surface px-2.5 py-1"
                        >
                          <input
                            v-model.number="generalConfig.director_min_words"
                            type="number"
                            min="10"
                            max="5000"
                            class="w-14 text-center text-xs font-black text-primary focus:outline-none bg-transparent"
                            @change="saveGeneralSettings()"
                          />
                          <span class="text-[10px] text-on-surface-variant/40">字</span>
                        </div>
                      </div>
                      <p class="text-[9px] text-on-surface-variant/60 leading-relaxed">
                        设置导演模式下小说章节的最低字数（默认800，不做上限限制）。大模型会根据铁律创作宏大、起伏跌宕且对白占比
                        &gt; 30% 的小说连载。
                      </p>
                    </div>
                  </div>

                  <!-- 系统外观 -->
                  <div class="space-y-2 pt-2">
                    <h4 class="text-[11px] font-bold text-on-surface">系统外观风格</h4>
