                        </button>
                      </div>
                    </div>
                  </div>
                </div>

                <!-- 2. 主动引擎与全局约束 -->
                <div class="space-y-4 pb-6 border-b border-outline-variant/10">
                  <div class="flex items-center space-x-2 text-primary font-bold text-xs select-none">
