                        "
                        class="relative w-11 h-6 rounded-full transition-all duration-300 focus:outline-none cursor-pointer flex-shrink-0"
                        :class="generalConfig.show_schedule ? 'bg-primary' : 'bg-outline-variant'"
                      >
                        <span
                          class="absolute w-5 h-5 rounded-full bg-white top-0.5 transition-all duration-300 shadow-md"
                          :class="generalConfig.show_schedule ? 'left-5.5' : 'left-0.5'"
                        ></span>
                      </button>
                    </div>

                    <!-- 显示成长目标 -->
                    <div class="py-3 flex items-center justify-between last:pb-0">
                      <div class="flex items-center space-x-3.5">
                        <div
                          class="p-1.5 rounded-xl bg-surface border border-outline-variant/40 text-on-surface-variant"
                        >
                          <BarChart3Icon class="w-3.5 h-3.5 text-primary" />
                        </div>
                        <div>
                          <h4 class="text-xs font-bold text-on-surface">显示角色成长目标</h4>
                          <p class="text-[9px] text-on-surface-variant mt-0.5">
                            在联系人详情中展示角色正在追求的长期成长目标。
                          </p>
                        </div>
                      </div>
                      <button
                        @click="
                          generalConfig.show_goals = !generalConfig.show_goals;
                          saveGeneralSettings();
                        "
                        class="relative w-11 h-6 rounded-full transition-all duration-300 focus:outline-none cursor-pointer flex-shrink-0"
                        :class="generalConfig.show_goals ? 'bg-primary' : 'bg-outline-variant'"
                      >
                        <span
                          class="absolute w-5 h-5 rounded-full bg-white top-0.5 transition-all duration-300 shadow-md"
                          :class="generalConfig.show_goals ? 'left-5.5' : 'left-0.5'"
                        ></span>
                      </button>
                    </div>

                    <!-- 角色会发布NSFW内容 -->
                    <div class="py-3 flex items-center justify-between last:pb-0">
                      <div class="flex items-center space-x-3.5">
                        <div
                          class="p-1.5 rounded-xl bg-surface border border-outline-variant/40 text-on-surface-variant"
                        >
                          <EyeOffIcon class="w-3.5 h-3.5 text-primary" />
                        </div>
                        <div>
                          <h4 class="text-xs font-bold text-on-surface">角色会发布NSFW内容</h4>
                          <p class="text-[9px] text-on-surface-variant mt-0.5">
                            启用后，角色将有 60% 的概率在朋友圈/论坛中发布或互动（评论）露骨及限制级 NSFW 内容。
                          </p>
                        </div>
                      </div>
                      <button
                        @click="
                          generalConfig.enable_nsfw = !generalConfig.enable_nsfw;
                          saveGeneralSettings();
                        "
                        class="relative w-11 h-6 rounded-full transition-all duration-300 focus:outline-none cursor-pointer flex-shrink-0"
                        :class="generalConfig.enable_nsfw ? 'bg-primary' : 'bg-outline-variant'"
                      >
                        <span
                          class="absolute w-5 h-5 rounded-full bg-white top-0.5 transition-all duration-300 shadow-md"
                          :class="generalConfig.enable_nsfw ? 'left-5.5' : 'left-0.5'"
                        ></span>
                      </button>
                    </div>

                    <!-- 启用音乐功能 -->
                    <div class="py-3 flex items-center justify-between last:pb-0">
                      <div class="flex items-start space-x-3.5">
                        <div
                          class="p-1.5 rounded-xl bg-surface border border-outline-variant/40 text-on-surface-variant"
                        >
                          <MusicIcon class="w-3.5 h-3.5 text-primary" />
                        </div>
                        <div>
                          <h4 class="text-xs font-bold text-on-surface">启用回音音乐功能</h4>
                          <p class="text-[9px] text-on-surface-variant mt-0.5">
                            开启后可在系统左侧栏激活音乐，并展现全局底部音乐控制栏。
                          </p>
                        </div>
                      </div>
                      <button
                        @click="
                          generalConfig.enable_music = !generalConfig.enable_music;
                          saveGeneralSettings();
                        "
                        class="relative w-11 h-6 rounded-full transition-all duration-300 focus:outline-none cursor-pointer flex-shrink-0"
                        :class="generalConfig.enable_music ? 'bg-primary' : 'bg-outline-variant'"
                      >
                        <span
                          class="absolute w-5 h-5 rounded-full bg-white top-0.5 transition-all duration-300 shadow-md"
                          :class="generalConfig.enable_music ? 'left-5.5' : 'left-0.5'"
                        ></span>
                      </button>
                    </div>

                    <!-- 对话中开启token统计 -->
                    <div class="py-3 flex items-center justify-between last:pb-0">
                      <div class="flex items-start space-x-3.5">
                        <div
                          class="p-1.5 rounded-xl bg-surface border border-outline-variant/40 text-on-surface-variant"
                        >
                          <ActivityIcon class="w-3.5 h-3.5 text-primary" />
                        </div>
                        <div>
                          <h4 class="text-xs font-bold text-on-surface">对话中开启 Token 统计</h4>
                          <p class="text-[9px] text-on-surface-variant mt-0.5">
                            开启后，将在与角色的对话窗口中角色回复气泡的下方，小字显示输入/输出 Token 和缓存命中率统计。
                          </p>
                        </div>
                      </div>
                      <button
                        @click="
                          generalConfig.enable_token_stats = !generalConfig.enable_token_stats;
                          saveGeneralSettings();
                        "
                        class="relative w-11 h-6 rounded-full transition-all duration-300 focus:outline-none cursor-pointer flex-shrink-0"
                        :class="generalConfig.enable_token_stats ? 'bg-primary' : 'bg-outline-variant'"
                      >
                        <span
                          class="absolute w-5 h-5 rounded-full bg-white top-0.5 transition-all duration-300 shadow-md"
                          :class="generalConfig.enable_token_stats ? 'left-5.5' : 'left-0.5'"
                        ></span>
                      </button>
                    </div>

                    <!-- 开启局域网映射 -->
                    <div v-if="!isDockerMode" class="py-3 flex flex-col space-y-2.5 last:pb-0">
                      <div class="flex items-center justify-between">
                        <div class="flex items-start space-x-3.5">
                          <div
                            class="p-1.5 rounded-xl bg-surface border border-outline-variant/40 text-on-surface-variant flex-shrink-0"
                          >
                            <GlobeIcon class="w-3.5 h-3.5 text-primary" />
                          </div>
                          <div>
                            <h4 class="text-xs font-bold text-on-surface">开启局域网映射</h4>
                            <p class="text-[9px] text-on-surface-variant mt-0.5">
                              开启后允许在打包的独立客户端中，通过局域网其他设备访问本项目，实现完全的数据互通。
                            </p>
                          </div>
                        </div>
                        <button
                          @click="
                            generalConfig.lan_mapping_enabled = !generalConfig.lan_mapping_enabled;
                            saveGeneralSettings();
                          "
                          class="relative w-11 h-6 rounded-full transition-all duration-300 focus:outline-none cursor-pointer flex-shrink-0"
                          :class="generalConfig.lan_mapping_enabled ? 'bg-primary' : 'bg-outline-variant'"
                        >
                          <span
                            class="absolute w-5 h-5 rounded-full bg-white top-0.5 transition-all duration-300 shadow-md"
                            :class="generalConfig.lan_mapping_enabled ? 'left-5.5' : 'left-0.5'"
                          ></span>
                        </button>
                      </div>

                      <!-- 端口输入项 (仅在开启时展示，动画平滑展开) -->
                      <div
                        v-if="generalConfig.lan_mapping_enabled"
                        class="pl-11 pr-2 py-1 flex items-center justify-between text-xs animate-in slide-in-from-top-2 duration-200"
                      >
                        <span class="text-[10px] text-on-surface-variant font-medium">局域网访问端口</span>
                        <div class="relative w-28">
                          <input
                            v-model.number="generalConfig.lan_mapping_port"
                            type="number"
                            placeholder="6868"
                            @blur="saveGeneralSettings()"
                            @keyup.enter="saveGeneralSettings()"
                            class="w-full text-right pr-6 pl-2 py-1 rounded-lg bg-surface border border-outline-variant text-on-surface focus:outline-none focus:border-primary text-xs shadow-inner"
                          />
                          <span
                            class="absolute right-2 top-1/2 -translate-y-1/2 text-[9px] text-on-surface-variant font-bold"
                            >端口</span
                          >
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              <!-- 个人中心 (Tab: profile) -->
              <div
                v-else-if="activeSettingsTab === 'profile'"
                class="space-y-6 animate-in fade-in duration-200 select-none"
              >
                <!-- 选项卡切换页签 -->
                <div class="flex bg-surface-high/60 border border-outline-variant/10 rounded-xl p-1 space-x-1">
                  <button
                    @click="userProfileActiveTab = 'profile'"
                    class="flex-1 py-1.5 text-xs font-bold rounded-lg transition-all text-center cursor-pointer font-sans"
                    :class="
                      userProfileActiveTab === 'profile'
                        ? 'bg-primary text-on-primary shadow-sm'
                        : 'text-on-surface-variant hover:text-on-surface hover:bg-surface-high/30'
                    "
                  >
                    基础资料
                  </button>
                  <button
                    @click="userProfileActiveTab = 'userMd'"
                    class="flex-1 py-1.5 text-xs font-bold rounded-lg transition-all text-center cursor-pointer font-sans"
                    :class="
                      userProfileActiveTab === 'userMd'
                        ? 'bg-primary text-on-primary shadow-sm'
                        : 'text-on-surface-variant hover:text-on-surface hover:bg-surface-high/30'
                    "
                  >
                    用户设定
                  </button>
                </div>

                <div class="space-y-5">
                  <!-- A. 基础资料页签 -->
                  <template v-if="userProfileActiveTab === 'profile'">
                    <!-- 应用头像设置 -->
                    <div
                      class="p-5 rounded-2xl bg-surface-low/40 border border-outline-variant/15 flex items-center space-x-4"
                    >
                      <div
                        class="w-14 h-14 rounded overflow-hidden border border-outline-variant bg-surface flex-shrink-0 cursor-pointer relative group transition-all hover:scale-105 active:scale-95 shadow-sm"
                        @click="triggerAvatarInput"
                      >
                        <img
                          v-if="userProfile.appAvatarUrl"
                          :src="userProfile.appAvatarUrl"
                          class="w-full h-full object-cover"
                        />
                        <img v-else :src="defaultAvatarSrc" class="w-full h-full object-cover" />
                        <div
                          class="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-200"
                        >
                          <CameraIcon class="w-4 h-4 text-white" />
                        </div>
                      </div>
                      <input
                        ref="avatarFileInput"
                        type="file"
                        accept="image/*"
                        class="hidden"
                        @change="handleAvatarChange"
                      />
                      <div class="flex-1 flex flex-col space-y-1 select-none min-w-0">
                        <span class="text-xs font-bold text-on-surface">应用头像</span>
                        <span class="text-[10px] text-on-surface-variant/75 leading-relaxed">
                          点击左侧头像上传新图片。此头像用于本客户端的侧边栏顶部展示，以及【朋友圈和论坛的用户头像】，建议进行配置。
                        </span>
                      </div>
                    </div>

                    <!-- 所在地编辑（只保留所在地） -->
                    <div class="grid grid-cols-2 gap-4 select-text">
                      <div class="space-y-1.5 col-span-2 relative">
                        <label class="text-[10px] uppercase font-bold text-on-surface-variant font-mono">所在地</label>
                        <input
                          v-model="userProfile.location"
                          type="text"
                          placeholder="设置所在地"
                          @focus="locationFocus = true"
                          @blur="locationFocus = false"
                          class="form-input text-xs w-full px-3 py-2 rounded-xl bg-surface border border-outline-variant focus:outline-none focus:border-primary transition-all"
                        />
                        <!-- 离线联想下拉列表 -->
                        <div
                          v-if="filteredCities.length > 0"
                          class="absolute left-0 right-0 top-full mt-1 bg-surface border border-outline-variant/65 rounded-xl shadow-xl z-50 overflow-hidden text-xs max-h-48 overflow-y-auto backdrop-blur-md bg-surface/95 animate-in fade-in slide-in-from-top-1 duration-150 select-none"
                        >
                          <div
                            v-for="item in filteredCities"
                            :key="item.full"
                            @mousedown="selectCity(item)"
                            class="px-3 py-2 hover:bg-primary/10 hover:text-primary cursor-pointer transition-colors border-b border-outline-variant/10 last:border-none flex justify-between items-center"
                          >
                            <span class="font-medium">{{
                              item.p === item.c ? item.c + item.d : item.p + item.c + item.d
                            }}</span>
                            <span class="text-[9px] text-on-surface-variant/50 font-mono">{{ item.display }}</span>
                          </div>
                        </div>
                      </div>
                    </div>

                    <!-- 数字钱包卡片 -->
                    <div
                      class="p-4 rounded-2xl bg-gradient-to-r from-primary/5 to-secondary/5 border border-outline-variant/15 flex items-center justify-between mt-1 select-text"
                    >
                      <div class="flex flex-col space-y-0.5 select-none">
                        <span class="text-[9px] font-bold text-on-surface-variant/80 uppercase font-mono tracking-wider"
                          >我的钱包 (回音虚拟币)</span
                        >
                        <span class="text-base font-black text-primary font-mono"
                          >{{ userProfile.walletBalance }}
                          <span class="text-[10px] font-normal text-on-surface-variant">元</span></span
                        >
                      </div>
                      <div class="w-5/12 flex items-center space-x-2">
                        <label class="text-[10px] text-on-surface-variant font-bold shrink-0">充值额度</label>
                        <input
                          v-model.number="userProfile.walletBalance"
                          type="number"
                          min="0"
                          placeholder="0"
                          class="form-input text-xs py-1.5 px-2 text-center bg-surface border border-outline-variant rounded-xl w-full focus:outline-none focus:border-primary transition-all"
                        />
                      </div>
                    </div>
                  </template>

                  <!-- B. 全局人设设定卡片列表 -->
                  <template v-else>
                    <div class="flex flex-col space-y-3 min-h-[300px] h-[400px]">
                      <div class="flex items-center justify-between select-none">
                        <span class="text-[10px] font-bold text-on-surface-variant uppercase tracking-wider font-mono"
                          >用户人设卡片</span
                        >
                        <button
                          @click="openAddUserProfile"
                          class="flex items-center space-x-1 text-xs text-primary border border-primary/20 hover:border-primary bg-primary/5 hover:bg-primary/10 px-2.5 py-1 rounded-lg transition-all font-bold cursor-pointer select-none"
                        >
                          <PlusIcon class="w-3.5 h-3.5" />
                          <span>添加人设</span>
                        </button>
                      </div>

                      <!-- 列表网格 -->
                      <div v-if="userProfilesList.length > 0" class="flex-1 overflow-y-auto pr-1 space-y-2.5">
                        <div class="grid grid-cols-2 gap-3">
                          <div
                            v-for="item in userProfilesList"
                            :key="item.profileId"
                            class="relative p-3.5 rounded-xl border border-outline-variant/10 bg-surface-low/30 hover:bg-surface-low/60 hover:border-primary/25 transition-all flex flex-col justify-between group overflow-hidden"
                          >
                            <div>
                              <!-- 顶部头像和基本信息 -->
                              <div class="flex items-center space-x-2.5">
                                <img
                                  :src="item.avatar || defaultAvatarSrc"
                                  class="w-9 h-9 rounded object-cover border border-outline-variant/20 flex-shrink-0 shadow-sm"
                                />
                                <div class="min-w-0 flex-1">
                                  <div class="text-xs font-bold text-on-surface truncate" :title="item.name">
                                    {{ item.name }}
                                  </div>
                                  <div class="flex flex-wrap items-center gap-1.5 mt-0.5 select-none">
                                    <!-- 性别徽章 -->
                                    <span
                                      class="text-[8px] font-bold px-1.5 py-0.5 rounded font-sans uppercase tracking-wider"
                                      :class="{
                                        'bg-blue-500/10 text-blue-500 border border-blue-500/15': item.gender === '男',
                                        'bg-pink-500/10 text-pink-500 border border-pink-500/15': item.gender === '女',
                                        'bg-purple-500/10 text-purple-500 border border-purple-500/15':
                                          item.gender !== '男' && item.gender !== '女',
                                      }"
                                    >
                                      {{ item.gender }}
                                    </span>
                                    <!-- 年龄徽章 -->
                                    <span
                                      v-if="item.age"
                                      class="text-[8px] font-bold px-1.5 py-0.5 rounded bg-surface-high/60 text-on-surface-variant/80 border border-outline-variant/15 font-sans"
                                    >
                                      {{ item.age }}岁
                                    </span>
                                  </div>
                                </div>
                              </div>
                              <!-- 描述说明 -->
                              <p
                                class="text-[10px] text-on-surface-variant/75 mt-2.5 leading-relaxed line-clamp-2 select-text"
                                :title="item.description || '暂无设定描述'"
                              >
                                {{ item.description || '暂无设定描述' }}
                              </p>
                            </div>

                            <!-- 悬浮动作栏 -->
                            <div
                              class="absolute inset-0 bg-surface-low/95 opacity-0 group-hover:opacity-100 transition-all duration-200 flex items-center justify-center space-x-3 backdrop-blur-sm"
                            >
                              <button
                                @click="openEditUserProfile(item)"
                                class="flex items-center space-x-1 text-xs text-primary border border-primary/20 hover:border-primary hover:bg-primary/10 bg-primary/5 px-3 py-1.5 rounded-lg font-bold transition-all cursor-pointer"
                              >
                                <PenLineIcon class="w-3.5 h-3.5" />
                                <span>编辑设定</span>
                              </button>
                              <button
                                @click="deleteUserProfileData(item.profileId)"
                                class="flex items-center space-x-1 text-xs text-error border border-error/20 hover:border-error hover:bg-error/10 bg-error/5 px-3 py-1.5 rounded-lg font-bold transition-all cursor-pointer"
                              >
                                <Trash2Icon class="w-3.5 h-3.5" />
                                <span>删除</span>
                              </button>
                            </div>
                          </div>
                        </div>
                      </div>

                      <!-- 空状态 -->
                      <div
                        v-else
                        class="flex-1 flex flex-col items-center justify-center py-12 text-on-surface-variant/40 select-none space-y-2.5 bg-surface-low/10 rounded-xl border border-dashed border-outline-variant/20"
                      >
                        <UserIcon class="w-8 h-8 opacity-40" />
                        <span class="text-xs">暂无用户人设设定，点击右上角添加</span>
                      </div>
                    </div>
                  </template>

                  <!-- 保存按钮 -->
                  <div
                    v-if="userProfileActiveTab === 'profile'"
                    class="flex justify-end pt-3 border-t border-outline-variant/10"
                  >
                    <button
                      @click="saveUserProfile"
                      :disabled="saving"
                      class="btn-primary flex items-center space-x-1.5 disabled:opacity-50 text-xs py-2 px-6 font-bold rounded-xl active:scale-95 transition-all select-none cursor-pointer"
                    >
                      <Loader2Icon v-if="saving" class="w-3.5 h-3.5 animate-spin" />
                      <SaveIcon v-else class="w-3.5 h-3.5" />
                      <span>保存并生效</span>
                    </button>
                  </div>
                </div>
              </div>

              <!-- A.2 状态栏设置 (Tab: states) -->
              <div v-else-if="activeSettingsTab === 'states'" class="space-y-6 animate-in fade-in duration-200">
                <!-- 预设创建/编辑面板 -->
                <div class="p-5 rounded-3xl border border-outline-variant bg-surface-high/60 flex flex-col space-y-4">
                  <h3
                    class="text-xs font-bold text-on-surface-variant uppercase tracking-wider flex items-center space-x-1.5"
                  >
                    <SparklesIcon class="w-3.5 h-3.5 text-indigo-500 animate-pulse" />
                    <span>{{ editingPresetId ? '修改状态栏预设' : '添加全新状态栏预设' }}</span>
                  </h3>

                  <div class="grid grid-cols-2 gap-4">
                    <!-- 字段名称 -->
                    <div class="flex flex-col space-y-1.5">
                      <label class="text-[11px] font-bold text-on-surface-variant">指标属性名称</label>
                      <input
                        type="text"
                        v-model="presetForm.label"
                        class="w-full px-3.5 py-2 rounded-2xl bg-surface border border-outline-variant focus:outline-none focus:border-primary text-xs text-on-surface"
                        placeholder="请输入状态名称"
                      />
                    </div>

                    <!-- 字段类型 -->
                    <div class="flex flex-col space-y-1.5">
                      <label class="text-[11px] font-bold text-on-surface-variant">指标类型</label>
                      <div class="flex p-1 rounded-2xl bg-surface border border-outline-variant">
                        <button
                          @click="presetForm.type = 'number'"
                          class="flex-grow py-1.5 text-xs font-bold rounded-xl transition-all cursor-pointer"
                          :class="
                            presetForm.type === 'number'
                              ? 'bg-surface-high text-primary shadow-sm'
                              : 'text-on-surface-variant hover:text-on-surface'
                          "
                        >
                          数字型 (0-100)
                        </button>
                        <button
                          @click="presetForm.type = 'text'"
                          class="flex-grow py-1.5 text-xs font-bold rounded-xl transition-all cursor-pointer"
                          :class="
                            presetForm.type === 'text'
                              ? 'bg-surface-high text-primary shadow-sm'
                              : 'text-on-surface-variant hover:text-on-surface'
                          "
                        >
                          文本型
                        </button>
                      </div>
                    </div>
                  </div>

                  <!-- 指标含义 -->
                  <div class="flex flex-col space-y-1.5">
                    <label class="text-[11px] font-bold text-on-surface-variant"
                      >指标含义 (作为提示词强约束注入 AI 脑区，例如：好感越高，聊天表现越亲密)</label
                    >
                    <textarea
                      v-model="presetForm.meaning"
                      class="w-full h-16 px-3.5 py-2 rounded-2xl bg-surface border border-outline-variant focus:outline-none focus:border-primary text-xs text-on-surface resize-none leading-relaxed"
                      placeholder="例如：好感越高，聊天表现越亲密。可以详细设定"
                    ></textarea>
                  </div>

                  <!-- 指标更新规则 -->
                  <div class="flex flex-col space-y-1.5">
                    <label class="text-[11px] font-bold text-on-surface-variant"
                      >指标更新规则 (AI 增减分值所要遵守的规则)</label
                    >
                    <textarea
                      v-model="presetForm.rule"
                      class="w-full h-20 px-3.5 py-2 rounded-2xl bg-surface border border-outline-variant focus:outline-none focus:border-primary text-xs text-on-surface resize-none leading-relaxed"
                      placeholder="例如：当{{user}}赞美、关心或提到暧昧话题时分值增加；当{{user}}冷淡、责怪时分值减少。"
                    ></textarea>
                  </div>

                  <!-- 是否设为全局状态栏 -->
                  <div class="py-3 flex items-center justify-between border-t border-b border-outline-variant/30">
                    <div>
                      <h4 class="text-xs font-bold text-on-surface">设为全局状态栏</h4>
                      <p class="text-[10px] text-on-surface-variant mt-0.5">
                        设为全局后，该指标将强制应用于【所有角色】，且各角色独立持久化各自的分值。
                      </p>
                    </div>
                    <button
                      @click="presetForm.is_global = !presetForm.is_global"
                      class="relative w-11 h-6 rounded-full transition-all focus:outline-none"
                      :class="presetForm.is_global ? 'bg-primary' : 'bg-outline-variant'"
                    >
                      <span
                        class="absolute w-5 h-5 rounded-full bg-white top-0.5 transition-all shadow-md"
                        :class="presetForm.is_global ? 'left-5.5' : 'left-0.5'"
                      ></span>
                    </button>
                  </div>

                  <!-- 动作按钮 -->
                  <div class="flex items-center space-x-2 pt-1">
                    <button
                      v-if="editingPresetId"
                      @click="cancelEditPreset"
                      class="flex-1 py-2 text-xs font-bold rounded-2xl border border-outline-variant text-on-surface-variant hover:bg-surface-high transition-colors cursor-pointer"
                    >
                      取消修改
                    </button>
                    <button
                      @click="handleAddOrUpdatePreset"
                      class="flex-1 py-2 text-xs font-bold rounded-2xl bg-primary text-white hover:bg-primary-hover shadow-md active:scale-95 transition-all cursor-pointer flex items-center justify-center space-x-1.5"
                    >
                      <CheckIcon class="w-3.5 h-3.5" />
                      <span>{{
                        editingPresetId
                          ? presetForm.is_global
                            ? '一键更新'
                            : '保存'
                          : presetForm.is_global
                            ? '添加指标预设并全局同步'
                            : '添加指标预设'
                      }}</span>
                    </button>
                  </div>
                </div>

                <!-- 当前已注册预设列表 -->
                <div class="space-y-3">
                  <h3 class="text-xs font-bold text-on-surface-variant uppercase tracking-wider">
                    当前已注册的预设指标
                  </h3>

                  <!-- 预设卡片堆叠 -->
                  <div v-if="statePresets.length > 0" class="grid grid-cols-2 gap-3">
                    <div
                      v-for="item in statePresets"
                      :key="item.id"
                      @click="editPresetItem(item)"
                      class="p-4 rounded-3xl border bg-surface border-outline-variant/60 flex items-start justify-between hover:shadow-md transition-all relative group cursor-pointer"
                    >
                      <div class="flex items-start space-x-3 min-w-0">
                        <div
                          class="w-8 h-8 rounded-full bg-on-surface/5 flex items-center justify-center text-lg flex-shrink-0 select-none"
                        >
                          {{ item.type === 'number' ? '📊' : '🏷️' }}
                        </div>
                        <div class="min-w-0">
                          <div class="flex items-center space-x-1.5">
                            <span class="text-xs font-extrabold text-on-surface truncate">{{ item.label }}</span>
                            <span
                              v-if="item.is_global"
                              class="text-[9px] px-1.5 py-0.5 rounded-full bg-rose-500/10 text-rose-500 font-extrabold shrink-0 border border-rose-500/10"
                              >全局</span
                            >
                            <span
                              v-else
                              class="text-[9px] px-1.5 py-0.5 rounded-full bg-on-surface/5 text-on-surface-variant font-bold shrink-0 border"
                              >预设</span
                            >
                          </div>
                          <p class="text-[10px] text-on-surface-variant truncate mt-1 leading-normal">
                            含义：{{ item.meaning }}
                          </p>
                          <p class="text-[10px] text-on-surface-variant truncate mt-0.5 leading-normal">
                            规则：{{ item.rule }}
                          </p>
                        </div>
                      </div>

                      <div class="flex items-center space-x-1 shrink-0 ml-1">
                        <!-- 编辑 -->
                        <button
                          @click.stop="editPresetItem(item)"
                          class="p-1 rounded-md text-on-surface-variant/70 hover:bg-on-surface/5 hover:text-on-surface transition-all flex items-center justify-center cursor-pointer"
                          title="编辑预设"
                        >
                          <EditIcon class="w-3.5 h-3.5" />
                        </button>
                        <!-- 删除 -->
                        <button
                          @click.stop="deletePresetItem(item.id)"
                          class="p-1 rounded-md text-red-500 hover:bg-red-500/10 transition-all flex items-center justify-center cursor-pointer"
                          title="删除预设"
                        >
                          <svg
                            class="w-3.5 h-3.5"
                            fill="none"
                            stroke="currentColor"
                            stroke-width="2"
                            viewBox="0 0 24 24"
                            xmlns="http://www.w3.org/2000/svg"
                          >
                            <path
                              stroke-linecap="round"
                              stroke-linejoin="round"
                              d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"
                            ></path>
                          </svg>
                        </button>
                      </div>
                    </div>
                  </div>

                  <!-- 空白状态 -->
                  <div
                    v-else
                    class="flex flex-col items-center justify-center py-10 bg-on-surface/5 border border-dashed border-outline-variant/60 rounded-3xl text-center select-none"
                  >
                    <HeartIcon class="w-8 h-8 text-on-surface-variant/30 animate-pulse mb-2" />
                    <span class="text-xs font-bold text-on-surface-variant/60">暂无任何状态指标预设</span>
                    <span class="text-[10px] text-on-surface-variant/40 mt-1 leading-normal"
                      >快在上方表单添加一个您独特的性格画像指标吧！</span
                    >
                  </div>
                </div>
              </div>

              <!-- B. 主大模型 -->
              <div v-else-if="activeSettingsTab === 'primary'" class="space-y-6">
                <div class="space-y-4 pt-2">
                  <div class="form-group">
                    <label class="form-label font-bold text-xs">模型提供商</label>
                    <div class="relative">
                      <button
                        @click="showPrimaryProviderDropdown = !showPrimaryProviderDropdown"
                        @blur="hideProviderDropdownDelayed('primary')"
                        class="form-input text-xs text-left w-full flex items-center justify-between cursor-pointer select-none active:scale-[0.99] transition-all"
                      >
                        <span>{{
                          modelProviders.find(p => p.value === primary.provider)?.label || '请选择提供商'
                        }}</span>
                        <ChevronDownIcon
                          class="w-3.5 h-3.5 text-on-surface-variant transition-transform duration-200"
                          :class="{ 'rotate-180': showPrimaryProviderDropdown }"
                        />
                      </button>

                      <!-- 自定义毛玻璃提供商选择气泡 -->
                      <div
                        v-if="showPrimaryProviderDropdown"
                        class="absolute left-0 right-0 top-full mt-1.5 rounded-xl border border-outline-variant bg-surface-high/90 backdrop-blur-xl shadow-xl py-1 z-30 select-none animate-in fade-in slide-in-from-top-1.5 duration-150"
                      >
                        <div
                          v-for="p in modelProviders"
                          :key="p.value"
                          @mousedown="selectProvider('primary', p.value)"
                          class="px-3.5 py-2 text-xs text-on-surface hover:bg-primary/10 hover:text-primary transition-all flex items-center justify-between cursor-pointer"
                          :class="{ 'bg-primary/5 text-primary font-bold': primary.provider === p.value }"
                        >
                          <span>{{ p.label }}</span>
                          <span
                            v-if="primary.provider === p.value"
                            class="text-[9px] font-bold text-primary bg-primary/10 px-1.5 py-0.5 rounded-md"
                            >当前</span
                          >
                        </div>
                      </div>
                    </div>
                  </div>
                  <div class="form-group">
                    <label class="form-label font-bold text-xs">Base URL</label>
                    <input
                      v-model="primary.baseUrl"
                      type="text"
                      class="form-input font-mono text-xs"
                      placeholder="https://api.openai.com/v1"
                    />
                  </div>
                  <div class="form-group">
                    <label class="form-label font-bold text-xs">API Key</label>
                    <div class="relative">
                      <input
                        v-model="primary.apiKey"
                        :type="showPrimaryApiKey ? 'text' : 'password'"
                        class="form-input pr-9 font-mono text-xs"
                        placeholder="sk-..."
                      />
                      <button
                        @click="showPrimaryApiKey = !showPrimaryApiKey"
                        class="absolute right-3 top-1/2 -translate-y-1/2 text-on-surface-variant"
                      >
                        <EyeIcon v-if="!showPrimaryApiKey" class="w-4 h-4" />
                        <EyeOffIcon v-else class="w-4 h-4" />
                      </button>
                    </div>
                  </div>
                  <div class="form-group">
                    <label class="form-label font-bold text-xs flex justify-between items-center">
                      <span>模型名称</span>
                      <button
                        @click="fetchModelList('primary')"
                        :disabled="fetchingPrimaryModels"
                        class="text-primary hover:opacity-80 flex items-center space-x-1 disabled:opacity-50 select-none active:scale-95 transition-all"
                      >
                        <Loader2Icon v-if="fetchingPrimaryModels" class="w-3 h-3 animate-spin" />
                        <RefreshCwIcon v-else class="w-3 h-3" />
                        <span>{{ fetchingPrimaryModels ? '拉取中...' : '在线获取模型列表' }}</span>
                      </button>
                    </label>
                    <div class="relative">
                      <input
                        v-model="primary.model"
                        type="text"
                        @focus="showPrimaryDropdown = true"
                        @blur="hideDropdownDelayed('primary')"
                        class="form-input font-mono text-xs pr-6"
                        placeholder="gpt-4o / deepseek-chat"
                      />
                      <!-- 自定义毛玻璃模糊过滤下拉卡片 -->
                      <div
                        v-if="showPrimaryDropdown && primaryModelsList.length > 0"
                        class="absolute left-0 right-0 top-full mt-1.5 max-h-48 overflow-y-auto rounded-xl border border-outline-variant bg-surface-high/90 backdrop-blur-xl shadow-xl py-1 z-30 cursor-default select-none animate-in fade-in slide-in-from-top-1.5 duration-150"
                      >
                        <div
                          v-for="m in filteredPrimaryModels"
                          :key="m"
                          @mousedown="selectModel('primary', m)"
                          class="px-3.5 py-2 text-[11px] font-mono text-on-surface hover:bg-primary/10 hover:text-primary transition-all flex items-center justify-between cursor-pointer"
                          :class="{ 'bg-primary/5 text-primary font-bold': primary.model === m }"
                        >
                          <span>{{ m }}</span>
                          <span
                            v-if="primary.model === m"
                            class="text-[9px] font-bold text-primary bg-primary/10 px-1.5 py-0.5 rounded-md"
                            >当前</span
                          >
                        </div>
                        <div
                          v-if="filteredPrimaryModels.length === 0"
                          class="px-3.5 py-2 text-[10px] text-on-surface-variant/50 text-center italic"
                        >
                          无匹配模型
                        </div>
                      </div>
                    </div>
                    <!-- 错误状态反馈 -->
                    <div
                      v-if="primaryModelsError"
                      class="text-[10px] text-error mt-1 select-none font-mono opacity-90 leading-normal"
                    >
                      {{ primaryModelsError }}
                    </div>
                  </div>
                  <div class="form-group">
                    <label class="form-label font-bold text-xs flex justify-between"
                      ><span>温度 (Temperature)</span
                      ><span class="text-primary font-mono">{{ primary.temperature.toFixed(1) }}</span></label
                    >
                    <input
                      v-model.number="primary.temperature"
                      type="range"
                      min="0"
                      max="2"
                      step="0.1"
                      class="w-full accent-primary"
                    />
                  </div>
                </div>
              </div>

              <!-- C. 辅助大模型 -->
              <div v-else-if="activeSettingsTab === 'secondary'" class="space-y-6 animate-in fade-in duration-200">
                <div class="bg-surface-low/30 border border-outline-variant/10 rounded-2xl p-5 space-y-5">
                  <div class="flex items-center justify-between pb-6 border-b border-outline-variant/10 mb-4">
                    <div>
                      <h3 class="text-sm font-bold text-on-surface">启用辅助大模型</h3>
                      <p class="text-[10px] text-on-surface-variant mt-1">
                        开启后，除角色对话和角色卡导入外的其他调用，都将使用辅助大模型（例如论坛/朋友圈功能等...）。
                      </p>
                    </div>
                    <button
                      @click="enableSecondary = !enableSecondary"
                      class="relative w-11 h-6 rounded-full transition-all focus:outline-none"
                      :class="enableSecondary ? 'bg-primary' : 'bg-outline-variant'"
                    >
                      <span
                        class="absolute w-5 h-5 rounded-full bg-white top-0.5 transition-all shadow-md"
                        :class="enableSecondary ? 'left-5.5' : 'left-0.5'"
                      ></span>
                    </button>
                  </div>

                  <div v-if="enableSecondary" class="space-y-4 pt-2">
                    <div class="form-group">
                      <label class="form-label font-bold text-xs">模型提供商</label>
                      <div class="relative">
                        <button
                          @click="showSecondaryProviderDropdown = !showSecondaryProviderDropdown"
                          @blur="hideProviderDropdownDelayed('secondary')"
                          class="form-input text-xs text-left w-full flex items-center justify-between cursor-pointer select-none active:scale-[0.99] transition-all"
                        >
                          <span>{{
                            modelProviders.find(p => p.value === secondary.provider)?.label || '请选择提供商'
                          }}</span>
                          <ChevronDownIcon
                            class="w-3.5 h-3.5 text-on-surface-variant transition-transform duration-200"
                            :class="{ 'rotate-180': showSecondaryProviderDropdown }"
                          />
                        </button>

                        <!-- 自定义毛玻璃提供商选择气泡 -->
                        <div
                          v-if="showSecondaryProviderDropdown"
                          class="absolute left-0 right-0 top-full mt-1.5 rounded-xl border border-outline-variant bg-surface-high/90 backdrop-blur-xl shadow-xl py-1 z-30 select-none animate-in fade-in slide-in-from-top-1.5 duration-150"
                        >
                          <div
                            v-for="p in modelProviders"
                            :key="p.value"
                            @mousedown="selectProvider('secondary', p.value)"
                            class="px-3.5 py-2 text-xs text-on-surface hover:bg-secondary/10 hover:text-secondary transition-all flex items-center justify-between cursor-pointer"
                            :class="{ 'bg-secondary/5 text-secondary font-bold': secondary.provider === p.value }"
                          >
                            <span>{{ p.label }}</span>
                            <span
                              v-if="secondary.provider === p.value"
                              class="text-[9px] font-bold text-secondary bg-secondary/10 px-1.5 py-0.5 rounded-md"
                              >当前</span
                            >
                          </div>
                        </div>
                      </div>
                    </div>
                    <div class="form-group">
                      <label class="form-label font-bold text-xs">Base URL</label>
                      <input
                        v-model="secondary.baseUrl"
                        type="text"
                        class="form-input font-mono text-xs"
                        placeholder="https://api.openai.com/v1"
                      />
                    </div>
                    <div class="form-group">
                      <label class="form-label font-bold text-xs">API Key</label>
                      <div class="relative">
                        <input
                          v-model="secondary.apiKey"
                          :type="showSecondaryApiKey ? 'text' : 'password'"
                          class="form-input pr-9 font-mono text-xs"
                          placeholder="sk-..."
                        />
                        <button
                          @click="showSecondaryApiKey = !showSecondaryApiKey"
                          class="absolute right-3 top-1/2 -translate-y-1/2 text-on-surface-variant"
                        >
                          <EyeIcon v-if="!showSecondaryApiKey" class="w-4 h-4" />
                          <EyeOffIcon v-else class="w-4 h-4" />
                        </button>
                      </div>
                    </div>
                    <div class="form-group">
                      <label class="form-label font-bold text-xs flex justify-between items-center">
                        <span>模型名称</span>
                        <button
                          @click="fetchModelList('secondary')"
                          :disabled="fetchingSecondaryModels"
                          class="text-secondary hover:opacity-80 flex items-center space-x-1 disabled:opacity-50 select-none active:scale-95 transition-all"
                        >
                          <Loader2Icon v-if="fetchingSecondaryModels" class="w-3 h-3 animate-spin" />
                          <RefreshCwIcon v-else class="w-3 h-3" />
                          <span>{{ fetchingSecondaryModels ? '拉取中...' : '在线获取模型列表' }}</span>
                        </button>
                      </label>
                      <div class="relative">
                        <input
                          v-model="secondary.model"
                          type="text"
                          @focus="showSecondaryDropdown = true"
                          @blur="hideDropdownDelayed('secondary')"
                          class="form-input font-mono text-xs pr-6"
                          placeholder="gpt-4o-mini"
                        />
                        <!-- 自定义毛玻璃模糊过滤下拉卡片 -->
                        <div
                          v-if="showSecondaryDropdown && secondaryModelsList.length > 0"
                          class="absolute left-0 right-0 top-full mt-1.5 max-h-48 overflow-y-auto rounded-xl border border-outline-variant bg-surface-high/90 backdrop-blur-xl shadow-xl py-1 z-30 cursor-default select-none animate-in fade-in slide-in-from-top-1.5 duration-150"
                        >
                          <div
                            v-for="m in filteredSecondaryModels"
                            :key="m"
                            @mousedown="selectModel('secondary', m)"
                            class="px-3.5 py-2 text-[11px] font-mono text-on-surface hover:bg-secondary/10 hover:text-secondary transition-all flex items-center justify-between cursor-pointer"
                            :class="{ 'bg-secondary/5 text-secondary font-bold': secondary.model === m }"
                          >
                            <span>{{ m }}</span>
                            <span
                              v-if="secondary.model === m"
                              class="text-[9px] font-bold text-secondary bg-secondary/10 px-1.5 py-0.5 rounded-md"
                              >当前</span
                            >
                          </div>
                          <div
                            v-if="filteredSecondaryModels.length === 0"
                            class="px-3.5 py-2 text-[10px] text-on-surface-variant/50 text-center italic"
                          >
                            无匹配模型
                          </div>
                        </div>
                      </div>
                      <!-- 错误状态反馈 -->
                      <div
                        v-if="secondaryModelsError"
                        class="text-[10px] text-error mt-1 select-none font-mono opacity-90 leading-normal"
                      >
                        {{ secondaryModelsError }}
                      </div>
                    </div>
                    <div class="form-group">
                      <label class="form-label font-bold text-xs flex justify-between"
                        ><span>温度 (Temperature)</span
                        ><span class="text-secondary font-mono">{{ secondary.temperature.toFixed(1) }}</span></label
                      >
                      <input
                        v-model.number="secondary.temperature"
                        type="range"
                        min="0"
                        max="2"
                        step="0.1"
                        class="w-full accent-secondary"
                      />
                    </div>
                  </div>
                </div>
              </div>

              <!-- D-2. 本地向量记忆设置 (Tab: vector) -->
              <div v-else-if="activeSettingsTab === 'vector'" class="space-y-6 animate-in fade-in duration-200">
                <div class="bg-surface-low/30 border border-outline-variant/10 rounded-2xl p-5 space-y-5">
                  <!-- 标题行 + 开关 -->
                  <div class="flex items-center justify-between pb-4 border-b border-outline-variant/20">
                    <div>
                      <h3 class="text-sm font-bold text-on-surface flex items-center space-x-1.5">
                        <BrainIcon class="w-4 h-4 text-primary" />
                        <span>语义向量记忆 (RAG)</span>
                      </h3>
                      <p class="text-[10px] text-on-surface-variant mt-1">
                        为数字生命引入基于语义向量的历史对话召回（长期记忆）。当提到历史话题时，自动在背景中精准唤醒记忆。
                      </p>
                    </div>
                    <button
                      @click="vectorConfig.enabled = !vectorConfig.enabled"
                      class="relative w-11 h-6 rounded-full transition-all focus:outline-none"
                      :class="vectorConfig.enabled ? 'bg-primary' : 'bg-outline-variant'"
                    >
                      <span
                        class="absolute w-5 h-5 rounded-full bg-white top-0.5 transition-all shadow-md"
                        :class="vectorConfig.enabled ? 'left-5.5' : 'left-0.5'"
                      ></span>
                    </button>
                  </div>

                  <!-- 展开的详细设置 -->
                  <div v-if="vectorConfig.enabled" class="space-y-4 pt-2 animate-in fade-in duration-200">
                    <!-- 模式选择 -->
                    <div class="form-group">
                      <label class="form-label font-bold text-xs">计算模式</label>
                      <div class="grid grid-cols-2 gap-3 mt-1.5">
                        <button
                          type="button"
                          @click="vectorConfig.mode = 'local'"
                          class="flex items-center justify-center space-x-2 py-2.5 px-3 rounded-xl border text-xs font-bold transition-all active:scale-98"
                          :class="vectorConfig.mode === 'local' ? 'border-primary bg-primary/5 text-primary' : 'border-outline-variant/30 hover:bg-surface-low text-on-surface-variant'"
                        >
                          <HardDriveIcon class="w-4 h-4" />
                          <span>本地 ONNX 推理</span>
                        </button>
                        <button
                          type="button"
                          @click="vectorConfig.mode = 'online'"
                          class="flex items-center justify-center space-x-2 py-2.5 px-3 rounded-xl border text-xs font-bold transition-all active:scale-98"
                          :class="vectorConfig.mode === 'online' ? 'border-primary bg-primary/5 text-primary' : 'border-outline-variant/30 hover:bg-surface-low text-on-surface-variant'"
                        >
                          <CloudIcon class="w-4 h-4" />
                          <span>在线 API 连接</span>
                        </button>
                      </div>
                    </div>

                    <!-- 1. 本地 ONNX 模式配置 -->
                    <div v-if="vectorConfig.mode === 'local'" class="space-y-4">
                      <!-- 硬件状态面板 -->
                      <div class="bg-surface-low/30 border border-outline-variant/10 rounded-2xl p-4 flex items-center justify-between">
                        <div class="flex items-center space-x-3">
                          <div class="w-9 h-9 rounded-xl bg-secondary/10 border border-secondary/20 flex items-center justify-center text-secondary">
                            <CpuIcon class="w-4 h-4" />
                          </div>
                          <div>
                            <h4 class="text-xs font-bold text-on-surface">本地硬件环境评估</h4>
                            <p class="text-[10px] text-on-surface-variant mt-0.5">
                              核心数: <span class="font-mono">{{ hardwareInfo.cpuCores }}核</span> | 
                              空闲内存: <span class="font-mono">{{ hardwareInfo.freeMemMB }}MB</span> / 总内存: <span class="font-mono">{{ hardwareInfo.totalMemMB }}MB</span>
                            </p>
                          </div>
                        </div>
                        <div class="text-right">
                          <span
                            v-if="hardwareInfo.totalMemMB < 8000"
                            class="text-[9px] font-bold text-error bg-error/10 border border-error/20 px-2 py-1 rounded-lg"
                          >
                            ⚠️ 建议选择在线 API
                          </span>
                          <span
                            v-else
                            class="text-[9px] font-bold text-primary bg-primary/10 border border-primary/20 px-2 py-1 rounded-lg"
                          >
                            ✨ 适合本地推理
                          </span>
                        </div>
                      </div>

                      <!-- 本地模型状态及下载 -->
                      <div class="bg-surface-low/30 border border-outline-variant/10 rounded-2xl p-4 space-y-4">
                        <div class="flex items-center justify-between">
                          <div class="flex items-center space-x-2">
                            <DatabaseIcon class="w-4 h-4 text-primary" />
                            <span class="text-xs font-bold text-on-surface">本地轻量模型 (bge-small-zh-v1.5)</span>
                          </div>
                          <div>
                            <span
                              v-if="vectorModelStatus.ready"
                              class="text-[9px] font-bold text-primary bg-primary/10 border border-primary/20 px-2 py-1 rounded-lg flex items-center space-x-1"
                            >
                              <CheckCircleIcon class="w-3 h-3 text-primary animate-pulse" />
                              <span>模型已加载并就绪</span>
                            </span>
                            <span
                              v-else-if="vectorModelStatus.downloaded"
                              class="text-[9px] font-bold text-secondary bg-secondary/10 border border-secondary/20 px-2 py-1 rounded-lg flex items-center space-x-1"
                            >
                              <CheckCircleIcon class="w-3 h-3 text-secondary" />
                              <span>已下载 (待保存加载)</span>
                            </span>
                            <span
                              v-else
                              class="text-[9px] font-bold text-error bg-error/10 border border-error/20 px-2 py-1 rounded-lg flex items-center space-x-1"
                            >
                              <AlertTriangleIcon class="w-3 h-3 text-error" />
                              <span>未检测到模型文件</span>
                            </span>
                          </div>
                        </div>

                        <!-- 未下载且不处于下载中 -->
                        <div v-if="!vectorModelStatus.downloaded && !isDownloadingModel" class="space-y-3 pt-1">
                          <div class="form-group">
                            <label class="form-label text-[10px] text-on-surface-variant font-bold">自定义模型下载源镜像 (非必填)</label>
                            <div class="flex space-x-2 mt-1">
                              <input
                                v-model="customMirrorUrl"
                                type="text"
                                class="form-input font-mono text-[11px] flex-1 py-1.5"
                                placeholder="https://hf-mirror.com"
                              />
                            </div>
                            <p class="text-[9px] text-on-surface-variant/70 mt-1">
                              默认使用国内快速镜像 https://hf-mirror.com 下载（模型约 94MB）。
                            </p>
                          </div>
                          <button
                            type="button"
                            @click="startDownloadVectorModel"
                            class="w-full btn-primary py-2 rounded-xl text-xs font-bold flex items-center justify-center space-x-1.5 transition-all"
                          >
                            <DownloadIcon class="w-3.5 h-3.5" />
                            <span>立即下载模型文件 (约94MB)</span>
                          </button>
                        </div>

                        <!-- 下载中进度条 -->
                        <div v-if="isDownloadingModel" class="space-y-2.5 pt-1">
                          <div class="flex justify-between items-center text-[10px]">
                            <span class="text-on-surface-variant flex items-center space-x-1.5 font-bold">
                              <Loader2Icon class="w-3 h-3 animate-spin text-primary" />
                              <span>正在下载: <span class="font-mono text-primary">{{ downloadingFileName }}</span></span>
                            </span>
                            <span class="font-mono text-primary font-bold">{{ downloadProgress }}%</span>
                          </div>
                          <div class="w-full h-2 rounded-full bg-outline-variant/20 overflow-hidden relative border border-outline-variant/10">
                            <div
                              class="h-full bg-gradient-to-r from-primary to-secondary rounded-full transition-all duration-300"
                              :style="{ width: `${downloadProgress}%` }"
                            ></div>
                          </div>
                          <button
                            type="button"
                            @click="cancelDownloadVectorModel"
                            class="w-full border border-error/20 bg-error/5 hover:bg-error/10 text-error text-[10px] py-1.5 rounded-xl font-bold transition-all"
                          >
                            取消模型下载
                          </button>
                        </div>
                      </div>
                    </div>

                    <!-- 2. 在线 API 模式配置 -->
                    <div v-if="vectorConfig.mode === 'online'" class="space-y-3.5">
                      <div class="form-group">
                        <label class="form-label font-bold text-xs">Embedding API Base URL</label>
                        <input
                          v-model="vectorConfig.onlineApiBase"
                          type="text"
                          class="form-input font-mono text-xs"
                          placeholder="https://api.siliconflow.cn/v1"
                        />
                      </div>
                      <div class="form-group">
                        <label class="form-label font-bold text-xs">Embedding API Key</label>
                        <input
                          v-model="vectorConfig.onlineApiKey"
                          type="password"
                          class="form-input font-mono text-xs"
                          placeholder="输入 SiliconFlow 或第三方平台密钥"
                        />
                      </div>
                      <div class="form-group">
                        <label class="form-label font-bold text-xs">Embedding 模型名称</label>
                        <input
                          v-model="vectorConfig.onlineModel"
                          type="text"
                          class="form-input font-mono text-xs"
                          placeholder="BAAI/bge-large-zh-v1.5"
                        />
                      </div>
                    </div>

                    <!-- 3. 历史对话逆序向量化进度条（全部角色） -->
                    <div class="bg-surface-low/30 border border-outline-variant/10 rounded-2xl p-4 space-y-4">
                      <div class="flex items-center justify-between">
                        <div class="flex items-center space-x-2">
                          <HistoryIcon class="w-4 h-4 text-primary" />
                          <span class="text-xs font-bold text-on-surface">存量对话历史向量化进度（全部角色）</span>
                        </div>
                        <span class="text-[10px] font-mono font-bold text-primary">
                          {{ vectorProgress.done }} / {{ vectorProgress.total }} 轮
                        </span>
                      </div>

                      <!-- 进度条 -->
                      <div class="w-full h-2 rounded-full bg-outline-variant/20 overflow-hidden border border-outline-variant/10">
                        <div
                          class="h-full bg-primary rounded-full transition-all duration-300"
                          :style="{ width: `${vectorProgress.total > 0 ? Math.min((vectorProgress.done / vectorProgress.total) * 100, 100) : 0}%` }"
                        ></div>
                      </div>

                      <!-- 补录操作区 -->
                      <div class="flex space-x-2 pt-1">
                        <button
                          v-if="!isBackfilling"
                          type="button"
                          @click="startVectorBackfill"
                          :disabled="!vectorConfig.enabled || (vectorConfig.mode === 'local' && !vectorModelStatus.ready)"
                          class="w-full btn-secondary py-2 rounded-xl text-xs font-bold transition-all disabled:opacity-40"
                        >
                          开始存量补录向量化
                        </button>
                        <button
                          v-else
                          type="button"
                          @click="cancelVectorBackfill"
                          class="w-full border border-error/20 bg-error/5 hover:bg-error/10 text-error text-xs py-2 rounded-xl font-bold transition-all"
                        >
                          <span class="flex items-center justify-center space-x-1.5">
                            <Loader2Icon class="w-3.5 h-3.5 animate-spin" />
                            <span>向量化补录中... 点击取消</span>
                          </span>
                        </button>
                      </div>
                      <p class="text-[9px] text-on-surface-variant/70">
                        逆序对本角色过往已产生的对话进行向量嵌入索引（只在闲时运行）。若不补录，历史消息将无法通过语义召回，但新对话仍会自动入库。
                      </p>
                    </div>
                  </div>
                </div>
              </div>

              <!-- E. AI 绘图设置 (Tab: drawing) -->
              <div v-else-if="activeSettingsTab === 'drawing'" class="space-y-6 animate-in fade-in duration-200">
                <div class="bg-surface-low/30 border border-outline-variant/10 rounded-2xl p-5 space-y-5">
                  <div class="flex items-center space-x-2.5 border-b border-outline-variant/20 pb-4">
                    <div
                      class="w-8 h-8 rounded-xl bg-primary/10 border border-primary/20 flex items-center justify-center text-primary"
                    >
                      <ImageIcon class="w-4 h-4" />
                    </div>
                    <div>
                      <h3 class="text-xs font-bold text-on-surface">NovelAI 绘图设置</h3>
                      <p class="text-[10px] text-on-surface-variant mt-0.5">
                        配置 NovelAI 文生图（T2I）API 参数以激活数字生命的美图共享与私聊生图功能
                      </p>
                    </div>
                  </div>

                  <div class="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div class="form-group md:col-span-2">
                      <label class="form-label font-bold text-xs">API Key</label>
                      <div class="relative">
                        <input
                          v-model="novelai.apiKey"
                          :type="showApiKey ? 'text' : 'password'"
                          placeholder="输入您的 NovelAI API Key (以 pst- 开头)"
                          class="form-input pr-10"
                          spellcheck="false"
                        />
                        <button
                          @click="showApiKey = !showApiKey"
                          type="button"
                          class="absolute right-3 top-1/2 -translate-y-1/2 text-on-surface-variant hover:text-primary transition-all"
                        >
                          <EyeIcon v-if="!showApiKey" class="w-4 h-4" />
                          <EyeOffIcon v-else class="w-4 h-4" />
                        </button>
                      </div>
                    </div>

                    <div class="form-group">
                      <label class="form-label font-bold text-xs">API Base URL</label>
                      <input
                        v-model="novelai.baseUrl"
                        type="text"
                        placeholder="https://image.novelai.net"
                        class="form-input"
                        spellcheck="false"
                      />
                    </div>

                    <div class="form-group">
                      <label class="form-label font-bold text-xs">模型选择</label>
                      <input
                        v-model="novelai.model"
                        type="text"
                        placeholder="nai-diffusion-4-5-full"
                        class="form-input font-mono"
                        spellcheck="false"
                      />
                      <div class="flex flex-wrap gap-1 mt-1.5">
                        <button
                          type="button"
                          @click="novelai.model = 'nai-diffusion-4-5-full'"
                          class="px-2 py-0.5 rounded bg-surface border border-outline-variant hover:border-primary text-[10px]"
                          :class="{
                            '!border-primary text-primary bg-primary/5': novelai.model === 'nai-diffusion-4-5-full',
                          }"
                        >
                          nai-diffusion-4-5-full
                        </button>
                        <button
                          type="button"
                          @click="novelai.model = 'nai-diffusion-4-5-curated'"
                          class="px-2 py-0.5 rounded bg-surface border border-outline-variant hover:border-primary text-[10px]"
                          :class="{
                            '!border-primary text-primary bg-primary/5': novelai.model === 'nai-diffusion-4-5-curated',
                          }"
                        >
                          nai-diffusion-4-5-curated
                        </button>
                      </div>
                    </div>

                    <!-- 画师串高级管理板块 -->
                    <div
                      class="form-group md:col-span-2 border border-outline-variant/30 bg-surface-container-low/30 p-4 rounded-2xl space-y-4"
                    >
                      <!-- A. 随机选用控制头 -->
                      <div class="flex items-center justify-between">
                        <div>
                          <label class="form-label font-bold text-xs">随机选用画师串</label>
                          <p class="text-[9px] text-on-surface-variant/80 mt-0.5">
                            开启后，每次生图将从下方预设列表中随机挑选一个画师串，避免生成画风过于单一。
                          </p>
                        </div>
                        <button
                          type="button"
                          @click="novelai.randomArtist = !novelai.randomArtist"
                          class="relative w-11 h-6 rounded-full transition-all duration-300 focus:outline-none cursor-pointer flex-shrink-0"
                          :class="novelai.randomArtist ? 'bg-primary' : 'bg-outline-variant'"
                        >
                          <span
                            class="absolute w-5 h-5 rounded-full bg-white top-0.5 transition-all duration-300 shadow-md"
                            :class="novelai.randomArtist ? 'left-5.5' : 'left-0.5'"
                          ></span>
                        </button>
                      </div>

                      <!-- B. 极简标签胶囊网格云 + 原位折叠滑出编辑器 (双模一体化常驻) -->
                      <div class="space-y-4 animate-fade-in">
                        <!-- 1. 胶囊标签网格 -->
                        <div class="flex flex-wrap gap-2.5 items-center">
                          <div
                            v-for="(item, idx) in novelai.artistStringList"
                            :key="idx"
                            @click="handleTagClick(idx)"
                            class="group relative inline-flex items-center space-x-1.5 px-3.5 py-1.5 rounded-full text-xs font-semibold select-none cursor-pointer transition-all duration-200 border"
                            :class="[
                              // 判定是否激活高亮状态：
                              // 开启随机时：展开编辑器者高亮
                              // 关闭随机时：当前固定 Pin 锁定者高亮，或者当前展开编辑器者高亮
                              (
                                novelai.randomArtist
                                  ? activeArtistIndex === idx
                                  : novelai.fixedArtistIndex === idx || activeArtistIndex === idx
                              )
                                ? 'bg-primary text-white border-primary shadow-[0_0_12px_rgba(70,72,212,0.4)] dark:shadow-[0_0_12px_rgba(78,222,163,0.35)] dark:bg-primary dark:text-black dark:border-primary'
                                : 'bg-surface-bright/70 text-on-surface hover:text-primary hover:border-primary/40 border-outline-variant/30 dark:bg-surface-container-lowest/80 opacity-70 hover:opacity-100',
                            ]"
                          >
                            <!-- 📌 固定锁定 Pin 图标 (仅在关闭随机模式下选中时显示) -->
                            <PinIcon
                              v-if="!novelai.randomArtist && novelai.fixedArtistIndex === idx"
                              class="w-3 h-3 text-white dark:text-black animate-pulse"
                            />

                            <span class="opacity-60 text-[9px] font-mono" v-else>#{{ idx + 1 }}</span>
                            <span>{{ item.name || '画师串 ' + (idx + 1) }}</span>

                            <!-- 删除按钮 -->
                            <button
                              type="button"
                              @click.stop="removeArtistString(idx)"
                              :disabled="novelai.artistStringList.length <= 1"
                              class="w-3.5 h-3.5 rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 hover:bg-error/15 hover:text-error disabled:opacity-0 disabled:pointer-events-none transition-all duration-150 ml-0.5"
                              title="删除此项"
                            >
                              <XIcon class="w-2.5 h-2.5" />
                            </button>
                          </div>

                          <!-- ➕ 新增风格胶囊 -->
                          <button
                            type="button"
                            @click="addArtistString"
                            class="inline-flex items-center space-x-1 px-3.5 py-1.5 rounded-full border border-dashed border-primary/40 text-primary hover:bg-primary/5 active:scale-95 transition-all duration-200 text-xs font-bold"
                          >
                            <PlusIcon class="w-3 h-3" />
                            <span>添加新画风</span>
                          </button>
                        </div>

                        <!-- 2. 原位滑出编辑器 (Edit Drawer Panel) -->
                        <Transition name="slide-up-fade">
                          <div
                            v-if="activeArtistIndex !== null && novelai.artistStringList[activeArtistIndex]"
                            class="relative flex flex-col p-4 bg-surface-container-lowest border border-outline-variant/50 rounded-2xl shadow-[0_10px_30px_rgba(0,0,0,0.06)] dark:shadow-[0_15px_40px_rgba(0,0,0,0.5)] border-t-2 border-t-primary/75 animate-fade-in"
                          >
                            <!-- 编辑面板头部 -->
                            <div
                              class="flex items-center justify-between border-b border-outline-variant/20 pb-2.5 mb-3.5"
                            >
                              <div class="flex items-center space-x-2.5 w-3/4">
                                <span
                                  class="text-[10px] font-mono font-bold text-primary bg-primary/5 border border-primary/10 px-1.5 py-0.5 rounded-md"
                                  >编辑中 #{{ activeArtistIndex + 1 }}</span
                                >
                                <input
                                  type="text"
                                  v-model="novelai.artistStringList[activeArtistIndex].name"
                                  class="bg-transparent border-0 border-b border-transparent focus:border-primary/40 focus:ring-0 text-xs font-bold text-on-surface p-0 pb-0.5 w-full placeholder:text-on-surface-variant/40 placeholder:font-normal outline-none transition-all duration-200"
                                  placeholder="✍_ 输入自定义风格别名（如: 赛博二次元，留空自动兜底）"
                                  spellcheck="false"
                                />
                              </div>
                              <button
                                type="button"
                                @click="activeArtistIndex = null"
                                class="text-on-surface-variant/60 hover:text-on-surface text-xs font-bold transition-all px-2.5 py-1.5 rounded-lg bg-surface hover:bg-surface-high border border-outline-variant/30 active:scale-95"
                              >
                                完成
                              </button>
                            </div>

                            <!-- 编辑面板文本内容 -->
                            <div class="space-y-1.5">
                              <label class="text-[10px] font-bold text-on-surface-variant/70 block"
                                >画师提示词串 (Artist Tags)</label
                              >
                              <textarea
                                v-model="novelai.artistStringList[activeArtistIndex].value"
                                rows="3"
                                placeholder="输入该风格要调用的画师/画风 Tags。例如: 1.5::artistau(d_elete) ::, portrait, realistic..."
                                class="form-input font-mono text-xs resize-none bg-surface-high/15 focus:bg-surface-container-lowest"
                                spellcheck="false"
                              ></textarea>
                              <p class="text-[9px] text-on-surface-variant/60">
                                提示：修改上方别名或文本内容将实时反馈并自动保存。
                              </p>
                            </div>
                          </div>
                        </Transition>
                      </div>
                    </div>

                    <div class="form-group md:col-span-2">
                      <label class="form-label font-bold text-xs">质量提示词</label>
                      <textarea
                        v-model="novelai.qualityPrompt"
                        rows="3"
                        placeholder="例如: masterpiece, best quality, highly detailed"
                        class="form-input font-mono text-xs resize-none"
                        spellcheck="false"
                      ></textarea>
                      <p class="text-[9px] text-on-surface-variant/70 mt-1">
                        开头不需要加","，生图时拼接在正向提示词的最后面，用于增强细节
                      </p>
                    </div>

                    <div class="form-group md:col-span-2">
                      <label class="form-label font-bold text-xs">默认负面提示词</label>
                      <textarea
                        v-model="novelai.negativePrompt"
                        rows="3"
                        placeholder="输入默认排除的 Tags"
                        class="form-input font-mono text-xs resize-none"
                        spellcheck="false"
                      ></textarea>
                    </div>

                    <div class="form-group md:col-span-2">
                      <label class="form-label font-bold text-xs">默认采样器</label>
                      <select v-model="novelai.sampler" class="form-input text-xs">
                        <option value="k_euler_ancestral">k_euler_ancestral (Euler Ancestral)</option>
                        <option value="k_euler">k_euler (Euler)</option>
                        <option value="k_dpmpp_2m">k_dpmpp_2m (DPM++ 2M)</option>
                        <option value="k_dpmpp_sde">k_dpmpp_sde (DPM++ SDE)</option>
                        <option value="k_dpmpp_2s_ancestral">k_dpmpp_2s_ancestral (DPM++ 2S Ancestral)</option>
                        <option value="k_dpm_fast">k_dpm_fast (DPM Fast)</option>
                        <option value="ddim">ddim (DDIM)</option>
                      </select>
                      <p class="text-[9px] text-on-surface-variant/70 mt-1">
                        默认推荐使用 Euler Ancestral 采样器，能呈现最生动的二次元细节
                      </p>
                    </div>

                    <div class="form-group md:col-span-2 border-t border-outline-variant/20 pt-4 mt-2">
                      <label class="form-label font-bold text-xs">默认生图尺寸</label>
                      <select v-model="novelai.defaultDimensions" class="form-input text-xs bg-surface-high/30">
                        <option value="portrait">竖图 (832 x 1216) — 适合手机壁纸与人物全身立绘</option>
                        <option value="landscape">横图 (1216 x 832) — 适合桌面壁纸与宏大风景叙事</option>
                        <option value="square">方图 (1024 x 1024) — 适合社交头像与局部细节特特写</option>
                        <option value="custom">自定义分辨率...</option>
                      </select>
                      <p class="text-[9px] text-on-surface-variant/70 mt-1">
                        设置后，之后所有的生图内容（包括私聊生图、随拍及朋友圈帖子）都将默认以此尺寸进行绘制。
                      </p>
                    </div>

                    <!-- 自定义默认尺寸高宽输入框 -->
                    <div
                      v-if="novelai.defaultDimensions === 'custom'"
                      class="form-group md:col-span-2 p-3.5 bg-surface-high/30 rounded-xl border border-outline-variant/10 flex flex-col space-y-2"
                    >
                      <label class="text-[10px] font-bold text-on-surface-variant uppercase tracking-wider font-mono"
                        >自定义默认生图分辨率 (必须为 64 的倍数)</label
                      >
                      <div class="flex items-center space-x-3">
                        <div
                          class="flex-1 flex items-center bg-surface border border-outline-variant/50 rounded-lg px-3 py-1.5"
                        >
                          <span class="text-[10px] text-on-surface-variant mr-2 select-none shrink-0 whitespace-nowrap"
                            >宽度:</span
                          >
                          <input
                            v-model.number="novelai.defaultWidth"
                            type="number"
                            step="64"
                            min="256"
                            max="2560"
                            @blur="
                              novelai.defaultWidth = Math.max(
                                256,
                                Math.min(2560, Math.round((novelai.defaultWidth || 832) / 64) * 64),
                              )
                            "
                            class="w-full text-xs font-mono bg-transparent text-on-surface focus:outline-none"
                          />
                        </div>
                        <span class="text-xs text-on-surface-variant font-bold">×</span>
                        <div
                          class="flex-1 flex items-center bg-surface border border-outline-variant/50 rounded-lg px-3 py-1.5"
                        >
                          <span class="text-[10px] text-on-surface-variant mr-2 select-none shrink-0 whitespace-nowrap"
                            >高度:</span
                          >
                          <input
                            v-model.number="novelai.defaultHeight"
                            type="number"
                            step="64"
                            min="256"
                            max="2560"
                            @blur="
                              novelai.defaultHeight = Math.max(
                                256,
                                Math.min(2560, Math.round((novelai.defaultHeight || 1216) / 64) * 64),
                              )
                            "
                            class="w-full text-xs font-mono bg-transparent text-on-surface focus:outline-none"
                          />
                        </div>
                      </div>
                      <p class="text-[9px] text-on-surface-variant/70 leading-normal">
                        注意：默认宽度和高度将作为背景生图（如朋友圈、随拍、静默自动配图）的优先尺寸标准。
                      </p>
                    </div>

                    <div
                      class="md:col-span-2 flex items-center justify-between bg-surface-high/20 p-4 rounded-xl border border-outline-variant/10"
                    >
                      <div class="space-y-0.5">
                        <label class="font-bold text-xs text-on-surface">手动生图确认模式</label>
                        <p class="text-[10px] text-on-surface-variant">
                          开启后，点击聊天输入框的生图按钮会先弹窗预览并可编辑 Prompt 提示词
                        </p>
                      </div>
                      <button
                        type="button"
                        @click="novelai.confirmMode = !novelai.confirmMode"
                        class="relative w-11 h-6 rounded-full transition-all duration-300 focus:outline-none cursor-pointer flex-shrink-0"
                        :class="novelai.confirmMode ? 'bg-primary' : 'bg-outline-variant'"
                      >
                        <span
                          class="absolute w-5 h-5 rounded-full bg-white top-0.5 transition-all duration-300 shadow-md"
                          :class="novelai.confirmMode ? 'left-5.5' : 'left-0.5'"
                        ></span>
                      </button>
                    </div>
                  </div>

                  <div
                    class="flex items-center justify-between border-t border-outline-variant/20 pt-4 bg-surface-low/10 p-4 rounded-xl"
                  >
                    <div class="flex items-center space-x-2">
                      <span class="text-xs font-bold text-on-surface">Anlas 剩余点数:</span>
                      <span v-if="isLoadingAnlas" class="text-xs font-mono text-primary animate-pulse">查询中...</span>
                      <span v-else class="text-sm font-mono font-extrabold text-primary">{{ anlasPoints }} 点</span>
                    </div>
                    <button
                      @click="() => refreshAnlas(false)"
                      :disabled="isLoadingAnlas || !novelai.apiKey"
                      class="px-3 py-1.5 rounded-lg border border-outline-variant text-[11px] text-on-surface hover:bg-surface-high transition-all flex items-center space-x-1 disabled:opacity-50"
                    >
                      <RefreshCwIcon class="w-3.5 h-3.5" :class="{ 'animate-spin': isLoadingAnlas }" />
                      <span>刷新点数</span>
                    </button>
                  </div>
                </div>
              </div>

              <!-- F. 主动引擎设置 (Tab: proactive) -->
              <div v-else-if="activeSettingsTab === 'proactive'" class="space-y-5 animate-in fade-in duration-200">
                <!-- 顶部红色警告提示 -->
                <div
                  class="flex items-start space-x-3 px-4 py-3 bg-red-500/5 border border-red-500/15 rounded-2xl text-red-600 dark:text-red-400 select-none"
                >
                  <AlertTriangleIcon class="w-4 h-4 flex-shrink-0 text-red-500 mt-0.5" />
                  <span class="text-xs font-bold leading-normal">
                    为节省Token，请将暂不联系的角色设置为<span
                      class="text-red-600 dark:text-red-400 font-extrabold underline decoration-red-400/60 decoration-2 underline-offset-2"
                      >【消息免打扰】</span
                    >。
                  </span>
                </div>

                <!-- 1. 搭讪频率控制组 -->
                <div class="space-y-3">
                  <div class="flex items-center space-x-2 px-1 select-none">
                    <div class="w-1.5 h-3.5 bg-primary rounded-full"></div>
                    <h3 class="text-xs font-bold text-on-surface">角色主动搭讪配置</h3>
                  </div>

                  <!-- 大卡片容器 -->
                  <div
                    class="bg-white dark:bg-surface-low border border-outline-variant/15 dark:border-outline-variant/10 rounded-2xl shadow-sm overflow-hidden divide-y divide-outline-variant/10"
                  >
                    <!-- 每日搭讪上限 -->
                    <div class="p-3.5 space-y-2">
                      <div class="flex items-center justify-between">
                        <span class="text-xs font-bold text-on-surface">每日搭讪上限</span>
                        <span
                          class="text-xs font-mono text-primary font-bold bg-primary/10 px-2 py-0.5 rounded-lg shrink-0"
                        >
                          {{ proactiveMaxDialogPerDay }} 次/天
                        </span>
                      </div>
                      <div class="flex items-center space-x-3 pt-0.5">
                        <span class="text-[10px] text-on-surface-variant/40 font-mono">0</span>
                        <div class="flex-1 flex items-center">
                          <input
                            v-model.number="proactiveMaxDialogPerDay"
                            type="range"
                            min="0"
                            max="10"
                            step="1"
                            class="proactive-range-input"
                          />
                        </div>
                        <span class="text-[10px] text-on-surface-variant/40 font-mono">10</span>
                      </div>
                      <p class="text-[9px] text-on-surface-variant/60 leading-normal pl-0.5">
                        每个角色每天在满足触发事件时最大发起的搭讪频次。设为 0 将完全禁用主动搭讪。
                      </p>
                    </div>

                    <!-- 最短搭讪间隔 -->
                    <div class="p-3.5 space-y-2">
                      <div class="flex items-center justify-between">
                        <span class="text-xs font-bold text-on-surface">最短搭讪间隔</span>
                        <span
                          class="text-xs font-mono text-primary font-bold bg-primary/10 px-2 py-0.5 rounded-lg shrink-0"
                        >
                          {{ proactiveCooldownHours }} 小时
                        </span>
                      </div>
                      <div class="flex items-center space-x-3 pt-0.5">
                        <span class="text-[10px] text-on-surface-variant/40 font-mono">0.5</span>
                        <div class="flex-1 flex items-center">
                          <input
                            v-model.number="proactiveCooldownHours"
                            type="range"
                            min="0.5"
                            max="24"
                            step="0.5"
                            class="proactive-range-input"
                          />
                        </div>
                        <span class="text-[10px] text-on-surface-variant/40 font-mono">24</span>
                      </div>
                      <p class="text-[9px] text-on-surface-variant/60 leading-normal pl-0.5">
                        相邻两次主动搭讪之间的冷却时间，防止短时间内造成消息轰炸。
                      </p>
                    </div>

                    <!-- 矜持期保护 -->
                    <div class="p-3.5 space-y-2">
                      <div class="flex items-center justify-between">
                        <span class="text-xs font-bold text-on-surface">矜持期保护时长</span>
                        <span
                          class="text-xs font-mono text-primary font-bold bg-primary/10 px-2 py-0.5 rounded-lg shrink-0"
                        >
                          {{ proactiveReserveHours }} 小时
                        </span>
                      </div>
                      <div class="flex items-center space-x-3 pt-0.5">
                        <span class="text-[10px] text-on-surface-variant/40 font-mono">1</span>
                        <div class="flex-1 flex items-center">
                          <input
                            v-model.number="proactiveReserveHours"
                            type="range"
                            min="1"
                            max="72"
                            step="1"
                            class="proactive-range-input"
                          />
                        </div>
                        <span class="text-[10px] text-on-surface-variant/40 font-mono">72</span>
                      </div>
                      <p class="text-[9px] text-on-surface-variant/60 leading-normal pl-0.5">
                        若最近一条对话消息是角色自己发送的（且非日记），且用户未回复，则角色在 X 小时内绝不连续搭讪。
                      </p>
                    </div>
                  </div>
                </div>

                <!-- 2. 社交圈行为配置 -->
                <div class="space-y-3 pt-1">
                  <div class="flex items-center space-x-2 px-1 select-none">
                    <div class="w-1.5 h-3.5 bg-primary rounded-full"></div>
                    <h3 class="text-xs font-bold text-on-surface">社交圈行为配置</h3>
                  </div>

                  <!-- 大卡片容器 -->
                  <div
                    class="bg-white dark:bg-surface-low border border-outline-variant/15 dark:border-outline-variant/10 rounded-2xl shadow-sm overflow-hidden divide-y divide-outline-variant/10"
                  >
                    <!-- 每日朋友圈上限 -->
                    <div class="p-3.5 space-y-2">
                      <div class="flex items-center justify-between">
                        <span class="text-xs font-bold text-on-surface">每日朋友圈上限</span>
                        <span
                          class="text-xs font-mono text-primary font-bold bg-primary/10 px-2.5 py-0.5 rounded-lg shrink-0"
                        >
                          {{ socialMaxMomentPerDay }} 条/天
                        </span>
                      </div>
                      <div class="flex items-center space-x-3 pt-0.5">
                        <span class="text-[10px] text-on-surface-variant/40 font-mono">0</span>
                        <div class="flex-1 flex items-center">
                          <input
                            v-model.number="socialMaxMomentPerDay"
                            type="range"
                            min="0"
                            max="5"
                            step="1"
                            class="proactive-range-input"
                          />
                        </div>
                        <span class="text-[10px] text-on-surface-variant/40 font-mono">5</span>
                      </div>
                      <p class="text-[9px] text-on-surface-variant/60 leading-normal pl-0.5">
                        每个角色每天最多发表的朋友圈动态条数。设为 0 将完全不发朋友圈。
                      </p>
                    </div>

                    <!-- 朋友圈最低间隔 -->
                    <div class="p-3.5 space-y-2">
                      <div class="flex items-center justify-between">
                        <span class="text-xs font-bold text-on-surface">朋友圈发表最低间隔</span>
                        <span
                          class="text-xs font-mono text-primary font-bold bg-primary/10 px-2.5 py-0.5 rounded-lg shrink-0"
                        >
                          {{ socialMomentMinIntervalHours }} 小时
                        </span>
                      </div>
                      <div class="flex items-center space-x-3 pt-0.5">
                        <span class="text-[10px] text-on-surface-variant/40 font-mono">1</span>
                        <div class="flex-1 flex items-center">
                          <input
                            v-model.number="socialMomentMinIntervalHours"
                            type="range"
                            min="1"
                            max="48"
                            step="1"
                            class="proactive-range-input"
                          />
                        </div>
                        <span class="text-[10px] text-on-surface-variant/40 font-mono">48</span>
                      </div>
                      <p class="text-[9px] text-on-surface-variant/60 leading-normal pl-0.5">
                        该角色两次发朋友圈动态之间的最低时间间隔。
                      </p>
                    </div>

                    <!-- 每周论坛发帖上限 -->
                    <div class="p-3.5 space-y-2">
                      <div class="flex items-center justify-between">
                        <span class="text-xs font-bold text-on-surface">每周论坛发帖上限</span>
                        <span
                          class="text-xs font-mono text-primary font-bold bg-primary/10 px-2.5 py-0.5 rounded-lg shrink-0"
                        >
                          {{ socialMaxForumPerWeek }} 篇/周
                        </span>
                      </div>
                      <div class="flex items-center space-x-3 pt-0.5">
                        <span class="text-[10px] text-on-surface-variant/40 font-mono">0</span>
                        <div class="flex-1 flex items-center">
                          <input
                            v-model.number="socialMaxForumPerWeek"
                            type="range"
                            min="0"
                            max="10"
                            step="1"
                            class="proactive-range-input"
                          />
                        </div>
                        <span class="text-[10px] text-on-surface-variant/40 font-mono">10</span>
                      </div>
                      <p class="text-[9px] text-on-surface-variant/60 leading-normal pl-0.5">
                        每个角色在论坛模块中每周最多发表的主题帖总数。设为 0 将完全不在论坛发帖。
                      </p>
                    </div>

                    <!-- 最短论坛发帖间隔 -->
                    <div class="p-3.5 space-y-2">
                      <div class="flex items-center justify-between">
                        <span class="text-xs font-bold text-on-surface">最短论坛发帖间隔</span>
                        <span
                          class="text-xs font-mono text-primary font-bold bg-primary/10 px-2.5 py-0.5 rounded-lg shrink-0"
                        >
                          {{ socialForumMinIntervalHours }} 小时
                        </span>
                      </div>
                      <div class="flex items-center space-x-3 pt-0.5">
                        <span class="text-[10px] text-on-surface-variant/40 font-mono">12</span>
                        <div class="flex-1 flex items-center">
                          <input
                            v-model.number="socialForumMinIntervalHours"
                            type="range"
                            min="12"
                            max="168"
                            step="12"
                            class="proactive-range-input"
                          />
                        </div>
                        <span class="text-[10px] text-on-surface-variant/40 font-mono">168</span>
                      </div>
                      <p class="text-[9px] text-on-surface-variant/60 leading-normal pl-0.5">
                        角色两次发论坛主题帖之间的最低时间间隔，防止在第一天就把本周的额度发完，让发帖频率更加自然。
                      </p>
                    </div>
                  </div>
                </div>

                <!-- 3. API 消费估算与提示 -->
                <div
                  class="bg-white dark:bg-surface-low border border-outline-variant/20 dark:border-outline-variant/10 rounded-2xl shadow-sm overflow-hidden space-y-0"
                >
                  <!-- 顶部标题栏 -->
                  <div
                    class="flex items-center justify-between border-b border-outline-variant/15 p-4 bg-slate-50/50 dark:bg-slate-900/10 select-none"
                  >
                    <div class="flex items-center space-x-2">
                      <div class="w-1.5 h-3.5 bg-primary rounded-full"></div>
                      <span class="text-xs font-bold text-on-surface">API 消费预算明细</span>
                    </div>
                  </div>

                  <!-- 活跃角色下拉展开折叠列表 -->
                  <div
                    class="px-4 py-3 bg-slate-50/40 dark:bg-slate-900/5 border-b border-outline-variant/10 text-[10px]"
                  >
                    <div
                      class="flex items-center justify-between cursor-pointer select-none"
                      @click="showActiveCharsList = !showActiveCharsList"
                    >
                      <span class="text-on-surface-variant font-medium">
                        当前主动引擎生效角色数：<strong class="text-primary font-black">{{
                          activeProactiveCharacters.length
                        }}</strong>
                        个（已排除了消息免打扰的角色）
                      </span>
                      <span class="text-primary hover:underline flex items-center space-x-1 font-bold">
                        <span>{{ showActiveCharsList ? '收起列表' : '展开列表' }}</span>
                        <ChevronDownIcon
                          class="w-3.5 h-3.5 transition-transform duration-200"
                          :class="{ 'rotate-180': showActiveCharsList }"
                        />
                      </span>
                    </div>
                    <div
                      v-show="showActiveCharsList"
                      class="mt-2 border-t border-outline-variant/10 pt-2 max-h-24 overflow-y-auto"
                    >
                      <div
                        v-if="activeProactiveCharacters.length === 0"
                        class="text-on-surface-variant/50 text-center py-1 select-none font-medium"
                      >
                        暂无生效中的角色（所有角色均已免打扰或无角色）
                      </div>
                      <div v-else class="flex flex-wrap gap-1.5">
                        <span
                          v-for="c in activeProactiveCharacters"
                          :key="c.id"
                          class="px-2 py-0.5 rounded-md bg-white border border-outline-variant/10 text-on-surface flex items-center space-x-1 shadow-sm"
                        >
                          <span class="w-1.5 h-1.5 rounded-full bg-emerald-500 shrink-0"></span>
                          <span class="truncate max-w-[80px] font-medium">{{ c.name }}</span>
                        </span>
                      </div>
                    </div>
                  </div>

                  <!-- 精美表格 -->
                  <div class="overflow-x-auto select-none">
                    <table class="w-full text-left border-collapse">
                      <thead>
                        <tr
                          class="bg-slate-50/50 dark:bg-slate-900/5 border-b border-outline-variant/15 text-[10px] font-bold text-on-surface-variant"
                        >
                          <th class="py-2.5 px-4 w-1/5">行为项目</th>
                          <th class="py-2.5 px-3">
                            调用规则与公式算法 (基于 N={{ activeProactiveCharacters.length }} 个活跃角色)
                          </th>
                          <th class="py-2.5 px-3 text-right w-24">单角色预计</th>
                          <th class="py-2.5 px-4 text-right w-28">总活跃角色预计</th>
                        </tr>
                      </thead>
                      <tbody class="divide-y divide-outline-variant/10 text-[10px]">
                        <!-- 1. 日记自省 -->
                        <tr class="hover:bg-slate-50/20 transition-all">
                          <td class="py-2.5 px-4 font-bold text-on-surface">
                            <div class="flex items-center space-x-2">
                              <BookOpenIcon class="w-3.5 h-3.5 text-emerald-600 dark:text-emerald-400 shrink-0" />
                              <span>每日日记</span>
                            </div>
                          </td>
                          <td class="py-2.5 px-3 text-on-surface-variant/80">
                            每日 17:00 后，有过聊天记录的角色固定触发 1 次自我写日记。
                          </td>
                          <td
                            class="py-2.5 px-3 text-right font-extrabold font-mono text-emerald-600 dark:text-emerald-400"
                          >
                            1.0 次/天
                          </td>
                          <td
                            class="py-2.5 px-4 text-right font-extrabold font-mono text-emerald-700 dark:text-emerald-400"
                          >
                            {{ (activeProactiveCharacters.length * 1.0).toFixed(1) }} 次/天
                          </td>
                        </tr>

                        <!-- 2. 主动搭讪 -->
                        <tr class="hover:bg-slate-50/20 transition-all">
                          <td class="py-2.5 px-4 font-bold text-on-surface">
                            <div class="flex items-center space-x-2">
                              <MessageSquareIcon class="w-3.5 h-3.5 text-blue-600 dark:text-blue-400 shrink-0" />
                              <span>主动搭讪沟通</span>
                            </div>
                          </td>
                          <td class="py-2.5 px-3 text-on-surface-variant/80">
                            离线超限、日程或清晨问候等事件命中时触发。单日最大触发额度。
                          </td>
                          <td class="py-2.5 px-3 text-right font-extrabold font-mono text-blue-600 dark:text-blue-400">
                            {{ proactiveMaxDialogPerDay }}.0 次/天
                          </td>
                          <td class="py-2.5 px-4 text-right font-extrabold font-mono text-blue-700 dark:text-blue-400">
                            {{ (activeProactiveCharacters.length * proactiveMaxDialogPerDay).toFixed(1) }} 次/天
                          </td>
                        </tr>

                        <!-- 3. 发动态（朋友圈/论坛） -->
                        <tr class="hover:bg-slate-50/20 transition-all">
                          <td class="py-2.5 px-4 font-bold text-on-surface">
                            <div class="flex items-center space-x-2">
                              <CameraIcon class="w-3.5 h-3.5 text-indigo-600 dark:text-indigo-400 shrink-0" />
                              <span>发朋友圈/论坛</span>
                            </div>
                          </td>
                          <td class="py-2.5 px-3 text-on-surface-variant/80">
                            自身发圈/论坛的调用数：朋友圈上限 {{ socialMaxMomentPerDay }} 条 + 论坛周上限
                            {{ socialMaxForumPerWeek }} 篇 ÷ 7天。
                          </td>
                          <td
                            class="py-2.5 px-3 text-right font-extrabold font-mono text-indigo-600 dark:text-indigo-400"
                          >
                            {{ (socialMaxMomentPerDay + socialMaxForumPerWeek / 7).toFixed(1) }} 次/天
                          </td>
                          <td
                            class="py-2.5 px-4 text-right font-extrabold font-mono text-indigo-700 dark:text-indigo-400"
                          >
                            {{
                              (
                                activeProactiveCharacters.length *
                                (socialMaxMomentPerDay + socialMaxForumPerWeek / 7)
                              ).toFixed(1)
                            }}
                            次/天
                          </td>
                        </tr>

                        <!-- 4. 被动社交互动 -->
                        <tr class="hover:bg-slate-50/20 transition-all">
                          <td class="py-2.5 px-4 font-bold text-on-surface">
                            <div class="flex items-center space-x-2">
                              <GlobeIcon class="w-3.5 h-3.5 text-purple-600 dark:text-purple-400 shrink-0" />
                              <span>朋友圈/论坛互动</span>
                            </div>
                          </td>
                          <td class="py-2.5 px-3 text-on-surface-variant/80">
                            对其他活跃角色动态的被动点赞、评论等回复交互（平均每人触发概率约 50%）：0.5 × (N - 1) ×
                            每日动态发帖总和。
                          </td>
                          <td
                            class="py-2.5 px-3 text-right font-extrabold font-mono text-purple-600 dark:text-purple-400"
                          >
                            {{
                              (activeProactiveCharacters.length > 1
                                ? 0.5 *
                                  (activeProactiveCharacters.length - 1) *
                                  (socialMaxMomentPerDay + socialMaxForumPerWeek / 7)
                                : 0
                              ).toFixed(1)
                            }}
                            次/天
                          </td>
                          <td
                            class="py-2.5 px-4 text-right font-extrabold font-mono text-purple-700 dark:text-purple-400"
                          >
                            {{
                              (
                                activeProactiveCharacters.length *
                                (activeProactiveCharacters.length > 1
                                  ? 0.5 *
                                    (activeProactiveCharacters.length - 1) *
                                    (socialMaxMomentPerDay + socialMaxForumPerWeek / 7)
                                  : 0)
                              ).toFixed(1)
                            }}
                            次/天
                          </td>
                        </tr>
                      </tbody>
                    </table>
                  </div>

                  <!-- 底部红色警告与大总计 -->
                  <div
                    class="border-t border-outline-variant/15 flex flex-col md:flex-row md:items-center justify-between gap-3 bg-red-500/5 p-4 select-none"
                  >
                    <div class="flex items-center space-x-2 text-on-surface">
                      <AlertTriangleIcon class="w-4 h-4 text-red-500 shrink-0" />
                      <div class="flex items-center space-x-1.5 flex-wrap">
                        <span class="text-xs font-bold leading-normal text-on-surface">
                          🚨
                          <strong
                            class="text-red-600 dark:text-red-400 font-extrabold text-sm underline decoration-red-400/60 decoration-2 underline-offset-2"
                            >单个角色</strong
                          >
                          每日预计最大大模型调用次数：
                        </span>
                        <span
                          class="text-sm font-extrabold text-primary font-mono bg-primary/10 px-2 py-0.5 rounded-lg shrink-0"
                        >
                          {{ singleCharProactiveCallsPerDay }} 次/天
                        </span>
                        <span class="text-xs text-on-surface-variant/60 font-semibold px-1">|</span>
                        <span class="text-xs font-bold leading-normal text-on-surface">
                          所有生效角色 (<strong class="text-primary">{{ activeProactiveCharacters.length }}</strong
                          >个) 总预算：
                        </span>
                        <span
                          class="text-sm font-extrabold text-primary font-mono bg-primary/15 px-2.5 py-0.5 rounded-lg shrink-0"
                        >
                          {{ totalProactiveCallsPerDay }} 次/天
                        </span>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              <!-- AI 小说设置 (Tab: novel) -->
              <div v-else-if="activeSettingsTab === 'novel'" class="space-y-6 animate-in fade-in duration-200">
                <!-- 子标签页切换 -->
                <div class="flex bg-surface-high/60 border border-outline-variant/10 rounded-xl p-1 space-x-1">
                  <button
                    @click="novelActiveTab = 'library'"
                    class="flex-1 py-1.5 text-xs font-bold rounded-lg transition-all text-center cursor-pointer font-sans"
                    :class="
                      novelActiveTab === 'library'
                        ? 'bg-primary text-on-primary shadow-sm'
                        : 'text-on-surface-variant hover:text-on-surface hover:bg-surface-high/30'
                    "
                  >
                    文风库
                  </button>
                  <button
                    @click="novelActiveTab = 'extract'"
                    class="flex-1 py-1.5 text-xs font-bold rounded-lg transition-all text-center cursor-pointer font-sans"
                    :class="
                      novelActiveTab === 'extract'
                        ? 'bg-primary text-on-primary shadow-sm'
                        : 'text-on-surface-variant hover:text-on-surface hover:bg-surface-high/30'
                    "
                  >
                    提取文风
                  </button>
                </div>

                <!-- 子标签页 A: 文风库 -->
                <div v-if="novelActiveTab === 'library'" class="space-y-4">
                  <div class="flex items-center justify-between">
                    <span class="text-xs font-bold text-on-surface-variant">我的文风列表</span>
                    <button
                      @click="openAddStyleModal"
                      class="flex items-center space-x-1 text-xs text-primary border border-primary/20 hover:border-primary bg-primary/5 hover:bg-primary/10 px-3 py-1.5 rounded-lg transition-all font-bold cursor-pointer"
                    >
                      <PlusIcon class="w-3.5 h-3.5" />
                      <span>新建文风</span>
                    </button>
                  </div>

                  <!-- 文风卡片列表 -->
                  <div class="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <!-- 用户自定义文风 -->
                    <div
                      v-for="style in novelStyles"
                      :key="style.id"
                      class="bg-surface-low/30 border border-outline-variant/20 rounded-2xl p-4 space-y-2 flex flex-col justify-between animate-in fade-in duration-200"
                    >
                      <div>
                        <div class="flex items-center justify-between border-b border-outline-variant/10 pb-2 mb-2">
                          <span class="text-xs font-bold text-on-surface truncate pr-2">{{ style.name }}</span>
                          <div class="flex items-center space-x-2 shrink-0">
                            <button
                              @click="openEditStyleModal(style)"
                              class="text-[10px] font-bold text-primary hover:underline"
                            >
                              编辑
                            </button>
                            <button
                              @click="deleteNovelStyle(style.id)"
                              class="text-[10px] font-bold text-red-500 hover:underline"
                            >
                              删除
                            </button>
                          </div>
                        </div>
                        <p
                          class="text-[10px] text-on-surface-variant/80 line-clamp-4 leading-relaxed font-mono whitespace-pre-wrap"
                        >
                          {{ style.prompt }}
                        </p>
                      </div>
                      <div
                        class="text-[8px] text-on-surface-variant/50 pt-2 border-t border-outline-variant/5 text-right font-mono"
                      >
                        创建于: {{ new Date(style.createdAt).toLocaleDateString() }}
                      </div>
                    </div>
                  </div>
                </div>

                <!-- 子标签页 B: 提取文风 -->
                <div
                  v-else-if="novelActiveTab === 'extract'"
                  class="bg-surface-low/30 border border-outline-variant/10 rounded-2xl p-5 space-y-5"
                >
                  <div class="flex flex-col space-y-1.5">
                    <div class="flex items-center justify-between">
                      <label class="text-xs font-bold text-on-surface">小说样本文本</label>
                      <button
                        @click="triggerUploadTxt"
                        class="flex items-center space-x-1 text-[10px] text-primary border border-primary/20 hover:border-primary bg-primary/5 hover:bg-primary/10 px-2.5 py-1 rounded-lg transition-all font-bold cursor-pointer"
                      >
                        <UploadCloudIcon class="w-3 h-3" />
                        <span>上传 .txt 文件</span>
                      </button>
                      <input
                        type="file"
                        ref="uploadTxtInput"
                        accept=".txt"
                        class="hidden"
                        @change="onUploadTxtChange"
                      />
                    </div>
                    <textarea
                      v-model="sampleText"
                      placeholder="请在此处粘贴小说样本文本（建议 500~3000 字，样本越典型，提取效果越好）..."
                      class="w-full min-h-[160px] max-h-[300px] bg-surface border border-outline-variant/60 rounded-xl p-3 text-xs text-on-surface focus:outline-none focus:border-primary font-mono resize-y shadow-inner"
                    ></textarea>
                  </div>

                  <div class="flex justify-end">
                    <button
                      @click="startExtractStyle"
                      :disabled="isExtractingStyle || !sampleText.trim()"
                      class="flex items-center space-x-1.5 text-xs text-white bg-primary hover:bg-primary/90 px-4 py-2 rounded-xl transition-all font-bold disabled:opacity-50 disabled:cursor-not-allowed shadow-md cursor-pointer"
                    >
                      <span
                        v-if="isExtractingStyle"
                        class="w-3.5 h-3.5 border-2 border-white border-t-transparent rounded-full animate-spin"
                      ></span>
                      <span>{{ isExtractingStyle ? '正在分析并提取文风...' : '分析并提取文风' }}</span>
                    </button>
                  </div>

                  <!-- 提取结果 -->
                  <div
                    v-if="extractedPrompt || isExtractingStyle"
                    class="space-y-4 pt-4 border-t border-outline-variant/20 animate-in fade-in duration-200"
                  >
                    <div class="flex flex-col space-y-1.5">
                      <label class="text-xs font-bold text-on-surface">分析与提取结果</label>
                      <textarea
                        v-model="extractedPrompt"
                        placeholder="AI 分析完成后，在此显示生成的文风提示词，您可以在此直接手动编辑修改..."
                        class="w-full min-h-[160px] max-h-[300px] bg-surface border border-outline-variant/60 rounded-xl p-3 text-xs text-on-surface focus:outline-none focus:border-primary font-mono resize-y shadow-inner"
                      ></textarea>
                    </div>

                    <div class="flex items-center space-x-3 max-w-sm">
                      <div class="flex-1 flex flex-col space-y-1">
                        <label class="text-[10px] font-bold text-on-surface-variant">保存为文风名称</label>
                        <input
                          v-model="extractedName"
                          type="text"
                          placeholder="例如：民国言情风"
                          class="bg-surface border border-outline-variant/60 rounded-xl px-3 py-1.5 text-xs text-on-surface focus:outline-none focus:border-primary"
                        />
                      </div>
                      <button
                        @click="saveExtractedStyle"
                        :disabled="!extractedPrompt.trim() || !extractedName.trim()"
                        class="self-end text-xs text-white bg-emerald-500 hover:bg-emerald-600 px-4 py-2 rounded-xl transition-all font-bold disabled:opacity-50 disabled:cursor-not-allowed shadow-md cursor-pointer"
                      >
                        保存到文风库
                      </button>
                    </div>
                  </div>
                </div>
              </div>

              <!-- D. 数据备份与迁移 (Tab: migration) -->
              <div
                v-else-if="activeSettingsTab === 'migration'"
                class="space-y-6 select-none animate-in fade-in duration-200"
              >
                <div
                  class="bg-surface-low/20 p-6 rounded-2xl border border-outline-variant/10 text-center relative overflow-hidden"
                >
                  <!-- 背景微弱流光特效 -->
                  <div
                    class="absolute -inset-0 opacity-10 bg-gradient-to-r from-primary via-secondary to-primary blur-3xl animate-pulse"
                  ></div>

                  <div
                    class="w-14 h-14 rounded-2xl bg-primary/10 border border-primary/20 flex items-center justify-center mx-auto mb-4 shadow-sm relative z-10"
                  >
                    <Share2Icon class="w-7 h-7 text-primary" />
                  </div>
                  <h2 class="text-sm font-bold text-on-surface relative z-10">本地数据转移与备份</h2>
                  <p class="text-xs text-on-surface-variant mt-2 max-w-lg mx-auto leading-relaxed relative z-10">
                    将您在软件中的核心数据（包括全部聊天记录、角色人设、物理记忆、朋友圈动态、自建歌单和全局设置等）一键打包备份为
                    <code class="font-mono bg-surface-high px-1.5 py-0.5 rounded text-primary text-[10px]">.echo</code>
                    的专属文件，方便在不同设备间迁移。
                  </p>
                </div>

                <div class="grid grid-cols-1 md:grid-cols-2 gap-5">
                  <!-- 备份导出卡片 -->
                  <div
                    class="bg-surface-low/30 border border-outline-variant/10 rounded-2xl p-5 flex flex-col justify-between hover:border-primary/20 transition-all group"
                  >
                    <div>
                      <div class="flex items-center space-x-2.5">
                        <div
                          class="w-8 h-8 rounded-xl bg-primary/10 border border-primary/20 flex items-center justify-center text-primary group-hover:scale-105 transition-all"
                        >
                          <DownloadIcon class="w-4 h-4" />
                        </div>
                        <h3 class="text-xs font-bold text-on-surface">一键导出数据备份</h3>
                      </div>
                      <p class="text-[11px] text-on-surface-variant mt-3 leading-relaxed">
                        物理打包本地所有数据，生成备份包，并提供保存路径选择。
                      </p>
                    </div>
                    <button
                      @click="handleExportProjectData"
                      :disabled="isExportingData || isImportingData"
                      class="btn-primary w-full mt-6 py-2 px-4 rounded-xl flex items-center justify-center space-x-2 text-xs font-semibold select-none cursor-pointer transition-all active:scale-95 disabled:opacity-50"
                    >
                      <Loader2Icon v-if="isExportingData" class="w-3.5 h-3.5 animate-spin" />
                      <DownloadIcon v-else class="w-3.5 h-3.5" />
                      <span>{{ isExportingData ? '正在打包导出...' : '导出核心备份 (.echo)' }}</span>
                    </button>
                  </div>

                  <!-- 还原导入卡片 -->
                  <div
                    class="bg-surface-low/30 border border-outline-variant/10 rounded-2xl p-5 flex flex-col justify-between hover:border-error/20 transition-all group"
                  >
                    <div>
                      <div class="flex items-center space-x-2.5">
                        <div
                          class="w-8 h-8 rounded-xl bg-error/10 border border-error/20 flex items-center justify-center text-error group-hover:scale-105 transition-all"
                        >
                          <RefreshCwIcon class="w-4 h-4" />
                        </div>
                        <h3 class="text-xs font-bold text-on-surface">一键导入覆盖还原</h3>
                      </div>
                      <p class="text-[11px] text-on-surface-variant mt-3 leading-relaxed">
                        选择本地的
                        <code class="font-mono bg-surface-high px-1 py-0.5 rounded text-error text-[10px]">.echo</code>
                        备份文件，删除当前的所有数据，全量覆盖导入，导入后应用将热重启。
                      </p>
                    </div>
                    <button
                      @click="handleImportProjectData"
                      :disabled="isExportingData || isImportingData"
                      class="btn-secondary border-error/20 hover:bg-error/10 hover:text-error hover:border-error/30 w-full mt-6 py-2 px-4 rounded-xl flex items-center justify-center space-x-2 text-xs font-semibold select-none cursor-pointer transition-all active:scale-95 disabled:opacity-50"
                    >
                      <Loader2Icon v-if="isImportingData" class="w-3.5 h-3.5 animate-spin text-error" />
                      <RefreshCwIcon v-else class="w-3.5 h-3.5 text-error" />
                      <span :class="{ 'text-error': !isImportingData }">
                        {{
                          isImportingData
                            ? isDockerMode
                              ? `正在流式上传恢复 (${importProgress}%)...`
                              : '正在全量还原并重启...'
                            : '全量覆盖导入 (.echo)'
                        }}
                      </span>
                    </button>
                  </div>
                </div>

                <!-- 安全指引提示区 -->
                <div
                  class="bg-surface-low/10 border border-outline-variant/10 p-4 rounded-xl flex items-start space-x-3"
                >
                  <AlertTriangleIcon class="w-4 h-4 text-warning flex-shrink-0 mt-0.5" />
                  <div class="space-y-1">
                    <h4 class="text-[11px] font-bold text-on-surface">导入操作安全提醒</h4>
                    <p class="text-[10px] text-on-surface-variant leading-relaxed">
                      由于导入备份为【全量覆盖性质】，导入后将删除现有软件中的所有数据。在点击确认导入前，请务必保证选取的
                      <code class="font-mono text-primary bg-surface-high px-1 rounded">.echo</code>
                      文件合法有效。导入过程中请勿强制退出应用或切断电源，以防数据损坏。
                    </p>
                  </div>
                </div>
              </div>

              <!-- 微信个人号托管面板 (Tab: wechat) -->
              <div
                v-else-if="activeSettingsTab === 'wechat'"
                class="space-y-6 select-none animate-in fade-in duration-200"
              >
                <!-- 1. 微信托管状态介绍头部 -->
                <div
                  class="bg-surface-low/20 p-6 rounded-2xl border border-outline-variant/10 relative overflow-hidden"
                >
                  <div
                    class="absolute -inset-0 opacity-5 bg-gradient-to-r from-primary via-emerald-500 to-primary blur-3xl animate-pulse"
                  ></div>

                  <div class="flex items-start space-x-4 relative z-10">
                    <div
                      class="w-12 h-12 rounded-2xl bg-emerald-500/10 border border-emerald-500/20 flex items-center justify-center text-emerald-500 shadow-sm flex-shrink-0"
                    >
                      <MessageCircleIcon class="w-6 h-6" />
                    </div>
                    <div>
                      <h2 class="text-sm font-bold text-on-surface">个人微信接入</h2>
                      <p class="text-[11px] text-on-surface-variant mt-2 leading-relaxed">
                        通过微信官方协议，将您的个人微信号接入 Echo
                        系统。您可以通过微信与角色对话，并物理双向同步到本地客户端对话框，实现跨平台交互体验。
                      </p>
                      <div
                        class="mt-3 flex items-center space-x-2 text-[10px] text-emerald-500/80 font-semibold bg-emerald-500/5 border border-emerald-500/10 px-2.5 py-1 rounded-lg w-max"
                      >
                        <span class="inline-block w-1.5 h-1.5 rounded-full bg-emerald-500 animate-ping"></span>
                        <span>官方托管通道 · 安全防封禁</span>
                      </div>
                    </div>
                  </div>
                </div>

                <!-- 红色文字警告提示 -->
                <div class="bg-error/5 border border-error/10 p-4 rounded-xl flex items-start space-x-3 select-none">
                  <AlertTriangleIcon class="w-4.5 h-4.5 text-error flex-shrink-0 mt-0.5" />
                  <div class="space-y-1">
                    <p class="text-[10px] text-error leading-relaxed font-medium">
                      【禁止敏感内容】：微信本身可能具备强力审核，请避免涉及色情、暴力、政治、违反法律法规、高危金融词汇等敏感内容，以避免账号被封禁。
                    </p>
                  </div>
                </div>

                <!-- 2. 二维码生成/登录绑定与托管大卡片 -->
                <div
                  class="bg-surface-low/30 border border-outline-variant/10 rounded-2xl p-6 relative hover:border-emerald-500/10 transition-all"
                >
                  <h3 class="text-xs font-bold text-on-surface flex items-center space-x-2 mb-4">
                    <span class="w-1 h-3 bg-emerald-500 rounded-full"></span>
                    <span>托管绑定与状态管理</span>
                  </h3>

                  <!-- 情况 A: 已经连接绑定微信 -->
                  <div
                    v-if="wechatState.connected"
                    class="flex flex-col md:flex-row items-center justify-between p-5 rounded-xl bg-surface-low border border-outline-variant/15 space-y-4 md:space-y-0"
                  >
                    <div class="flex items-center space-x-4">
                      <!-- 绿色翡翠呼吸灯头像框 -->
                      <div class="relative">
                        <div
                          class="w-12 h-12 rounded-full bg-emerald-500/10 border border-emerald-500/30 flex items-center justify-center text-emerald-500"
                        >
                          <MessageCircleIcon class="w-6 h-6" />
                        </div>
                        <span
                          class="absolute bottom-0 right-0 w-3 h-3 rounded-full border-2 border-surface bg-emerald-500 animate-pulse"
                        ></span>
                      </div>
                      <div>
                        <div class="flex items-center space-x-2">
                          <span class="text-xs font-bold text-on-surface">微信状态：</span>
                          <span
                            class="inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold bg-emerald-500/10 text-emerald-500 border border-emerald-500/20"
                            >在线就绪</span
                          >
                        </div>
                        <p class="text-[11px] text-on-surface-variant mt-1.5 font-mono">
                          托管账号 UIN:
                          <span class="text-primary font-semibold select-all">{{
                            wechatState.accountId || 'wechat_robot'
                          }}</span>
                        </p>
                      </div>
                    </div>

                    <button
                      @click="handleWeChatUnbind"
                      class="btn-secondary border-error/20 hover:bg-error/10 hover:text-error hover:border-error/30 py-2 px-5 rounded-xl flex items-center space-x-2 text-xs font-semibold select-none cursor-pointer transition-all active:scale-95"
                    >
                      <TrashIcon class="w-3.5 h-3.5 text-error" />
                      <span class="text-error">安全注销并断开托管</span>
                    </button>
                  </div>

                  <!-- 情况 B: 尚未连接绑定微信 (显示生成二维码或渲染二维码) -->
                  <div v-else class="flex flex-col items-center justify-center p-6 text-center">
                    <!-- B1: 已经获取到了扫码二维码 Url -->
                    <div v-if="wechatState.qrcodeUrl" class="space-y-4">
                      <div
                        class="relative w-48 h-48 bg-white p-3 rounded-2xl border border-outline-variant/20 mx-auto shadow-md flex items-center justify-center overflow-hidden"
                      >
                        <img
                          :src="wechatState.qrcodeUrl"
                          alt="微信绑定二维码"
                          class="w-full h-full object-contain"
                          @error="onQRCodeLoadError"
                        />
                      </div>

                      <div class="space-y-1">
                        <p class="text-xs font-bold text-on-surface flex items-center justify-center space-x-1.5">
                          <span class="w-1.5 h-1.5 rounded-full bg-primary animate-ping"></span>
                          <span class="animate-pulse">等待手机微信扫码绑定</span>
                        </p>
                        <p class="text-[10px] text-on-surface-variant max-w-sm mx-auto leading-relaxed">
                          二维码限时 5 分钟失效，扫码授权并点击“确认”后，系统将自动连接激活。
                        </p>
                      </div>

                      <div class="flex items-center justify-center space-x-3 mt-4">
                        <button
                          @click="triggerWeChatLogin"
                          :disabled="isRequestingQR"
                          class="btn-secondary py-1.5 px-4 rounded-xl text-xs font-semibold transition-all flex items-center space-x-1.5 cursor-pointer"
                        >
                          <RefreshCwIcon class="w-3.5 h-3.5" :class="{ 'animate-spin': isRequestingQR }" />
                          <span>重新生成二维码</span>
                        </button>
                        <button
                          @click="wechatState.qrcodeUrl = null"
                          class="btn-secondary border-outline/20 hover:bg-surface-high py-1.5 px-4 rounded-xl text-xs font-semibold transition-all cursor-pointer"
                        >
                          <span>取消扫码</span>
                        </button>
                      </div>
                    </div>

                    <!-- B2: 二维码还未生成 -->
                    <div v-else class="space-y-4">
                      <div
                        class="w-14 h-14 rounded-2xl bg-surface-low border border-outline-variant/15 flex items-center justify-center text-on-surface-variant/40 mx-auto shadow-inner"
                      >
                        <MessageCircleIcon class="w-7 h-7 opacity-35" />
                      </div>
                      <div>
                        <h4 class="text-xs font-bold text-on-surface">您的 Echo 系统目前尚未绑定任何微信账号</h4>
                        <p class="text-[10px] text-on-surface-variant mt-1.5 max-w-md leading-relaxed mx-auto">
                          单次限制绑定 1
                          个微信号。点击下方按钮即可向微信安全协议服务器申请注册并生成托管扫码绑定二维码。
                        </p>
                      </div>
                      <button
                        @click="triggerWeChatLogin"
                        :disabled="isRequestingQR"
                        class="btn-primary py-2 px-6 rounded-xl flex items-center justify-center space-x-2 text-xs font-bold transition-all active:scale-95 cursor-pointer select-none mx-auto animate-bounce"
                        style="animation-duration: 2.5s"
                      >
                        <Loader2Icon v-if="isRequestingQR" class="w-3.5 h-3.5 animate-spin" />
                        <MessageCircleIcon v-else class="w-3.5 h-3.5" />
                        <span>{{ isRequestingQR ? '正在建立安全握手通道...' : '生成微信安全托管绑定二维码' }}</span>
                      </button>
                    </div>
                  </div>
                </div>

                <!-- 3. 好友关系绑定映射控制台 -->
                <div class="bg-surface-low/30 border border-outline-variant/10 rounded-2xl p-6 relative">
                  <h3 class="text-xs font-bold text-on-surface flex items-center space-x-2 mb-2">
                    <span class="w-1 h-3 bg-emerald-500 rounded-full"></span>
                    <span>微信好友 & 角色映射</span>
                  </h3>
                  <p class="text-[10px] text-on-surface-variant leading-relaxed mb-4">
                    您可以自由指定"宠幸"哪一位角色。指定后，将独享该角色的专属回复。
                  </p>

                  <!-- 绑定映射表 -->
                  <div
                    v-if="mappedFriends.length > 0"
                    class="overflow-hidden border border-outline-variant/15 rounded-xl bg-surface-low select-text"
                  >
                    <table class="w-full text-left border-collapse">
                      <thead>
                        <tr
                          class="bg-surface-high/30 border-b border-outline-variant/10 text-[10px] text-on-surface-variant font-bold"
                        >
                          <th class="py-2.5 px-4">微信好友加密 ID</th>
                          <th class="py-2.5 px-4">当前绑定的角色</th>
                          <th class="py-2.5 px-4 text-right">托管状态</th>
                        </tr>
                      </thead>
                      <tbody class="divide-y divide-outline-variant/10 text-xs">
                        <tr
                          v-for="friend in mappedFriends"
                          :key="friend.friendId"
                          class="hover:bg-surface-high/20 transition-colors"
                        >
                          <!-- 好友加密ID -->
                          <td
                            class="py-3 px-4 font-mono text-[11px] text-on-surface-variant/90 max-w-[180px] truncate select-all"
                            :title="friend.friendId"
                          >
                            {{ friend.friendId }}
                          </td>
                          <!-- 选择宠幸绑定的数字生命 -->
                          <td class="py-3 px-4">
                            <select
                              :value="friend.characterId"
                              @change="onFriendMappingChange(friend.friendId, $event)"
                              class="bg-surface border border-outline-variant/20 rounded-lg py-1 px-2.5 text-xs text-on-surface focus:border-primary focus:ring-1 focus:ring-primary focus:outline-none transition-all cursor-pointer font-medium max-w-[200px]"
                            >
                              <option value="">-- 静默过滤 (不予回复) --</option>
