                              v-if="friend.characterId"
                              class="inline-flex items-center space-x-1 px-2 py-0.5 rounded text-[10px] font-semibold bg-emerald-500/10 text-emerald-500 border border-emerald-500/20"
                            >
                              <span class="inline-block w-1 h-1 rounded-full bg-emerald-500"></span>
                              <span>托管服务中</span>
                            </span>
                            <span
                              v-else
                              class="inline-flex items-center space-x-1 px-2 py-0.5 rounded text-[10px] font-semibold bg-surface-high text-on-surface-variant/40 border border-outline-variant/10"
                            >
                              <span>已静音</span>
                            </span>
                          </td>
                        </tr>
                      </tbody>
                    </table>
