                            <span>Discord-小酒窝</span>
                            <span
                              class="text-[9px] font-normal px-1.5 py-0.5 rounded bg-[#738BD8]/10 text-[#738BD8] select-none scale-90 flex-shrink-0"
                              >官方海外社区</span
                            >
                          </h4>
                          <p class="text-[10px] text-on-surface-variant truncate mt-0.5">小酒窝Discord海外社区</p>
                        </div>
                      </a>
                    </div>
                  </div>

                  <!-- 🚀 致谢部分 -->
                  <div class="pt-4 border-t border-outline-variant/10">
                    <div
                      @click="showAcknowledgements = !showAcknowledgements"
