                          >
                            <div class="flex items-center space-x-2.5 min-w-0">
                              <span
                                class="text-xs font-bold text-on-surface group-hover:text-primary transition-colors truncate"
                              >
                                {{ item.projectName }}
                              </span>
                              <span class="text-[10px] text-on-surface-variant/60 shrink-0">
                                作者: {{ item.author }}
                              </span>
                            </div>
                            <div class="flex items-center min-w-0">
                              <a
                                :href="item.url"
                                target="_blank"
                                class="text-[10px] font-mono text-on-surface-variant hover:text-primary hover:underline cursor-pointer flex items-center space-x-1 truncate max-w-full"
                              >
                                <span class="truncate max-w-[240px] sm:max-w-[360px]">{{ item.url }}</span>
                                <ExternalLinkIcon
                                  class="w-3 h-3 opacity-60 group-hover:opacity-100 group-hover:text-primary transition-opacity shrink-0"
                                />
                              </a>
                            </div>
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              <!-- F. 意见反馈 -->
              <div
                v-else-if="activeSettingsTab === 'feedback'"
                class="flex-1 flex flex-col min-h-0 h-full overflow-hidden"
              >
                <FeedbackPanel class="flex-1" />
              </div>
            </div>

            <!-- 固定底部操作粘滞栏 -->
            <div
              v-if="
                activeSettingsTab !== 'about' &&
                activeSettingsTab !== 'migration' &&
                activeSettingsTab !== 'profile' &&
                activeSettingsTab !== 'feedback' &&
                activeSettingsTab !== 'logs'
              "
              class="flex-shrink-0 p-4 border-t border-outline-variant/20 bg-surface flex flex-col space-y-3 select-none"
            >
              <div class="flex items-center justify-between max-w-3xl w-full mx-auto">
                <button
                  v-if="activeSettingsTab === 'drawing'"
                  @click="() => refreshAnlas(false)"
                  :disabled="isLoadingAnlas || !novelai.apiKey"
                  class="btn-secondary flex items-center space-x-1.5 disabled:opacity-50 text-xs py-2 px-4 rounded-xl active:scale-95 transition-all"
                >
                  <Loader2Icon v-if="isLoadingAnlas" class="w-3.5 h-3.5 animate-spin" />
                  <RefreshCwIcon v-else class="w-3.5 h-3.5" />
                  <span>{{ isLoadingAnlas ? '获取中...' : '刷新点数' }}</span>
                </button>
                <button
                  v-else
                  @click="testModelConnection"
                  :disabled="testing"
                  class="btn-secondary flex items-center space-x-1.5 disabled:opacity-50 text-xs py-2 px-4 rounded-xl active:scale-95 transition-all"
                >
                  <ActivityIcon v-if="!testing" class="w-3.5 h-3.5" />
                  <Loader2Icon v-else class="w-3.5 h-3.5 animate-spin" />
                  <span>{{ testing ? '测试中...' : '测试接口' }}</span>
                </button>

                <button
                  @click="
                    activeSettingsTab === 'drawing'
                      ? saveNovelAiConfig()
                      : activeSettingsTab === 'proactive'
                        ? saveProactiveSettings()
                        : activeSettingsTab === 'vector'
                          ? saveVectorMemoryConfig()
                          : saveModelConfig()
                  "
                  :disabled="saving"
                  class="btn-primary flex items-center space-x-1.5 disabled:opacity-50 text-xs py-2 px-4 font-bold rounded-xl active:scale-95 transition-all"
                >
                  <Loader2Icon v-if="saving" class="w-3.5 h-3.5 animate-spin" />
                  <SaveIcon v-else class="w-3.5 h-3.5" />
                  <span>{{ saving ? '保存中...' : '保存配置' }}</span>
                </button>
              </div>

              <!-- 测试结果反馈 -->
              <div
                v-if="testResult"
                class="max-w-3xl w-full mx-auto p-3 rounded-xl border text-xs"
                :class="
                  testResult.success
                    ? 'border-primary/20 bg-primary/5 text-primary'
                    : 'border-error/20 bg-error/5 text-error'
                "
              >
                <div
                  class="font-bold flex items-center justify-between mb-2 border-b border-current/10 pb-1.5 select-none"
                >
                  <div class="flex items-center space-x-1.5">
                    <CheckCircleIcon v-if="testResult.success" class="w-4 h-4" />
                    <XCircleIcon v-else class="w-4 h-4" />
                    <span>{{ testResult.success ? '大模型通道连通正常' : '大模型通道存在连接失败' }}</span>
                  </div>
                  <button
                    @click="testResult = null"
                    class="p-0.5 rounded-lg hover:bg-current/10 transition-colors cursor-pointer text-current/60 hover:text-current active:scale-95 focus:outline-none flex items-center justify-center"
                    title="收起结果"
                  >
                    <XIcon class="w-3.5 h-3.5" />
                  </button>
                </div>

                <div class="space-y-2">
                  <!-- 主大模型通道结果 -->
                  <div>
                    <div class="flex items-center space-x-1.5 font-semibold mb-0.5">
                      <span
                        class="w-1.5 h-1.5 rounded-full"
                        :class="testResult.primary?.success ? 'bg-primary' : 'bg-error'"
                      ></span>
                      <span class="opacity-95">主大模型通道：</span>
                      <span :class="testResult.primary?.success ? 'text-primary font-bold' : 'text-error font-bold'">
                        {{ testResult.primary?.success ? '测试通过' : '连接失败' }}
                      </span>
                    </div>
                    <div
                      class="text-on-surface-variant text-[10px] font-mono whitespace-pre-wrap pl-3 max-h-[80px] overflow-y-auto opacity-80 leading-relaxed"
                    >
                      {{ testResult.primary?.message }}
                    </div>
                  </div>

                  <!-- 辅助大模型通道结果 -->
                  <div v-if="testResult.secondary">
                    <div
                      class="flex items-center space-x-1.5 font-semibold mb-0.5 border-t border-current/5 pt-1.5 mt-1.5"
                    >
                      <span
                        class="w-1.5 h-1.5 rounded-full"
                        :class="testResult.secondary?.success ? 'bg-primary' : 'bg-error'"
                      ></span>
                      <span class="opacity-95">辅助大模型通道：</span>
                      <span :class="testResult.secondary?.success ? 'text-primary font-bold' : 'text-error font-bold'">
                        {{ testResult.secondary?.success ? '测试通过' : '连接失败' }}
                      </span>
                    </div>
                    <div
                      class="text-on-surface-variant text-[10px] font-mono whitespace-pre-wrap pl-3 max-h-[80px] overflow-y-auto opacity-80 leading-relaxed"
                    >
                      {{ testResult.secondary?.message }}
                    </div>
                  </div>
                  <div
                    v-else
                    class="text-[10px] text-on-surface-variant/40 pl-3 italic border-t border-current/5 pt-1.5 mt-1.5 select-none"
                  >
                    辅助大模型通道：未启用或未配置
                  </div>
                </div>
              </div>
            </div>
          </div>
        </template>

        <!-- ── 通讯录详情区 ── -->
        <template v-else-if="sideView === 'contacts'">
          <div
            v-if="!selectedContactId"
            class="flex-1 flex flex-col items-center justify-center text-center p-8 bg-surface select-none"
