                >
                  <img
                    v-if="characterAvatars[selectedContactId]"
                    :src="characterAvatars[selectedContactId]"
                    class="w-full h-full object-cover"
                  />
                  <UserIcon v-else class="w-8 h-8 text-on-surface-variant m-auto mt-4" />
                  <!-- 悬浮微透明层 -->
