                    title="点击打开该角色的本地物理文件夹 📂"
                  >
                    <GlobeIcon class="w-3 h-3 text-primary opacity-70 group-hover:scale-110 transition-transform" />
                    <span
                      >角色专属目录：<code class="group-hover:border-primary/30 group-hover:bg-primary/5 transition-all"
                        >characters/{{ characterList.find(c => c.id === selectedContactId)?.folder_name }}</code
                      ></span
                    >
                  </p>
                  <div class="flex items-center space-x-2 mt-2">
                    <span
                      class="text-[9px] tracking-wider uppercase bg-primary/5 text-primary border border-primary/10 px-1.5 py-0.5 rounded font-bold font-mono"
