                      性格核心设定 (SOUL.md)
                    </div>
                    <button
                      @click="contactEditModes.soul = !contactEditModes.soul"
                      class="flex items-center space-x-1 text-xs text-primary border border-primary/20 hover:border-primary bg-primary/5 hover:bg-primary/10 px-2.5 py-1 rounded-md transition-all font-bold cursor-pointer select-none flex-shrink-0"
                    >
                      <component :is="contactEditModes.soul ? EyeIcon : PenLineIcon" class="w-3.5 h-3.5" />
                      <span>{{ contactEditModes.soul ? '预览设定' : '修改设定' }}</span>
                    </button>
                  </div>
                  <!-- 预览模式 -->
                  <div
                    v-if="!contactEditModes.soul"
                    class="flex-1 p-4 rounded-xl border border-outline-variant bg-surface text-on-surface text-xs leading-relaxed overflow-y-auto min-h-[300px] select-text markdown-body shadow-sm"
                    v-html="renderMarkdown(contactSoulContent || '*设定未装载*')"
                  ></div>
                  <!-- 编辑模式 -->
                  <textarea
                    v-else
                    v-model="contactSoulContent"
                    class="flex-1 w-full font-mono text-xs bg-surface border border-outline-variant rounded-xl p-3 focus:outline-none focus:border-primary resize-none text-on-surface overflow-y-auto min-h-[300px] shadow-inner"
                  ></textarea>

                  <div v-if="contactEditModes.soul" class="flex justify-end space-x-2 mt-3 flex-shrink-0 select-none">
                    <button
                      @click="
                        contactEditModes.soul = false;
                        selectCharacterForContactDetails(selectedContactId);
                      "
                      class="btn-secondary text-xs py-1.5 px-4"
                    >
                      取消
                    </button>
                    <button
                      @click="saveContactDetails"
                      class="btn-primary text-xs py-1.5 px-4 font-bold flex items-center space-x-1"
                    >
                      <SaveIcon class="w-3 h-3" /><span>保存修改</span>
                    </button>
                  </div>
