                    <div class="text-[10px] font-bold text-on-surface-variant uppercase tracking-wider font-mono">
                      双轨记忆设定 (MEMORY.md)
                    </div>
                    <div class="flex items-center space-x-2 flex-shrink-0">
                      <button
                        @click="tidyCharacterMemory('contact')"
