                      >
                        <component :is="contactEditModes.user ? EyeIcon : PenLineIcon" class="w-3.5 h-3.5" />
                        <span>{{ contactEditModes.user ? '预览侧写' : '修改侧写' }}</span>
                      </button>
                    </div>
                  </div>
                  <!-- 预览模式 -->
                  <div
