                  </div>
                  <div
                    v-else-if="!contactGalleryImages.length"
                    class="flex-1 flex flex-col items-center justify-center py-12 text-center border-2 border-dashed border-outline-variant/40 rounded-2xl bg-surface-high/10"
                  >
                    <ImageIcon class="w-10 h-10 text-on-surface-variant/40 mb-2.5" />
