                          <div v-else class="w-full h-full flex items-center justify-center bg-surface-high/50">
                            <Loader2Icon class="w-5 h-5 text-on-surface-variant/20 animate-spin" />
                          </div>
                        </div>

                        <!-- 物理删除按钮 -->
                        <button
