                          <span
                            class="text-[9px] text-on-surface-variant/50 dark:text-zinc-500 truncate max-w-[100px]"
                            >{{ s.singer }}</span
                          >
                        </div>
                      </div>
                    </div>
                  </transition>
                </div>

                <!-- 快捷导入按钮 -->
                <div
                  v-if="activeMusicTab === 'playlist' && !currentDetailPlaylistSongs.length"
                  class="flex items-center space-x-2"
                >
                  <button
