                        >
                          <span class="w-1.5 h-1.5 rounded-full bg-black/80"></span>
                          <span>深邃纯黑</span>
                        </button>
                        <button
                          @click="lyricBgColor = 'rgba(255, 255, 255, 0.15)'"
