                        >
                          <span class="w-1.5 h-1.5 rounded-full bg-[#1e293b]/50"></span>
                          <span>极光深蓝</span>
                        </button>
                      </div>
                    </div>

                    <!-- 文字颜色 -->
                    <div class="space-y-3">
