                                : 'text-on-surface-variant/70 hover:bg-surface-medium'
                            "
                            class="flex-1 py-1 text-[9.5px] font-bold rounded-lg transition-all cursor-pointer"
                          >
                            ✨ 渐变模式
                          </button>
                        </div>

