                              </div>
                              <div class="flex flex-col leading-none">
                                <span class="text-[7px] font-black text-on-surface-variant/40 uppercase">END</span>
                                <span class="text-[9px] font-bold font-mono text-on-surface-variant mt-0.5">{{
                                  lyricTextEndColor
