                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </template>

        <!-- ── 聊天与导入视图分流 ── -->
        <template v-else>
          <!-- 没有选中角色 / 导入视图 -->
          <template v-if="activeView === 'import'">
            <div class="flex-1 flex flex-col items-center justify-center p-8">
              <div class="max-w-md w-full">
                <div class="flex items-center space-x-2.5 mb-2 select-none">
                  <button
                    v-if="isMobile"
                    @click="activeView = 'chat'"
