                      ? 'border-primary bg-primary/5 scale-[0.99]'
                      : 'border-outline-variant hover:border-primary/50'
                  "
                  @click="triggerFileInput"
                >
                  <input
                    ref="fileInput"
                    type="file"
                    accept="image/png,application/json,.json"
                    class="hidden"
                    @change="handleFileSelect"
                  />
