                    </div>
                    <div class="text-[10px] text-on-surface-variant mt-0.5">
                      {{ uploadStep === 'parsing' ? 'STEP 1/2' : 'STEP 2/2' }}
                    </div>
                  </div>
                </div>

                <div
                  v-if="parseError"
                  class="mt-4 p-3 rounded-xl border border-error/20 bg-error/5 text-error text-xs flex items-center space-x-2"
                >
                  <XCircleIcon class="w-4 h-4 flex-shrink-0" />
                  <span>{{ parseError }}</span>
                </div>
              </div>
            </div>
          </template>
          <template v-else-if="activeView === 'manual_create'">
            <!-- 手动录入角色界面 -->
            <div class="flex-1 flex flex-col h-full overflow-y-auto p-6 md:p-8">
              <div class="max-w-3xl w-full mx-auto flex flex-col space-y-6">
                <!-- 头部栏 -->
                <div class="flex items-center justify-between border-b border-outline-variant/30 pb-4">
                  <div class="flex items-center space-x-2.5 select-none">
                    <div>
                      <div class="text-lg font-bold text-on-surface">手动录入角色</div>
                      <p class="text-xs text-on-surface-variant mt-0.5">
                        完全自定义地手动填写角色各项设定，创建您专属的数字生命。
                      </p>
                    </div>
                  </div>
                </div>

                <!-- 表单主要内容，两栏布局 -->
                <div class="grid grid-cols-1 md:grid-cols-3 gap-6">
