                  <div class="space-y-5 flex flex-col">
                    <!-- 头像上传区域 -->
                    <div
                      class="flex flex-col items-center p-5 bg-surface-container/30 border border-outline-variant/30 rounded-2xl shadow-sm"
                    >
                      <label class="text-xs font-bold text-on-surface-variant mb-3">角色头像 (必填)</label>
                      <div
