                      >
                        <img
                          v-if="manualAvatarPreviewUrl"
                          :src="manualAvatarPreviewUrl"
                          class="w-full h-full object-cover pointer-events-none select-none"
                        />
                        <template v-else>
                          <UploadCloudIcon
                            class="w-8 h-8 text-on-surface-variant/40 group-hover:text-primary transition-colors"
                          />
                          <span class="text-[10px] text-on-surface-variant/50 mt-2">上传头像</span>
                        </template>
                        <div
                          v-if="manualAvatarPreviewUrl"
                          class="absolute inset-0 bg-black/45 opacity-0 group-hover:opacity-100 flex items-center justify-center text-white text-xs font-medium transition-opacity"
                        >
                          更换头像
                        </div>
                      </div>
                      <input
                        ref="manualAvatarInputRef"
                        type="file"
                        accept="image/*"
                        class="hidden"
                        @change="handleManualAvatarSelect"
                      />
                      <p class="text-[10px] text-on-surface-variant/40 mt-3 text-center">
                        支持任意比例，将自动以 1:1 裁剪填充展示
                      </p>
                    </div>

                    <!-- 基本设置 -->
                    <div
                      class="p-5 bg-surface-container/30 border border-outline-variant/30 rounded-2xl shadow-sm space-y-4"
                    >
                      <div class="flex flex-col space-y-1.5">
                        <label class="text-xs font-bold text-on-surface-variant">角色姓名</label>
                        <input
                          v-model="manualCharName"
                          type="text"
                          placeholder="例如：布洛妮娅"
                          class="w-full px-3 py-2 text-xs bg-surface border border-outline-variant rounded-lg focus:outline-none focus:border-primary transition-colors text-on-surface"
                          @input="handleNameInputForPinyin"
                        />
                      </div>

                      <div class="flex flex-col space-y-1.5">
                        <label class="text-xs font-bold text-on-surface-variant">拼音/英文唯一标识</label>
                        <input
                          v-model="manualCharFolderName"
                          type="text"
                          placeholder="例如：bronya"
                          class="w-full px-3 py-2 text-xs bg-surface border border-outline-variant rounded-lg focus:outline-none focus:border-primary transition-colors font-mono text-on-surface"
                        />
                        <span class="text-[9px] text-on-surface-variant/50"
                          >用于物理文件夹命名，建议使用纯小写字母与数字</span
                        >
                      </div>
                    </div>
                  </div>

                  <!-- 右栏：核心设定文件配置 (占 2 栏) -->
                  <div class="md:col-span-2 space-y-5">
                    <!-- 角色人设 Soul.md -->
                    <div
                      class="p-5 bg-surface-container/30 border border-outline-variant/30 rounded-2xl shadow-sm space-y-2.5 flex flex-col h-[250px]"
                    >
                      <div class="flex items-center justify-between">
                        <label class="text-xs font-bold text-on-surface-variant">角色人设 (Soul.md)</label>
                        <span class="text-[10px] text-primary font-mono">SOUL_CONFIG</span>
                      </div>
                      <textarea
                        v-model="manualSoulContent"
                        placeholder="# 角色定位与概览
这里写该角色的社会身份、主要性格特征与核心功能...

# 性格核心与矛盾
写下角色的内在冲突、矛盾细节或最突出的行为取向（使用 {{char}} 表示角色自身，{{user}} 表示用户）...

# 语言风格底层成因
写下角色的说话口气，常用的语助词或口头禅..."
                        class="flex-1 w-full px-3 py-2 text-xs bg-surface border border-outline-variant rounded-lg focus:outline-none focus:border-primary transition-colors resize-none font-mono leading-relaxed text-on-surface placeholder:text-on-surface-variant/40"
                      ></textarea>
                    </div>

                    <div
                      class="p-5 bg-surface-container/30 border border-outline-variant/30 rounded-2xl shadow-sm space-y-2.5 flex flex-col h-[250px]"
                    >
                      <div class="flex items-center justify-between">
                        <label class="text-xs font-bold text-on-surface-variant">世界观设定 (World.md)</label>
                        <span class="text-[10px] text-primary font-mono">WORLD_CONFIG</span>
                      </div>
                      <textarea
                        v-model="manualWorldContent"
                        placeholder="# 场景世界设定
描述该角色身处的环境大背景、主要物理规则、势力范围或你们初识的背景设定..."
                        class="flex-1 w-full px-3 py-2 text-xs bg-surface border border-outline-variant rounded-lg focus:outline-none focus:border-primary transition-colors resize-none font-mono leading-relaxed text-on-surface placeholder:text-on-surface-variant/40"
                      ></textarea>
                    </div>
                  </div>
                </div>

                <!-- 底部操作按钮 -->
                <div class="flex items-center justify-end space-x-3 pt-4 border-t border-outline-variant/30">
                  <button
                    @click="activeView = 'chat'"
                    class="px-4 py-2 rounded-lg border border-outline-variant text-xs font-bold text-on-surface-variant hover:bg-surface-high/60 active:scale-95 transition-all cursor-pointer"
                  >
                    取消
                  </button>
                  <button
                    @click="onManualCreateConfirm"
                    :disabled="manualSaving"
                    class="px-4 py-2 rounded-lg bg-primary text-white text-xs font-bold hover:bg-primary-container active:scale-95 disabled:opacity-50 transition-all flex items-center space-x-1.5 cursor-pointer shadow-sm"
                  >
                    <Loader2Icon v-if="manualSaving" class="animate-spin w-3.5 h-3.5" />
                    <span>{{ manualSaving ? '正在诞生生命...' : '保存并诞生' }}</span>
                  </button>
                </div>
              </div>
            </div>
          </template>

          <!-- 未选择角色的占位 -->
          <template v-else-if="!activeCharacter && !isGroupActive">
            <div class="flex-1 flex flex-col items-center justify-center text-center px-8">
              <div class="w-16 h-16 rounded-full bg-surface-high flex items-center justify-center mb-4">
                <MessageSquareIcon class="w-8 h-8 text-on-surface-variant/30" />
              </div>
              <p class="text-sm text-on-surface-variant/50">选择一个角色开始对话</p>
            </div>
          </template>

          <!-- ── 主聊天窗口 ── -->
          <template v-else>
            <!-- 顶部 Header -->
            <header
              class="h-14 px-5 border-b border-chat-border bg-chat-header flex items-center justify-between flex-shrink-0"
            >
              <div class="flex items-center space-x-3">
                <button
                  v-if="isMobile"
                  @click="selectedCharacterId = null"
                  class="mr-1.5 p-1.5 rounded-xl hover:bg-surface-high text-on-surface-variant active:scale-95 transition-all flex items-center justify-center cursor-pointer"
                  title="返回列表"
                >
                  <ChevronLeftIcon class="w-5 h-5" />
                </button>
                <div
                  class="w-8 h-8 rounded overflow-hidden border border-outline-variant bg-surface flex-shrink-0 flex items-center justify-center"
                  :class="{
                    'cursor-pointer hover:scale-105 active:scale-95 transition-all duration-200 shadow-sm':
                      activeCharacter && activeCharacter.id !== 'character_creator_bot',
                  }"
                  :title="
                    activeCharacter && activeCharacter.id !== 'character_creator_bot' ? '点击查看角色详细资料' : ''
                  "
                  @click="activeCharacter && activeCharacter.id !== 'character_creator_bot' && viewCharacterDetails()"
                >
                  <template v-if="isGroupActive">
                    <img
                      v-if="selectedCharacterId && groupAvatars[selectedCharacterId as string]"
                      :src="groupAvatars[selectedCharacterId as string]"
                      class="w-full h-full object-cover"
                    />
                    <UserIcon v-else class="w-4 h-4 text-on-surface-variant m-auto" />
                  </template>
                  <template v-else-if="activeCharacter">
                    <template v-if="activeCharacter.id === 'character_creator_bot'">
                      <img :src="creatorBotAvatarUrl" class="w-full h-full object-cover" />
                    </template>
                    <template v-else>
                      <img
                        v-if="characterAvatars[activeCharacter.id]"
                        :src="characterAvatars[activeCharacter.id]"
                        class="w-full h-full object-cover"
                      />
                      <UserIcon v-else class="w-4 h-4 text-on-surface-variant m-auto mt-2" />
                    </template>
                  </template>
                </div>
                <div class="relative">
                  <div class="text-sm font-bold text-on-surface flex items-center space-x-1.5">
                    <span v-if="isGroupActive">{{ activeGroupChat.name }}</span>
                    <span v-else-if="activeCharacter">{{ activeCharacter.name }}</span>
                    <span v-if="isCurrentCharStreaming" class="text-xs font-normal text-primary/80 animate-pulse"
                      >（对方正在输入...）</span
                    >

                    <!-- 爱心图标挂件 (入口按钮) -->
                    <button
                      v-if="activeCharacter && activeCharacter.id !== 'character_creator_bot'"
                      @click.stop="showStatesDropdown = !showStatesDropdown"
                      class="ml-1 flex items-center justify-center p-1 rounded-full text-rose-500 hover:bg-rose-500/10 active:scale-95 transition-all select-none focus:outline-none"
                      :class="{ 'bg-rose-500/10 shadow-sm scale-110': showStatesDropdown }"
                      title="查看角色状态"
                    >
                      <HeartIcon class="w-4 h-4 fill-current animate-pulse" />
                    </button>
                  </div>
                  <div class="text-[10px] text-on-surface-variant/60 flex items-center space-x-1">
                    <span class="w-1.5 h-1.5 rounded-full bg-green-400 inline-block"></span>
                    <span v-if="isGroupActive">时空交汇中 ({{ activeGroupChatMembers.length }}人)</span>
                    <span v-else>在线</span>
                  </div>

                  <!-- 下拉展开的内心状态悬浮卡片 -->
                  <div
                    v-if="showStatesDropdown && activeCharacter && activeCharacter.id !== 'character_creator_bot'"
                    class="rounded-2xl border border-outline-variant bg-surface-high/95 backdrop-blur-xl shadow-2xl p-4 flex flex-col space-y-3.5 z-30 cursor-default select-none animate-in fade-in duration-200"
                    :class="[
                      isMobile 
                        ? 'fixed top-16 left-1/2 -translate-x-1/2 w-[90vw] max-w-[340px]' 
                        : 'absolute top-full mt-2 left-0 w-80 slide-in-from-top-2'
                    ]"
                    @click.stop
                  >
                    <!-- 头部标题 -->
                    <div class="flex items-center justify-between border-b border-outline-variant pb-2">
                      <span class="text-xs font-bold text-on-surface flex items-center space-x-1">
                        <HeartIcon class="w-3.5 h-3.5 fill-current text-rose-500" />
                        <span>内心状态系统</span>
                      </span>
                      <span class="text-[10px] text-on-surface-variant/60">点击指标可微调数值</span>
                    </div>

                    <!-- 状态列表 -->
                    <div class="flex flex-col space-y-2">
                      <div v-for="item in activeCharacterStates" :key="item.key" class="relative w-full">
                        <!-- A. 文本型编辑状态（纵向大容量 textarea） -->
                        <div
                          v-if="activePopoverKey === item.key && item.type === 'text'"
                          class="flex flex-col space-y-2 p-3 rounded-xl border border-primary bg-primary/5 text-xs w-full cursor-default select-none animate-in fade-in duration-150"
                          @click.stop
                        >
                          <!-- 顶部标题与删除操作 -->
                          <div class="flex items-center justify-between">
                            <div class="flex items-center space-x-1.5 min-w-0">
                              <span class="text-sm shrink-0">{{ item.emoji }}</span>
                              <span class="font-bold text-[11px] text-primary truncate">{{ item.label }}</span>
                            </div>

                            <!-- 物理删除该自定义指标 (基础预置指标绝对不可删除) -->
                            <button
                              v-if="!['intimacy', 'mood'].includes(item.key)"
                              @click.stop="deleteCustomState(item.key)"
                              class="p-1 rounded-md text-red-500 hover:bg-red-500/10 hover:text-red-600 transition-all flex items-center justify-center cursor-pointer"
                              title="彻底删除该状态指标"
                            >
                              <svg
                                class="w-3.5 h-3.5"
                                fill="none"
                                stroke="currentColor"
                                stroke-width="2"
                                viewBox="0 0 24 24"
                                xmlns="http://www.w3.org/2000/svg"
                              >
                                <path
                                  stroke-linecap="round"
                                  stroke-linejoin="round"
                                  d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"
                                ></path>
                              </svg>
                            </button>
                          </div>

                          <!-- 宽敞的多行文本输入区 -->
                          <textarea
                            v-model="popoverValue"
                            rows="3"
                            class="w-full px-2.5 py-1.5 text-[11px] rounded-lg bg-surface border border-outline-variant focus:outline-none focus:border-primary text-on-surface font-medium resize-y focus:ring-1 focus:ring-primary/20 leading-relaxed font-sans"
                            @keyup.esc="activePopoverKey = null"
                            placeholder="请输入该指标的长文本人设设定..."
                          ></textarea>

                          <!-- 底部控制按钮 -->
                          <div class="flex items-center justify-end space-x-2 select-none">
                            <button
                              @click.stop="activePopoverKey = null"
                              class="btn-secondary text-[10px] py-1 px-3 rounded-lg flex items-center space-x-1"
                            >
                              <span>取消</span>
                            </button>
                            <button
                              @click.stop="saveStateValue(item.key, popoverValue)"
                              class="btn-primary text-[10px] py-1 px-3.5 font-bold rounded-lg flex items-center space-x-1"
                            >
                              <span>保存</span>
                            </button>
                          </div>
                        </div>

                        <!-- B. 数字型编辑状态（维持原有横向极简 Inline 条，钱包余额特殊展开微型表单） -->
                        <div
                          v-else-if="activePopoverKey === item.key && item.type !== 'text'"
                          class="flex px-3 py-1.5 rounded-xl border border-primary bg-primary/5 text-xs font-semibold w-full cursor-default select-none animate-in fade-in duration-150"
                          :class="item.key === 'balance' ? 'flex-col space-y-2.5 p-3' : 'items-center justify-between'"
                          @click.stop
                        >
                          <!-- 编辑主条 -->
                          <div class="flex items-center min-w-0 flex-1" :class="item.key === 'balance' ? 'w-full justify-between' : 'mr-2 space-x-1.5'">
                            <div class="flex items-center space-x-1.5 min-w-0 flex-1 mr-2">
                              <span class="text-sm shrink-0">{{ item.emoji }}</span>
                              <span class="opacity-90 font-bold text-[11px] text-primary truncate shrink-0">{{
                                item.label
                              }}</span>

                              <!-- 亲密度快/慢切换小按钮 (点击爱心打开的亲密度状态栏上) -->
                              <button
                                v-if="item.key === 'intimacy'"
                                @click.stop="toggleIntimacySpeed"
                                class="px-2 py-0.5 rounded-md text-[9px] font-bold select-none cursor-pointer transition-all border flex items-center space-x-1 shrink-0 ml-1 mr-0.5 animate-fade-in"
                                :class="
                                  intimacySpeed === 'slow'
                                    ? 'bg-rose-500/10 border-rose-500/20 text-rose-600 dark:text-rose-400 hover:bg-rose-500/20'
                                    : 'bg-amber-500/10 border-amber-500/20 text-amber-600 dark:text-amber-400 hover:bg-amber-500/20'
                                "
                                :title="intimacySpeed === 'slow' ? '当前为慢速成长模式' : '当前为快速成长模式'"
                              >
                                <span>{{ intimacySpeed === 'slow' ? '🐢 慢' : '⚡ 快' }}</span>
                              </button>

                              <!-- 数字型输入框 (支持整数与高精度小数) -->
                              <input
                                type="number"
                                :min="item.min ?? 0"
                                :max="item.key === 'balance' ? 999999999999 : (item.max ?? 100)"
                                :step="item.key === 'balance' ? '0.01' : '1'"
                                v-model.number="popoverValue"
                                class="w-full px-2 py-1 text-[11px] rounded-lg bg-surface border border-outline-variant focus:outline-none focus:border-primary text-on-surface font-extrabold focus:ring-1 focus:ring-primary/20"
                                @keyup.enter="saveStateValue(item.key, popoverValue)"
                                @keyup.esc="activePopoverKey = null"
                                @keypress="
                                  event => {
                                    if (!/[0-9.]/.test(event.key)) event.preventDefault();
                                  }
                                "
                                placeholder="值"
                              />
                            </div>

                            <!-- 仅在 item.key === 'balance' 时把操作按钮跟输入框横向排列 -->
                            <div v-if="item.key === 'balance'" class="flex items-center space-x-1 shrink-0">
                              <button
                                @click.stop="activePopoverKey = null"
                                class="p-1 rounded-md text-on-surface-variant hover:bg-on-surface/5 hover:text-on-surface transition-all flex items-center justify-center cursor-pointer"
                                title="取消"
                              >
                                <svg
                                  class="w-3.5 h-3.5"
                                  fill="none"
                                  stroke="currentColor"
                                  stroke-width="2.5"
                                  viewBox="0 0 24 24"
                                  xmlns="http://www.w3.org/2000/svg"
                                >
                                  <path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12"></path>
                                </svg>
                              </button>

                              <button
                                @click.stop="saveStateValue(item.key, popoverValue)"
                                class="p-1 rounded-md bg-primary text-white hover:bg-primary-hover shadow-sm transition-all flex items-center justify-center cursor-pointer"
                                title="保存"
                              >
                                <svg
                                  class="w-3.5 h-3.5"
                                  fill="none"
                                  stroke="currentColor"
                                  stroke-width="2.5"
                                  viewBox="0 0 24 24"
                                  xmlns="http://www.w3.org/2000/svg"
                                >
                                  <path stroke-linecap="round" stroke-linejoin="round" d="M5 13l4 4L19 7"></path>
                                </svg>
                              </button>
                            </div>
                          </div>

                          <!-- 仅在非 balance 且为数字型时展示原本的按钮组 -->
                          <div v-if="item.key !== 'balance'" class="flex items-center space-x-1 shrink-0">
                            <!-- 物理删除该自定义指标 (基础预置指标绝对不可删除) -->
                            <button
                              v-if="!['intimacy', 'mood'].includes(item.key)"
                              @click.stop="deleteCustomState(item.key)"
                              class="p-1 rounded-md text-red-500 hover:bg-red-500/10 hover:text-red-600 transition-all flex items-center justify-center cursor-pointer"
                              title="彻底删除该状态指标"
                            >
                              <svg
                                class="w-3.5 h-3.5"
                                fill="none"
                                stroke="currentColor"
                                stroke-width="2"
                                viewBox="0 0 24 24"
                                xmlns="http://www.w3.org/2000/svg"
                              >
                                <path
                                  stroke-linecap="round"
                                  stroke-linejoin="round"
                                  d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"
                                ></path>
                              </svg>
                            </button>

                            <!-- 放弃/取消编辑 -->
                            <button
                              @click.stop="activePopoverKey = null"
                              class="p-1 rounded-md text-on-surface-variant hover:bg-on-surface/5 hover:text-on-surface transition-all flex items-center justify-center cursor-pointer"
                              title="取消"
                            >
                              <svg
                                class="w-3.5 h-3.5"
                                fill="none"
                                stroke="currentColor"
                                stroke-width="2.5"
                                viewBox="0 0 24 24"
                                xmlns="http://www.w3.org/2000/svg"
                              >
                                <path stroke-linecap="round" stroke-linejoin="round" d="M6 18L18 6M6 6l12 12"></path>
                              </svg>
                            </button>

                            <!-- 保存编辑 -->
                            <button
                              @click.stop="saveStateValue(item.key, popoverValue)"
                              class="p-1 rounded-md bg-primary text-white hover:bg-primary-hover shadow-sm transition-all flex items-center justify-center cursor-pointer"
                              title="保存"
                            >
                              <svg
                                class="w-3.5 h-3.5"
                                fill="none"
                                stroke="currentColor"
                                stroke-width="2.5"
                                viewBox="0 0 24 24"
                                xmlns="http://www.w3.org/2000/svg"
                              >
                                <path stroke-linecap="round" stroke-linejoin="round" d="M5 13l4 4L19 7"></path>
                              </svg>
                            </button>
                          </div>

                          <!-- 仅在 item.key === 'balance' 时渲染定期发薪微型表单 -->
                          <div 
                            v-if="item.key === 'balance'"
                            class="flex flex-col space-y-1.5 border-t border-outline-variant/60 pt-2 w-full text-[10px] animate-in slide-in-from-top-1 duration-150"
                          >
                            <div class="flex items-center text-primary font-bold">
                              <span>📅 定期自动增资配置</span>
                            </div>
                            <div class="grid grid-cols-3 gap-1.5 w-full">
                              <div class="flex flex-col space-y-0.5 min-w-0">
                                <span class="text-[9px] text-on-surface-variant/70">发薪周期</span>
                                <select
                                  v-model="tempSalaryPeriod"
                                  class="px-1.5 py-0.5 rounded bg-surface border border-outline-variant focus:outline-none focus:border-primary text-on-surface text-[10px] font-semibold cursor-pointer truncate"
                                >
                                  <option value="none">不自动增资</option>
                                  <option value="daily">每天 (天结)</option>
                                  <option value="weekly">每周一 (周结)</option>
                                  <option value="monthly">每月1号 (月结)</option>
                                </select>
                              </div>
                              <div class="flex flex-col space-y-0.5 min-w-0">
                                <span class="text-[9px] text-on-surface-variant/70">单次金额</span>
                                <input
                                  type="number"
                                  step="0.01"
                                  min="0"
                                  v-model.number="tempSalaryBase"
                                  :disabled="tempSalaryPeriod === 'none'"
                                  class="px-1.5 py-0.5 rounded bg-surface border border-outline-variant focus:outline-none focus:border-primary text-on-surface text-[10px] font-extrabold disabled:opacity-50 min-w-0"
                                  placeholder="0.00"
                                />
                              </div>
                              <div class="flex flex-col space-y-0.5 min-w-0">
                                <span class="text-[9px] text-on-surface-variant/70">资金来源 (15字内)</span>
                                <input
                                  type="text"
                                  v-model="tempSalaryDesc"
                                  :disabled="tempSalaryPeriod === 'none'"
                                  maxlength="15"
                                  class="px-1.5 py-0.5 rounded bg-surface border border-outline-variant focus:outline-none focus:border-primary text-on-surface text-[10px] font-medium disabled:opacity-50 min-w-0 truncate"
                                  placeholder="请输入"
                                />
                              </div>
                            </div>
                          </div>
                        </div>

                        <!-- 指标项本体 (非编辑状态，点击进入 Inline 编辑) -->
                        <div
                          v-else
                          @click.stop="openStatePopover(item)"
                          class="flex items-center justify-between px-3 py-2 rounded-xl text-xs font-semibold cursor-pointer transition-all active:scale-98 border hover:shadow-sm"
                          :class="[
                            item.key === 'intimacy'
                              ? 'bg-rose-500/5 border-rose-500/10 text-rose-600 dark:text-rose-400 hover:bg-rose-500/12'
                              : item.key === 'mood'
                                ? 'bg-amber-500/5 border-amber-500/10 text-amber-600 dark:text-amber-400 hover:bg-amber-500/12'
                                : 'bg-indigo-500/5 border-indigo-500/10 text-indigo-600 dark:text-indigo-400 hover:bg-indigo-500/12',
                          ]"
                        >
                          <div class="flex items-center space-x-2">
                            <span>{{ item.emoji }}</span>
                            <span class="opacity-90 font-medium">{{ item.label }}</span>
                          </div>
                          <div
                            class="flex items-center space-x-1.5 min-w-0 ml-3"
                            :class="{
                              'flex-shrink-0': item.type !== 'text',
                              'flex-1 justify-end': item.type === 'text',
                            }"
                          >
                            <span class="font-extrabold break-all whitespace-normal text-right">{{
                              item.key === 'balance'
                                ? isNaN(Number(item.value))
                                  ? '0.00'
                                  : Number(item.value).toFixed(2)
                                : item.value
                            }}</span>
                            <span
                              v-if="item.key === 'intimacy'"
                              class="text-[10px] opacity-75 font-normal flex-shrink-0"
                              >({{ getIntimacyPhaseText(item.value) }})</span
                            >
                          </div>
                        </div>

                        <!-- 钱包余额特有的只读收支说明提示 -->
                        <div 
                          v-if="item.key === 'balance' && activePopoverKey !== 'balance' && getSalaryPeriodVal() !== 'none'"
                          class="text-[9px] text-on-surface-variant/70 italic mt-0.5 px-2 flex items-center space-x-1 select-none animate-in fade-in duration-200"
                        >
                          <span>📅 每{{ getSalaryPeriodText() }}自动注入 {{ getSalaryBaseVal() }} 元 ({{ getSalaryDescVal() }})</span>
                        </div>
                      </div>
                    </div>

                    <!-- 底部操作区域 -->
                    <div class="flex items-center justify-between border-t border-outline-variant pt-2.5">
                      <button
                        @click="showAddStateModal = true"
                        class="flex-1 flex items-center justify-center space-x-1 py-2 px-3 rounded-xl text-xs font-semibold bg-on-surface/5 border border-on-surface/10 hover:bg-on-surface/10 text-on-surface-variant transition-all cursor-pointer select-none active:scale-95"
                      >
                        <PlusIcon class="w-3.5 h-3.5" />
                        <span>添加拓展属性</span>
                      </button>
                    </div>
                  </div>
                </div>
              </div>

              <!-- 右侧工具按钮 -->
              <div class="flex items-center space-x-1">
                <!-- 移动端：收纳为极其精致的“三点更多”操作浮窗 -->
                <template v-if="isMobile">
                  <div class="relative">
                    <button
                      @click.stop="showTopMoreMenu = !showTopMoreMenu"
                      class="p-1.5 rounded-lg hover:bg-surface-high/60 text-on-surface-variant hover:text-on-surface transition-all active:scale-95 flex items-center justify-center cursor-pointer"
                      title="更多操作"
                    >
                      <MoreHorizontalIcon class="w-5 h-5" />
                    </button>

                    <!-- 顶栏 Action 更多操作浮窗 (绝对定位) -->
                    <div
                      v-if="showTopMoreMenu"
                      @click.stop
                      class="absolute top-full right-0 mt-2 w-48 rounded-2xl border border-outline-variant bg-surface shadow-2xl p-2 flex flex-col space-y-1.5 z-30 animate-in fade-in slide-in-from-top-2 duration-150"
                    >
                      <!-- 快捷切换人设入口（仅在无消息且已绑定人设时可见，支持单聊与群聊） -->
                      <button
                        v-if="
                          currentChatBindingProfileId &&
                          chatMessages.length === 0 &&
                          (isGroupActive || (activeCharacter && activeCharacter.id !== 'character_creator_bot'))
                        "
                        @click="
                          openFirstChatConfig();
                          showTopMoreMenu = false;
                        "
                        class="flex items-center space-x-2.5 px-3 py-2 rounded-xl text-xs font-semibold text-on-surface-variant hover:text-primary hover:bg-primary/10 transition-all select-none w-full text-left"
                      >
                        <UserIcon class="w-4 h-4 text-primary" />
                        <span>切换扮演人设</span>
                      </button>

                      <!-- 聊天模式切换入口（普通角色及群聊均可见） -->
                      <button
                        v-if="isGroupActive || (activeCharacter && activeCharacter.id !== 'character_creator_bot')"
                        @click="
                          showChatModeModal = true;
                          showTopMoreMenu = false;
                        "
                        class="flex items-center space-x-2.5 px-3 py-2 rounded-xl text-xs font-semibold text-on-surface-variant hover:text-primary hover:bg-primary/10 transition-all select-none w-full text-left"
                      >
                        <MessageSquareHeartIcon class="w-4 h-4 text-primary" />
                        <span>聊天模式</span>
                        <span
                          class="ml-auto text-[9px] px-1.5 py-0.5 rounded-md bg-primary/10 text-primary font-bold"
                          >{{
                            currentChatMode === 'dialogue'
                              ? '仅对话'
                              : currentChatMode === 'descriptive'
                                ? '包含描写'
                                : '导演模式'
                          }}</span
                        >
                      </button>

                      <!-- AI小说写手入口（仅 descriptive 和 dialogue 模式可见） -->
                      <button
                        v-if="
                          activeCharacter &&
                          activeCharacter.id !== 'character_creator_bot' &&
                          (characterChatModeCache[activeCharacter.id] === 'dialogue' ||
                            characterChatModeCache[activeCharacter.id] === 'descriptive') &&
                          !isGroupActive
                        "
                        @click="
                          openNovelPanel();
                          showTopMoreMenu = false;
                        "
                        class="flex items-center space-x-2.5 px-3 py-2 rounded-xl text-xs font-semibold text-on-surface-variant hover:text-primary hover:bg-primary/10 transition-all select-none w-full text-left relative"
                      >
                        <BookIcon class="w-4 h-4 text-primary" />
                        <span>AI写手</span>
                      </button>

                      <button
                        v-if="activeCharacter && activeCharacter.id !== 'character_creator_bot'"
                        @click="
                          triggerDreamReflection();
                          showTopMoreMenu = false;
                        "
                        class="flex items-center space-x-2.5 px-3 py-2 rounded-xl text-xs font-semibold text-on-surface-variant hover:text-indigo-500 hover:bg-indigo-500/10 transition-all select-none w-full text-left"
                      >
                        <MoonIcon class="w-4 h-4 text-indigo-500" />
                        <span>睡眠自省进化</span>
                      </button>
                      <button
                        v-if="activeCharacter && activeCharacter.id !== 'character_creator_bot'"
                        @click="
                          openBrainPanel();
                          showTopMoreMenu = false;
                        "
                        class="flex items-center space-x-2.5 px-3 py-2 rounded-xl text-xs font-semibold text-on-surface-variant hover:text-on-surface hover:bg-on-surface/5 transition-all select-none w-full text-left"
                      >
                        <BrainIcon class="w-4 h-4 text-primary" />
                        <span>查看并编辑记忆</span>
                      </button>
                      <button
                        v-if="activeCharacter && activeCharacter.id !== 'character_creator_bot'"
                        @click="
                          openDiaryPanel();
                          showTopMoreMenu = false;
                        "
                        class="flex items-center space-x-2.5 px-3 py-2 rounded-xl text-xs font-semibold text-on-surface-variant hover:text-on-surface hover:bg-on-surface/5 transition-all select-none w-full text-left"
                      >
                        <FileLockIcon class="w-4 h-4 text-green-500" />
                        <span>查看角色日记</span>
                      </button>
                      <button
                        v-if="isGroupActive"
                        @click="
                          openGroupBrainPanel();
                          showTopMoreMenu = false;
                        "
                        class="flex items-center space-x-2.5 px-3 py-2 rounded-xl text-xs font-semibold text-on-surface-variant hover:text-on-surface hover:bg-on-surface/5 transition-all select-none w-full text-left"
                      >
                        <BrainIcon class="w-4 h-4 text-primary" />
                        <span>查看并编辑群记忆</span>
                      </button>
                      <button
                        @click="
                          triggerCleanChoice();
                          showTopMoreMenu = false;
                        "
                        class="flex items-center space-x-2.5 px-3 py-2 rounded-xl text-xs font-semibold text-red-500 hover:bg-red-500/10 transition-all select-none w-full text-left"
                      >
                        <TrashIcon class="w-4 h-4 text-red-500" />
                        <span>清除会话与记忆</span>
                      </button>
                    </div>
                  </div>
                </template>

                <!-- PC 端：维持原本平铺的一排精美小图标，高容错 -->
                <template v-else>
                  <!-- 聊天模式切换按钮 -->
                  <button
                    v-if="isGroupActive || (activeCharacter && activeCharacter.id !== 'character_creator_bot')"
                    @click="showChatModeModal = true"
                    class="p-1.5 rounded-lg hover:bg-primary/10 text-on-surface-variant hover:text-primary transition-all"
                    title="聊天模式切换"
                  >
                    <MessageSquareHeartIcon class="w-4 h-4" stroke-width="1.5" />
                  </button>

                  <!-- AI小说写手按钮 -->
                  <button
                    v-if="
                      activeCharacter &&
                      activeCharacter.id !== 'character_creator_bot' &&
                      (characterChatModeCache[activeCharacter.id] === 'dialogue' ||
                        characterChatModeCache[activeCharacter.id] === 'descriptive') &&
                      !isGroupActive
                    "
                    @click="openNovelPanel"
                    class="p-1.5 rounded-lg hover:bg-surface-high/60 text-on-surface-variant hover:text-primary transition-all relative flex items-center justify-center cursor-pointer select-none"
                    title="AI写手"
                  >
                    <BookIcon class="w-4 h-4" stroke-width="1.5" />
                  </button>

                  <!-- 梦境图标：手动触发角色睡眠反思进化 -->
                  <button
                    v-if="activeCharacter && activeCharacter.id !== 'character_creator_bot'"
                    @click="triggerDreamReflection"
                    class="p-1.5 rounded-lg hover:bg-surface-high/60 text-on-surface-variant hover:text-indigo-500 transition-all"
                    :class="{ 'animate-pulse text-indigo-500 bg-indigo-500/10': isDreaming }"
                    title="手动唤醒做梦进化（睡眠自省）"
                  >
                    <MoonIcon class="w-4 h-4" stroke-width="1.5" />
                  </button>

                  <!-- 大脑图标：查看/编辑角色记忆文件 -->
                  <button
                    v-if="activeCharacter && activeCharacter.id !== 'character_creator_bot'"
                    @click="openBrainPanel"
                    class="p-1.5 rounded-lg hover:bg-surface-high/60 text-on-surface-variant hover:text-on-surface transition-all"
                    title="查看并编辑角色记忆"
                  >
                    <BrainIcon class="w-4 h-4" stroke-width="1.5" />
                  </button>

                  <!-- 日记图标：查看角色日记 -->
                  <button
                    v-if="activeCharacter && activeCharacter.id !== 'character_creator_bot'"
                    @click="openDiaryPanel"
                    class="p-1.5 rounded-lg hover:bg-surface-high/60 text-on-surface-variant hover:text-on-surface transition-all"
                    title="查看角色日记"
                  >
                    <FileLockIcon class="w-4 h-4" stroke-width="1.5" />
                  </button>

                  <!-- 大脑图标：查看/编辑群聊记忆与大事记 (仅群聊模式可见) -->
                  <button
                    v-if="isGroupActive"
                    @click="openGroupBrainPanel"
                    class="p-1.5 rounded-lg hover:bg-surface-high/60 text-on-surface-variant hover:text-on-surface transition-all mr-0.5"
                    title="查看并编辑群聊记忆与大事记"
                  >
                    <BrainIcon class="w-4 h-4" stroke-width="1.5" />
                  </button>

                  <!-- 扫帚图标：清除会话与记忆 / 创角Bot重置 -->
                  <button
                    id="brush-cleaning"
                    @click="triggerCleanChoice"
                    class="brush-cleaning p-1.5 rounded-lg hover:bg-surface-high/60 text-on-surface-variant hover:text-red-500 transition-all active:scale-95 flex items-center justify-center"
                    :title="
                      activeCharacter && activeCharacter.id === 'character_creator_bot'
                        ? '重置并重新创角'
                        : '清除会话与记忆'
                    "
                  >
                    <svg
                      class="brush-cleaning w-4 h-4"
                      xmlns="http://www.w3.org/2000/svg"
                      viewBox="0 0 24 24"
                      fill="none"
                      stroke="currentColor"
                      stroke-width="1.5"
                      stroke-linecap="round"
                      stroke-linejoin="round"
                    >
                      <path d="m16 22-1-4" />
                      <path
                        d="M19 14a1 1 0 0 0 1-1v-1a2 2 0 0 0-2-2h-3a1 1 0 0 1-1-1V4a2 2 0 0 0-4 0v5a1 1 0 0 1-1 1H6a2 2 0 0 0-2 2v1a1 1 0 0 0 1 1"
                      />
                      <path d="M19 14H5l-1.973 6.767A1 1 0 0 0 4 22h16a1 1 0 0 0 .973-1.233z" />
                      <path d="m8 22 1-4" />
                    </svg>
                  </button>
                </template>
              </div>
            </header>

            <!-- 性格成长演化横幅 -->
            <div
              v-if="activeEvolutionDraft && activeEvolutionCharId === activeCharacter?.id"
              class="mx-5 mt-4 p-4 rounded-2xl bg-primary/10 backdrop-blur border border-primary/20 flex items-center justify-between shadow-sm animate-pulse select-none flex-shrink-0"
            >
              <div class="flex items-center space-x-3.5">
                <div
                  class="w-8 h-8 rounded-full bg-primary/20 flex items-center justify-center text-primary flex-shrink-0"
                >
                  <SparklesIcon class="w-4 h-4" />
                </div>
                <div>
                  <h4 class="text-xs font-bold text-on-surface">🌱 {{ activeCharacter.name }} 似乎在悄悄成长...</h4>
                  <p class="text-[10px] text-on-surface-variant/80 mt-0.5">
                    检测到核心性格人设发生了自然演化，需要您的确认批准。
                  </p>
                </div>
              </div>
              <button
                @click="showEvolutionModal = true"
                class="px-3.5 py-1.5 rounded-xl bg-primary hover:bg-primary-high text-[10px] font-bold text-white shadow transition-all cursor-pointer select-none"
              >
                查看详情
              </button>
            </div>

            <!-- 聊天气泡主容器（相对定位挂载回底悬浮按钮） -->
            <div class="flex-1 min-h-0 flex flex-col relative">
              <!-- 🗂️ 批量删除后的记忆提醒横幅 -->
              <div
                v-if="showMemoryWarningBanner"
                class="mx-5 mt-3 mb-1 px-4 py-3 rounded-2xl bg-amber-500/10 border border-amber-500/25 flex items-center justify-between gap-3 animate-in slide-in-from-top-2 duration-300 flex-shrink-0 select-none"
              >
                <div class="flex items-center space-x-3 flex-1 min-w-0">
                  <div class="w-7 h-7 rounded-full bg-amber-500/15 flex items-center justify-center flex-shrink-0">
                    <span class="text-sm">🧠</span>
                  </div>
                  <p class="text-[11px] text-amber-700 dark:text-amber-400 font-semibold leading-snug">
                    旧记忆可能仍在影响 AI 回复，建议手动编辑记忆文件清除相关内容。
                  </p>
                </div>
                <button
                  @click="showMemoryWarningBanner = false"
                  class="flex-shrink-0 w-5 h-5 rounded-full text-amber-600/60 hover:text-amber-600 hover:bg-amber-500/10 transition-colors flex items-center justify-center cursor-pointer"
                >
                  <XIcon class="w-3.5 h-3.5" />
                </button>
              </div>

              <!-- 聊天气泡区 -->
              <div
                ref="chatContainer"
                class="w-full h-full overflow-y-auto px-5 py-4 flex flex-col space-y-3 select-text"
                @scroll.passive="handleChatScroll"
                @click="activeInnerThoughtMsgId = null"
              >
                <!-- 初始空白（不显示开场白） -->
                <div
                  v-if="chatMessages.length === 0"
                  class="flex flex-col items-center justify-center h-full text-center"
                >
                  <div
                    class="w-14 h-14 rounded overflow-hidden border border-on-surface/5 bg-surface mb-3 shadow-md flex items-center justify-center"
                  >
                    <template v-if="isGroupActive">
                      <img
                        v-if="selectedCharacterId && groupAvatars[selectedCharacterId]"
                        :src="groupAvatars[selectedCharacterId]"
                        class="w-full h-full object-cover"
                      />
                      <UserIcon v-else class="w-7 h-7 text-on-surface-variant m-auto" />
                    </template>
                    <template v-else-if="activeCharacter">
                      <template v-if="activeCharacter.id === 'character_creator_bot'">
                        <img :src="creatorBotAvatarUrl" class="w-full h-full object-cover" />
                      </template>
                      <template v-else>
                        <img
                          v-if="characterAvatars[activeCharacter.id]"
                          :src="characterAvatars[activeCharacter.id]"
                          class="w-full h-full object-cover"
                        />
                      </template>
                    </template>
                  </div>
                  <p class="text-sm font-semibold text-on-surface">
                    {{ isGroupActive ? activeGroupChat?.name : activeCharacter?.name }}
                  </p>
                  <p class="text-xs text-on-surface-variant/50 mt-1">发送消息开始对话</p>
                  <div class="mt-4 space-y-1 text-xs text-primary font-bold">
                    <p>请点击右上角设置对话模式</p>
                    <p>如果需要，请手动在右上角开启AI写手</p>
                  </div>
                </div>

                <!-- 弹性垫片：当消息少时，强力拉伸将气泡顶到最底部；当消息多时自适应压缩归零，绝不影响滚动！ -->
                <div v-if="chatMessages.length > 0" class="flex-grow min-h-0 flex-shrink-0"></div>

                <!-- 消息列表 -->
                <template v-for="(msg, idx) in chatMessages" :key="idx">
                  <!-- 自适应微信时间戳 -->
                  <div
                    v-if="shouldShowTime(msg, chatMessages[idx - 1])"
                    class="flex justify-center my-3 select-none flex-shrink-0"
                  >
                    <span
                      class="text-[10px] bg-on-surface-variant/5 text-on-surface-variant/40 px-2.5 py-0.5 rounded-full tracking-wide font-medium"
                    >
                      {{ formatMessageTime(msg.created_at) }}
                    </span>
                  </div>
                  <!-- 系统气泡 -->
                  <div v-if="msg.isSystem" class="flex justify-center py-1">
                    <div
                      class="px-3 py-1.5 rounded-full border border-outline-variant/30 bg-surface-low text-[10px] text-on-surface-variant flex items-center space-x-1.5 max-w-[85%]"
                    >
                      <CpuIcon class="w-3 h-3 flex-shrink-0 text-secondary" />
                      <span class="font-mono leading-relaxed">{{ msg.content }}</span>
                    </div>
                  </div>

                  <!-- 用户消息（右侧） -->
                  <div
                    v-else-if="msg.role === 'user'"
                    class="flex justify-end items-start space-x-2 relative select-none"
                    style="touch-action: manipulation"
                    :class="isMultiSelectMode ? 'cursor-pointer' : ''"
                    @click="isMultiSelectMode && msg.id ? toggleMessageSelect(msg.id) : undefined"
                  >
                    <!-- 多选复选框（右侧，用户消息） -->
                    <div
                      v-if="isMultiSelectMode && msg.id"
                      class="flex-shrink-0 self-start mt-1 mr-1 w-5 h-5 rounded-full border-2 flex items-center justify-center transition-all"
                      :class="
                        selectedMessageIds.has(msg.id)
                          ? 'bg-primary border-primary'
                          : 'border-outline-variant bg-surface'
                      "
                    >
                      <CheckIcon v-if="selectedMessageIds.has(msg.id)" class="w-3 h-3 text-white" stroke-width="3" />
                    </div>
                    <div class="max-w-[68%] flex flex-col items-end">
                      <!-- 图片气泡 -->
                      <div
                        v-if="msg.imageBase64"
                        class="mb-1 w-fit rounded-xl overflow-hidden border border-primary/20 shadow-sm transition-opacity"
                        :class="isMultiSelectMode ? 'cursor-pointer' : 'cursor-pointer hover:opacity-95'"
                        @click.stop="
                          isMultiSelectMode && msg.id
                            ? toggleMessageSelect(msg.id)
                            : openImagePreview({
                                id: msg.id,
                                round_id: msg.round_id,
                                base64: msg.imageBase64,
                                filename: msg.imageMeta?.filename || 'user_drawing.png',
                                relativePath: msg.imageMeta?.relativePath || '',
                                prompt: msg.imageMeta?.prompt || '',
                                negativePrompt: msg.imageMeta?.negativePrompt || '',
                                createdAt: msg.imageMeta?.createdAt || msg.timestamp || Date.now(),
                                dimensions: msg.imageMeta?.dimensions || 'portrait',
                                prefixType: msg.imageMeta?.prefixType || 'chat',
                                characterId: selectedCharacterId || '',
                              })
                        "
                        @contextmenu.prevent="openMessageContextMenu($event, msg)"
                        @touchstart="onLongPressStart($event, msg, 'message')"
                        @touchend="onLongPressEnd"
                        @touchmove="onLongPressMove"
                      >
                        <!-- pointer-events:none 让触摸事件穿透到父容器，-webkit-touch-callout:none 屏蔽 iOS/安卓 原生长按图片上拉菜单 -->
                        <img
                          :src="msg.imageBase64"
                          class="max-w-full max-h-48 object-contain select-none pointer-events-none"
                          style="-webkit-touch-callout: none; -webkit-user-drag: none"
                          @load="scrollToBottom('auto', false)"
                        />
                      </div>

                      <!-- 自定义表情包大图气泡 -->
                      <div
                        v-if="msg.customEmojiUrl"
                        class="mb-1 max-w-[88px] max-h-[88px] rounded-xl overflow-hidden p-1 flex items-center justify-center select-none bg-transparent hover:scale-105 active:scale-95 transition-all cursor-pointer"
                        @contextmenu.prevent="openMessageContextMenu($event, msg)"
                        @touchstart="onLongPressStart($event, msg, 'message')"
                        @touchend="onLongPressEnd"
                        @touchmove="onLongPressMove"
                      >
                        <img
                          :src="msg.customEmojiUrl"
                          class="w-full h-full object-contain select-none pointer-events-none"
                        />
                      </div>

                      <!-- 高颜值微信红包封面卡片 -->
                      <div
                        v-if="msg.redPacket"
                        class="wechat-red-packet-card mb-1 rounded-lg overflow-hidden shadow-md hover:shadow-lg transition-all hover:scale-[1.01] cursor-pointer select-none"
                        @contextmenu.prevent="openMessageContextMenu($event, msg)"
                        @touchstart="onLongPressStart($event, msg, 'message')"
                        @touchend="onLongPressEnd"
                        @touchmove="onLongPressMove"
                      >
                        <!-- A. 等待领取状态 (waiting) -->
                        <template v-if="!msg.redPacket.status || msg.redPacket.status === 'waiting'">
                          <!-- 上半部分：红橙渐变 (专属红包金色丝边) -->
                          <div
                            class="p-3.5 text-white flex items-center space-x-3.5 min-w-[210px] border-b border-white/5"
                            :class="
                              msg.redPacket.targetId
                                ? 'bg-gradient-to-br from-[#e0523f] via-[#da3f2d] to-[#b32b1c] border-2 border-yellow-400/20'
                                : 'bg-gradient-to-br from-[#f25542] to-[#da3f2d]'
                            "
                          >
                            <!-- 金色圆形容器包🧧 -->
                            <div
                              class="w-10 h-10 rounded-full bg-[#fcedc4]/15 flex items-center justify-center flex-shrink-0 border border-[#fcedc4]/20 shadow-sm relative"
                            >
                              <span class="text-xl">🧧</span>
                              <span
                                v-if="msg.redPacket.targetId"
                                class="absolute -top-0.5 -right-0.5 text-[8px] bg-yellow-400 text-stone-900 px-0.5 rounded font-black scale-75 origin-top-right"
                                >专</span
                              >
                            </div>
                            <div class="flex-1 min-w-0">
                              <div
                                class="text-xs font-bold truncate text-[#fcedc4] leading-normal flex items-center space-x-1"
                              >
                                <span
                                  v-if="msg.redPacket.targetId"
                                  class="text-[9px] px-1 py-0.2 bg-yellow-400 text-stone-900 rounded font-black scale-90 origin-left flex-shrink-0"
                                  >专属</span
                                >
                                <span class="truncate">{{ msg.redPacket.title || '恭喜发财，大吉大利' }}</span>
                              </div>
                              <div class="text-[10px] opacity-90 mt-0.5 text-white/90">
                                <span v-if="msg.redPacket.targetId">专属成员：{{ msg.redPacket.targetName }}</span>
                                <span v-else>金额：{{ parseFloat(msg.redPacket.amount).toFixed(2) }} 元</span>
                              </div>
                            </div>
                          </div>
                          <!-- 下半部分：深红细底条 -->
                          <div
                            class="px-3.5 py-1.5 bg-[#cf3c2a] text-[#fcedc4]/70 text-[9px] flex items-center justify-between border-t border-white/5 font-medium"
                          >
                            <span>{{ msg.redPacket.targetId ? '专属红包' : '普通群红包' }}</span>
                            <span class="opacity-80 flex items-center space-x-1">
                              <span class="w-1.5 h-1.5 rounded-full bg-yellow-400 animate-pulse"></span>
                              <span>{{
                                msg.redPacket.targetId ? `等待 ${msg.redPacket.targetName} 领取...` : '等待对方领取...'
                              }}</span>
                            </span>
                          </div>
                        </template>

                        <!-- B. 已拆开 / 已领取状态 (received) -->
                        <template v-else-if="msg.redPacket.status === 'received'">
                          <!-- 上半部分：淡红橙半透明 -->
                          <div
                            class="p-3.5 bg-gradient-to-br from-[#f25542]/55 to-[#da3f2d]/55 text-white/60 flex items-center space-x-3.5 min-w-[210px] border-b border-white/5"
                          >
                            <!-- 已拆开红包的信封微标 -->
                            <div
                              class="w-10 h-10 rounded-full bg-[#fcedc4]/10 flex items-center justify-center flex-shrink-0 border border-[#fcedc4]/10"
                            >
                              <span class="text-lg opacity-60">✉️</span>
                            </div>
                            <div class="flex-1 min-w-0">
                              <div class="text-xs font-bold truncate text-[#fcedc4]/70 leading-normal">
                                {{ msg.redPacket.title || '恭喜发财，大吉大利' }}
                              </div>
                              <div class="text-[10px] opacity-75 mt-0.5">
                                金额：{{ parseFloat(msg.redPacket.amount).toFixed(2) }} 元
                                <span v-if="msg.redPacket.targetId">({{ msg.redPacket.targetName }}已拆开)</span>
                                <span v-else>(已拆开)</span>
                              </div>
                            </div>
                          </div>
                          <!-- 下半部分：淡红细底条 -->
                          <div
                            class="px-3.5 py-1.5 bg-[#cf3c2a]/60 text-[#fcedc4]/50 text-[9px] flex items-center justify-between border-t border-white/5 font-medium"
                          >
                            <span>{{ msg.redPacket.targetId ? '专属红包' : '普通红包' }}</span>
                            <span>已被拆开领用</span>
                          </div>
                        </template>

                        <!-- C. 已退回状态 (returned) -->
                        <template v-else-if="msg.redPacket.status === 'returned'">
                          <!-- 上半部分：深灰色半透明 -->
                          <div
                            class="p-3.5 bg-gradient-to-br from-gray-500/65 to-gray-600/65 text-white/60 flex items-center space-x-3.5 min-w-[210px] border-b border-white/5"
                          >
                            <!-- 已退回红包的微标 -->
                            <div
                              class="w-10 h-10 rounded-full bg-white/10 flex items-center justify-center flex-shrink-0 border border-white/15"
                            >
                              <span class="text-lg opacity-60">↩️</span>
                            </div>
                            <div class="flex-1 min-w-0">
                              <div class="text-xs font-bold truncate text-white/50 leading-normal line-through">
                                {{ msg.redPacket.title || '恭喜发财，大吉大利' }}
                              </div>
                              <div class="text-[10px] opacity-75 mt-0.5">
                                金额：{{ parseFloat(msg.redPacket.amount).toFixed(2) }} 元
                                <span v-if="msg.redPacket.targetId">({{ msg.redPacket.targetName }}已拒收)</span>
                                <span v-else>(已退回)</span>
                              </div>
                            </div>
                          </div>
                          <!-- 下半部分：深灰细底条 -->
                          <div
                            class="px-3.5 py-1.5 bg-gray-700/80 text-white/50 text-[9px] flex items-center justify-between border-t border-white/5 font-medium"
                          >
                            <span>{{ msg.redPacket.targetId ? '专属红包' : '普通红包' }}</span>
                            <span>已被拒收并退款</span>
                          </div>
                        </template>
                      </div>

                      <!-- 转账气泡 (向后兼容) -->
                      <div v-if="msg.transfer" class="wechat-transfer-bubble user-bubble mb-1">
                        <BanknoteIcon class="w-5 h-5 text-green-300 flex-shrink-0" />
                        <div>
                          <div class="text-xs font-bold">转账</div>
                          <div class="text-[10px] opacity-80">金额：{{ msg.transfer.amount }} 元</div>
                        </div>
                      </div>

                      <!-- 文字气泡 (有图片、自定义表情或红包时不在下方重复渲染绿色气泡) -->
                      <div
                        v-if="msg.content && !msg.redPacket && !msg.transfer && !msg.customEmojiUrl"
                        class="user-chat-bubble markdown-body"
                        :class="{ 'emoji-only-bubble': isEmojiOnly(msg.content) }"
                        v-html="renderMarkdown(cleanUserContentForUI(msg.content))"
                        @contextmenu.prevent="openMessageContextMenu($event, msg)"
                        @touchstart="onLongPressStart($event, msg, 'message')"
                        @touchend="onLongPressEnd"
                        @touchmove="onLongPressMove"
                      ></div>
                    </div>
                    <!-- 用户头像方形圆角化 -->
                    <div
                      class="w-8 h-8 rounded overflow-hidden border border-on-surface/5 bg-surface-low flex-shrink-0 flex items-center justify-center shadow-sm"
                    >
                      <img
                        :src="currentUserChatAvatar"
                        class="w-full h-full object-cover pointer-events-none select-none"
                        style="-webkit-touch-callout: none"
                      />
                    </div>
                  </div>

                  <!-- AI 消息（左侧） -->
                  <div
                    v-else-if="msg.role === 'assistant'"
                    class="flex items-start space-x-2 relative select-none"
                    style="touch-action: manipulation"
                    :class="isMultiSelectMode ? 'cursor-pointer' : ''"
                    @click="isMultiSelectMode && msg.id ? toggleMessageSelect(msg.id) : undefined"
                  >
                    <!-- 多选复选框（左侧，AI消息） -->
                    <div
                      v-if="isMultiSelectMode && msg.id"
                      class="flex-shrink-0 self-start mt-1 w-5 h-5 rounded-full border-2 flex items-center justify-center transition-all order-first"
                      :class="
                        selectedMessageIds.has(msg.id)
                          ? 'bg-primary border-primary'
                          : 'border-outline-variant bg-surface'
                      "
                    >
                      <CheckIcon v-if="selectedMessageIds.has(msg.id)" class="w-3 h-3 text-white" stroke-width="3" />
                    </div>
                    <!-- AI角色头像方形圆角化 -->
                    <div
                      class="w-8 h-8 rounded overflow-hidden border border-on-surface/5 bg-surface flex-shrink-0 flex items-center justify-center shadow-sm"
                    >
                      <template
                        v-if="
                          msg.sender_id === 'character_creator_bot' ||
                          (activeCharacter && activeCharacter.id === 'character_creator_bot' && msg.role !== 'user')
                        "
                      >
                        <img
                          :src="creatorBotAvatarUrl"
                          class="w-full h-full object-cover pointer-events-none select-none"
                          style="-webkit-touch-callout: none"
                        />
                      </template>
                      <template v-else>
                        <img
                          v-if="msg.sender_id && characterAvatars[msg.sender_id as string]"
                          :src="characterAvatars[msg.sender_id as string]"
                          class="w-full h-full object-cover pointer-events-none select-none"
                          style="-webkit-touch-callout: none"
                        />
                        <img
                          v-else-if="activeCharacter && characterAvatars[activeCharacter.id]"
                          :src="characterAvatars[activeCharacter.id]"
                          class="w-full h-full object-cover pointer-events-none select-none"
                          style="-webkit-touch-callout: none"
                        />
                        <div v-else class="w-full h-full flex items-center justify-center bg-gray-200">
                          <UserIcon class="w-4 h-4 text-gray-400" />
                        </div>
                      </template>
                    </div>
                    <div class="max-w-[68%]">
                      <!-- 群聊下在消息上方展示 AI 发言人姓名 -->
                      <div
                        v-if="isGroupActive && msg.sender_id && msg.sender_id !== 'user'"
                        class="text-[10px] text-on-surface-variant/50 mb-1 ml-1 font-bold"
                      >
                        {{ getSenderInfo(msg.sender_id).name }}
                      </div>
                      <!-- 图片气泡 -->
                      <div
                        v-if="msg.imageBase64"
                        class="mb-1 w-fit rounded-xl overflow-hidden border border-primary/20 shadow-sm transition-opacity"
                        :class="isMultiSelectMode ? 'cursor-pointer' : 'cursor-pointer hover:opacity-95'"
                        @click.stop="
                          isMultiSelectMode && msg.id
                            ? toggleMessageSelect(msg.id)
                            : openImagePreview({
                                id: msg.id,
                                round_id: msg.round_id,
                                base64: msg.imageBase64,
                                filename: msg.imageMeta?.filename || 'ai_drawing.png',
                                relativePath: msg.imageMeta?.relativePath || '',
                                prompt: msg.imageMeta?.prompt || '',
                                negativePrompt: msg.imageMeta?.negativePrompt || '',
                                createdAt: msg.imageMeta?.createdAt || msg.timestamp || Date.now(),
                                dimensions: msg.imageMeta?.dimensions || 'portrait',
                                prefixType: msg.imageMeta?.prefixType || 'chat',
                                characterId: selectedCharacterId || '',
                              })
                        "
                        @contextmenu.prevent="openMessageContextMenu($event, msg)"
                        @touchstart="onLongPressStart($event, msg, 'message')"
                        @touchend="onLongPressEnd"
                        @touchmove="onLongPressMove"
                      >
                        <!-- pointer-events:none 让触摸事件穿透到父容器，-webkit-touch-callout:none 屏蔽 iOS/安卣 原生长按图片上拉菜单 -->
                        <img
                          :src="msg.imageBase64"
                          class="max-w-full max-h-48 object-contain select-none pointer-events-none"
                          style="-webkit-touch-callout: none; -webkit-user-drag: none"
                          @load="scrollToBottom('auto', false)"
                        />
                      </div>

                      <!-- 自定义表情包大图气泡 -->
                      <div
                        v-if="msg.customEmojiUrl"
                        class="mb-1 max-w-[88px] max-h-[88px] rounded-xl overflow-hidden p-1 flex items-center justify-center select-none bg-transparent hover:scale-105 active:scale-95 transition-all cursor-pointer"
                        @contextmenu.prevent="openMessageContextMenu($event, msg)"
                        @touchstart="onLongPressStart($event, msg, 'message')"
                        @touchend="onLongPressEnd"
                        @touchmove="onLongPressMove"
                      >
                        <img
                          :src="msg.customEmojiUrl"
                          class="w-full h-full object-contain select-none pointer-events-none"
                        />
                      </div>

                      <!-- 典雅日记手账本消息卡片 -->
                      <div
                        v-else-if="msg.diary"
                        class="diary-card-bubble p-4 rounded-2xl bg-gradient-to-br from-[#f8f5eb] to-[#f0ebde] border border-[#d6cdb4] shadow-md hover:shadow-lg transition-all hover:scale-[1.01] cursor-pointer select-none min-w-[240px] text-stone-800"
                        @click="openDiaryForCharacter(msg.character_id || activeCharacter?.id)"
                      >
                        <div class="flex items-center space-x-2.5 mb-2.5 pb-2 border-b border-[#e6deca]/60">
                          <div
                            class="w-8 h-8 rounded-full bg-[#8c7e63]/10 flex items-center justify-center flex-shrink-0 text-stone-700 shadow-inner"
                          >
                            <span>📓</span>
                          </div>
                          <div class="flex-1 min-w-0">
                            <div class="text-xs font-bold text-stone-800 truncate">
                              {{ msg.diary.characterName || activeCharacter?.name }} 的手账日记
                            </div>
                            <div class="text-[10px] text-stone-500/80 mt-0.5">{{ msg.diary.date }}</div>
                          </div>
                        </div>
                        <!-- 日记摘要 -->
                        <div class="text-xs text-stone-600 leading-relaxed italic mb-3 select-text line-clamp-3">
                          “ {{ msg.diary.excerpt }} ”
                        </div>
                        <!-- 引导点击查看按钮 -->
                        <div
                          class="flex items-center justify-between text-[10px] text-stone-500 font-bold bg-[#faf9f6]/80 px-2.5 py-1.5 rounded-lg border border-[#e6deca]/30"
                        >
                          <span>🔒 仅我可见的真实自省</span>
                          <span class="text-primary hover:underline flex items-center space-x-0.5">
                            <span>翻开看看</span>
                            <span>→</span>
                          </span>
                        </div>
                      </div>

                      <!-- 高颜值回音红包卡片 (角色发给用户) -->
                      <div
                        v-else-if="msg.redPacket"
                        class="wechat-red-packet-card mb-1 rounded-lg overflow-hidden shadow-md hover:shadow-lg transition-all hover:scale-[1.01] cursor-pointer select-none min-w-[210px]"
                        @click="handleReceiveCharacterRedPacket(msg)"
                        @contextmenu.prevent="openMessageContextMenu($event, msg)"
                        @touchstart="onLongPressStart($event, msg, 'message')"
                        @touchend="onLongPressEnd"
                        @touchmove="onLongPressMove"
                      >
                        <!-- A. 等待领取状态 (waiting) -->
                        <template v-if="!msg.redPacket.status || msg.redPacket.status === 'waiting'">
                          <!-- 上半部分：红橙渐变 -->
                          <div
                            class="p-3.5 bg-gradient-to-br from-[#f25542] to-[#da3f2d] text-white flex items-center space-x-3.5 border-b border-white/5"
                          >
                            <!-- 金色圆形容器包🧧 -->
                            <div
                              class="w-10 h-10 rounded-full bg-[#fcedc4]/15 flex items-center justify-center flex-shrink-0 border border-[#fcedc4]/20 shadow-sm"
                            >
                              <span class="text-xl">🧧</span>
                            </div>
                            <div class="flex-1 min-w-0">
                              <div class="text-xs font-bold truncate text-[#fcedc4] leading-normal">
                                {{ msg.redPacket.title || '恭喜发财，大吉大利' }}
                              </div>
                              <div class="text-[10px] mt-0.5 text-white/90">给你发了一个红包</div>
                            </div>
                          </div>
                          <!-- 下半部分：深红细底条 -->
                          <div
                            class="px-3.5 py-1.5 bg-[#cf3c2a] text-[#fcedc4]/70 text-[9px] flex items-center justify-between border-t border-white/5 font-medium"
                          >
                            <span>回音红包</span>
                            <span class="animate-pulse text-yellow-300 font-bold flex items-center space-x-1">
                              <span>点击拆开</span>
                              <span>🧧</span>
                            </span>
                          </div>
                        </template>

                        <!-- B. 已拆开 / 已领取状态 (received) -->
                        <template v-else>
                          <!-- 上半部分：淡红橙半透明 -->
                          <div
                            class="p-3.5 bg-gradient-to-br from-[#f25542]/55 to-[#da3f2d]/55 text-white/60 flex items-center space-x-3.5 border-b border-white/5"
                          >
                            <!-- 已拆开红包的信封微标 -->
                            <div
                              class="w-10 h-10 rounded-full bg-[#fcedc4]/10 flex items-center justify-center flex-shrink-0 border border-[#fcedc4]/10"
                            >
                              <span class="text-lg opacity-60">✉️</span>
                            </div>
                            <div class="flex-1 min-w-0">
                              <div class="text-xs font-bold truncate text-[#fcedc4]/70 leading-normal">
                                {{ msg.redPacket.title }}
                              </div>
                              <div class="text-[10px] opacity-75 mt-0.5">
                                已领取 {{ parseFloat(msg.redPacket.amount).toFixed(2) }} 元
                              </div>
                            </div>
                          </div>
                          <!-- 下半部分：淡红细底条 -->
                          <div
                            class="px-3.5 py-1.5 bg-[#cf3c2a]/60 text-[#fcedc4]/50 text-[9px] flex items-center justify-between border-t border-white/5 font-medium"
                          >
                            <span>回音红包</span>
                            <span>已存入零钱</span>
                          </div>
                        </template>
                      </div>

                      <!-- 常规文字气泡 -->
                      <div v-else-if="msg.content" class="relative w-fit">
                        <div
                          class="ai-chat-bubble relative"
                          :class="{
                            'emoji-only-bubble': isEmojiOnly(msg.content),
                            'border-red-500/30 bg-red-500/5 dark:bg-red-500/10 text-red-600 dark:text-red-400':
                              msg.isError,
                          }"
                          @contextmenu.prevent="openMessageContextMenu($event, msg)"
                          @touchstart="onLongPressStart($event, msg, 'message')"
                          @touchend="onLongPressEnd"
                          @touchmove="onLongPressMove"
                        >
                          <!-- 失败警告的小图标 -->
                          <div
                            v-if="msg.isError"
                            class="absolute -left-6 top-1/2 -translate-y-1/2 flex items-center justify-center w-5 h-5 rounded-full bg-red-500/10 text-red-500 border border-red-500/20"
                            title="连接超时，右键气泡可重新回复"
                          >
                            <AlertTriangleIcon class="w-3.5 h-3.5" />
                          </div>
                          <div class="markdown-body" v-html="renderMarkdown(msg.content)"></div>

                          <!-- 玻璃拟态角色心声悬浮窗 -->
                          <transition
                            enter-active-class="transition duration-200 ease-out"
                            enter-from-class="opacity-0 translate-y-2 scale-95"
                            enter-to-class="opacity-100 translate-y-0 scale-100"
                            leave-active-class="transition duration-150 ease-in"
                            leave-from-class="opacity-100 translate-y-0 scale-100"
                            leave-to-class="opacity-0 translate-y-2 scale-95"
                          >
                            <div
                              v-if="currentChatMode === 'dialogue' && msg.inner_thought && activeInnerThoughtMsgId === msg.id"
                              class="absolute z-10 bottom-full left-0 mb-2 w-64 p-3 rounded-xl border border-[#ffb6c1]/20 dark:border-[#ffb6c1]/10 bg-white/80 dark:bg-[#1f1619]/80 backdrop-blur-md shadow-lg text-[11px] leading-relaxed text-pink-700 dark:text-pink-300 font-medium select-text"
                            >
                              <div class="flex items-center space-x-1 text-[10px] text-pink-500 dark:text-pink-400 mb-1 font-bold select-none">
                                <ScanHeartIcon class="w-3.5 h-3.5 animate-pulse" />
                                <span>角色心声</span>
                              </div>
                              <p class="italic">“{{ msg.inner_thought }}”</p>
                              <!-- 装饰用小三角 -->
                              <div class="absolute top-full left-4 -mt-1 border-4 border-transparent border-t-white/80 dark:border-t-[#1f1619]/80"></div>
                            </div>
                          </transition>
                        </div>

                        <!-- 微型 ScanHeartIcon 图标 (显示在气泡外面，绝对定位到右侧，脱离文档流宽度，兼顾电脑与手机端安全展露) -->
                        <button
                          v-if="currentChatMode === 'dialogue' && msg.inner_thought"
                          class="absolute -right-6 top-1/2 -translate-y-1/2 w-5 h-5 rounded-full flex items-center justify-center text-pink-500 dark:text-pink-400 bg-pink-500/10 hover:bg-pink-500/20 active:scale-95 transition-all select-none"
                          title="查看角色心声"
                          @click.stop="toggleInnerThought(msg.id)"
                        >
                          <ScanHeartIcon class="w-3.5 h-3.5" />
                        </button>
                      </div>

                      <!-- Token 统计小字指标 -->
                      <div
                        v-if="
                          generalConfig.enable_token_stats &&
                          msg.prompt_tokens !== undefined &&
                          msg.prompt_tokens !== null &&
                          msg.prompt_tokens > 0
                        "
                        class="text-[9px] text-on-surface-variant/40 mt-1 pl-1 select-none font-mono leading-none flex items-center space-x-1"
                      >
                        <span>输入token: {{ msg.prompt_tokens }}</span>
                        <span>|</span>
                        <span>输出token: {{ msg.completion_tokens }}</span>
                        <template v-if="msg.cached_tokens !== undefined && msg.cached_tokens !== null">
                          <span>|</span>
                          <span
                            >缓存命中率:
                            {{
                              msg.prompt_tokens > 0 ? Math.round((msg.cached_tokens / msg.prompt_tokens) * 100) : 0
                            }}%</span
                          >
                        </template>
                      </div>
                    </div>
                  </div>
                </template>
              </div>

              <!-- 回底悬浮按钮 -->
              <transition name="fade">
                <button
                  v-if="showScrollToBottomBtn"
                  @click="scrollToBottom('smooth', true)"
                  class="absolute bottom-4 right-6 w-9 h-9 rounded-full bg-surface/90 hover:bg-surface-high/90 border border-outline-variant/60 flex items-center justify-center shadow-lg hover:shadow-xl transition-all duration-300 hover:scale-105 active:scale-95 text-primary backdrop-blur cursor-pointer z-20"
                  title="返回最新消息"
                >
                  <ChevronDownIcon class="w-5 h-5" stroke-width="2.5" />
                </button>
              </transition>
            </div>

            <!-- 🗂️ 多选删除工具栏（多选模式时替换底部输入区显示） -->
            <div
              v-if="isMultiSelectMode"
              class="border-t border-chat-border bg-surface flex-shrink-0 flex items-center justify-between px-5 py-3 select-none animate-in slide-in-from-bottom-2 duration-200 z-20"
            >
              <button
                @click="exitMultiSelect"
                class="px-4 py-2 rounded-xl text-xs font-bold text-on-surface-variant hover:bg-on-surface/5 transition-all border border-outline-variant/50 cursor-pointer active:scale-95"
              >
                取消
              </button>
              <span class="text-xs font-semibold text-on-surface-variant"> 已选 {{ selectedMessageIds.size }} 条 </span>
              <button
                @click="confirmBatchDelete"
                :disabled="selectedMessageIds.size === 0"
                class="px-4 py-2 rounded-xl text-xs font-bold text-white bg-error hover:bg-error/90 transition-all shadow-sm disabled:opacity-40 cursor-pointer active:scale-95 flex items-center space-x-1.5"
              >
                <TrashIcon class="w-3.5 h-3.5" />
                <span>删除{{ selectedMessageIds.size > 0 ? `（${selectedMessageIds.size}）` : '' }}</span>
              </button>
            </div>

            <!-- 底部输入区 -->
            <div
              :style="!isMobile ? { height: inputHeight + 'px' } : { height: 'auto' }"
              class="border-t border-chat-border bg-chat-input-bg flex-shrink-0 flex flex-col relative select-none w-full animate-fade-in"
              :class="isMobile ? 'px-3.5 py-2.5' : ''"
            >
              <!-- 首次聊天会话配置锁定遮罩 -->
              <div
                v-if="
                  selectedCharacterId &&
                  chatMessages.length === 0 &&
                  hasConfiguredFirstChatMap[selectedCharacterId] === false
                "
                class="absolute inset-0 bg-surface/75 backdrop-blur-md z-[60] flex items-center justify-center animate-fade-in p-4 border-t border-chat-border"
              >
                <div
                  class="flex items-center justify-between space-x-6 w-auto bg-surface-variant/40 backdrop-blur-xl border border-outline-variant/30 shadow-[0_12px_30px_rgba(0,0,0,0.04)] rounded-2xl p-4 px-5"
                >
                  <!-- 纯文本提示：仅一行简洁提示语 -->
                  <span class="text-xs font-bold text-on-surface select-none">首次聊天，请先配置会话以开启对话。</span>

                  <!-- 精致配置按钮 -->
                  <button
                    @click="openFirstChatConfig"
                    class="btn-primary !h-8 px-4 !rounded-xl text-[11px] font-extrabold flex-shrink-0 flex items-center justify-center transition-all cursor-pointer active:scale-95 shadow-sm shadow-primary/10"
                  >
                    配置会话
                  </button>
                </div>
              </div>
              <!-- 拖拽高度 handle (仅PC端可用) -->
              <div
                v-if="!isMobile"
                @mousedown="startInputResize"
                class="absolute top-0 left-0 right-0 h-[4px] hover:bg-primary cursor-row-resize transition-all z-30"
                title="拖动更改区域大小"
              ></div>

              <!-- 🚀 移动端：精简单行输入框 (同一行整合) -->
              <template v-if="isMobile">
                <div class="flex items-end space-x-2 w-full relative">
                  <!-- 最左侧：自适应 textarea 输入框 -->
                  <div class="relative flex-1 min-w-0">
                    <!-- @成员提及浮窗 (仅群聊且可见时) -->
                    <div
                      v-if="showAtMentionModal && filteredAtMentionMembers.length > 0"
                      class="absolute bottom-full left-0 mb-2 w-52 max-h-48 overflow-y-auto rounded-xl border border-outline-variant bg-surface shadow-2xl p-1.5 flex flex-col space-y-0.5 z-50 select-none animate-in fade-in slide-in-from-bottom-2 duration-150"
                    >
                      <div class="px-2.5 py-1 text-[9px] text-on-surface-variant/50 font-bold uppercase tracking-wider">
                        选择群成员进行提及
                      </div>
                      <button
                        v-for="(member, idx) in filteredAtMentionMembers"
                        :key="member.id"
                        @click="insertAtMention(member.name)"
                        @mouseenter="activeAtMentionSelectIndex = idx"
                        class="flex items-center space-x-2 px-2.5 py-1.5 rounded-lg text-xs font-semibold text-on-surface-variant hover:text-on-surface w-full text-left transition-all cursor-pointer"
                        :class="
                          activeAtMentionSelectIndex === idx ? 'bg-primary/10 text-primary hover:text-primary' : ''
                        "
                      >
                        <div class="w-5 h-5 rounded overflow-hidden border border-outline-variant/30 flex-shrink-0">
                          <img
                            v-if="characterAvatars[member.id]"
                            :src="characterAvatars[member.id]"
                            class="w-full h-full object-cover"
                          />
                          <UserIcon v-else class="w-3.5 h-3.5 text-on-surface-variant m-auto mt-0.5" />
                        </div>
                        <span class="truncate">{{ member.name }}</span>
                      </button>
                    </div>

                    <textarea
                      ref="chatTextarea"
                      v-model="chatInputText"
                      @keydown="handleKeyDown"
                      @paste="handlePaste"
                      @input="
                        e => {
                          adjustTextareaHeight(e);
                          handleInputAtMention(e);
                        }
                      "
                      @focus="handleTextareaFocus"
                      @blur="isInputFocused = false"
                      @compositionstart="handleCompositionStart"
                      @compositionend="handleCompositionEnd"
                      placeholder="发送消息..."
                      rows="1"
                      style="max-height: 120px"
                      class="w-full py-2 px-3 rounded-xl bg-surface text-on-surface text-sm focus:outline-none focus:ring-1 focus:ring-primary/20 border border-chat-input-border resize-none disabled:opacity-50 transition-all placeholder-on-surface-variant/30 leading-relaxed overflow-y-auto select-text shadow-inner"
                    ></textarea>

                    <!-- 粘贴图片预览 (绝对定位在输入框上方) -->
                    <div
                      v-if="pastedImageBase64"
                      class="absolute bottom-full left-0 mb-2.5 w-14 h-14 rounded-lg overflow-hidden border border-primary/30 shadow-md bg-surface z-10 animate-fade-in"
                    >
                      <img :src="pastedImageBase64" class="w-full h-full object-cover" />
                      <button
                        @click="pastedImageBase64 = ''"
                        class="absolute top-0.5 right-0.5 w-4 h-4 rounded-full bg-error text-white text-[10px] flex items-center justify-center hover:scale-110 transition-all"
                      >
                        ×
                      </button>
                    </div>
                  </div>

                  <!-- 🚀 右侧三大按钮紧凑组合区：恢复正常 w-9 尺寸，但保持 space-x-1 紧凑间距以节省空间 -->
                  <div class="flex items-center space-x-1 flex-shrink-0 mb-0.5">
                    <!-- 表情按钮 -->
                    <button
                      @click.stop="toggleEmojiPanel"
                      class="flex items-center justify-center w-9 h-9 rounded-xl hover:bg-surface-high/60 text-on-surface-variant hover:text-primary transition-all active:scale-95 cursor-pointer"
                      :class="{ 'text-primary bg-surface-high': showEmojiPanel }"
                      title="表情"
                    >
                      <SmileIcon class="w-5.5 h-5.5" />
                    </button>

                    <!-- 加号按钮 -->
                    <div class="relative">
                      <button
                        @click.stop="showMobilePlusMenu = !showMobilePlusMenu"
                        class="flex items-center justify-center w-9 h-9 rounded-xl hover:bg-surface-high/60 text-on-surface-variant hover:text-primary transition-all active:scale-95 cursor-pointer"
                        :class="{ 'text-primary bg-surface-high shadow-inner': showMobilePlusMenu }"
                        title="更多功能"
                      >
                        <PlusIcon class="w-5.5 h-5.5" />
                      </button>

                      <!-- 移动端加号功能浮窗 (绝对定位，点击红包、会话历史、生图) -->
                      <div
                        v-if="showMobilePlusMenu"
                        @click.stop
                        class="absolute bottom-full right-0 mb-3.5 w-40 rounded-2xl border border-outline-variant bg-surface shadow-2xl p-2.5 flex flex-col space-y-1.5 z-50 animate-in fade-in slide-in-from-bottom-2 duration-150"
                      >
                        <!-- 红包 -->
                        <button
                          @click="
                            openRedPacket();
                            showMobilePlusMenu = false;
                          "
                          class="flex items-center space-x-2.5 px-3 py-2 rounded-xl text-xs font-semibold text-on-surface-variant hover:text-red-500 hover:bg-red-500/10 transition-all w-full text-left"
                        >
                          <GiftIcon class="w-4 h-4 text-red-500" />
                          <span>发红包</span>
                        </button>

                        <!-- 会话历史 -->
                        <button
                          @click="
                            openChatHistoryModal();
                            showMobilePlusMenu = false;
                          "
                          class="flex items-center space-x-2.5 px-3 py-2 rounded-xl text-xs font-semibold text-on-surface-variant hover:text-primary hover:bg-primary/10 transition-all w-full text-left"
                        >
                          <HistoryIcon class="w-4 h-4 text-primary" />
                          <span>会话历史</span>
                        </button>

                        <!-- AI 绘图 -->
                        <button
                          v-if="!isGroupActive"
                          @click="
                            triggerChatImageGeneration();
                            showMobilePlusMenu = false;
                          "
                          :disabled="isAnalyzingPrompt || isDrawingImage"
                          class="flex items-center space-x-2.5 px-3 py-2 rounded-xl text-xs font-semibold text-on-surface-variant hover:text-indigo-500 hover:bg-indigo-500/10 transition-all w-full text-left disabled:opacity-50"
                        >
                          <Loader2Icon
                            v-if="isAnalyzingPrompt || isDrawingImage"
                            class="w-4 h-4 animate-spin text-indigo-500"
                          />
                          <ApertureIcon v-else class="w-4 h-4 text-indigo-500" />
                          <span>AI 绘图</span>
                        </button>

                        <!-- AI 吐槽大会 -->
                        <button
                          v-if="!isGroupActive"
                          @click="
                            toggleRoastPanel();
                            showMobilePlusMenu = false;
                          "
                          class="flex items-center space-x-2.5 px-3 py-2 rounded-xl text-xs font-semibold text-on-surface-variant hover:text-rose-500 hover:bg-rose-500/10 transition-all w-full text-left"
                        >
                          <MaskIcon class="w-4 h-4 text-rose-500" />
                          <span>AI 吐槽大会</span>
                        </button>
                      </div>
                    </div>

                    <!-- 最右侧：发送按钮 -->
                    <button
                      @pointerdown.prevent="sendChatMessage"
                      @click.prevent
                      :disabled="isCurrentCharStreaming || (!chatInputText.trim() && !pastedImageBase64)"
                      class="flex items-center justify-center w-9 h-9 rounded-xl bg-primary text-on-primary disabled:opacity-40 transition-all active:scale-95 cursor-pointer shadow-sm"
                      title="发送"
                    >
                      <Loader2Icon v-if="isCurrentCharStreaming" class="w-4 h-4 animate-spin" />
                      <SendIcon v-else class="w-4 h-4" />
                    </button>
                  </div>
                </div>

                <!-- 移动端 Emoji 悬浮面板 (绝对定位) -->
                <div
                  v-if="showEmojiPanel"
                  @click.stop
                  class="absolute bottom-full left-2 right-2 mb-3.5 z-40 p-3.5 flex flex-col h-[260px] justify-between animate-fade-in select-none bg-surface border border-outline-variant shadow-2xl rounded-2xl"
                >
                  <input
                    ref="emojiFileInput"
                    type="file"
                    accept="image/*"
                    class="hidden"
                    multiple
                    @change="handleEmojiFileSelect"
                  />

                  <!-- 默认表情 -->
                  <div
                    v-if="emojiActiveTab === 'default'"
                    class="flex flex-wrap gap-1.5 overflow-y-auto flex-1 select-none pr-1 py-1"
                  >
                    <button
                      v-for="emoji in emojiList"
                      :key="emoji"
                      class="w-7.5 h-7.5 flex items-center justify-center text-lg hover:scale-125 hover:bg-surface-high/60 rounded transition-all cursor-pointer"
                      @click="insertEmoji(emoji)"
                    >
                      {{ emoji }}
                    </button>
                  </div>

                  <!-- 自定义表情 -->
                  <div v-else class="flex flex-wrap gap-2.5 overflow-y-auto flex-1 select-none pr-1 py-1 min-h-0">
                    <button
                      @click="triggerEmojiUpload"
                      class="w-14 h-14 flex-shrink-0 rounded-lg border border-dashed border-outline-variant/60 hover:border-primary/50 flex items-center justify-center bg-surface hover:bg-primary/5 cursor-pointer active:scale-95 transition-all shadow-sm group"
                    >
                      <PlusIcon class="w-4 h-4 text-on-surface-variant/50 group-hover:text-primary transition-colors" />
                    </button>
                    <div
                      v-for="emoji in customEmojiList"
                      :key="emoji.id"
                      @click="sendCustomEmoji(emoji)"
                      class="w-14 h-14 flex-shrink-0 rounded-lg overflow-hidden flex items-center justify-center p-0.5 cursor-pointer hover:scale-105 active:scale-95 transition-all group relative"
                    >
                      <img :src="emoji.base64" class="w-full h-full object-contain select-none" />
                      <button
                        @click.stop="deleteCustomEmoji(emoji.id)"
                        class="absolute top-0.5 right-0.5 w-3.5 h-3.5 rounded-full bg-black/60 hover:bg-red-500 text-white text-[8px] flex items-center justify-center opacity-0 group-hover:opacity-100 transition-all shadow active:scale-90"
                      >
                        ×
                      </button>
                    </div>
                  </div>

                  <!-- 切换页签 -->
                  <div
                    class="flex items-center space-x-3 pt-2 border-t border-outline-variant/20 mt-1.5 flex-shrink-0 select-none"
                  >
                    <button
                      @click="emojiActiveTab = 'default'"
                      class="w-7.5 h-7.5 rounded-lg flex items-center justify-center transition-all cursor-pointer border shadow-sm"
                      :class="
                        emojiActiveTab === 'default'
                          ? 'bg-surface text-primary border-primary/20 scale-105 font-bold shadow'
                          : 'bg-surface-high/40 text-on-surface-variant hover:text-on-surface hover:bg-surface-high border-outline-variant/30'
                      "
                    >
                      <SmileIcon class="w-4 h-4" />
                    </button>
                    <button
                      @click="emojiActiveTab = 'favorites'"
                      class="w-7.5 h-7.5 rounded-lg flex items-center justify-center transition-all cursor-pointer border shadow-sm"
                      :class="
                        emojiActiveTab === 'favorites'
                          ? 'bg-surface text-[#ff4b72] border-[#ff4b72]/20 scale-105 font-bold shadow'
                          : 'bg-surface-high/40 text-on-surface-variant hover:text-on-surface hover:bg-surface-high border-outline-variant/30'
                      "
                    >
                      <HeartIcon class="w-4 h-4" />
                    </button>
                  </div>
                </div>
              </template>

              <!-- 💻 PC 端：原有的拖拽式双排工具栏输入区 -->
              <template v-else>
                <!-- 工具栏 (flex-shrink-0) -->
                <div class="px-4 pt-2.5 pb-1 flex items-center space-x-1 flex-shrink-0 w-full">
                  <!-- 表情 -->
                  <button
                    @click.stop="toggleEmojiPanel"
                    class="input-tool-btn"
                    :class="{ 'text-primary bg-surface-high': showEmojiPanel }"
                    title="表情"
                  >
                    <SmileIcon class="w-5 h-5" />
                  </button>

                  <!-- 红包 -->
                  <button
                    @click.stop="openRedPacket"
                    class="input-tool-btn hover:text-red-500 hover:scale-110 active:scale-95 transition-all duration-200"
                    title="发红包"
                  >
                    <GiftIcon class="w-5 h-5" />
                  </button>

                  <!-- 会话历史 -->
                  <button
                    @click.stop="openChatHistoryModal"
                    class="input-tool-btn"
                    :class="{ 'text-primary bg-surface-high': showChatHistoryModal }"
                    title="会话历史"
                  >
                    <HistoryIcon class="w-5 h-5" />
                  </button>

                  <!-- AI 绘图 -->
                  <button
                    v-if="!isGroupActive"
                    @click="triggerChatImageGeneration"
                    :disabled="isAnalyzingPrompt || isDrawingImage"
                    class="input-tool-btn disabled:opacity-50"
                    title="AI 绘图"
                  >
                    <Loader2Icon v-if="isAnalyzingPrompt || isDrawingImage" class="w-5 h-5 animate-spin" />
                    <ApertureIcon v-else class="w-5 h-5 transition-all duration-300" />
                  </button>

                  <!-- AI 吐槽大会 -->
                  <button
                    v-if="!isGroupActive"
                    @click="toggleRoastPanel"
                    class="input-tool-btn animate-fade-in"
                    :class="{ 'text-primary bg-surface-high': showRoastPanel }"
                    title="AI 吐槽大会"
                  >
                    <MaskIcon class="w-5 h-5 transition-all duration-300" />
                  </button>

                  <!-- 当前用户人设回显 (仅电脑端/宽屏显示，可在未开启对话时切换人设) -->
                  <div
                    v-if="
                      currentChatBindingProfileId &&
                      userProfilesList.find(p => p.profileId === currentChatBindingProfileId)?.name
                    "
                    style="margin-left: auto"
                    class="flex items-center select-none text-[11px] font-normal text-on-surface-variant/40"
                    title="当前会话您已绑定的用户人设 (无消息时支持切换，一旦开启会话不允许修改，以防剧情逻辑错乱)"
                  >
                    当前用户：{{ userProfilesList.find(p => p.profileId === currentChatBindingProfileId)?.name }}
                    <span
                      v-if="chatMessages.length === 0"
                      @click.stop="openFirstChatConfig()"
                      class="ml-1.5 text-primary hover:text-primary-hover cursor-pointer underline font-medium"
                    >
                      切换
                    </span>
                  </div>
                </div>

                <!-- Emoji 面板 (PC绝对定位浮窗) -->
                <div
                  v-if="showEmojiPanel"
                  @click.stop
                  class="absolute bottom-full left-4 right-4 mb-2.5 z-40 p-4 flex flex-col h-[280px] justify-between animate-fade-in select-none bg-surface border border-outline-variant shadow-2xl rounded-2xl"
                >
                  <input
                    ref="emojiFileInput"
                    type="file"
                    accept="image/*"
                    class="hidden"
                    multiple
                    @change="handleEmojiFileSelect"
                  />

                  <!-- A. 默认表情 -->
                  <div
                    v-if="emojiActiveTab === 'default'"
                    class="flex flex-wrap gap-2 overflow-y-auto flex-1 select-none pr-1 py-1"
                  >
                    <button
                      v-for="emoji in emojiList"
                      :key="emoji"
                      class="w-7 h-7 flex items-center justify-center text-xl hover:scale-125 hover:bg-surface-high/60 rounded transition-all cursor-pointer"
                      @click="insertEmoji(emoji)"
                    >
                      {{ emoji }}
                    </button>
                  </div>

                  <!-- B. 自定义表情 -->
                  <div v-else class="flex flex-wrap gap-2.5 overflow-y-auto flex-1 select-none pr-1 py-1 min-h-0">
                    <button
                      @click="triggerEmojiUpload"
                      class="w-14 h-14 flex-shrink-0 rounded-lg border border-dashed border-outline-variant/60 hover:border-primary/50 flex items-center justify-center bg-surface hover:bg-primary/5 cursor-pointer active:scale-95 transition-all shadow-sm group"
                      title="添加自定义表情"
                    >
                      <PlusIcon class="w-5 h-5 text-on-surface-variant/50 group-hover:text-primary transition-colors" />
                    </button>
                    <div
                      v-for="emoji in customEmojiList"
                      :key="emoji.id"
                      @click="sendCustomEmoji(emoji)"
                      class="w-14 h-14 flex-shrink-0 rounded-lg overflow-hidden flex items-center justify-center p-0.5 cursor-pointer hover:scale-105 active:scale-95 transition-all group relative"
                      :title="emoji.meaning"
                    >
                      <img :src="emoji.base64" class="w-full h-full object-contain select-none" />
                      <button
                        @click.stop="deleteCustomEmoji(emoji.id)"
                        class="absolute top-0.5 right-0.5 w-3.5 h-3.5 rounded-full bg-black/60 hover:bg-red-500 text-white text-[8px] flex items-center justify-center opacity-0 group-hover:opacity-100 transition-all shadow active:scale-90"
                        title="删除表情"
                      >
                        ×
                      </button>
                    </div>
                  </div>

                  <!-- 底部切换 Tab 页签 -->
                  <div
                    class="flex items-center space-x-3.5 pt-2.5 pb-1 border-t border-outline-variant/20 mt-2 flex-shrink-0 select-none"
                  >
                    <button
                      @click="emojiActiveTab = 'default'"
                      class="w-8 h-8 rounded-lg flex items-center justify-center transition-all cursor-pointer border shadow-sm"
                      :class="
                        emojiActiveTab === 'default'
                          ? 'bg-surface text-primary border-primary/20 scale-105 font-bold shadow'
                          : 'bg-surface-high/40 text-on-surface-variant hover:text-on-surface hover:bg-surface-high border-outline-variant/30'
                      "
                      title="默认表情"
                    >
                      <SmileIcon class="w-4 h-4" />
                    </button>
                    <button
                      @click="emojiActiveTab = 'favorites'"
                      class="w-8 h-8 rounded-lg flex items-center justify-center transition-all cursor-pointer border shadow-sm"
                      :class="
                        emojiActiveTab === 'favorites'
                          ? 'bg-surface text-[#ff4b72] border-[#ff4b72]/20 scale-105 font-bold shadow'
                          : 'bg-surface-high/40 text-on-surface-variant hover:text-on-surface hover:bg-surface-high border-outline-variant/30'
                      "
                      title="自定义表情"
                    >
                      <HeartIcon class="w-4 h-4" />
                    </button>
                  </div>
                </div>

                <!-- 文本输入框 (PC flex-grow) -->
                <div class="px-4 pt-1.5 pb-2.5 flex-1 flex flex-col min-h-0">
                  <div class="relative flex-1 flex flex-col min-h-0">
                    <!-- @成员提及浮窗 (仅群聊且可见时) -->
                    <div
                      v-if="showAtMentionModal && filteredAtMentionMembers.length > 0"
                      class="absolute bottom-full left-0 mb-2 w-52 max-h-48 overflow-y-auto rounded-xl border border-outline-variant bg-surface shadow-2xl p-1.5 flex flex-col space-y-0.5 z-50 select-none animate-in fade-in slide-in-from-bottom-2 duration-150"
                    >
                      <div class="px-2.5 py-1 text-[9px] text-on-surface-variant/50 font-bold uppercase tracking-wider">
                        选择群成员进行提及
                      </div>
                      <button
                        v-for="(member, idx) in filteredAtMentionMembers"
                        :key="member.id"
                        @click="insertAtMention(member.name)"
                        @mouseenter="activeAtMentionSelectIndex = idx"
                        class="flex items-center space-x-2 px-2.5 py-1.5 rounded-lg text-xs font-semibold text-on-surface-variant hover:text-on-surface w-full text-left transition-all cursor-pointer"
                        :class="
                          activeAtMentionSelectIndex === idx ? 'bg-primary/10 text-primary hover:text-primary' : ''
                        "
                      >
                        <div class="w-5 h-5 rounded overflow-hidden border border-outline-variant/30 flex-shrink-0">
                          <img
                            v-if="characterAvatars[member.id]"
                            :src="characterAvatars[member.id]"
                            class="w-full h-full object-cover"
                          />
                          <UserIcon v-else class="w-3.5 h-3.5 text-on-surface-variant m-auto mt-0.5" />
                        </div>
                        <span class="truncate">{{ member.name }}</span>
                      </button>
                    </div>

                    <textarea
                      ref="chatTextarea"
                      v-model="chatInputText"
                      @keydown="handleKeyDown"
                      @paste="handlePaste"
                      @focus="handleTextareaFocus"
                      @input="handleInputAtMention"
                      @compositionstart="handleCompositionStart"
                      @compositionend="handleCompositionEnd"
                      placeholder="发送消息... (Enter 发送，Shift+Enter 换行)"
                      class="w-full flex-1 py-2 rounded-xl bg-surface text-on-surface text-sm focus:outline-none focus:ring-1 focus:ring-primary/20 border border-chat-input-border resize-none disabled:opacity-50 transition-all placeholder-on-surface-variant/30 leading-relaxed overflow-y-auto select-text"
                      :class="pastedImageBase64 ? 'pl-20 pr-3' : 'px-3'"
                    ></textarea>
                    <!-- 粘贴图片预览 (居左) -->
                    <div
                      v-if="pastedImageBase64"
                      class="absolute top-2 left-2 w-16 h-16 rounded-lg overflow-hidden border border-primary/30 shadow-sm bg-surface z-10"
                    >
                      <img :src="pastedImageBase64" class="w-full h-full object-cover" />
                      <button
                        @click="pastedImageBase64 = ''"
                        class="absolute top-0.5 right-0.5 w-4 h-4 rounded-full bg-error text-white text-[10px] flex items-center justify-center hover:scale-110 transition-all"
                      >
                        ×
                      </button>
                    </div>
                  </div>
                  <div class="flex justify-between items-center mt-1.5 flex-shrink-0">
                    <span class="text-[9px] text-on-surface-variant/35 font-medium tracking-wide"
                      >Enter 发送，Shift+Enter 换行</span
                    >
                    <button
                      @pointerdown.prevent="sendChatMessage"
                      @click.prevent
                      :disabled="isCurrentCharStreaming || (!chatInputText.trim() && !pastedImageBase64)"
                      class="px-3.5 py-1.5 rounded-lg bg-primary text-on-primary text-xs font-bold disabled:opacity-40 hover:opacity-90 transition-all flex items-center space-x-1.5 shadow-sm active:scale-95"
                    >
                      <Loader2Icon v-if="isCurrentCharStreaming" class="w-3.5 h-3.5 animate-spin" />
                      <SendIcon v-else class="w-3.5 h-3.5" />
                      <span>{{ isCurrentCharStreaming ? '接收中...' : '发送' }}</span>
                    </button>
                  </div>
                </div>
              </template>
            </div>
          </template>
        </template>
      </main>
    </div>

    <!-- ========================= 右键菜单 ========================= -->
    <div
      v-if="contextMenu.visible"
      class="fixed z-50 bg-surface border border-outline-variant rounded-xl shadow-2xl py-1.5 min-w-[140px] overflow-hidden"
      :style="{ left: contextMenu.x + 'px', top: contextMenu.y + 'px' }"
      @click.stop
    >
      <!-- A. 会话列表右键 -->
      <template v-if="contextMenu.type === 'chat'">
        <button class="ctx-menu-item" @click="ctxPin">
          <PinIcon class="w-3.5 h-3.5 mr-2" />
          {{ contextMenu.char && conversationMeta[contextMenu.char.id]?.pinned ? '取消置顶' : '置顶' }}
        </button>
        <button class="ctx-menu-item" @click="ctxMarkUnread">
          <BellDotIcon class="w-3.5 h-3.5 mr-2" />
          {{ contextMenu.char && conversationMeta[contextMenu.char.id]?.unread ? '标为已读' : '标为未读' }}
        </button>
        <button class="ctx-menu-item" @click="ctxToggleMute">
          <BellOffIcon class="w-3.5 h-3.5 mr-2" />
          {{ contextMenu.char && conversationMeta[contextMenu.char.id]?.muted ? '取消免打扰' : '消息免打扰' }}
        </button>
        <button v-if="contextMenu.char && contextMenu.char.isGroup" class="ctx-menu-item" @click="ctxEditGroupName">
          <PenIcon class="w-3.5 h-3.5 mr-2" />
          修改群名称
        </button>
        <div class="my-1 border-t border-outline-variant/30"></div>
        <button class="ctx-menu-item text-error" @click="ctxHideConversation">
          <EyeOffIcon class="w-3.5 h-3.5 mr-2" />
          {{ contextMenu.char && contextMenu.char.isGroup ? '解散群聊' : '删除会话' }}
        </button>
      </template>

      <!-- B. 通讯录角色右键 -->
      <template v-else-if="contextMenu.type === 'contact'">
        <button class="ctx-menu-item" @click="ctxStartChat">
          <MessageCircleIcon class="w-3.5 h-3.5 mr-2 text-primary" />
          发起对话
        </button>
        <div class="my-1 border-t border-outline-variant/30"></div>
        <button class="ctx-menu-item text-error" @click="ctxDeleteCharacter">
          <XIcon class="w-3.5 h-3.5 mr-2 text-error" />
          删除角色
        </button>
      </template>

      <!-- C. 聊天气泡右键 -->
      <template v-else-if="contextMenu.type === 'message'">
        <button class="ctx-menu-item" @click="ctxEnterMultiSelect">
          <CheckSquareIcon class="w-3.5 h-3.5 mr-2 text-primary" stroke-width="2" />
          <span>多选</span>
        </button>
        <button class="ctx-menu-item" @click="ctxCopyMessage">
          <CopyIcon class="w-3.5 h-3.5 mr-2 text-primary" stroke-width="2" />
          <span>复制全文</span>
        </button>
        <button
          v-if="isMobile && contextMenu.message && contextMenu.message.content"
          class="ctx-menu-item"
          @click="ctxOpenSelectCopy"
        >
          <ScissorsIcon class="w-3.5 h-3.5 mr-2 text-primary" stroke-width="2" />
          <span>选择复制</span>
        </button>
        <button
          v-if="contextMenu.message && contextMenu.message.role === 'assistant'"
          class="ctx-menu-item"
          @click="ctxRegenerateMessage"
        >
          <RefreshCwIcon class="w-3.5 h-3.5 mr-2 text-primary" stroke-width="2" />
          <span>重新回复</span>
        </button>
        <button v-if="canEditMessage(contextMenu.message)" class="ctx-menu-item" @click="ctxEditMessage">
          <EditIcon class="w-3.5 h-3.5 mr-2 text-primary" stroke-width="2" />
          <span>修改消息</span>
        </button>
        <button class="ctx-menu-item" @click="ctxForwardMessage">
          <Share2Icon class="w-3.5 h-3.5 mr-2 text-primary" stroke-width="2" />
          <span>转发</span>
        </button>
        <button class="ctx-menu-item" @click="ctxFavoriteMessage">
          <BookmarkIcon class="w-3.5 h-3.5 mr-2 text-primary" stroke-width="2" />
          <span>收藏</span>
        </button>
        <div class="my-1 border-t border-outline-variant/30"></div>
        <button class="ctx-menu-item text-error" @click="ctxDeleteMessage">
          <TrashIcon class="w-3.5 h-3.5 mr-2 text-error" stroke-width="2" />
          <span>删除此条</span>
        </button>
      </template>
    </div>

    <!-- ========================= 弹窗：拓展属性 (数字生命的内心指标拓展) ========================= -->
    <div v-if="showAddStateModal" class="modal-overlay" @click.self="showAddStateModal = false">
      <div
        class="modal-panel w-[400px] flex flex-col p-5 bg-surface-high/85 backdrop-blur-xl border border-outline-variant/60 rounded-3xl shadow-2xl relative"
      >
        <div class="flex items-center justify-between pb-3.5 border-b border-outline-variant/40 mb-4 flex-shrink-0">
          <h3 class="text-sm font-extrabold text-on-surface flex items-center space-x-2">
            <SparklesIcon class="w-4 h-4 text-indigo-500 animate-pulse" />
            <span>拓展开天属性</span>
          </h3>
          <button
            @click="showAddStateModal = false"
            class="modal-close-btn p-1 rounded-lg hover:bg-on-surface/5 text-on-surface-variant transition-colors"
          >
            <XIcon class="w-4 h-4" />
          </button>
        </div>

        <div class="space-y-4 flex-1">
          <!-- 快捷应用预置指标模板 -->
          <div
            v-if="statePresets.length > 0"
            class="flex flex-col space-y-1.5 pb-3 border-b border-outline-variant/30 mb-3 flex-shrink-0"
          >
            <label class="text-[11px] font-extrabold text-primary flex items-center space-x-1">
              <SparklesIcon class="w-3 h-3 text-primary animate-pulse" />
              <span>应用预置指标模板（需在设置中进行配置）</span>
            </label>
            <select
              @change="
                event => {
                  const target = event.target as HTMLSelectElement;
                  const preset = statePresets.find(p => p.id === target.value);
                  if (preset) {
                    newStateLabel = preset.label;
                    newStateType = preset.type;
                    newStateMeaning = preset.meaning;
                    newStateRule = preset.rule;
                  }
                  target.value = ''; // 选完复位，方便下次选择
                }
              "
              class="w-full px-3.5 py-2 rounded-2xl bg-on-surface/5 border border-outline-variant focus:outline-none focus:border-primary text-xs text-on-surface font-semibold"
            >
              <option value="">-- 请选择一个预置指标模板 --</option>
              <option v-for="p in statePresets.filter(preset => !preset.is_global)" :key="p.id" :value="p.id">
                {{ p.label }} ({{ p.type === 'number' ? '数字型' : '文本型' }})
              </option>
            </select>
          </div>

          <!-- 字段名称 -->
          <div class="flex flex-col space-y-1.5">
            <label class="text-xs font-bold text-on-surface-variant">字段属性名称</label>
            <input
              type="text"
              v-model="newStateLabel"
              class="w-full px-4 py-2.5 rounded-2xl bg-on-surface/5 border border-outline-variant focus:outline-none focus:border-primary text-xs text-on-surface"
              placeholder="请输入新属性字段名称"
            />
          </div>

          <!-- 指标含义 (注入AI提示词) -->
          <div class="flex flex-col space-y-1.5">
            <label class="text-xs font-bold text-on-surface-variant"
              >指标含义 (注入AI提示词，告知AI这个指标的具体含义)</label
            >
            <textarea
              v-model="newStateMeaning"
              class="w-full h-16 px-4 py-2 rounded-2xl bg-on-surface/5 border border-outline-variant focus:outline-none focus:border-primary text-xs text-on-surface resize-none"
            ></textarea>
          </div>

          <!-- 字段类型 -->
          <div class="flex flex-col space-y-2">
            <label class="text-xs font-bold text-on-surface-variant">字段类型</label>
            <div class="flex p-1 rounded-2xl bg-on-surface/5 border border-outline-variant">
              <button
                @click="newStateType = 'number'"
                class="flex-1 py-2 text-xs font-bold rounded-xl transition-all cursor-pointer"
                :class="
                  newStateType === 'number'
                    ? 'bg-surface text-primary shadow-sm'
                    : 'text-on-surface-variant hover:text-on-surface'
                "
              >
                数字型 (0-100)
              </button>
              <button
                @click="newStateType = 'text'"
                class="flex-1 py-2 text-xs font-bold rounded-xl transition-all cursor-pointer"
                :class="
                  newStateType === 'text'
                    ? 'bg-surface text-primary shadow-sm'
                    : 'text-on-surface-variant hover:text-on-surface'
                "
              >
                文本型
              </button>
            </div>
          </div>

          <!-- 指标更新规则 (强制文字型与数字型均展示并必填) -->
          <div class="flex flex-col space-y-1.5 animate-in slide-in-from-top-1 duration-200">
            <label class="text-xs font-bold text-on-surface-variant">指标更新规则</label>
            <textarea
              v-model="newStateRule"
              class="w-full h-20 px-4 py-2.5 rounded-2xl bg-on-surface/5 border border-outline-variant focus:outline-none focus:border-primary text-xs text-on-surface resize-none"
              placeholder="例如：当{{user}}赞美、关心或提到暧昧话题时分值增加/变更；当{{user}}冷淡、指责时分值减少/变更。"
            ></textarea>
          </div>
        </div>

        <div class="flex items-center space-x-3 pt-4 border-t border-outline-variant/40 mt-4 flex-shrink-0">
          <button
            @click="showAddStateModal = false"
            class="flex-1 py-2.5 text-xs font-bold rounded-2xl border border-outline-variant text-on-surface hover:bg-on-surface/5 transition-colors"
          >
            取消
          </button>
          <button
            @click="handleAddCustomState"
            class="flex-1 py-2.5 text-xs font-bold rounded-2xl bg-primary text-white hover:bg-primary-hover transition-colors shadow-md active:scale-95"
            :disabled="!newStateLabel.trim() || !newStateRule.trim() || !newStateMeaning.trim()"
          >
            确认添加指标
          </button>
        </div>
      </div>
    </div>

    <!-- ========================= 弹窗：物理删除指标确认警告 ========================= -->
    <div v-if="showDeleteConfirmModal" class="modal-overlay" @click.self="showDeleteConfirmModal = false">
      <div
        class="modal-panel w-[380px] p-6 bg-surface-high/90 backdrop-blur-2xl border border-red-500/20 rounded-3xl shadow-2xl relative select-none animate-in fade-in zoom-in-95 duration-150 flex flex-col space-y-4"
      >
        <!-- 头部警示标 -->
        <div class="flex items-center space-x-3.5">
          <div
            class="w-10 h-10 rounded-full bg-red-500/10 flex items-center justify-center text-red-500 flex-shrink-0 animate-pulse"
          >
            <svg
              class="w-5 h-5"
              fill="none"
              stroke="currentColor"
              stroke-width="2.5"
              viewBox="0 0 24 24"
              xmlns="http://www.w3.org/2000/svg"
            >
              <path
                stroke-linecap="round"
                stroke-linejoin="round"
                d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"
              ></path>
            </svg>
          </div>
          <div class="flex-1">
            <h3 class="text-sm font-extrabold text-on-surface">确定要彻底删除该状态指标吗？</h3>
            <p class="text-[11px] text-on-surface-variant/70 mt-1 leading-normal">
              此操作将物理擦除该角色 State.md 中的该项指标且不可撤销。
            </p>
          </div>
        </div>

        <!-- 底部操作按钮 -->
        <div class="flex items-center space-x-3 pt-2">
          <button
            @click="showDeleteConfirmModal = false"
            class="flex-1 py-2.5 text-xs font-bold rounded-2xl border border-outline-variant text-on-surface hover:bg-on-surface/5 transition-all cursor-pointer"
          >
            取消
          </button>
          <button
            @click="confirmDeleteCustomState"
            class="flex-1 py-2.5 text-xs font-bold rounded-2xl bg-red-500 text-white hover:bg-red-600 shadow-md active:scale-95 transition-all cursor-pointer flex items-center justify-center space-x-1.5"
          >
            <svg
              class="w-4 h-4"
              fill="none"
              stroke="currentColor"
              stroke-width="2"
              viewBox="0 0 24 24"
              xmlns="http://www.w3.org/2000/svg"
            >
              <path
                stroke-linecap="round"
                stroke-linejoin="round"
                d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"
              ></path>
            </svg>
            <span>确认彻底删除</span>
          </button>
        </div>
      </div>
    </div>

    <!-- ========================= 弹窗：会话历史 ========================= -->
    <div
      v-if="showChatHistoryModal && activeCharacter"
      class="modal-overlay"
      @click.self="showChatHistoryModal = false"
    >
      <div class="modal-panel w-[620px] h-[680px] flex flex-col">
        <!-- 标题栏 -->
        <div class="modal-header">
          <div class="flex items-center space-x-2">
            <HistoryIcon class="w-4 h-4 text-primary" />
            <span>{{ activeCharacter.name }} · 会话历史</span>
          </div>
          <button @click="showChatHistoryModal = false" class="modal-close-btn"><XIcon class="w-4 h-4" /></button>
        </div>

        <!-- 搜索框 -->
        <div class="px-5 py-3 border-b border-outline-variant/30 flex-shrink-0">
          <div class="relative flex items-center">
            <SearchIcon class="absolute left-3 w-4 h-4 text-on-surface-variant/50 pointer-events-none" />
            <input
              v-model="chatHistorySearchQuery"
              @input="onChatHistorySearch"
              type="text"
              placeholder="搜索与角色的所有对话记录..."
              class="w-full pl-9 pr-9 py-2.5 rounded-xl bg-surface border border-outline-variant text-sm text-on-surface focus:outline-none focus:border-primary/50 focus:ring-1 focus:ring-primary/20 transition-all placeholder-on-surface-variant/40"
            />
            <button
              v-if="chatHistorySearchQuery"
              @click="
                chatHistorySearchQuery = '';
                onChatHistorySearch();
              "
              class="absolute right-3 text-on-surface-variant/50 hover:text-on-surface transition-colors"
            >
              <XIcon class="w-4 h-4" />
            </button>
          </div>
          <div class="mt-1.5 text-[10px] text-on-surface-variant/50 pl-0.5">
            <span v-if="chatHistorySearchQuery && !isChatHistorySearching">
              找到 {{ chatHistoryDisplayMessages.length }} 条相关记录
            </span>
            <span v-else-if="isChatHistorySearching">搜索中...</span>
            <span v-else>显示最近 50 条聊天记录，搜索可查看全部历史</span>
          </div>
        </div>

        <!-- 消息列表 -->
        <div class="flex-1 overflow-y-auto px-5 py-3 space-y-2 min-h-0">
          <!-- 加载中 -->
          <div v-if="isChatHistoryLoading" class="flex items-center justify-center h-full">
            <div class="flex flex-col items-center space-y-2 text-on-surface-variant/50">
              <Loader2Icon class="w-6 h-6 animate-spin" />
              <span class="text-xs">加载历史记录中...</span>
            </div>
          </div>

          <!-- 空状态 -->
          <div v-else-if="chatHistoryDisplayMessages.length === 0" class="flex items-center justify-center h-full">
            <div class="flex flex-col items-center space-y-2 text-on-surface-variant/40">
              <HistoryIcon class="w-10 h-10" />
              <span class="text-sm">{{ chatHistorySearchQuery ? '未找到相关记录' : '暂无聊天记录' }}</span>
            </div>
          </div>

          <!-- 消息气泡列表 -->
          <template v-else>
            <div
              v-for="msg in chatHistoryDisplayMessages"
              :key="msg.id || msg.timestamp"
              class="flex gap-2.5 animate-fade-in"
              :class="msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'"
            >
              <!-- 头像 -->
              <div class="flex-shrink-0 w-7 h-7 rounded-full overflow-hidden mt-0.5 border border-outline-variant/30">
                <template v-if="msg.role === 'user'">
                  <img v-if="userProfile.avatarUrl" :src="userProfile.avatarUrl" class="w-full h-full object-cover" />
                  <img v-else :src="defaultAvatarSrc" class="w-full h-full object-cover" />
                </template>
                <template v-else>
                  <img
                    v-if="characterAvatars[activeCharacter.id]"
                    :src="characterAvatars[activeCharacter.id]"
                    class="w-full h-full object-cover"
                  />
                  <div
                    v-else
                    class="w-full h-full bg-primary/20 flex items-center justify-center text-[10px] font-bold text-primary"
                  >
                    {{ activeCharacter.name?.[0] || '?' }}
                  </div>
                </template>
              </div>

              <!-- 消息体 -->
              <div class="flex flex-col max-w-[75%]" :class="msg.role === 'user' ? 'items-end' : 'items-start'">
                <!-- 时间戳 -->
                <span class="text-[10px] text-on-surface-variant/45 mb-1 px-0.5">
                  {{ formatHistoryTimestamp(msg.timestamp) }}
                </span>
                <!-- 气泡 -->
                <div
                  class="px-3 py-2 rounded-2xl text-xs leading-relaxed break-words select-text"
                  :class="
                    msg.role === 'user'
                      ? 'bg-primary rounded-tr-sm text-white'
                      : 'bg-surface border border-outline-variant/50 text-on-surface rounded-tl-sm'
                  "
                >
                  <!-- 高亮搜索词 -->
                  <span
                    v-if="chatHistorySearchQuery"
                    v-html="highlightSearchTerm(cleanUserContentForUI(msg.content), chatHistorySearchQuery)"
                  ></span>
                  <span v-else>{{ cleanUserContentForUI(msg.content) }}</span>
                </div>
              </div>
            </div>
          </template>
        </div>
      </div>
    </div>

    <!-- ========================= 弹窗：首次聊天前置配置 (完全重构隔离版) ========================= -->
    <div v-if="showFirstChatConfigModal" class="first-chat-overlay" @click.self="showFirstChatConfigModal = false">
      <div class="first-chat-panel animate-in zoom-in-95 duration-200 select-none">
        <!-- 头部 -->
        <div class="first-chat-header">
          <div class="first-chat-header-title">
            <span class="first-chat-title-tag"></span>
            <span class="first-chat-title-text">初始化会话</span>
          </div>
          <button @click="showFirstChatConfigModal = false" class="first-chat-close-btn">
            <XIcon style="width: 14px !important; height: 14px !important" />
          </button>
        </div>

        <!-- 副标题 -->
        <div class="first-chat-subtitle">配置当前聊天专属的用户人设与会话模式</div>

        <!-- 正文 -->
        <div class="first-chat-body">
          <!-- 1. 选择扮演的用户人设 -->
          <div class="first-chat-field">
            <label class="first-chat-label">您要在会话中扮演的人设 <span class="first-chat-required">*</span></label>

            <!-- 下拉框触发区 -->
            <div
              @click="
                !isAlreadyBoundProfile ? (showFirstChatProfileDropdown = !showFirstChatProfileDropdown) : undefined
              "
              class="first-chat-dropdown-trigger"
              :class="{ 'first-chat-dropdown-disabled': isAlreadyBoundProfile }"
              :title="
                isAlreadyBoundProfile ? '该会话已绑定此用户人设，开启聊天后不可更改，以防剧情逻辑错乱' : undefined
              "
            >
              <div v-if="firstChatConfigForm.profileId" class="first-chat-dropdown-selected">
                <!-- 头像外圈 -->
                <div class="first-chat-avatar-container">
                  <img
                    v-if="userProfilesList.find(p => p.profileId === firstChatConfigForm.profileId)?.avatar"
                    :src="userProfilesList.find(p => p.profileId === firstChatConfigForm.profileId)?.avatar"
                    class="first-chat-avatar-img"
                  />
                  <div v-else class="first-chat-avatar-text">
                    {{
                      userProfilesList.find(p => p.profileId === firstChatConfigForm.profileId)?.name?.slice(0, 1) ||
                      '?'
                    }}
                  </div>
                </div>
                <!-- 文本信息 -->
                <div class="first-chat-profile-info">
                  <div class="first-chat-profile-name flex items-center space-x-1.5">
                    <span>{{ userProfilesList.find(p => p.profileId === firstChatConfigForm.profileId)?.name }}</span>
                    <span
                      v-if="isAlreadyBoundProfile"
                      class="text-[9px] px-1 py-0.2 bg-on-surface/5 text-on-surface-variant/40 rounded border border-outline-variant/30 font-extrabold flex items-center space-x-0.5"
                    >
                      <svg
                        xmlns="http://www.w3.org/2000/svg"
                        class="w-2.5 h-2.5"
                        fill="none"
                        viewBox="0 0 24 24"
                        stroke="currentColor"
                        stroke-width="2.5"
                      >
                        <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
                        <path d="M7 11V7a5 5 0 0 1 10 0v4" />
                      </svg>
                      <span>已锁定</span>
                    </span>
                  </div>
                  <div class="first-chat-profile-desc">
                    {{
                      userProfilesList.find(p => p.profileId === firstChatConfigForm.profileId)?.description ||
                      '暂无描述'
                    }}
                  </div>
                </div>
              </div>
              <div v-else class="first-chat-dropdown-placeholder">请选择您扮演的用户人设...</div>

              <svg
                v-if="isAlreadyBoundProfile"
                xmlns="http://www.w3.org/2000/svg"
                class="w-3.5 h-3.5 text-on-surface-variant/30 flex-shrink-0"
                fill="none"
                viewBox="0 0 24 24"
                stroke="currentColor"
                stroke-width="2.2"
              >
                <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
                <path d="M7 11V7a5 5 0 0 1 10 0v4" />
              </svg>
              <ChevronDownIcon
                v-else
                class="first-chat-dropdown-arrow"
                :style="{ transform: showFirstChatProfileDropdown ? 'rotate(180deg) !important' : 'none !important' }"
              />
            </div>

            <!-- 下拉浮层面板 -->
            <div v-if="showFirstChatProfileDropdown" class="first-chat-dropdown-menu">
              <div class="first-chat-dropdown-scroll">
                <button
                  v-for="profile in userProfilesList"
                  :key="profile.profileId"
                  @click="
                    firstChatConfigForm.profileId = profile.profileId;
                    showFirstChatProfileDropdown = false;
                  "
                  class="first-chat-dropdown-item"
                  :class="{ 'first-chat-item-active': firstChatConfigForm.profileId === profile.profileId }"
                >
                  <div class="first-chat-avatar-container-small">
                    <img v-if="profile.avatar" :src="profile.avatar" class="first-chat-avatar-img-small" />
                    <div v-else class="first-chat-avatar-text-small">{{ profile.name?.slice(0, 1) }}</div>
                  </div>
                  <div class="first-chat-profile-info-small">
                    <div class="first-chat-profile-name-small">{{ profile.name }}</div>
                    <div class="first-chat-profile-desc-small">{{ profile.description || '暂无描述' }}</div>
                  </div>
                </button>

                <div v-if="userProfilesList.length === 0" class="first-chat-empty">目前本地尚无用户人设设定 🐾</div>
              </div>

              <!-- 底部常驻按钮 -->
              <div class="first-chat-dropdown-footer">
                <button @click="triggerFirstChatAddProfile" class="first-chat-add-btn">
                  <PlusIcon style="width: 14px !important; height: 14px !important; margin-right: 4px !important" />
                  <span>新建人设设定</span>
                </button>
              </div>
            </div>
          </div>

          <!-- 2. 会话对话模式 -->
          <div class="first-chat-field">
            <label class="first-chat-label">会话对话模式</label>
            <div class="first-chat-segment">
              <button
                @click="firstChatConfigForm.chatMode = 'dialogue'"
                class="first-chat-segment-btn"
                :class="{ 'first-chat-segment-btn-active': firstChatConfigForm.chatMode === 'dialogue' }"
              >
                仅对话
              </button>
              <button
                @click="firstChatConfigForm.chatMode = 'descriptive'"
                class="first-chat-segment-btn"
                :class="{ 'first-chat-segment-btn-active': firstChatConfigForm.chatMode === 'descriptive' }"
              >
                包含描写
              </button>
              <button
                v-if="selectedCharacterId && !groupChats.some(g => g.id === selectedCharacterId)"
                @click="firstChatConfigForm.chatMode = 'director'"
                class="first-chat-segment-btn"
                :class="{ 'first-chat-segment-btn-active': firstChatConfigForm.chatMode === 'director' }"
              >
                导演模式
              </button>
            </div>
            <!-- 模式描述说明 -->
            <div class="first-chat-mode-tip">
              <span v-if="firstChatConfigForm.chatMode === 'dialogue'"
                >💬 仅对话模式：AI 将只以纯气泡对话的形式输出，类似普通社交聊天的单语气。</span
              >
              <span v-else-if="firstChatConfigForm.chatMode === 'descriptive'"
                >📖 包含描写模式：AI 的回复中将带上动作、神态或周遭环境等第三人称侧写描写。</span
              >
              <span v-else-if="firstChatConfigForm.chatMode === 'director'"
                >🎬 导演模式：允许您通过分身和多视角机制深入控制剧情，不限于单一对话形式。</span
              >
            </div>
          </div>

          <!-- 3. AI 小说写手开关 (群聊不支持 AI 写手，仅单聊可见) -->
          <div v-if="!isGroupActive" class="first-chat-field">
            <div class="first-chat-switch-card">
              <div class="first-chat-switch-left">
                <div class="first-chat-switch-icon-box">
                  <BookIcon style="width: 16px !important; height: 16px !important" />
                </div>
                <div class="first-chat-switch-text-box">
                  <div class="first-chat-switch-title">开启 AI 小说写手</div>
                  <div class="first-chat-switch-desc">自动将对话记录实时改编为精美小说章节</div>
                </div>
              </div>

              <!-- 开关按钮 -->
              <button
                @click="firstChatConfigForm.novelEnabled = !firstChatConfigForm.novelEnabled"
                class="first-chat-switch-btn"
                :class="{ 'first-chat-switch-btn-active': firstChatConfigForm.novelEnabled }"
              >
                <span
                  class="first-chat-switch-dot"
                  :class="{ 'first-chat-switch-dot-active': firstChatConfigForm.novelEnabled }"
                ></span>
              </button>
            </div>

            <!-- 改编尺度展开区域 -->
            <transition name="fade-slide">
              <div
                v-if="firstChatConfigForm.novelEnabled"
                class="mt-4 space-y-2 animate-in fade-in slide-in-from-top-2 duration-200"
              >
                <label class="first-chat-label">改编尺度</label>
                <div class="first-chat-segment">
                  <button
                    @click="firstChatConfigForm.novelAdaptation = 'faithful'"
                    class="first-chat-segment-btn"
                    :class="{ 'first-chat-segment-btn-active': firstChatConfigForm.novelAdaptation === 'faithful' }"
                  >
                    忠实记录
                  </button>
                  <button
                    @click="firstChatConfigForm.novelAdaptation = 'moderate'"
                    class="first-chat-segment-btn"
                    :class="{ 'first-chat-segment-btn-active': firstChatConfigForm.novelAdaptation === 'moderate' }"
                  >
                    适度改编
                  </button>
                  <button
                    @click="firstChatConfigForm.novelAdaptation = 'free'"
                    class="first-chat-segment-btn"
                    :class="{ 'first-chat-segment-btn-active': firstChatConfigForm.novelAdaptation === 'free' }"
                  >
                    自由创作
                  </button>
                </div>
              </div>
            </transition>
          </div>
        </div>

        <!-- 页脚 -->
        <div class="first-chat-footer">
          <button @click="showFirstChatConfigModal = false" class="first-chat-footer-btn-cancel">取消</button>
          <button @click="saveFirstChatConfig" class="first-chat-footer-btn-confirm">确定</button>
        </div>
      </div>
    </div>

    <!-- ========================= 弹窗：AI小说写手 ========================= -->
    <div v-if="showNovelPanel && activeCharacter" class="modal-overlay z-[9999]" @click.self="showNovelPanel = false">
      <div class="modal-panel w-[500px] max-h-[85vh] flex flex-col animate-in zoom-in-95 duration-200 select-none">
        <!-- 头部 -->
        <div class="modal-header flex-shrink-0">
          <div class="flex items-center space-x-2">
            <BookIcon class="w-4.5 h-4.5 text-primary" />
            <span>AI 小说写手 ({{ activeCharacter.name }})</span>
          </div>
          <button @click="showNovelPanel = false" class="modal-close-btn"><XIcon class="w-4 h-4" /></button>
        </div>

        <!-- 内容区域 -->
        <div class="flex-1 overflow-y-auto p-5 space-y-5 min-h-0">
          <!-- 开启开关 -->
          <div
            class="flex items-center justify-between bg-surface-high/20 p-3.5 rounded-xl border border-outline-variant/10"
          >
            <div class="flex flex-col">
              <span class="text-xs font-bold text-on-surface">开启 AI 写手</span>
              <span class="text-[10px] text-on-surface-variant/70 mt-0.5">等积累足够对话历史后，将静默生成新章节</span>
            </div>
            <button
              @click="
                novelEnabled = !novelEnabled;
                triggerSaveNovelSettings();
              "
              class="relative w-11 h-6 rounded-full transition-all duration-300 focus:outline-none cursor-pointer flex-shrink-0"
              :class="novelEnabled ? 'bg-primary' : 'bg-outline-variant'"
            >
              <span
                class="absolute w-5 h-5 rounded-full bg-white top-0.5 transition-all duration-300 shadow-md"
                :class="novelEnabled ? 'left-5.5' : 'left-0.5'"
              ></span>
            </button>
          </div>

          <!-- 首次开启写手时，选择首章改编起始点 -->
          <div
            v-if="novelEnabled && novelChaptersList.length === 0"
            class="flex flex-col space-y-2 bg-surface-high/10 p-3.5 rounded-xl border border-outline-variant/10 animate-in fade-in duration-200"
          >
            <span class="text-xs font-bold text-on-surface">首章改编起点选择</span>
            <div class="flex items-center space-x-6 mt-1">
              <label class="flex items-center space-x-1.5 cursor-pointer text-xs text-on-surface">
                <input
                  type="radio"
                  name="novelStartFrom"
                  value="today"
                  v-model="novelStartFrom"
                  @change="triggerSaveNovelSettings"
                  class="accent-primary"
                />
                <span>从今天开始改编</span>
              </label>
              <label class="flex items-center space-x-1.5 cursor-pointer text-xs text-on-surface">
                <input
                  type="radio"
                  name="novelStartFrom"
                  value="all"
                  v-model="novelStartFrom"
                  @change="triggerSaveNovelSettings"
                  class="accent-primary"
                />
                <span>从头（历史第一条）开始</span>
              </label>
            </div>
          </div>

          <!-- 自定义文风选择 -->
          <div class="flex flex-col space-y-1.5 relative select-none">
            <label class="text-xs font-bold text-on-surface">文风选择</label>

            <!-- 下拉框触发器按钮 -->
            <div
              @click="clickNovelStyleSelector"
              class="w-full bg-surface border border-outline-variant/60 rounded-xl px-3 py-2 text-xs text-on-surface cursor-pointer flex items-center justify-between transition-all hover:border-primary/50"
            >
              <span class="truncate font-semibold">{{ getSelectedStyleName }}</span>
              <ChevronDownIcon
                class="w-4 h-4 text-on-surface-variant transition-transform duration-200"
                :class="{ 'transform rotate-180': showStyleDropdown }"
              />
            </div>

            <!-- 下拉展开选项 -->
            <div
              v-if="showStyleDropdown"
              class="absolute top-full left-0 right-0 mt-1.5 bg-surface border border-outline-variant rounded-xl shadow-xl z-50 p-1 flex flex-col space-y-0.5 max-h-40 overflow-y-auto animate-in fade-in slide-in-from-top-1 duration-100"
            >
              <!-- 系统默认文风 -->
              <div
                @click="selectStyle('')"
                class="px-3 py-2 rounded-lg text-xs hover:bg-surface-high cursor-pointer transition-all truncate"
                :class="{ 'text-primary font-bold bg-primary/5': novelStyleId === '' }"
              >
                默认文风（内置，建议自行在设置页面配置）
              </div>
              <div
                v-for="style in novelStyles"
                :key="style.id"
                @click="selectStyle(style.id)"
                class="px-3 py-2 rounded-lg text-xs hover:bg-surface-high cursor-pointer transition-all truncate"
                :class="{ 'text-primary font-bold bg-primary/5': novelStyleId === style.id }"
              >
                {{ style.name }}
              </div>
            </div>
          </div>

          <!-- 叙事人称 -->
          <div class="flex flex-col space-y-2">
            <label class="text-xs font-bold text-on-surface">叙事人称</label>
            <div class="flex flex-col space-y-2 bg-surface-high/10 p-3 rounded-xl border border-outline-variant/10">
              <label class="flex items-center space-x-2.5 cursor-pointer text-xs text-on-surface">
                <input
                  type="radio"
                  v-model="novelPov"
                  value="third_user"
                  @change="triggerSaveNovelSettings"
                  class="text-primary focus:ring-primary w-4 h-4"
                />
                <span
                  >第三人称，以 <strong>{{ userProfile.nickname }}</strong> 为主角</span
                >
              </label>
              <label class="flex items-center space-x-2.5 cursor-pointer text-xs text-on-surface">
                <input
                  type="radio"
                  v-model="novelPov"
                  value="third_char"
                  @change="triggerSaveNovelSettings"
                  class="text-primary focus:ring-primary w-4 h-4"
                />
                <span
                  >第三人称，以 <strong>{{ activeCharacter.name }}</strong> 为主角</span
                >
              </label>
              <label class="flex items-center space-x-2.5 cursor-pointer text-xs text-on-surface">
                <input
                  type="radio"
                  v-model="novelPov"
                  value="user_first"
                  @change="triggerSaveNovelSettings"
                  class="text-primary focus:ring-primary w-4 h-4"
                />
                <span
                  ><strong>{{ userProfile.nickname }}</strong> 的第一人称 ("我")</span
                >
              </label>
              <label class="flex items-center space-x-2.5 cursor-pointer text-xs text-on-surface">
                <input
                  type="radio"
                  v-model="novelPov"
                  value="char_first"
                  @change="triggerSaveNovelSettings"
                  class="text-primary focus:ring-primary w-4 h-4"
                />
                <span
                  ><strong>{{ activeCharacter.name }}</strong> 的第一人称 ("我")</span
                >
              </label>
            </div>
          </div>

          <!-- 改编尺度 -->
          <div class="flex flex-col space-y-1.5">
            <label class="text-xs font-bold text-on-surface">改编尺度</label>
            <div class="grid grid-cols-3 gap-2.5">
              <label
                class="flex items-center justify-center border border-outline-variant rounded-xl p-2.5 cursor-pointer text-xs text-on-surface transition-all"
                :class="
                  novelAdaptation === 'faithful'
                    ? 'border-primary bg-primary/5 font-bold text-primary'
                    : 'bg-surface hover:bg-surface-high/30'
                "
              >
                <input
                  type="radio"
                  v-model="novelAdaptation"
                  value="faithful"
                  @change="triggerSaveNovelSettings"
                  class="sr-only"
                />
                <span>忠实记录</span>
              </label>
              <label
                class="flex items-center justify-center border border-outline-variant rounded-xl p-2.5 cursor-pointer text-xs text-on-surface transition-all"
                :class="
                  novelAdaptation === 'moderate'
                    ? 'border-primary bg-primary/5 font-bold text-primary'
                    : 'bg-surface hover:bg-surface-high/30'
                "
              >
                <input
                  type="radio"
                  v-model="novelAdaptation"
                  value="moderate"
                  @change="triggerSaveNovelSettings"
                  class="sr-only"
                />
                <span>适度改编</span>
              </label>
              <label
                class="flex items-center justify-center border border-outline-variant rounded-xl p-2.5 cursor-pointer text-xs text-on-surface transition-all"
                :class="
                  novelAdaptation === 'free'
                    ? 'border-primary bg-primary/5 font-bold text-primary'
                    : 'bg-surface hover:bg-surface-high/30'
                "
              >
                <input
                  type="radio"
                  v-model="novelAdaptation"
                  value="free"
                  @change="triggerSaveNovelSettings"
                  class="sr-only"
                />
                <span>自由创作</span>
              </label>
            </div>
          </div>
        </div>

        <!-- 底部操作区 -->
        <div class="p-4 border-t border-outline-variant/30 flex-shrink-0">
          <!-- 续写小说按钮：始终显示，允许用户手动触发写作 -->
          <button
            @click="triggerNovelContinue"
            :disabled="!!novelContinuingMap[selectedCharacterId || '']"
            class="w-full rounded-xl font-bold py-2.5 text-xs transition-all duration-200 flex items-center justify-center space-x-2"
            :class="
              novelContinuingMap[selectedCharacterId || '']
                ? 'bg-outline-variant/30 text-on-surface-variant cursor-not-allowed'
                : 'bg-primary text-white hover:bg-primary/90 active:scale-[0.98] shadow-sm shadow-primary/20'
            "
          >
            <SparklesIcon v-if="!novelContinuingMap[selectedCharacterId || '']" class="w-4 h-4" />
            <span
              v-if="novelContinuingMap[selectedCharacterId || '']"
              class="inline-block w-3.5 h-3.5 border-2 border-white/30 border-t-white rounded-full animate-spin"
            ></span>
            <span>{{ novelContinuingMap[selectedCharacterId || ''] ? '正在续写中，请稍候...' : '立即续写小说' }}</span>
          </button>

          <!-- 进度条：显示当前累计未改编的 token 数量与阈值进度 -->
          <div v-if="novelProgressMap[selectedCharacterId || '']" class="mt-3.5 space-y-1.5 px-1">
            <div class="flex items-center justify-between text-[10px] font-bold text-on-surface-variant/70">
              <span>未改编对话进度</span>
              <span>
                {{ novelProgressMap[selectedCharacterId || ''].pendingTokens }} /
                {{ novelProgressMap[selectedCharacterId || ''].threshold }} Tokens ({{
                  Math.min(
                    Math.round(
                      (novelProgressMap[selectedCharacterId || ''].pendingTokens /
                        novelProgressMap[selectedCharacterId || ''].threshold) *
                        100,
                    ),
                    100,
                  )
                }}%)
              </span>
            </div>
            <!-- 外层槽位 -->
            <div class="w-full h-1.5 rounded-full bg-outline-variant/20 overflow-hidden">
              <!-- 内层进度填充 -->
              <div
                class="h-full rounded-full transition-all duration-500 ease-out"
                :class="
                  novelProgressMap[selectedCharacterId || ''].pendingTokens >=
                  novelProgressMap[selectedCharacterId || ''].threshold
                    ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.4)]'
                    : 'bg-primary'
                "
                :style="{
                  width: `${Math.min((novelProgressMap[selectedCharacterId || ''].pendingTokens / novelProgressMap[selectedCharacterId || ''].threshold) * 100, 100)}%`,
                }"
              ></div>
            </div>
          </div>
        </div>
      </div>
    </div>

    <!-- ========================= 弹窗：编辑小说属性（书名与封面） ========================= -->
    <div
      v-if="showEditBookModal"
      class="modal-overlay z-[10000] animate-in fade-in duration-200"
      @click.self="showEditBookModal = false"
    >
      <div class="modal-panel w-[420px] flex flex-col animate-in zoom-in-95 duration-200 select-none">
        <div class="modal-header">
          <div class="flex items-center space-x-2">
            <BookOpenIcon class="w-4 h-4 text-primary" stroke-width="2" />
            <span class="text-xs font-bold">编辑小说属性</span>
          </div>
          <button @click="showEditBookModal = false" class="modal-close-btn"><XIcon class="w-4 h-4" /></button>
        </div>

        <div class="p-6 space-y-5 flex-1 min-h-0">
          <!-- 封面图展示与点击更换 -->
          <div class="flex flex-col items-center space-y-3">
            <label class="text-[11px] font-bold text-on-surface-variant/70">小说封面</label>
            <div
              class="relative group aspect-[2/3] w-28 rounded-xl overflow-hidden shadow border border-outline-variant/15 bg-surface-high/20 cursor-pointer"
              @click="changeBookCover(editingBook.novelId)"
            >
              <img
                :src="editingBook.coverUrl"
                class="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
              />
              <div
                class="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center text-[10px] text-white font-bold"
              >
                点击更换封面
              </div>
            </div>
          </div>

          <!-- 书名输入框 -->
          <div class="flex flex-col space-y-1.5">
            <label class="text-[11px] font-bold text-on-surface-variant/70">小说书名</label>
            <input
              v-model="editingBookTitle"
              type="text"
              placeholder="请输入小说名称"
              class="w-full bg-surface border border-outline-variant/60 rounded-xl px-3.5 py-2.5 text-xs text-on-surface focus:outline-none focus:border-primary"
            />
          </div>
        </div>

        <div class="p-4 bg-surface-low border-t border-outline-variant/20 flex items-center justify-end space-x-2.5">
          <button
            @click="showEditBookModal = false"
            class="px-4 py-2 border border-outline-variant/50 text-on-surface-variant text-[11px] font-bold rounded-xl hover:bg-surface-high transition-all"
          >
            取消
          </button>
          <button
            @click="saveBookTitle"
            class="px-4 py-2 bg-primary text-white text-[11px] font-bold rounded-xl hover:bg-primary/90 active:scale-95 transition-all"
          >
            保存修改
          </button>
        </div>
      </div>
    </div>

    <!-- ========================= 弹窗：新建/编辑小说文风 ========================= -->
    <div
      v-if="showAddStyleModal"
      class="modal-overlay z-[10000] animate-in fade-in duration-200"
      @click.self="showAddStyleModal = false"
    >
      <div class="modal-panel w-[500px] max-h-[500px] flex flex-col animate-in zoom-in-95 duration-200 select-none">
        <div class="modal-header">
          <div class="flex items-center space-x-2">
            <span class="text-sm">✨</span>
            <span class="text-xs font-bold">{{ editingStyle ? '编辑小说文风' : '新建小说文风' }}</span>
          </div>
          <button @click="showAddStyleModal = false" class="modal-close-btn"><XIcon class="w-4 h-4" /></button>
        </div>

        <div class="p-5 space-y-4 flex-1 overflow-y-auto min-h-0">
          <div class="flex flex-col space-y-1.5">
            <label class="text-xs font-bold text-on-surface">文风名称</label>
            <input
              v-model="styleForm.name"
              type="text"
              placeholder="例如：古典仙侠风、废土轻小说"
              class="w-full bg-surface border border-outline-variant/60 rounded-xl px-3 py-2 text-xs text-on-surface focus:outline-none focus:border-primary"
            />
          </div>

          <div class="flex flex-col space-y-1.5">
            <label class="text-xs font-bold text-on-surface">文风提示词 (Style Prompt)</label>
            <textarea
              v-model="styleForm.prompt"
              rows="8"
              placeholder="请输入控制 AI 写作风格的提示词。例如句式偏好、节奏要求、情绪展示手法等..."
              class="w-full bg-surface border border-outline-variant/60 rounded-xl p-3 text-xs text-on-surface focus:outline-none focus:border-primary font-mono resize-none shadow-inner"
            ></textarea>
          </div>
        </div>

        <div class="modal-footer px-5 py-3 border-t border-outline-variant/30 flex justify-end space-x-3 flex-shrink-0">
          <button
            @click="showAddStyleModal = false"
            class="px-4 py-2 border border-outline-variant rounded-xl text-xs hover:bg-surface-high/30 transition-all font-bold"
          >
            取消
          </button>
          <button
            @click="saveNovelStyle"
            class="px-4 py-2 bg-primary text-white rounded-xl text-xs hover:bg-primary/90 transition-all font-bold shadow-md"
          >
            保存文风
          </button>
        </div>
      </div>
    </div>

    <!-- ========================= 弹窗：大脑（角色记忆编辑） ========================= -->
    <div
      v-if="showBrainPanel && (activeCharacter || isGroupActive)"
      class="modal-overlay"
      @click.self="showBrainPanel = false"
    >
      <div class="modal-panel w-[640px] h-[580px] flex flex-col">
        <div class="modal-header">
          <div class="flex items-center space-x-2">
            <BrainIcon class="w-4 h-4 text-primary" />
            <span>{{ isGroupActive ? activeGroupChat?.name : activeCharacter?.name }} · 记忆与画像</span>
          </div>
          <button @click="showBrainPanel = false" class="modal-close-btn"><XIcon class="w-4 h-4" /></button>
        </div>

        <div class="flex border-b border-outline-variant/30">
          <button
            v-for="tab in currentBrainTabs"
            :key="tab.key"
            @click="brainActiveTab = tab.key"
            class="px-4 py-2.5 text-xs font-bold border-b-2 transition-all"
            :class="
              brainActiveTab === tab.key
                ? 'border-primary text-primary'
                : 'border-transparent text-on-surface-variant hover:text-on-surface'
            "
          >
            {{ tab.label }}
          </button>
        </div>

        <div class="p-5 flex-1 overflow-y-auto min-h-0 flex flex-col">
          <div v-if="brainActiveTab === 'soul'" class="flex-1 flex flex-col min-h-0">
            <div class="flex items-center justify-between mb-2 flex-shrink-0">
              <div class="text-[10px] text-on-surface-variant font-mono">Soul.md · 角色性格核心设定</div>
              <button
                @click="brainEditModes.soul = !brainEditModes.soul"
                class="flex items-center space-x-1 text-xs text-primary border border-primary/20 hover:border-primary bg-primary/5 hover:bg-primary/10 px-2.5 py-1 rounded-md transition-all font-bold cursor-pointer select-none flex-shrink-0"
              >
                <component :is="brainEditModes.soul ? EyeIcon : PenLineIcon" class="w-3.5 h-3.5" />
                <span>{{ brainEditModes.soul ? '预览设定' : '修改设定' }}</span>
              </button>
            </div>
            <!-- 预览 -->
            <div
              v-if="!brainEditModes.soul"
              class="flex-1 p-4 rounded-lg border border-outline-variant bg-surface text-xs leading-relaxed overflow-y-auto select-text markdown-body shadow-sm"
              v-html="renderMarkdown(brainSoulContent || '*性格设定为空*')"
            ></div>
            <!-- 编辑 -->
            <textarea
              v-else
              v-model="brainSoulContent"
              class="flex-1 w-full font-mono text-xs bg-surface border border-outline-variant rounded-lg p-3 focus:outline-none focus:border-primary resize-none text-on-surface overflow-y-auto shadow-inner"
            ></textarea>
          </div>

          <div v-else-if="brainActiveTab === 'world'" class="flex-1 flex flex-col min-h-0">
            <div class="flex items-center justify-between mb-2 flex-shrink-0">
              <div class="text-[10px] text-on-surface-variant font-mono">World.md · 世界观与背景设定</div>
              <button
                @click="brainEditModes.world = !brainEditModes.world"
                class="flex items-center space-x-1 text-xs text-primary border border-primary/20 hover:border-primary bg-primary/5 hover:bg-primary/10 px-2.5 py-1 rounded-md transition-all font-bold cursor-pointer select-none flex-shrink-0"
              >
                <component :is="brainEditModes.world ? EyeIcon : PenLineIcon" class="w-3.5 h-3.5" />
                <span>{{ brainEditModes.world ? '预览设定' : '修改设定' }}</span>
              </button>
            </div>
            <!-- 预览 -->
            <div
              v-if="!brainEditModes.world"
              class="flex-1 p-4 rounded-lg border border-outline-variant bg-surface text-xs leading-relaxed overflow-y-auto select-text markdown-body shadow-sm"
              v-html="renderMarkdown(brainWorldContent || '*世界设定为空*')"
            ></div>
            <!-- 编辑 -->
            <textarea
              v-else
              v-model="brainWorldContent"
              class="flex-1 w-full font-mono text-xs bg-surface border border-outline-variant rounded-lg p-3 focus:outline-none focus:border-primary resize-none text-on-surface overflow-y-auto shadow-inner"
            ></textarea>
          </div>

          <div v-else-if="brainActiveTab === 'memory'" class="flex-1 flex flex-col min-h-0">
            <div class="flex items-center justify-between mb-2 flex-shrink-0">
              <div class="text-[10px] text-on-surface-variant font-mono">
                {{ isGroupActive ? 'Memory.md · 群聊记忆' : 'Memory.md · 双轨记忆（STM + LTM）' }}
              </div>
              <div class="flex items-center space-x-2 flex-shrink-0">
                <button
                  v-if="!isGroupActive"
                  @click="tidyCharacterMemory('brain')"
                  :disabled="isTidyingMemory"
                  class="flex items-center space-x-1.5 text-xs text-secondary border border-secondary/20 hover:border-secondary bg-secondary/5 hover:bg-secondary/10 disabled:opacity-50 disabled:cursor-not-allowed px-2.5 py-1 rounded-md transition-all font-bold cursor-pointer select-none flex-shrink-0 animate-fade-in"
                >
                  <component
                    :is="isTidyingMemory ? Loader2Icon : SparklesIcon"
                    class="w-3.5 h-3.5"
                    :class="{ 'animate-spin': isTidyingMemory }"
                  />
                  <span>{{ isTidyingMemory ? '整理中...' : '整理记忆' }}</span>
                </button>
                <button
                  @click="brainEditModes.memory = !brainEditModes.memory"
                  class="flex items-center space-x-1 text-xs text-primary border border-primary/20 hover:border-primary bg-primary/5 hover:bg-primary/10 px-2.5 py-1 rounded-md transition-all font-bold cursor-pointer select-none flex-shrink-0"
                >
                  <component :is="brainEditModes.memory ? EyeIcon : PenLineIcon" class="w-3.5 h-3.5" />
                  <span>{{ brainEditModes.memory ? '预览记忆' : '修改记忆' }}</span>
                </button>
              </div>
            </div>
            <!-- 预览 -->
            <div
              v-if="!brainEditModes.memory"
              class="flex-1 p-4 rounded-lg border border-outline-variant bg-surface text-xs leading-relaxed overflow-y-auto select-text markdown-body shadow-sm"
              v-html="renderMarkdown(brainMemoryContent || '*记忆为空*')"
            ></div>
            <!-- 编辑 -->
            <textarea
              v-else
              v-model="brainMemoryContent"
              class="flex-1 w-full font-mono text-xs bg-surface border border-outline-variant rounded-lg p-3 focus:outline-none focus:border-primary resize-none text-on-surface overflow-y-auto shadow-inner"
            ></textarea>
          </div>

          <div v-else-if="brainActiveTab === 'summary'" class="flex-1 flex flex-col min-h-0">
            <div class="flex items-center justify-between mb-2 flex-shrink-0">
              <div class="text-[10px] text-on-surface-variant font-mono">SUMMARY.md · 群聊大事记简报</div>
              <button
                @click="brainEditModes.summary = !brainEditModes.summary"
                class="flex items-center space-x-1 text-xs text-primary border border-primary/20 hover:border-primary bg-primary/5 hover:bg-primary/10 px-2.5 py-1 rounded-md transition-all font-bold cursor-pointer select-none flex-shrink-0"
              >
                <component :is="brainEditModes.summary ? EyeIcon : PenLineIcon" class="w-3.5 h-3.5" />
                <span>{{ brainEditModes.summary ? '预览大事记' : '修改大事记' }}</span>
              </button>
            </div>
            <!-- 预览 -->
            <div
              v-if="!brainEditModes.summary"
              class="flex-1 p-4 rounded-lg border border-outline-variant bg-surface text-xs leading-relaxed overflow-y-auto select-text markdown-body shadow-sm"
              v-html="renderMarkdown(brainSummaryContent || '*暂无大事记简报*')"
            ></div>
            <!-- 编辑 -->
            <textarea
              v-else
              v-model="brainSummaryContent"
              class="flex-1 w-full font-mono text-xs bg-surface border border-outline-variant rounded-lg p-3 focus:outline-none focus:border-primary resize-none text-on-surface overflow-y-auto shadow-inner"
            ></textarea>
          </div>

          <div v-else-if="brainActiveTab === 'charUser'" class="flex-1 flex flex-col min-h-0">
            <div class="flex items-center justify-between mb-2 flex-shrink-0">
              <div class="text-[10px] text-on-surface-variant font-mono">USER.md · 角色专属用户画像</div>
              <button
                @click="brainEditModes.charUser = !brainEditModes.charUser"
                class="flex items-center space-x-1 text-xs text-primary border border-primary/20 hover:border-primary bg-primary/5 hover:bg-primary/10 px-2.5 py-1 rounded-md transition-all font-bold cursor-pointer select-none flex-shrink-0"
              >
                <component :is="brainEditModes.charUser ? EyeIcon : PenLineIcon" class="w-3.5 h-3.5" />
                <span>{{ brainEditModes.charUser ? '预览侧写' : '修改侧写' }}</span>
              </button>
            </div>
            <!-- 预览 -->
            <div
              v-if="!brainEditModes.charUser"
              class="flex-1 p-4 rounded-lg border border-outline-variant bg-surface text-xs leading-relaxed overflow-y-auto select-text markdown-body shadow-sm"
              v-html="renderMarkdown(brainCharUserContent || '*暂无专属画像侧写事实*')"
            ></div>
            <!-- 编辑 -->
            <textarea
              v-else
              v-model="brainCharUserContent"
              class="flex-1 w-full font-mono text-xs bg-surface border border-outline-variant rounded-lg p-3 focus:outline-none focus:border-primary resize-none text-on-surface overflow-y-auto shadow-inner"
            ></textarea>
          </div>

          <div class="flex justify-end space-x-2 mt-4 flex-shrink-0">
            <button @click="showBrainPanel = false" class="btn-secondary">关闭</button>
            <button @click="saveBrainFiles" class="btn-primary flex items-center space-x-1.5">
              <SaveIcon class="w-3.5 h-3.5" />
              <span>保存并生效</span>
            </button>
          </div>
        </div>
      </div>
    </div>

    <!-- ========================= 弹窗：日记 ========================= -->
    <div
      v-if="showDiaryPanel && (activeCharacter || selectedContactId)"
      class="modal-overlay"
      @click.self="showDiaryPanel = false"
    >
      <div class="modal-panel w-[660px] h-[480px] flex flex-col">
        <div class="modal-header flex-shrink-0">
          <div class="flex items-center space-x-2">
            <FileLockIcon class="w-4 h-4 text-secondary" />
            <span
              >{{ activeCharacter?.name || characterList.find(c => c.id === selectedContactId)?.name }} · 日记簿</span
            >
          </div>
          <button @click="showDiaryPanel = false" class="modal-close-btn"><XIcon class="w-4 h-4" /></button>
        </div>
        <div class="flex-1 flex min-h-0 bg-surface">
          <!-- 左侧日记列表 -->
          <div class="w-1/3 border-r border-outline-variant bg-surface-low overflow-y-auto flex flex-col p-2 space-y-1">
            <!-- 手动触发写日记魔法按钮 -->
            <button
              @click="triggerManualDiary"
              :disabled="isWritingDiary"
              class="w-full text-center px-3 py-2 rounded-lg border border-primary/20 hover:border-primary bg-primary/5 hover:bg-primary/10 text-primary text-xs font-bold transition-all flex items-center justify-center space-x-1.5 mb-2 cursor-pointer disabled:opacity-40 select-none flex-shrink-0"
            >
              <SparklesIcon class="w-3.5 h-3.5 flex-shrink-0 animate-pulse text-primary" />
              <span>{{ isWritingDiary ? '自省落笔中...' : '让 TA 写一篇' }}</span>
            </button>

            <div v-if="parsedDiariesList.length === 0" class="text-center py-12 text-xs text-on-surface-variant/40">
              暂无日记
            </div>
            <button
              v-for="(diary, idx) in parsedDiariesList"
              :key="idx"
              @click="selectedDiaryIdx = idx"
              class="w-full text-left px-3 py-2.5 rounded-lg transition-all flex items-center space-x-2"
              :class="
                selectedDiaryIdx === idx
                  ? 'bg-primary text-on-primary font-bold shadow-md'
                  : 'text-on-surface-variant hover:bg-surface-high/60'
              "
            >
              <PenToolIcon class="w-3.5 h-3.5 flex-shrink-0 opacity-70" />
              <span class="truncate text-xs tracking-wide">{{ diary.date }}</span>
            </button>
          </div>
          <!-- 右侧日记正文 -->
          <div class="flex-1 p-5 overflow-y-auto flex flex-col bg-surface-lowest">
            <div
              v-if="parsedDiariesList.length === 0"
              class="flex-1 flex flex-col items-center justify-center text-center text-on-surface-variant/40"
            >
              <FileLockIcon class="w-12 h-12 mb-3 opacity-25" />
              <p class="text-sm font-semibold">寂静如水</p>
              <p class="text-xs mt-1">角色最早也要在17点之后才会写日记</p>
            </div>
            <div v-else-if="parsedDiariesList[selectedDiaryIdx]" class="flex-1 flex flex-col">
              <div class="pb-2 border-b border-outline-variant/60 flex items-center justify-between flex-shrink-0">
                <div class="text-sm font-bold text-on-surface flex items-center space-x-2">
                  <CalendarIcon class="w-3.5 h-3.5 text-primary" />
                  <span>{{ parsedDiariesList[selectedDiaryIdx].date }}</span>
                </div>
                <!-- 右上角操作按钮组 -->
                <div class="flex items-center space-x-1.5">
                  <!-- 收藏日记按钮 -->
                  <button
                    @click="toggleFavoriteDiary(parsedDiariesList[selectedDiaryIdx])"
                    class="px-2.5 py-1 rounded-lg border text-[10px] font-bold flex items-center space-x-1 transition-all active:scale-95 cursor-pointer"
                    :class="
                      parsedDiariesList[selectedDiaryIdx].isFavorited
                        ? 'bg-yellow-500/10 border-yellow-500/30 text-yellow-600'
                        : 'bg-surface border-outline-variant text-on-surface-variant hover:text-yellow-500'
                    "
                  >
                    <BookmarkIcon
                      class="w-3 h-3"
                      :class="{ 'fill-yellow-500': parsedDiariesList[selectedDiaryIdx].isFavorited }"
                    />
                    <span>{{ parsedDiariesList[selectedDiaryIdx].isFavorited ? '已收藏' : '收藏日记' }}</span>
                  </button>
                  <!-- 删除当前篇日记按钮 -->
                  <button
                    @click="deleteDiaryEntry(parsedDiariesList[selectedDiaryIdx])"
                    class="px-2.5 py-1 rounded-lg border border-outline-variant text-[10px] font-bold flex items-center space-x-1 transition-all active:scale-95 cursor-pointer bg-surface text-on-surface-variant hover:bg-red-500/10 hover:border-red-500/30 hover:text-red-500"
                    title="删除这篇日记"
                  >
                    <TrashIcon class="w-3 h-3" />
                    <span>删除</span>
                  </button>
                </div>
              </div>
              <!-- 亮色纸张书卷风 / 暗色 Tech-Noir 风格 -->
              <div
                class="mt-4 flex-1 p-4 rounded-xl leading-relaxed text-sm shadow-inner overflow-y-auto border border-outline-variant transition-all font-serif whitespace-pre-wrap"
                :class="
                  isDark ? 'bg-surface-low text-on-surface font-mono' : 'bg-[#faf6ee] text-[#433527] border-[#e8dfd5]'
                "
              >
                {{ parsedDiariesList[selectedDiaryIdx].content }}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>

    <!-- ========================= 弹窗：吐槽大会 ========================= -->
    <div
      v-if="showRoastPanel && activeCharacter"
      class="modal-overlay"
      @click.self="showRoastPanel = false"
    >
      <div class="modal-panel w-[520px] h-[580px] flex flex-col overflow-hidden animate-scale-up rounded-2xl border border-outline-variant/30 shadow-2xl bg-surface">
        <!-- 头部：自适应明暗模式，呼吸感 Padding -->
        <div class="modal-header flex-shrink-0 px-6 py-4.5 border-b border-outline-variant/30">
          <div class="flex items-center space-x-3">
            <div class="w-8 h-8 rounded-lg bg-rose-500/10 flex items-center justify-center text-rose-500 shadow-inner">
              <MaskIcon class="w-4.5 h-4.5" />
            </div>
            <div>
              <span class="text-xs font-bold text-on-surface tracking-wide">
                {{ activeCharacter.name }}
              </span>
              <span class="text-[10px] text-on-surface-variant/50 ml-1 font-mono tracking-wider">· 戏外吐槽大会</span>
            </div>
          </div>
          <button
            @click="showRoastPanel = false"
            class="modal-close-btn hover:bg-surface-high/60 p-1.5 rounded-lg transition-colors"
          >
            <XIcon class="w-4 h-4" />
          </button>
        </div>

        <!-- 吐槽历史混合流时间线：精致的渐变背景与呼吸感的卡片间距 -->
        <div class="flex-1 overflow-y-auto p-6 space-y-4 bg-gradient-to-b from-surface-low to-surface/30 custom-scrollbar min-h-0">
          <div v-if="roastHistory.length === 0 && !isRoastGenerating" class="h-full flex flex-col items-center justify-center text-center p-6">
            <div class="w-16 h-16 rounded-full bg-on-surface-variant/5 flex items-center justify-center mb-3 text-on-surface-variant/20 shadow-inner">
              <MaskIcon class="w-8 h-8" />
            </div>
            <p class="text-xs text-on-surface-variant/60 font-mono">当前没有任何吐槽发言记录</p>
            <p class="text-[10px] text-on-surface-variant/40 mt-1 font-mono">在下方选择你期待的演员人格，邀请其登台吐槽！</p>
          </div>

          <div v-else class="space-y-4">
            <!-- 生成中的骨架屏 -->
            <div
              v-if="isRoastGenerating"
              class="p-4 bg-surface border border-outline-variant/40 rounded-xl space-y-2.5 animate-pulse shadow-sm"
            >
              <div class="flex items-center justify-between">
                <div class="h-4 w-14 bg-surface-high rounded"></div>
                <div class="h-3 w-16 bg-surface-high rounded"></div>
              </div>
              <div class="space-y-1.5 pt-1">
                <div class="h-3.5 w-full bg-surface-high rounded"></div>
                <div class="h-3.5 w-5/6 bg-surface-high rounded"></div>
              </div>
            </div>

            <!-- 历史吐槽卡片：圆角升级、加入微阴影 -->
            <div
              v-for="roast in roastHistory"
              :key="roast.id"
              class="p-4 bg-surface/95 border border-outline-variant/35 rounded-xl shadow-[0_2px_8px_rgba(0,0,0,0.015)] dark:shadow-[0_4px_12px_rgba(0,0,0,0.15)] hover:shadow-md hover:border-outline-variant/65 transition-all duration-300 flex flex-col space-y-2"
            >
              <!-- 卡片头部：Badge + 时间 -->
              <div class="flex items-center justify-between select-none">
                <span
                  class="px-2 py-0.5 text-[9px] font-bold rounded-md font-mono"
                  :class="getRoastModeInfo(roast.inner_thought).color"
                >
                  {{ getRoastModeInfo(roast.inner_thought).text }}
                </span>
                <span class="text-[9px] text-on-surface-variant/45 font-mono">
                  {{ new Date(roast.timestamp).toLocaleString('zh-CN', { hour: '2-digit', minute: '2-digit', second: '2-digit' }) }}
                </span>
              </div>
              <!-- 卡片正文 -->
              <p class="text-xs leading-relaxed text-on-surface whitespace-pre-wrap font-sans break-words select-text">
                {{ roast.content }}
              </p>
            </div>
          </div>
        </div>

        <!-- 底部操作区：呼吸感的 P-6 padding、加深间距 -->
        <div class="p-6 border-t border-outline-variant/30 bg-surface flex-shrink-0 flex flex-col space-y-4">
          <!-- 极简模式切换 Tab 键：更大的 Tab 舒适区 -->
          <div class="flex items-center bg-surface-low border border-outline-variant/40 p-1 rounded-xl shadow-inner">
            <button
              @click="selectedRoastMode = 'praise'"
              class="flex-1 py-1.5 text-xs transition-all cursor-pointer rounded-lg select-none text-center"
              :class="selectedRoastMode === 'praise' ? 'bg-amber-500/15 text-amber-600 dark:text-amber-400 font-bold border border-amber-500/20 shadow-sm' : 'bg-transparent text-on-surface-variant/50 hover:text-on-surface border border-transparent'"
            >
              💎 赞美版
            </button>
            <button
              @click="selectedRoastMode = 'calm'"
              class="flex-1 py-1.5 text-xs transition-all cursor-pointer rounded-lg select-none text-center"
              :class="selectedRoastMode === 'calm' ? 'bg-emerald-500/15 text-emerald-600 dark:text-emerald-400 font-bold border border-emerald-500/20 shadow-sm' : 'bg-transparent text-on-surface-variant/50 hover:text-on-surface border border-transparent'"
            >
              🧊 冷静版
            </button>
            <button
              @click="selectedRoastMode = 'angry'"
              class="flex-1 py-1.5 text-xs transition-all cursor-pointer rounded-lg select-none text-center"
              :class="selectedRoastMode === 'angry' ? 'bg-rose-500/15 text-rose-600 dark:text-rose-400 font-bold border border-rose-500/20 shadow-sm' : 'bg-transparent text-on-surface-variant/50 hover:text-on-surface border border-transparent'"
            >
              🔥 暴躁版
            </button>
          </div>

          <!-- 发起吐槽按钮：高阶微缩阴影动效 -->
          <button
            @click="triggerAiRoast"
            :disabled="isRoastGenerating"
            class="w-full py-2.5 bg-primary text-on-primary font-bold text-xs rounded-xl shadow-lg shadow-primary/10 hover:shadow-xl hover:shadow-primary/20 hover:-translate-y-0.5 active:translate-y-0 active:scale-98 transition-all duration-300 flex items-center justify-center space-x-2 disabled:opacity-50 disabled:pointer-events-none cursor-pointer tracking-wider font-mono"
          >
            <Loader2Icon v-if="isRoastGenerating" class="w-3.5 h-3.5 animate-spin" />
            <span v-else class="text-xs">🎭</span>
            <span>{{ isRoastGenerating ? 'AI 演员正在拿麦上台...' : '邀请 AI 演员登台吐槽' }}</span>
          </button>
        </div>
      </div>
    </div>

    <!-- ========================= 弹窗：创建群聊 ========================= -->
    <div v-if="showCreateGroupModal" class="modal-overlay" @click.self="showCreateGroupModal = false">
      <div
        class="modal-panel w-[380px] rounded-2xl overflow-hidden shadow-2xl border border-outline-variant/30 bg-surface-container-lowest animate-fade-in select-none"
      >
        <!-- 头部：极简冷白毛玻璃质感 -->
        <div
          class="flex items-center justify-between px-5 py-4 border-b border-outline-variant/30 bg-surface-container-high/60 backdrop-blur-md"
        >
          <div class="flex items-center space-x-2.5">
            <div class="w-7 h-7 rounded-lg bg-primary/10 flex items-center justify-center text-primary shadow-inner">
              <UsersIcon class="w-4 h-4" stroke-width="2" />
            </div>
            <div>
              <h3 class="font-bold text-xs text-on-surface tracking-tight leading-normal">发起群聊</h3>
              <p class="text-[9px] text-on-surface-variant/50">不完善的测试功能</p>
            </div>
          </div>
          <button
            @click="showCreateGroupModal = false"
            class="w-6 h-6 rounded-full hover:bg-surface-high text-on-surface-variant/60 hover:text-on-surface flex items-center justify-center transition-all focus:outline-none"
          >
            <XIcon class="w-3.5 h-3.5" />
          </button>
        </div>

        <div class="p-5 space-y-4">
          <!-- 1. 群名输入框 -->
          <div class="space-y-1.5">
            <label class="text-[10px] uppercase font-bold text-on-surface-variant/70 font-mono tracking-wider"
              >群聊名称</label
            >
            <input
              v-model="newGroupName"
              type="text"
              max="20"
              class="w-full bg-surface border border-outline-variant/60 hover:border-outline focus:border-primary focus:ring-4 focus:ring-primary/10 rounded-xl px-3 py-2 text-xs text-on-surface transition-all duration-200 outline-none placeholder:text-on-surface-variant/30 shadow-inner"
              placeholder="请输入群聊名称"
            />
          </div>

          <!-- 2. 群成员多选与极速搜索 -->
          <div class="space-y-1.5">
            <div class="flex justify-between items-center">
              <label class="text-[10px] uppercase font-bold text-on-surface-variant/70 font-mono tracking-wider"
                >选择群成员（最多3个）</label
              >
              <span class="text-xs font-bold text-primary font-mono bg-primary/5 px-1.5 py-0.5 rounded"
                >{{ selectedGroupMembers.length }}/3</span
              >
            </div>

            <!-- 精美微型搜索栏 -->
            <div class="relative flex items-center">
              <SearchIcon class="absolute left-2.5 w-3.5 h-3.5 text-on-surface-variant/40" />
              <input
                v-model="groupMemberSearchQuery"
                type="text"
                class="w-full bg-surface border border-outline-variant/30 focus:border-primary focus:ring-2 focus:ring-primary/5 rounded-lg pl-8 pr-7 py-1.5 text-[10px] text-on-surface transition-all outline-none placeholder:text-on-surface-variant/40"
                placeholder="搜索备选 AI 成员名字..."
              />
              <button
                v-if="groupMemberSearchQuery"
                @click="groupMemberSearchQuery = ''"
                class="absolute right-2.5 w-4 h-4 text-on-surface-variant/50 hover:text-on-surface flex items-center justify-center rounded-full hover:bg-surface-high transition-colors focus:outline-none"
              >
                <XIcon class="w-2.5 h-2.5" />
              </button>
            </div>

            <!-- 成员滚动面板 -->
            <div
              class="max-h-[180px] overflow-y-auto border border-outline-variant/30 rounded-xl p-2 space-y-1.5 bg-surface-low/50"
            >
              <div
                v-for="char in filteredGroupMembers"
                :key="char.id"
                class="flex items-center justify-between p-2 rounded-xl transition-all duration-200 select-none border border-transparent"
                :class="
                  selectedGroupMembers.includes(char.id) ? 'bg-primary/5 border-primary/10' : 'hover:bg-surface-high/60'
                "
              >
                <div class="flex items-center space-x-2.5 min-w-0">
                  <div
                    class="w-7 h-7 rounded-lg overflow-hidden border border-outline-variant/30 flex-shrink-0 bg-surface shadow-sm relative ring-1 ring-outline-variant/10"
                  >
                    <img
                      v-if="characterAvatars[char.id]"
                      :src="characterAvatars[char.id]"
                      class="w-full h-full object-cover"
                    />
                  </div>
                  <div class="flex items-center space-x-2 min-w-0">
                    <span class="text-xs font-semibold text-on-surface truncate">{{ char.name }}</span>
                  </div>
                </div>
                <!-- 微信圆形勾选框 -->
                <button
                  @click="
                    selectedGroupMembers.includes(char.id)
                      ? (selectedGroupMembers = selectedGroupMembers.filter(id => id !== char.id))
                      : selectedGroupMembers.length < 3 && selectedGroupMembers.push(char.id)
                  "
                  class="w-[18px] h-[18px] rounded-full border flex items-center justify-center transition-all duration-200 focus:outline-none flex-shrink-0"
                  :class="
                    selectedGroupMembers.includes(char.id)
                      ? 'border-primary bg-primary text-white scale-105 shadow-sm shadow-primary/20'
                      : 'border-outline-variant/80 bg-surface hover:border-outline'
                  "
                  :disabled="selectedGroupMembers.length >= 3 && !selectedGroupMembers.includes(char.id)"
                >
                  <CheckIcon
                    v-if="selectedGroupMembers.includes(char.id)"
                    class="w-2.5 h-2.5 text-white"
                    stroke-width="3"
                  />
                </button>
              </div>
            </div>
          </div>

          <!-- 3. 时空融合温馨贴士 -->
          <div
            class="text-[9px] text-primary/80 leading-relaxed bg-primary/5 p-3 rounded-xl border border-primary/10 flex items-start space-x-2"
          >
            <SparklesIcon class="w-3.5 h-3.5 text-primary flex-shrink-0 mt-0.5 animate-pulse" />
            <span>【群聊功能说明】：群聊模式将被强制锁定为 **「包含描写」** 模式，以确保群聊内容更具张力。</span>
          </div>

          <!-- 4. 动作按钮 -->
          <div class="flex justify-end space-x-2.5 pt-1.5">
            <button
              @click="showCreateGroupModal = false"
              class="border border-outline-variant/60 hover:border-outline text-on-surface-variant hover:bg-surface-container-high rounded-xl py-1.5 px-4 text-xs font-medium active:scale-95 transition-all duration-200 focus:outline-none"
            >
              取消
            </button>
            <button
              @click="createGroupChatAction"
              class="bg-primary hover:bg-primary-container text-white rounded-xl py-1.5 px-4 text-xs font-bold active:scale-95 shadow-md shadow-primary/10 hover:shadow-lg hover:shadow-primary/20 hover:-translate-y-0.5 transition-all duration-200 focus:outline-none"
            >
              创建群聊
            </button>
          </div>
        </div>
      </div>
    </div>

    <!-- ========================= 弹窗：修改群名称 ========================= -->
    <div v-if="showEditGroupNameModal" class="modal-overlay" @click.self="showEditGroupNameModal = false">
      <div
        class="modal-panel w-[320px] rounded-2xl overflow-hidden shadow-2xl border bg-surface animate-fade-in select-none"
      >
        <div class="modal-header">
          <div class="flex items-center space-x-2">
            <PenIcon class="w-4 h-4 text-primary" />
            <span class="font-bold text-sm text-on-surface">修改群名称</span>
          </div>
          <button @click="showEditGroupNameModal = false" class="modal-close-btn">
            <XIcon class="w-4 h-4" />
          </button>
        </div>
        <div class="p-5 space-y-4">
          <div class="form-group">
            <label class="form-label text-[10px] uppercase font-bold text-on-surface-variant font-mono">新群名称</label>
            <input
              v-model="editGroupNameVal"
              type="text"
              max="20"
              class="form-input text-xs"
              placeholder="请输入新的群名称..."
            />
          </div>
          <div class="flex justify-end space-x-2 pt-1">
            <button
              @click="showEditGroupNameModal = false"
              class="btn-secondary text-xs py-1.5 px-4 rounded-lg active:scale-95 transition-all duration-200"
            >
              取消
            </button>
            <button
              @click="saveGroupNameAction"
              class="btn-primary text-xs py-1.5 px-4 rounded-lg active:scale-95 transition-all duration-200"
            >
              保存
            </button>
          </div>
        </div>
      </div>
    </div>

    <!-- ========================= 弹窗：红包 ========================= -->
    <div v-if="showRedPacketModal" class="modal-overlay" @click.self="showRedPacketModal = false">
      <div
        class="modal-panel w-[320px] rounded-2xl overflow-hidden shadow-2xl border bg-surface animate-fade-in select-none"
      >
        <div class="modal-header bg-gradient-to-r from-[#f25542] to-[#da3f2d] text-white">
          <div class="flex items-center space-x-2">
            <span class="text-lg">🧧</span><span class="font-bold text-sm text-[#fcedc4]">发红包</span>
          </div>
          <button
            @click="showRedPacketModal = false"
            class="text-[#fcedc4] hover:text-white hover:scale-115 transition-all"
          >
            <XIcon class="w-4 h-4" />
          </button>
        </div>
        <div class="p-5 space-y-4">
          <!-- 群聊红包类型切换 -->
          <div v-if="isGroupActive" class="form-group">
            <label class="form-label text-[10px] uppercase font-bold text-on-surface-variant font-mono">红包类型</label>
            <div class="flex items-center space-x-4 mt-1">
              <label class="flex items-center space-x-1 cursor-pointer text-xs">
                <input
                  type="radio"
                  value="normal"
                  v-model="groupRedPacketType"
                  class="text-primary focus:ring-primary"
                />
                <span>普通群红包</span>
              </label>
              <label class="flex items-center space-x-1 cursor-pointer text-xs">
                <input
                  type="radio"
                  value="exclusive"
                  v-model="groupRedPacketType"
                  class="text-primary focus:ring-primary"
                />
                <span>专属红包</span>
              </label>
            </div>
          </div>

          <!-- 专属红包指定成员 -->
          <div
            v-if="isGroupActive && groupRedPacketType === 'exclusive'"
            class="form-group animate-in slide-in-from-top-1 duration-200"
          >
            <label class="form-label text-[10px] uppercase font-bold text-on-surface-variant font-mono"
              >指定领取人</label
            >
            <div class="relative">
              <button
                @click.stop="showExclusiveDropdown = !showExclusiveDropdown"
                @blur="hideExclusiveDropdownDelayed"
                class="form-input text-xs text-left w-full flex items-center justify-between cursor-pointer select-none active:scale-[0.99] transition-all mt-1"
              >
                <span :class="{ 'text-on-surface-variant/60': !groupRedPacketTargetId }">
                  {{
                    groupRedPacketTargetId
                      ? getSenderInfo(groupRedPacketTargetId).name || '未命名成员'
                      : '请选择群成员...'
                  }}
                </span>
                <ChevronDownIcon
                  class="w-3.5 h-3.5 text-on-surface-variant transition-transform duration-200"
                  :class="{ 'rotate-180': showExclusiveDropdown }"
                />
              </button>

              <!-- 自定义毛玻璃成员选择面板 -->
              <div
                v-if="showExclusiveDropdown"
                class="absolute left-0 right-0 top-full mt-1.5 rounded-xl border border-outline-variant bg-surface-high/90 backdrop-blur-xl shadow-xl py-1 z-30 select-none animate-in fade-in slide-in-from-top-1.5 duration-150 max-h-48 overflow-y-auto"
              >
                <div
                  v-for="charId in activeGroupChatMembers"
                  :key="charId"
                  @mousedown="
                    groupRedPacketTargetId = charId;
                    showExclusiveDropdown = false;
                  "
                  class="px-3.5 py-2 text-xs text-on-surface hover:bg-primary/10 hover:text-primary transition-all flex items-center justify-between cursor-pointer"
                  :class="{ 'bg-primary/5 text-primary font-semibold': groupRedPacketTargetId === charId }"
                >
                  <span>{{ getSenderInfo(charId).name }}</span>
                  <CheckIcon
                    v-if="groupRedPacketTargetId === charId"
                    class="w-3.5 h-3.5 text-primary"
                    stroke-width="2.5"
                  />
                </div>
              </div>
            </div>
          </div>

          <div class="form-group">
            <label class="form-label text-[10px] uppercase font-bold text-on-surface-variant font-mono"
              >红包金额（元）</label
            >
            <input
              v-model.number="redPacketAmount"
              type="number"
              min="0.01"
              step="0.01"
              max="999999"
              class="form-input text-xs"
              placeholder="请输入金额"
            />
          </div>
          <div class="form-group">
            <label class="form-label text-[10px] uppercase font-bold text-on-surface-variant font-mono"
              >附言/祝福语</label
            >
            <input
              v-model="redPacketTitle"
              type="text"
              max="30"
              class="form-input text-xs"
              placeholder="恭喜发财，大吉大利"
            />
          </div>
          <div
            class="text-[10px] text-on-surface-variant/80 leading-normal bg-surface-low p-2.5 rounded-lg border border-outline-variant/30"
          >
            <template v-if="isGroupActive && groupRedPacketType === 'normal'">
              普通红包将分发给群内 <span class="text-primary font-bold">{{ activeGroupChatMembers.length }}</span> 位 AI
              角色。 共需扣除：<span class="text-error font-bold"
                >{{ (activeGroupChatMembers.length * (redPacketAmount || 0)).toFixed(2) }} 元</span
              >
            </template>
            <template v-else>
              扣减您的虚拟回音币，单份金额：<span class="text-primary font-bold"
                >{{ (redPacketAmount || 0).toFixed(2) }} 元</span
              >
            </template>
            <div class="mt-1 opacity-75">
              当前钱包余额：<span class="text-primary font-semibold"
                >{{ userProfile.walletBalance.toFixed(2) }} 元</span
              >
            </div>
          </div>
          <div class="flex justify-end space-x-2 pt-1">
            <button @click="showRedPacketModal = false" class="btn-secondary text-xs py-1.5 px-4 rounded-lg">
              取消
            </button>
            <button
              @click="sendRedPacket"
              class="btn-primary bg-gradient-to-r from-[#f25542] to-[#da3f2d] hover:opacity-90 text-[#fcedc4] font-bold border-none text-xs py-1.5 px-4 rounded-lg shadow-md active:scale-95 transition-all"
            >
              塞红包
            </button>
          </div>
        </div>
      </div>
    </div>

    <!-- ========================= 弹窗：拆回音红包 ========================= -->
    <div
      v-if="showReceiveRedPacketModal && activeReceivingRedPacketMsg"
      class="modal-overlay bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center animate-fade-in"
      @click.self="showReceiveRedPacketModal = false"
    >
      <div
        class="bg-[#da4735] w-[280px] h-[370px] rounded-2xl relative flex flex-col items-center justify-between p-6 text-white shadow-2xl overflow-hidden border border-[#ef5644] select-none"
      >
        <!-- 微信红包顶部好看的半圆翻盖背景切线装饰 -->
        <div
          class="absolute top-0 left-0 right-0 h-[120px] bg-[#d23d2b] rounded-b-[140px] shadow-md border-b border-black/5 z-0"
        ></div>

        <!-- 关闭小按钮 -->
        <button
          @click="showReceiveRedPacketModal = false"
          class="absolute top-4 right-4 text-white/60 hover:text-white/90 hover:scale-110 transition-all z-20 text-sm font-bold font-mono"
        >
          ✕
        </button>

        <div class="flex flex-col items-center mt-6 z-10 w-full">
          <!-- 发红包角色的头像 -->
          <div
            class="w-12 h-12 rounded-full border-2 border-[#fcedc4] bg-surface flex-shrink-0 flex items-center justify-center overflow-hidden shadow-md"
          >
            <img
              v-if="
                redPacketSender &&
                (redPacketSender.id === 'user' ? redPacketSender.avatar : characterAvatars[redPacketSender.id])
              "
              :src="redPacketSender.id === 'user' ? redPacketSender.avatar : characterAvatars[redPacketSender.id]"
              class="w-full h-full object-cover"
            />
            <span v-else class="text-stone-800 text-sm font-bold">👤</span>
          </div>

          <!-- 角色名 + 提示 -->
          <div class="text-xs font-bold text-[#fcedc4] mt-2.5 drop-shadow-sm">
            {{ redPacketSender?.name || '神秘成员' }}
          </div>
          <div class="text-[10px] text-white/80 mt-1">给你发了一个回音红包</div>

          <!-- 祝福附言 -->
          <div class="text-sm font-black mt-6 text-[#fcedc4] max-w-[210px] text-center leading-relaxed italic truncate">
            “ {{ activeReceivingRedPacketMsg.redPacket.title || '恭喜发财，大吉大利' }} ”
          </div>
        </div>

        <!-- 极其炫酷的金色圆形「 拆 」字旋转按钮 -->
        <div class="z-10 mb-8 flex flex-col items-center justify-center">
          <button
            @click="openCharacterRedPacket"
            class="w-[72px] h-[72px] rounded-full bg-[#fcedc4] hover:bg-[#fae6b4] text-[#cf3c2a] font-extrabold text-2xl flex items-center justify-center cursor-pointer shadow-xl border-4 border-[#cf3c2a] active:scale-95 transition-all select-none"
            :class="{ 'animate-spin': isOpeningRedPacket }"
            title="拆红包"
          >
            {{ isOpeningRedPacket ? '↻' : '拆' }}
          </button>
          <div class="text-[9px] text-white/50 mt-3">
            金额：{{ parseFloat(activeReceivingRedPacketMsg.redPacket.amount).toFixed(2) }} 元
          </div>
        </div>
      </div>
    </div>

    <!-- ========================= 弹窗：添加自定义表情 (统一批量与单张) ========================= -->
    <div v-if="showBatchEmojiModal" class="modal-overlay z-[99999]" @click.self="showBatchEmojiModal = false">
      <div
        class="modal-panel p-5 space-y-4 animate-fade-in shadow-2xl rounded-2xl border bg-surface select-none transition-all duration-300"
        :class="batchEmojiList.length === 1 ? 'w-[320px]' : 'w-[520px] max-w-[95vw]'"
      >
        <div class="text-center font-bold text-xs text-on-surface">
          {{ batchEmojiList.length === 1 ? '添加自定义表情' : `批量添加自定义表情 (${batchEmojiList.length} 张)` }}
        </div>

        <!-- 表情列表网格 -->
        <div
          class="pr-1 py-1"
          :class="
            batchEmojiList.length === 1
              ? 'flex flex-col space-y-3'
              : 'grid grid-cols-1 sm:grid-cols-2 gap-4 overflow-y-auto max-h-[380px] min-h-0'
          "
        >
          <div
            v-for="(item, index) in batchEmojiList"
            :key="item.id"
            class="flex items-center space-x-3.5 p-3.5 rounded-xl border border-outline-variant bg-surface-low relative group shadow-sm"
          >
            <!-- 左侧：图片预览 -->
            <div
              class="w-16 h-16 rounded-xl border border-outline-variant bg-surface p-1.5 flex items-center justify-center shadow-inner overflow-hidden relative flex-shrink-0"
            >
              <img :src="item.base64" class="max-w-full max-h-full object-contain pointer-events-none select-none" />
              <!-- 悬浮删除小按钮 -->
              <button
                @click="removeBatchEmojiItem(item.id)"
                class="absolute -top-1 -right-1 w-5 h-5 flex items-center justify-center rounded-full bg-error/95 hover:bg-error text-white text-[9px] font-bold shadow-md hover:scale-110 active:scale-95 transition-all select-none cursor-pointer"
                title="移除此项"
              >
                ✕
              </button>
            </div>
            <!-- 右侧：文字描述编辑 -->
            <div class="flex-1 min-w-0">
              <label class="block text-[8px] uppercase font-bold text-on-surface-variant font-mono mb-1 select-none"
                >表情描述 ({{ index + 1 }})</label
              >
              <input
                v-model="item.meaning"
                type="text"
                placeholder="表情文字含义 (如：得意)"
                class="form-input text-xs py-1.5 px-2.5 rounded-lg border border-outline-variant bg-surface focus:border-primary w-full"
                @keyup.enter="confirmAddBatchEmojis"
              />
            </div>
          </div>
        </div>

        <div class="flex justify-end space-x-2 pt-2.5 select-none border-t border-outline-variant/40">
          <button @click="showBatchEmojiModal = false" class="btn-secondary text-xs py-1.5 px-4 rounded-lg">
            取消
          </button>
          <button
            @click="confirmAddBatchEmojis"
            :disabled="isBatchImportDisabled"
            class="btn-primary text-xs py-1.5 px-4 font-bold rounded-lg disabled:opacity-40 disabled:cursor-not-allowed"
          >
            {{ batchEmojiList.length === 1 ? '确认添加' : '一键导入' }}
          </button>
        </div>
      </div>
    </div>

    <!-- ========================= 弹窗：修改消息内容 ========================= -->
    <div v-if="showEditMessageModal" class="modal-overlay z-[99999]" @click.self="showEditMessageModal = false">
      <div
        class="modal-panel w-[420px] p-5 space-y-4 animate-fade-in shadow-2xl rounded-2xl border bg-surface select-none"
      >
        <div class="text-center font-bold text-xs text-on-surface">修改消息内容</div>

        <div class="form-group">
          <label class="form-label text-[9px] uppercase font-bold text-on-surface-variant font-mono">
            {{ activeEditingMessage?.role === 'user' ? '修改我的发送内容' : '修改角色回复内容' }}
          </label>
          <textarea
            v-model="editingMessageText"
            rows="6"
            placeholder="请输入修改后的消息内容..."
            class="form-input text-xs w-full resize-none p-2 border rounded-lg bg-surface-low text-on-surface font-sans"
          ></textarea>
        </div>

        <div class="flex justify-end space-x-2 pt-1 select-none">
          <button @click="showEditMessageModal = false" class="btn-secondary text-xs py-1.5 px-4 rounded-lg">
            取消
          </button>
          <button
            @click="confirmEditMessage"
            :disabled="!editingMessageText.trim()"
            class="btn-primary text-xs py-1.5 px-4 font-bold rounded-lg disabled:opacity-40"
          >
            保存修改
          </button>
        </div>
      </div>
    </div>

    <!-- AI 角色导入确认弹窗 -->
    <CharacterPreviewModal
      ref="characterPreviewModalRef"
      :is-open="isPreviewOpen"
      :card-data="uploadedRawData"
      :pinyin-name="previewPinyinName"
      :soul-content="previewSoul"
      :world-content="previewWorld"
      :avatar-url="uploadedAvatarUrl"
      @confirm="onImportConfirm"
      @cancel="onImportCancel"
      @show-alert="showCustomAlert"
      @re-summarize="onReSummarize"
    />
    <!-- 角色专属聊天模式切换弹窗 -->
    <div
      v-if="showChatModeModal && (activeCharacter || isGroupActive)"
      class="modal-overlay z-[99999]"
      @click.self="showChatModeModal = false"
    >
      <div
        class="modal-panel max-w-sm w-full p-6 space-y-5 animate-fade-in shadow-2xl rounded-2xl border border-outline-variant/10 bg-surface/85 backdrop-blur-[30px] select-none text-on-surface"
      >
        <!-- 弹窗标题 -->
        <div class="flex items-center justify-between">
          <div class="flex items-center space-x-2.5">
            <div
              class="w-9 h-9 rounded-xl bg-primary/10 border border-primary/20 flex items-center justify-center text-primary"
            >
              <MessageSquareHeartIcon class="w-4 h-4" />
            </div>
            <div>
              <h3 class="text-[13px] font-bold">
                {{ isGroupActive ? activeGroupChat?.name : activeCharacter?.name }} 的聊天模式
              </h3>
              <p class="text-[9px] text-on-surface-variant/60 mt-0.5">
                {{ isGroupActive ? '群组模式独立保存，互不影响' : '每个角色独立保存，互不影响' }}
              </p>
            </div>
          </div>
          <button
            @click="showChatModeModal = false"
            class="p-1.5 rounded-lg hover:bg-surface-high text-on-surface-variant cursor-pointer"
          >
            <XIcon class="w-4 h-4" />
          </button>
        </div>

        <!-- 三个模式选择卡片 -->
        <div class="space-y-2.5">
          <!-- 纯文字对话 -->
          <button
            @click="setChatMode('dialogue')"
            class="w-full text-left p-4 rounded-2xl border-2 transition-all focus:outline-none cursor-pointer"
            :class="
              currentChatMode === 'dialogue'
                ? 'border-primary bg-primary/5'
                : 'border-outline-variant/40 hover:border-primary/40 hover:bg-surface-high'
            "
          >
            <div class="flex items-center space-x-3">
              <div
                class="w-8 h-8 rounded-xl flex items-center justify-center flex-shrink-0"
                :class="
                  currentChatMode === 'dialogue'
                    ? 'bg-primary/15 text-primary'
                    : 'bg-surface-high text-on-surface-variant'
                "
              >
                <MessageSquareIcon class="w-4 h-4" />
              </div>
              <div class="flex-1 min-w-0">
                <div class="flex items-center space-x-2">
                  <span
                    class="text-xs font-bold"
                    :class="currentChatMode === 'dialogue' ? 'text-primary' : 'text-on-surface'"
                    >仅对话</span
                  >
                  <span
                    v-if="currentChatMode === 'dialogue'"
                    class="text-[8px] px-1.5 py-0.5 rounded-md bg-primary text-white font-bold"
                    >当前</span
                  >
                </div>
                <p class="text-[9px] text-on-surface-variant/70 mt-0.5 leading-relaxed">
                  输出最直接的纯文字对话，轻松自然、干净简洁。
                </p>
              </div>
            </div>
          </button>

          <!-- 动作描写 -->
          <button
            @click="setChatMode('descriptive')"
            class="w-full text-left p-4 rounded-2xl border-2 transition-all focus:outline-none cursor-pointer"
            :class="
              currentChatMode === 'descriptive'
                ? 'border-primary bg-primary/5'
                : 'border-outline-variant/40 hover:border-primary/40 hover:bg-surface-high'
            "
          >
            <div class="flex items-center space-x-3">
              <div
                class="w-8 h-8 rounded-xl flex items-center justify-center flex-shrink-0"
                :class="
                  currentChatMode === 'descriptive'
                    ? 'bg-primary/15 text-primary'
                    : 'bg-surface-high text-on-surface-variant'
                "
              >
                <PenLineIcon class="w-4 h-4" />
              </div>
              <div class="flex-1 min-w-0">
                <div class="flex items-center space-x-2">
                  <span
                    class="text-xs font-bold"
                    :class="currentChatMode === 'descriptive' ? 'text-primary' : 'text-on-surface'"
                    >包含描写</span
                  >
                  <span
                    v-if="currentChatMode === 'descriptive'"
                    class="text-[8px] px-1.5 py-0.5 rounded-md bg-primary text-white font-bold"
                    >当前</span
                  >
                </div>
                <p class="text-[9px] text-on-surface-variant/70 mt-0.5 leading-relaxed">
                  回复中融合心理、神态及动作描写，极具沉浸感。
                </p>
              </div>
            </div>
          </button>

          <!-- 导演模式 -->
          <button
            v-if="!isGroupActive"
            @click="setChatMode('director')"
            class="w-full text-left p-4 rounded-2xl border-2 transition-all focus:outline-none cursor-pointer"
            :class="
              currentChatMode === 'director'
                ? 'border-primary bg-primary/5'
                : 'border-outline-variant/40 hover:border-primary/40 hover:bg-surface-high'
            "
          >
            <div class="flex items-center space-x-3">
              <div
                class="w-8 h-8 rounded-xl flex items-center justify-center flex-shrink-0"
                :class="
                  currentChatMode === 'director'
                    ? 'bg-primary/15 text-primary'
                    : 'bg-surface-high text-on-surface-variant'
                "
              >
                <BookOpenIcon class="w-4 h-4" />
              </div>
              <div class="flex-1 min-w-0">
                <div class="flex items-center space-x-2">
                  <span
                    class="text-xs font-bold"
                    :class="currentChatMode === 'director' ? 'text-primary' : 'text-on-surface'"
                    >导演模式</span
                  >
                  <span
                    v-if="currentChatMode === 'director'"
                    class="text-[8px] px-1.5 py-0.5 rounded-md bg-primary text-white font-bold"
                    >当前</span
                  >
                </div>
                <p class="text-[9px] text-on-surface-variant/70 mt-0.5 leading-relaxed">
                  全程第三人称视角撰写小说故事，使用 /开始 生成开场白。
                </p>
              </div>
            </div>
          </button>
        </div>

        <!-- 切换警告提示 -->
        <div class="flex items-start space-x-2 px-3 py-2.5 rounded-xl bg-amber-500/8 border border-amber-500/20">
          <svg
            class="w-3.5 h-3.5 text-amber-500 flex-shrink-0 mt-0.5"
            fill="none"
            viewBox="0 0 24 24"
            stroke-width="2"
            stroke="currentColor"
          >
            <path
              stroke-linecap="round"
              stroke-linejoin="round"
              d="M12 9v3.75m-9.303 3.376c-.866 1.5.217 3.374 1.948 3.374h14.71c1.73 0 2.813-1.874 1.948-3.374L13.949 3.378c-.866-1.5-3.032-1.5-3.898 0L2.697 16.126ZM12 15.75h.007v.008H12v-.008Z"
            />
          </svg>
          <p class="text-[9px] text-amber-600/90 leading-relaxed">
            建议不要在对话过程中切换聊天模式，可能会导致历史消息的显示与实际存储格式不一致。
          </p>
        </div>
      </div>
    </div>
    <!-- ========================= 全局自定义高保真数据备份还原模态框 ========================= -->

    <div v-if="showImportModal" class="modal-overlay z-[99999]" @click.self="showImportModal = false">
      <div
        class="modal-panel max-w-md w-full p-6 space-y-5 animate-fade-in shadow-2xl rounded-2xl border border-outline-variant/10 bg-surface/85 backdrop-blur-[30px] select-none text-on-surface"
      >
        <!-- 弹窗标题 -->
        <div class="flex items-center justify-between pb-1">
          <div class="flex items-center space-x-2.5">
            <div
              class="w-9 h-9 rounded-xl bg-primary/10 border border-primary/20 flex items-center justify-center text-primary"
            >
              <RefreshCwIcon class="w-4 h-4" />
            </div>
            <div>
              <h3 class="text-[13px] font-bold">全量导入备份还原</h3>
              <p class="text-[10px] text-on-surface-variant mt-0.5">
                {{ isDockerMode ? 'Docker 云端映射智能备份导入' : '回音系统高保真物理级覆盖' }}
              </p>
            </div>
          </div>
          <button
            @click="showImportModal = false"
            class="text-on-surface-variant/60 hover:text-on-surface transition-colors cursor-pointer select-none"
          >
            <XIcon class="w-4 h-4" />
          </button>
        </div>

        <!-- 统一的拖拽 & 点击文件上传区 -->
        <div
          @dragenter.prevent="isDraggingBackupFile = true"
          @dragover.prevent="isDraggingBackupFile = true"
          @dragleave.prevent="isDraggingBackupFile = false"
          @drop.prevent="onBackupFileDropped"
          @click="triggerBackupFileInput"
          class="border-2 border-dashed rounded-xl p-6 flex flex-col items-center justify-center cursor-pointer select-none transition-all duration-300 relative group"
          :class="[
            isDraggingBackupFile
              ? 'border-primary bg-primary/5 scale-[1.01] shadow-lg shadow-primary/5'
              : 'border-outline-variant/30 bg-surface-low/10 hover:border-primary/40 hover:bg-surface-low/30',
          ]"
        >
          <!-- 浏览器/Docker模式下隐藏的原生文件上传 Input 触发器 -->
          <input
            type="file"
            id="docker-backup-file-input"
            accept=".echo"
            class="hidden"
            @change="onDockerFileSelected"
          />

          <!-- 状态 A：未选择文件 -->
          <div v-if="!selectedFileName" class="text-center space-y-3 py-4">
            <div
              class="w-12 h-12 rounded-full bg-surface-high/50 border border-outline-variant/10 flex items-center justify-center mx-auto group-hover:scale-110 transition-all duration-300"
            >
              <UploadCloudIcon class="w-6 h-6 text-on-surface-variant/80 group-hover:text-primary transition-colors" />
            </div>
            <div class="space-y-1">
              <p class="text-[11px] font-medium">
                {{ isDockerMode ? '拖拽本地 .echo 备份包到此释放' : '拖拽 .echo 备份文件到此释放' }}
              </p>
              <p class="text-[9px] text-on-surface-variant/70">
                {{ isDockerMode ? '或者点击此区域在本地设备中浏览选择' : '或者点击此区域在文件管理器中浏览选择' }}
              </p>
            </div>
          </div>

          <!-- 状态 B：已选中文件 -->
          <div v-else class="text-center space-y-3 py-4 w-full px-2">
            <div
              class="w-12 h-12 rounded-2xl bg-green-500/10 border border-green-500/20 flex items-center justify-center mx-auto scale-105 animate-pulse"
            >
              <FileCheckIcon class="w-6 h-6 text-green-500" />
            </div>
            <div class="space-y-1">
              <p class="text-[11px] font-bold text-green-500 truncate max-w-[280px] mx-auto">{{ selectedFileName }}</p>
              <p class="text-[9px] text-on-surface-variant/70">备份包解析完毕 • 物理就绪</p>
            </div>
          </div>
        </div>

        <!-- 危险覆盖警示卡片 -->
        <div class="bg-red-500/5 border border-red-500/10 p-3.5 rounded-xl flex items-start space-x-3 select-none">
          <AlertOctagonIcon class="w-4 h-4 text-red-500 flex-shrink-0 mt-0.5" />
          <div class="space-y-1">
            <h4 class="text-[10px] font-bold text-red-500">🔥 高危覆盖警示</h4>
            <p class="text-[9px] text-on-surface-variant/90 leading-relaxed">
              此项还原为【覆盖物理写入】性质。一旦执行，您当前现存的所有聊天记忆、人设卡片、自制朋友圈及偏好设置将【被永久连根删除】且绝对无法恢复！系统导入成功后会自动进行热重启以重新挂载数据。
            </p>
          </div>
        </div>

        <!-- 操作按钮组 -->
        <div class="flex items-center space-x-3 pt-2">
          <button
            @click="showImportModal = false"
            class="btn-secondary w-full py-2 px-4 rounded-xl text-xs font-semibold select-none cursor-pointer transition-all active:scale-95 text-center"
          >
            我再想想
          </button>
          <button
            @click="executeCustomImport"
            :disabled="!selectedFilePath"
            class="btn-primary bg-red-500 border-red-600 hover:bg-red-600 text-white w-full py-2 px-4 rounded-xl text-xs font-semibold select-none cursor-pointer transition-all active:scale-95 disabled:opacity-30 disabled:pointer-events-none text-center shadow-lg shadow-red-500/10"
          >
            确认导入并热重启
          </button>
        </div>
      </div>
    </div>

    <!-- ========================= 全局自定义高保真 Dialog 对话框 ========================= -->
    <div v-if="customDialog.visible" class="modal-overlay !z-[99999]" @click.self="customDialog.visible = false">
      <!-- 1. 普通模式：确认/警告/提示弹窗 -->
      <div
        v-if="customDialog.type !== 'clean-choice'"
        class="modal-panel max-w-sm w-full p-6 space-y-4 animate-fade-in shadow-2xl rounded-2xl border bg-surface select-none"
      >
        <div class="flex items-start space-x-3.5">
          <div
            class="w-10 h-10 rounded-xl flex items-center justify-center flex-shrink-0"
            :class="{
              'bg-primary/10 text-primary': customDialog.type === 'info',
              'bg-green-500/10 text-green-500': customDialog.type === 'success',
              'bg-red-500/10 text-red-500': customDialog.type === 'error',
              'bg-yellow-500/10 text-yellow-500': customDialog.type === 'confirm',
            }"
          >
            <CheckCircleIcon v-if="customDialog.type === 'success'" class="w-5 h-5 animate-pulse" />
            <BrainIcon v-else-if="customDialog.type === 'info'" class="w-5 h-5" />
            <XCircleIcon v-else-if="customDialog.type === 'error'" class="w-5 h-5" />
            <AlertTriangleIcon v-else class="w-5 h-5" />
          </div>
          <div class="flex-1 min-w-0">
            <h4 class="text-sm font-bold text-on-surface leading-tight">{{ customDialog.title }}</h4>
            <p class="text-xs text-on-surface-variant mt-2 leading-relaxed whitespace-pre-wrap break-all select-text">
              {{ customDialog.message }}
            </p>
          </div>
        </div>

        <div class="flex justify-end space-x-2 pt-1 select-none">
          <button
            v-if="customDialog.type === 'confirm'"
            @click="customDialog.onCancel && customDialog.onCancel()"
            class="btn-secondary text-xs py-1.5 px-4 rounded-lg"
          >
            取消
          </button>
          <button
            @click="customDialog.onConfirm && customDialog.onConfirm()"
            class="btn-primary text-xs py-1.5 px-4 font-bold rounded-lg"
          >
            确定
          </button>
        </div>
      </div>

      <!-- 2. 特殊清除选项模式：高保真双卡片分流选择 -->
      <div
        v-else
        class="modal-panel max-w-md w-full p-6 space-y-5 animate-fade-in shadow-2xl rounded-2xl border bg-surface select-none"
      >
        <div class="flex items-center space-x-3 border-b border-chat-border pb-3">
          <div class="w-9 h-9 rounded-xl flex items-center justify-center bg-red-500/10 text-red-500 flex-shrink-0">
            <svg
              class="w-5 h-5 animate-pulse"
              xmlns="http://www.w3.org/2000/svg"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              stroke-width="2"
              stroke-linecap="round"
              stroke-linejoin="round"
            >
              <path d="m16 22-1-4" />
              <path
                d="M19 14a1 1 0 0 0 1-1v-1a2 2 0 0 0-2-2h-3a1 1 0 0 1-1-1V4a2 2 0 0 0-4 0v5a1 1 0 0 1-1 1H6a2 2 0 0 0-2 2v1a1 1 0 0 0 1 1"
              />
              <path d="M19 14H5l-1.973 6.767A1 1 0 0 0 4 22h16a1 1 0 0 0 .973-1.233z" />
              <path d="m8 22 1-4" />
            </svg>
          </div>
          <h4 class="text-sm font-bold text-on-surface leading-tight">{{ customDialog.title }}</h4>
        </div>

        <p class="text-xs text-on-surface-variant leading-relaxed">
          请选择要对<span v-if="isGroupActive"
            >群聊 <strong class="text-on-surface font-semibold">[{{ activeGroupChat?.name }}]</strong></span
          ><span v-else
            >角色 <strong class="text-on-surface font-semibold">[{{ activeCharacter?.name }}]</strong></span
          >
          执行的清除操作：
        </p>

        <div class="space-y-3">
          <!-- 选项 1 大卡片 -->
          <button
            @click="handleCleanOption(1)"
            class="w-full text-left p-3.5 rounded-xl border border-chat-border hover:border-primary/40 bg-surface-low/50 hover:bg-primary/5 active:scale-[0.98] transition-all flex items-start space-x-3 group"
          >
            <span
              class="w-5 h-5 rounded-full bg-primary/10 text-primary flex items-center justify-center text-xs font-bold flex-shrink-0 mt-0.5 group-hover:bg-primary/20"
              >1</span
            >
            <div class="flex-1">
              <div class="text-xs font-bold text-on-surface group-hover:text-primary transition-colors">
                清除窗口会话 (逻辑清除)
              </div>
              <div class="text-[10px] text-on-surface-variant/70 mt-1 leading-relaxed">
                清除当前窗口会话。记忆和聊天历史数据【不丢失】，但将从界面上隐藏（无法搜索到），再次打开是空白会话，角色仍保留记忆。
              </div>
            </div>
          </button>
          <!-- 选项 2 大卡片 -->
          <button
            @click="handleCleanOption(2)"
            class="w-full text-left p-3.5 rounded-xl border border-red-500/20 hover:border-red-500/50 bg-red-500/5 hover:bg-red-500/10 active:scale-[0.98] transition-all flex items-start space-x-3 group"
          >
            <span
              class="w-5 h-5 rounded-full bg-red-500/10 text-red-500 flex items-center justify-center text-xs font-bold flex-shrink-0 mt-0.5 group-hover:bg-red-500/20"
              >2</span
            >
            <div class="flex-1">
              <div class="text-xs font-bold text-red-500 group-hover:text-red-600 transition-colors">
                清除历史和记忆 (物理彻底清空)
              </div>
              <div class="text-[10px] text-red-500/70 mt-1 leading-relaxed">
                <template v-if="isGroupActive">
                  ⚠️ 【高危操作】*：物理清除该群聊的所有聊天记录。彻底清空此群聊专属的 `Memory.md` 群组短期记忆与
                  `SUMMARY.md`
                  共用大事记文档。此操作【仅清除群聊相关】，完全不影响任何群成员角色本身的个人人设、私聊记忆与世界设定！
                </template>
                <template v-else>
                  ⚠️ 【高危操作】*：物理清除所有聊天历史。清空专属 `MEMORY.md` 里的长短期记忆，清空该角色专属的
                  `USER.md` 画像事实等等文件，仅保留性格设定 (`SOUL.md`) 与世界设定 (`WORLD.md`)。
                </template>
              </div>
            </div>
          </button>
        </div>

        <div class="flex justify-end pt-1">
          <button
            @click="customDialog.visible = false"
            class="btn-secondary text-xs py-1.5 px-5 rounded-lg active:scale-95"
          >
            取消
          </button>
        </div>
      </div>
    </div>

    <!-- ========================= 双轨记忆 AI 整理确认大文本编辑器弹窗 ========================= -->
    <div v-if="showMemoryTidyModal" class="modal-overlay" @click.self="showMemoryTidyModal = false">
      <div
        class="modal-panel max-w-2xl w-full p-6 space-y-4 animate-fade-in shadow-2xl rounded-2xl border border-outline-variant bg-surface/85 backdrop-blur-md flex flex-col max-h-[85vh]"
      >
        <div class="flex items-center space-x-2 pb-2 border-b border-outline-variant flex-shrink-0">
          <SparklesIcon class="w-5 h-5 text-secondary animate-pulse" />
          <h4 class="text-sm font-bold text-on-surface">✨ 【{{ tidyCharName }}】的 AI 整理记忆确认</h4>
        </div>

        <p class="text-[11px] text-on-surface-variant leading-relaxed flex-shrink-0">
          AI 已根据历史交互事实完成了对该角色双轨记忆的归纳与优化（STM & LTM）。
          请在下方仔细核对。<strong>您也可以直接在框内进行任何手工编辑和修润</strong>。确认无误后点击下方按钮保存生效：
        </p>

        <!-- 编辑文本域 -->
        <textarea
          v-model="tidiedMemoryTempContent"
          class="flex-1 w-full font-mono text-xs bg-surface border border-outline-variant rounded-xl p-4 focus:outline-none focus:border-primary resize-none text-on-surface overflow-y-auto shadow-inner select-text min-h-[350px] leading-relaxed"
        ></textarea>

        <div class="flex justify-end space-x-2.5 pt-2 border-t border-outline-variant flex-shrink-0 select-none">
          <button @click="showMemoryTidyModal = false" class="btn-secondary text-xs py-2 px-5 rounded-xl">取消</button>
          <button
            @click="saveTidiedMemory"
            class="btn-primary text-xs py-2 px-5 font-bold rounded-xl flex items-center space-x-1.5 active:scale-95 transition-all"
          >
            <SaveIcon class="w-3.5 h-3.5" />
            <span>确认并保存</span>
          </button>
        </div>
      </div>
    </div>

    <!-- ========================= 专属画像 AI 整理确认大文本编辑器弹窗 ========================= -->
    <div v-if="showUserTidyModal" class="modal-overlay" @click.self="showUserTidyModal = false">
      <div
        class="modal-panel max-w-2xl w-full p-6 space-y-4 animate-fade-in shadow-2xl rounded-2xl border border-outline-variant bg-surface/85 backdrop-blur-md flex flex-col max-h-[85vh]"
      >
        <div class="flex items-center space-x-2 pb-2 border-b border-outline-variant flex-shrink-0">
          <SparklesIcon class="w-5 h-5 text-secondary animate-pulse" />
          <h4 class="text-sm font-bold text-on-surface">✨ 【{{ tidyCharName }}】的 AI 整理专属画像确认</h4>
        </div>

        <p class="text-[11px] text-on-surface-variant leading-relaxed flex-shrink-0">
          AI 已根据历史交互事实和记忆，对该角色的专属画像（USER.md）完成了提炼与优化。
          请在下方核对。<strong>您也可以直接在框内进行任何手工编辑和修润</strong>。确认无误后点击下方按钮保存生效：
        </p>

        <!-- 编辑文本域 -->
        <textarea
          v-model="tidiedUserTempContent"
          class="flex-1 w-full font-mono text-xs bg-surface border border-outline-variant rounded-xl p-4 focus:outline-none focus:border-primary resize-none text-on-surface overflow-y-auto shadow-inner select-text min-h-[350px] leading-relaxed"
        ></textarea>

        <div class="flex justify-end space-x-2.5 pt-2 border-t border-outline-variant flex-shrink-0 select-none">
          <button @click="showUserTidyModal = false" class="btn-secondary text-xs py-2 px-5 rounded-xl">取消</button>
          <button
            @click="saveTidiedUser"
            class="btn-primary text-xs py-2 px-5 font-bold rounded-xl flex items-center space-x-1.5 active:scale-95 transition-all"
          >
            <SaveIcon class="w-3.5 h-3.5" />
            <span>确认并保存</span>
          </button>
        </div>
      </div>
    </div>

    <!-- 全局拖拽图片遮罩提示层 (毛玻璃高档动效) -->
    <div
      v-if="isDraggingFile"
      @dragover.prevent
      @dragleave.prevent="handleDragLeave"
      @drop.prevent="handleDrop"
      class="fixed inset-0 z-[100] flex flex-col items-center justify-center bg-background/60 backdrop-blur-md transition-all select-none animate-fade-in"
    >
      <div
        class="border border-outline-variant/60 bg-surface-high/80 p-10 rounded-2xl flex flex-col items-center space-y-4 shadow-2xl animate-scale-in max-w-sm text-center"
      >
        <div class="w-14 h-14 rounded-xl bg-primary/10 flex items-center justify-center text-primary shadow-sm">
          <ImageIcon class="w-7 h-7" />
        </div>
        <div class="space-y-1">
          <h3 class="text-sm font-bold text-on-surface">拖拽图片发送</h3>
          <p class="text-[11px] text-on-surface-variant/80">松开鼠标，直接将图片置入输入框中</p>
        </div>
      </div>
    </div>

    <!-- 性格演化 Diff 对比模态框 -->
    <div
      v-if="showEvolutionModal && activeEvolutionDraft"
      class="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-fade-in select-text"
    >
      <div
        class="w-full max-w-xl bg-surface rounded-2xl border border-outline-variant shadow-2xl flex flex-col max-h-[85vh] overflow-hidden select-text animate-scale-in"
      >
        <!-- 头部 -->
        <header
          class="p-5 border-b border-outline-variant/60 bg-surface flex items-center justify-between flex-shrink-0"
        >
          <div class="flex items-center space-x-2.5">
            <SparklesIcon class="w-5 h-5 text-primary animate-pulse" />
            <span class="text-sm font-bold text-on-surface">🌱 性格设定自然演化 Diff 对比</span>
          </div>
          <button
            @click="showEvolutionModal = false"
            class="p-1 rounded hover:bg-surface-high text-on-surface-variant hover:text-on-surface transition-colors cursor-pointer select-none"
          >
            <XIcon class="w-4 h-4" />
          </button>
        </header>

        <!-- 主滚动内容 -->
        <div class="flex-1 overflow-y-auto p-6 space-y-5 min-h-0 text-xs leading-relaxed">
          <div
            class="p-4 rounded-xl bg-surface-low border border-outline-variant/50 text-[11px] text-on-surface-variant flex-shrink-0 leading-relaxed select-none"
          >
            <strong>💡 性格自然演化说明：</strong>
            Echo 系统根据角色在 DREAM.md
            中积累的行为避坑指南及与您的长周期深度磨合对话，生成了局部核心设定修改提案。这象征着该数字生命在与您的相处中完成了独一无二的性格温化。
          </div>

          <!-- 变化项列表 -->
          <div class="space-y-5">
            <div
              v-for="(change, idx) in activeEvolutionDraft.soul_changes"
              :key="idx"
              class="border border-outline-variant rounded-xl overflow-hidden shadow-sm bg-surface-lowest"
            >
              <div
                class="px-4 py-2 border-b border-outline-variant bg-surface text-[10px] font-bold text-on-surface-variant/80 tracking-wide font-mono flex items-center justify-between select-none"
              >
                <span>位置：{{ change.section }}</span>
                <span
                  class="px-2 py-0.5 rounded-full bg-primary/10 text-primary text-[8px] font-mono font-bold scale-90"
                  >Evolution Proposal</span
                >
              </div>

              <div class="p-4 space-y-3">
                <!-- Before (Red) -->
                <div class="p-3 rounded-lg bg-red-500/5 border border-red-500/10 text-red-700 dark:text-red-400">
                  <div class="text-[9px] uppercase font-bold text-red-500/70 tracking-wider mb-1 font-mono select-none">
                    修改前 (Before)
                  </div>
                  <div class="font-medium">- {{ change.before }}</div>
                </div>

                <!-- After (Green) -->
                <div
                  class="p-3 rounded-lg bg-green-500/5 border border-green-500/10 text-green-700 dark:text-green-400"
                >
                  <div
                    class="text-[9px] uppercase font-bold text-green-500/70 tracking-wider mb-1 font-mono select-none"
                  >
                    修改后 (After)
                  </div>
                  <div class="font-medium">+ {{ change.after }}</div>
                </div>

                <!-- Reason (Blue) -->
                <div
                  class="p-3 rounded-lg bg-primary/5 border border-primary/15 text-on-surface-variant leading-relaxed"
                >
                  <div class="text-[9px] uppercase font-bold text-primary tracking-wider mb-1 font-mono select-none">
                    自然上演逻辑 (Reason)
                  </div>
                  <div class="italic text-[11px] font-medium leading-relaxed">{{ change.reason }}</div>
                </div>
              </div>
            </div>
          </div>
        </div>

        <!-- 底部动作条 -->
        <footer
          class="p-4 bg-surface border-t border-outline-variant/60 flex justify-end space-x-3 select-none flex-shrink-0"
        >
          <button
            @click="rejectSoulEvolution"
            class="px-4 py-2 rounded-xl border border-outline-variant hover:bg-surface-high text-xs font-bold text-on-surface transition-all cursor-pointer"
          >
            ✗ 丢弃/拒绝演化
          </button>
          <button
            @click="approveSoulEvolution"
            class="px-5 py-2 rounded-xl bg-primary hover:bg-primary-high text-xs font-bold text-white shadow-md transition-all cursor-pointer flex items-center space-x-1.5"
          >
            <SparklesIcon class="w-3.5 h-3.5 animate-pulse" />
            <span>✓ 批准更新 Soul.md</span>
          </button>
        </footer>
      </div>
    </div>

    <!-- 自定义角色状态指标配置弹窗 -->
    <div
      v-if="showCustomizeStatesModal"
      class="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-fade-in select-text"
    >
      <div
        class="w-full max-w-lg bg-surface rounded-2xl border border-outline-variant shadow-2xl flex flex-col max-h-[80vh] overflow-hidden select-text animate-scale-in"
      >
        <header
          class="p-5 border-b border-outline-variant/60 bg-surface flex items-center justify-between flex-shrink-0 select-none"
        >
          <div class="flex items-center space-x-2.5">
            <SlidersHorizontalIcon class="w-4.5 h-4.5 text-primary animate-pulse" />
            <span class="text-sm font-bold text-on-surface">🛠️ 自定义状态指标配置 (State.md)</span>
          </div>
          <button
            @click="showCustomizeStatesModal = false"
            class="p-1 rounded hover:bg-surface-high text-on-surface-variant hover:text-on-surface transition-colors cursor-pointer select-none"
          >
            <XIcon class="w-4 h-4" />
          </button>
        </header>

        <div class="flex-1 overflow-y-auto p-6 space-y-4 min-h-0 text-xs leading-relaxed">
          <div
            class="p-3 rounded-lg bg-surface-low border border-outline-variant text-[11px] text-on-surface-variant leading-relaxed select-none"
          >
            <strong>💡 自定义状态指南：</strong>
            请在下方直接修改该角色的专属 `State.md` JSON 参数。您可以自由增加、删除状态项，或修改其
            Label、Emoji、初始值与量程。AI 自省评估时将自动读取并进行 Delta 更新。
          </div>

          <textarea
            v-model="editingStatesString"
            class="w-full h-64 font-mono text-[11px] bg-surface-low border border-outline-variant rounded-xl p-3 focus:outline-none focus:border-primary resize-none text-on-surface overflow-y-auto shadow-inner leading-normal"
          ></textarea>
        </div>

        <footer
          class="p-4 bg-surface border-t border-outline-variant/60 flex justify-end space-x-2.5 select-none flex-shrink-0"
        >
          <button
            @click="showCustomizeStatesModal = false"
            class="px-4 py-2 rounded-xl border border-outline-variant hover:bg-surface-high text-xs font-bold text-on-surface transition-all cursor-pointer"
          >
            取消
          </button>
          <button
            @click="saveCustomizedStates"
            class="px-5 py-2 rounded-xl bg-primary hover:bg-primary-high text-xs font-bold text-white shadow-md transition-all cursor-pointer"
          >
            ✓ 保存配置并刷新
          </button>
        </footer>
      </div>
    </div>

    <!-- 发表论坛帖子弹窗 -->
    <div
      v-if="showPublishForumModal"
      class="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-fade-in select-text"
    >
      <div
        class="w-full max-w-lg bg-surface rounded-2xl border border-outline-variant shadow-2xl flex flex-col max-h-[80vh] overflow-hidden select-text animate-scale-in"
      >
        <header
          class="p-5 border-b border-outline-variant/60 bg-surface flex items-center justify-between flex-shrink-0 select-none"
        >
          <div class="flex items-center space-x-2.5">
            <ScrollIcon class="w-5 h-5 text-primary animate-pulse" />
            <span class="text-sm font-bold text-on-surface flex items-center space-x-1.5">
              <PenLineIcon class="w-4 h-4 text-primary" />
              <span>发表新帖到回音社区</span>
            </span>
          </div>
          <button
            @click="showPublishForumModal = false"
            class="p-1 rounded hover:bg-surface-high text-on-surface-variant hover:text-on-surface transition-colors cursor-pointer select-none"
          >
            <XIcon class="w-4 h-4" />
          </button>
        </header>

        <div class="flex-1 overflow-y-auto p-6 space-y-5 min-h-0 text-xs leading-relaxed">
          <!-- 选择板块 -->
          <div class="space-y-2">
            <label class="text-[11px] font-bold text-on-surface-variant">选择目标社区板块</label>
            <div class="grid grid-cols-3 gap-2">
              <button
                v-for="b in boards.filter(item => item.id !== 'all')"
                :key="b.id"
                @click="newForumBoardId = b.id"
                type="button"
                class="py-2 px-3 rounded-xl border text-center font-bold transition-all cursor-pointer truncate flex items-center justify-center space-x-1.5"
                :class="[
                  newForumBoardId === b.id
                    ? b.id === 'nsfw'
                      ? 'bg-red-600 text-white border-red-600 shadow-sm font-bold'
                      : 'bg-primary text-white border-primary shadow-sm font-bold'
                    : b.id === 'nsfw'
                      ? 'bg-red-500/5 border-red-500/20 text-red-500 hover:bg-red-500/10'
                      : 'bg-surface-low border-outline-variant/50 text-on-surface-variant hover:bg-surface-high',
                ]"
              >
                <component
                  :is="b.icon"
                  class="w-3.5 h-3.5"
                  :class="[
                    newForumBoardId === b.id
                      ? 'text-white'
                      : b.id === 'nsfw'
                        ? 'text-red-500'
                        : 'text-on-surface-variant/70',
                  ]"
                />
                <span>{{ b.name }}</span>
              </button>
            </div>
          </div>

          <!-- 帖子标题 -->
          <div class="space-y-2">
            <label class="text-[11px] font-bold text-on-surface-variant">帖子标题</label>
            <input
              v-model="newForumTitle"
              type="text"
              placeholder="请输入一个富于技术感或趣味性的标题..."
              class="w-full px-4 py-2.5 rounded-xl bg-surface-low border border-outline-variant text-on-surface placeholder-on-surface-variant/30 focus:outline-none focus:border-primary text-xs transition-all shadow-inner"
            />
          </div>

          <!-- 帖子正文 -->
          <div class="space-y-2">
            <label class="text-[11px] font-bold text-on-surface-variant">帖子内容正文</label>
            <textarea
              v-model="newForumContent"
              placeholder="请在此畅所欲言，支持 Markdown 排版风格，角色们会根据你的发帖在下方参与深度互动哦 💬"
              class="w-full h-44 p-4 text-xs bg-surface-low border border-outline-variant rounded-2xl focus:outline-none focus:border-primary resize-none text-on-surface overflow-y-auto shadow-inner leading-relaxed"
            ></textarea>
          </div>
        </div>

        <footer
          class="p-4 bg-surface border-t border-outline-variant/60 flex justify-between items-center select-none flex-shrink-0"
        >
          <button
            @click.stop="openStickersPanel($event, 'newForumContent')"
            class="p-1.5 rounded-lg text-on-surface-variant/70 hover:text-primary hover:bg-surface-high transition-all cursor-pointer active:scale-95 flex-shrink-0"
            title="表情与表情包"
          >
            <SmileIcon class="w-4.5 h-4.5" />
          </button>
          <div class="flex space-x-2.5">
            <button
              @click="showPublishForumModal = false"
              class="px-4 py-2 rounded-xl border border-outline-variant hover:bg-surface-high text-xs font-bold text-on-surface transition-all cursor-pointer"
            >
              取消
            </button>
            <button
              @click="publishUserForumPost"
              :disabled="!newForumTitle.trim() || !newForumContent.trim()"
              class="px-5 py-2 rounded-xl bg-primary hover:bg-primary-high text-xs font-bold text-white shadow-md transition-all cursor-pointer disabled:opacity-40 disabled:cursor-not-allowed"
            >
              ✓ 发帖发布
            </button>
          </div>
        </footer>
      </div>
    </div>

    <!-- ====== 音乐底栏播放控制栏 ====== -->
    <div
      v-if="!isMobile && generalConfig.enable_music"
      class="h-20 bg-surface-low border-t border-outline-variant/60 shadow-[0_-4px_24px_rgba(0,0,0,0.06)] px-6 flex items-center justify-between z-40 select-none flex-shrink-0"
    >
      <!-- 左侧：封面、歌名、歌手 -->
      <div class="flex items-center space-x-3.5 w-1/4 min-w-0">
        <div
          @click="musicStore.state.currentSong && (showPlayExpanded = true)"
          class="w-12 h-12 rounded-xl overflow-hidden bg-surface border border-outline-variant shadow-sm relative group cursor-pointer"
        >
          <img
            :src="musicStore.state.currentSong?.img || DEFAULT_COVER"
            @error="handleCoverError"
            class="w-full h-full object-cover"
          />
          <div
            class="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center"
          >
            <span class="text-white text-base">⛶</span>
          </div>
        </div>
        <div class="min-w-0 flex-1">
          <div
            class="text-xs font-bold text-on-surface truncate cursor-pointer hover:text-primary animate-fade-in flex items-center space-x-1"
            @click="musicStore.state.currentSong && (showPlayExpanded = true)"
          >
            <span :class="{ 'text-red-500/90 dark:text-red-400': musicStore.state.statusText }">
              {{ musicStore.state.currentSong?.name || '回音音乐 - 听你想听 🐾' }}
            </span>
          </div>
          <div
            v-if="musicStore.state.statusText"
            class="text-[9.5px] font-bold truncate mt-0.5 flex items-center space-x-1"
            :class="
              musicStore.state.statusText.startsWith('✅')
                ? 'text-emerald-500 dark:text-emerald-400'
                : 'text-orange-500 dark:text-red-400 animate-pulse'
            "
          >
            <span>{{ musicStore.state.statusText }}</span>
          </div>
          <div v-else class="text-[10px] text-on-surface-variant truncate mt-0.5">
            {{ musicStore.state.currentSong?.singer || 'Echo Player' }}
          </div>
        </div>
      </div>

      <!-- 中间：核心控制与进度条 -->
      <div class="flex-1 max-w-xl flex flex-col items-center px-4">
        <!-- 控制按钮组 -->
        <div class="flex items-center space-x-6">
          <!-- 循环模式 -->
          <button
            @click="
              musicStore.state.loopMode =
                musicStore.state.loopMode === 'listLoop'
                  ? 'random'
                  : musicStore.state.loopMode === 'random'
                    ? 'singleLoop'
                    : 'listLoop'
            "
            class="p-1 rounded text-on-surface-variant hover:text-on-surface transition-colors cursor-pointer"
            :title="
              musicStore.state.loopMode === 'listLoop'
                ? '列表循环'
                : musicStore.state.loopMode === 'random'
                  ? '随机播放'
                  : '单曲循环'
            "
          >
            <RepeatIcon v-if="musicStore.state.loopMode === 'listLoop'" class="w-4 h-4 text-primary" />
            <ShuffleIcon v-else-if="musicStore.state.loopMode === 'random'" class="w-4 h-4 text-primary" />
            <Repeat1Icon v-else class="w-4 h-4 text-primary" />
          </button>

          <!-- 上一首 -->
          <button
            @click="musicStore.playPrev()"
            class="p-1.5 rounded-lg text-on-surface-variant hover:text-on-surface hover:bg-surface-high/50 active:scale-95 transition-all cursor-pointer"
          >
            <SkipBackIcon class="w-4 h-4" />
          </button>

          <!-- 播放/暂停 -->
          <button
            @click="musicStore.togglePlay()"
            class="w-10 h-10 rounded-full bg-primary text-white flex items-center justify-center hover:scale-105 active:scale-95 shadow-md transition-all cursor-pointer"
          >
            <PauseIcon v-if="musicStore.state.isPlaying" class="w-4 h-4" />
            <PlayIcon v-else class="w-4 h-4 fill-white ml-0.5" />
          </button>

          <!-- 下一首 -->
          <button
            @click="musicStore.playNext()"
            class="p-1.5 rounded-lg text-on-surface-variant hover:text-on-surface hover:bg-surface-high/50 active:scale-95 transition-all cursor-pointer"
          >
            <SkipForwardIcon class="w-4 h-4" />
          </button>

          <!-- 桌面歌词 -->
          <template v-if="!isDockerMode">
            <button
              @click="musicStore.toggleDesktopLyric()"
              class="p-1 rounded text-on-surface-variant hover:text-on-surface transition-colors cursor-pointer"
              :class="{ 'text-primary font-bold': musicStore.state.enableDesktopLyric }"
              title="词 (桌面歌词)"
            >
              <span class="text-[11px] font-black font-sans">词</span>
            </button>
          </template>
        </div>

        <!-- 进度条 -->
        <div class="w-full flex items-center space-x-2.5 mt-2">
          <span class="text-[9px] font-mono text-on-surface-variant/70">{{
            formatDuration(musicStore.state.currentTime)
          }}</span>
          <div
            class="flex-1 h-1 bg-surface-low hover:h-1.5 rounded-full relative group cursor-pointer"
            @click="
              e => {
                if (musicStore.audio) {
                  const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
                  const percent = (e.clientX - rect.left) / rect.width;
                  musicStore.audio.currentTime = percent * musicStore.state.duration;
                }
              }
            "
          >
            <div
              class="bg-primary h-full rounded-full transition-all duration-75 relative"
              :style="{ width: (musicStore.state.currentTime / (musicStore.state.duration || 1)) * 100 + '%' }"
            >
              <span
                class="w-2.5 h-2.5 bg-primary border-2 border-white dark:border-zinc-950 rounded-full absolute -right-1.25 -top-0.75 shadow opacity-0 group-hover:opacity-100 transition-opacity"
              ></span>
            </div>
          </div>
          <span class="text-[9px] font-mono text-on-surface-variant/70">{{
            formatDuration(musicStore.state.duration)
          }}</span>
        </div>
      </div>

      <!-- 右侧：音量与增删 -->
      <div class="w-1/4 flex items-center justify-end space-x-4 flex-shrink-0 select-none">
        <!-- 音质标识 -->
        <span
          class="px-2 py-0.5 rounded-full text-[9px] font-black bg-primary/10 text-primary uppercase select-none font-mono"
          >{{ musicStore.state.quality }}</span
        >

        <!-- 红心收藏 -->
        <button
          @click="musicStore.state.currentSong && musicStore.toggleFavorite(musicStore.state.currentSong)"
          class="p-1 text-on-surface-variant hover:text-red-500 transition-all active:scale-90 cursor-pointer"
          :title="
            musicStore.state.currentSong && musicStore.isFavorited(musicStore.state.currentSong.songmid)
              ? '取消收藏'
              : '收藏'
          "
          :disabled="!musicStore.state.currentSong"
          :class="{ 'opacity-30 cursor-not-allowed': !musicStore.state.currentSong }"
        >
          <HeartIcon
            class="w-4.5 h-4.5"
            :class="
              musicStore.state.currentSong && musicStore.isFavorited(musicStore.state.currentSong.songmid)
                ? 'fill-red-500 text-red-500 scale-110'
                : 'scale-100'
            "
          />
        </button>

        <!-- 音量 -->
        <div class="flex items-center space-x-2 group/vol">
          <button
            @click="musicStore.toggleMute()"
            class="p-1 text-on-surface-variant hover:text-on-surface cursor-pointer"
          >
            <VolumeXIcon v-if="musicStore.state.isMuted" class="w-4.5 h-4.5" />
            <Volume2Icon v-else class="w-4.5 h-4.5" />
          </button>
          <input
            type="range"
            min="0"
            max="100"
            :value="musicStore.state.isMuted ? 0 : musicStore.state.volume"
            @input="e => musicStore.setVolume(Number((e.target as HTMLInputElement).value))"
            class="w-16 accent-primary h-1 rounded-full cursor-pointer opacity-40 group-hover/vol:opacity-100 transition-opacity"
          />
        </div>

        <!-- 当前播放队列按钮 -->
        <button
          @click="showQueueDrawer = !showQueueDrawer"
          class="play-queue-trigger-button p-1 rounded text-on-surface-variant hover:text-on-surface transition-colors cursor-pointer focus:outline-none flex items-center justify-center relative"
          :class="{ 'text-primary': showQueueDrawer }"
          title="播放队列"
        >
          <ListMusicIcon class="w-4.5 h-4.5" />
          <!-- 队列曲目数小微标 -->
          <span
            v-if="musicStore.state.playQueue.length"
            class="absolute -top-1 -right-1 w-3.5 h-3.5 rounded-full text-[7.5px] text-white flex items-center justify-center select-none font-bold font-mono"
            :class="isDark ? 'bg-emerald-400 text-zinc-950 font-black' : 'bg-primary'"
          >
            {{ musicStore.state.playQueue.length }}
          </span>
        </button>
      </div>
    </div>

    <!-- ====== 当前播放队列侧边抽屉 (Play Queue Drawer) ====== -->
    <transition
      enter-active-class="transition duration-300 ease-out transform"
      enter-from-class="translate-x-full opacity-0"
      enter-to-class="translate-x-0 opacity-100"
      leave-active-class="transition duration-200 ease-in transform"
      leave-from-class="translate-x-0 opacity-100"
      leave-to-class="translate-x-full opacity-0"
    >
      <div
        v-if="showQueueDrawer"
        class="play-queue-drawer-container fixed top-0 right-0 w-80 bottom-20 z-40 border-l p-4 flex flex-col transition-all duration-500 backdrop-blur-lg shadow-2xl select-none"
        :class="
          isDark
            ? 'bg-zinc-950/70 border-white/[0.04] text-zinc-200 shadow-[0_0_50px_rgba(0,0,0,0.8)]'
            : 'bg-white/70 border-primary/5 text-on-surface shadow-[0_0_40px_rgba(70,72,212,0.08)]'
        "
      >
        <!-- 抽屉头部 -->
        <header
          class="pb-3 border-b flex items-center justify-between select-none flex-shrink-0"
          :class="isDark ? 'border-zinc-800/80' : 'border-primary/10'"
        >
          <div class="flex items-center space-x-1.5">
            <ListMusicIcon class="w-4.5 h-4.5 text-primary" />
            <span class="text-xs font-black tracking-wide">当前播放队列 ({{ musicStore.state.playQueue.length }})</span>
          </div>

          <div class="flex items-center space-x-2.5">
            <!-- 一键清空 -->
            <button
              v-if="musicStore.state.playQueue.length"
              @click="
                musicStore.state.playQueue = [];
                musicStore.state.currentQueueIndex = -1;
                showQueueDrawer = false;
              "
              class="text-[9px] font-black hover:text-red-500 transition-colors focus:outline-none cursor-pointer"
              :class="isDark ? 'text-zinc-500' : 'text-on-surface-variant/60'"
            >
              清空队列
            </button>
            <button
              @click="showQueueDrawer = false"
              class="text-[10px] font-black hover:text-on-surface transition-colors cursor-pointer focus:outline-none"
              :class="isDark ? 'text-zinc-500' : 'text-on-surface-variant/60'"
            >
              ✕
            </button>
          </div>
        </header>

        <!-- 列表内容区 -->
        <div class="flex-1 overflow-y-auto space-y-1 mt-4 scrollbar-thin">
          <div
            v-if="!musicStore.state.playQueue.length"
            class="py-32 text-center text-[10px] text-on-surface-variant/50 dark:text-zinc-500"
          >
            队列为空，双击歌曲加入吧 🐾
          </div>

          <div
            v-else
            v-for="(song, idx) in musicStore.state.playQueue"
            :key="song.songmid + '-' + idx"
            class="px-3 py-2 rounded-xl text-xs flex items-center justify-between cursor-pointer group transition-all duration-200"
            :class="[
              musicStore.state.currentSong?.songmid === song.songmid
                ? isDark
                  ? 'bg-emerald-400/5 text-emerald-400 font-extrabold shadow-sm'
                  : 'bg-primary/5 text-primary font-extrabold shadow-sm'
                : isDark
                  ? 'hover:bg-white/[0.03] text-zinc-300'
                  : 'hover:bg-primary/5 text-on-surface',
            ]"
            @dblclick="musicStore.playSong(song, musicStore.state.playQueue)"
          >
            <!-- 左侧：歌曲信息和播放状态小声波 -->
            <div class="flex items-center space-x-2 min-w-0 flex-1">
              <!-- 声波柱形动画 -->
              <div
                v-if="musicStore.state.currentSong?.songmid === song.songmid && musicStore.state.isPlaying"
                class="flex items-end space-x-0.5 h-2.5 w-3 flex-shrink-0 mb-0.5"
              >
                <span class="w-0.5 bg-current rounded-full animate-pulse" style="height: 100%"></span>
                <span
                  class="w-0.5 bg-current rounded-full animate-pulse"
                  style="height: 60%; animation-delay: 0.2s"
                ></span>
                <span
                  class="w-0.5 bg-current rounded-full animate-pulse"
                  style="height: 80%; animation-delay: 0.4s"
                ></span>
              </div>
              <span class="truncate pr-1.5">{{ song.name }}</span>
            </div>

            <!-- 右侧：歌手与移除按钮 -->
            <div class="flex items-center space-x-2 flex-shrink-0 select-none">
              <span
                class="text-[9px] max-w-[80px] truncate"
                :class="musicStore.state.currentSong?.songmid === song.songmid ? 'opacity-80' : 'opacity-40'"
              >
                {{ song.singer }}
              </span>
              <!-- 移出队列按钮 -->
              <button
                @click.stop="
                  () => {
                    musicStore.state.playQueue.splice(idx, 1);
                    if (musicStore.state.currentQueueIndex === idx) {
                      if (musicStore.state.playQueue.length) {
                        musicStore.playSong(
                          musicStore.state.playQueue[Math.min(idx, musicStore.state.playQueue.length - 1)],
                          musicStore.state.playQueue,
                        );
                      } else {
                        musicStore.state.currentSong = null;
                        musicStore.state.isPlaying = false;
                      }
                    } else if (musicStore.state.currentQueueIndex > idx) {
                      musicStore.state.currentQueueIndex--;
                    }
                  }
                "
                class="w-4 h-4 rounded-full hover:bg-red-500 hover:text-white flex items-center justify-center transition-all cursor-pointer opacity-0 group-hover:opacity-100 text-on-surface-variant/40"
              >
                ✕
              </button>
            </div>
          </div>
        </div>
      </div>
    </transition>

    <!-- ====== 全屏歌词大唱片展开详情播放页 ====== -->
    <transition
      enter-active-class="transition duration-500 cubic-bezier(0.16, 1, 0.3, 1)"
      enter-from-class="translate-y-full"
      enter-to-class="translate-y-0"
      leave-active-class="transition duration-400 cubic-bezier(0.7, 0, 0.84, 0)"
      leave-from-class="translate-y-0"
      leave-to-class="translate-y-full"
    >
      <div
        v-if="showPlayExpanded && musicStore.state.currentSong"
        class="fixed inset-0 z-50 flex flex-col overflow-hidden select-text transition-colors duration-500"
        :class="isDark ? 'bg-[#0a0a0a] text-zinc-100' : 'bg-[#f4f5fc] text-on-surface'"
      >
        <!-- 梦幻磨砂背景氛层 -->
        <div
          class="absolute inset-0 bg-cover bg-center filter blur-[100px] transition-all duration-1000 pointer-events-none z-0"
          :class="isDark ? 'opacity-[0.12] scale-110' : 'opacity-[0.25] scale-105'"
          :style="{ backgroundImage: `url(${musicStore.state.currentSong.img || DEFAULT_COVER})` }"
        ></div>

        <!-- 顶部控制头 (pt-20 精致下压，符合全面屏刘海与 Mac 红绿灯避让规范) -->
        <header class="pt-20 pb-4 px-10 flex items-center justify-between z-10 select-none flex-shrink-0">
          <button
            @click="showPlayExpanded = false"
            class="px-4 py-1.5 rounded-full text-xs font-extrabold transition-all cursor-pointer active:scale-95 flex items-center space-x-1.5 z-20"
            :class="
              isDark
                ? 'bg-white/5 hover:bg-white/10 border border-white/10 text-zinc-100'
                : 'bg-primary/5 hover:bg-primary/10 border border-primary/15 text-primary'
            "
          >
            <span>▼</span> <span>收起播放页</span>
          </button>
          <div class="text-center z-10 flex flex-col items-center">
            <h3
              class="text-sm font-black truncate max-w-sm tracking-wide transition-colors duration-500"
              :class="isDark ? 'text-zinc-100' : 'text-on-surface'"
            >
              {{ musicStore.state.currentSong.name }}
            </h3>
            <p
              class="text-[10.5px] mt-1.5 truncate max-w-sm font-medium transition-colors duration-500"
              :class="isDark ? 'text-zinc-400' : 'text-on-surface-variant/80'"
            >
              {{ musicStore.state.currentSong.singer }}
            </p>
          </div>
          <span
            class="px-2.5 py-0.5 rounded-full text-[9px] font-extrabold font-mono select-none uppercase tracking-wider transition-colors duration-500 z-10"
            :class="
              isDark
                ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20'
                : 'bg-primary/5 text-primary border border-primary/20'
            "
          >
            {{ musicStore.state.quality || '320K' }}
          </span>
        </header>

        <!-- 主内容区域 (左侧封面缩窄，右侧歌词/评论双栏加宽) -->
        <div class="flex-1 flex min-h-0 z-10 px-12 py-6 items-center">
          <!-- 左侧：正圆形缓缓旋转封面 (宽度完美收窄至 38%) -->
          <div class="w-[38%] h-full flex flex-col items-center justify-center relative select-none z-10">
            <!-- 极致轻奢的双层渐变星轨环 -->
            <div class="relative w-64 h-64 flex items-center justify-center">
              <!-- 逆向和正向的虚线运行圆环轨道 -->
              <div
                class="absolute inset-0 rounded-full border border-dashed transition-all duration-700 animate-spin-slow opacity-30 dark:opacity-20"
                :class="isDark ? 'border-emerald-400' : 'border-primary'"
              ></div>
              <div
                class="absolute inset-4 rounded-full border border-dotted transition-all duration-700 animate-spin-slow opacity-25 dark:opacity-15"
                :class="isDark ? 'border-emerald-400' : 'border-primary'"
                style="animation-direction: reverse; animation-duration: 40s"
              ></div>

              <!-- 核心正圆形流光封面 -->
              <div
                class="w-56 h-56 rounded-full overflow-hidden border-2 transition-all duration-700 z-10 shadow-2xl relative"
                :class="[
                  isDark
                    ? 'border-zinc-700/80 shadow-[0_20px_60px_rgba(78,222,163,0.18)]'
                    : 'border-white shadow-[0_20px_50px_rgba(70,72,212,0.18)]',
                  musicStore.state.isPlaying ? 'animate-spin-slow' : 'animate-spin-slow animate-spin-paused',
                ]"
              >
                <!-- 播放封面图片 -->
                <img
                  :src="musicStore.state.currentSong.img || DEFAULT_COVER"
                  @error="handleCoverError"
                  class="w-full h-full object-cover select-none pointer-events-none"
                />
              </div>
            </div>

            <!-- 歌曲播放状态微标 -->
            <div class="flex items-center space-x-2 mt-8 z-10">
              <span
                class="w-1.5 h-1.5 rounded-full"
                :class="[musicStore.state.isPlaying ? 'animate-pulse' : '', isDark ? 'bg-emerald-400' : 'bg-primary']"
              ></span>
              <p
                class="text-[9px] font-bold font-mono tracking-widest uppercase select-none transition-colors duration-500"
                :class="isDark ? 'text-zinc-500' : 'text-on-surface-variant/50'"
              >
                {{ musicStore.state.isPlaying ? 'Now Playing' : 'Playback Paused' }}
              </p>
            </div>
          </div>

          <!-- 右侧：歌词 / 评论双栏切换区 (加宽至 62%) -->
          <div
            class="w-[62%] h-full flex flex-col min-h-0 pl-10 border-l transition-colors duration-500"
            :class="isDark ? 'border-zinc-800/60' : 'border-primary/10'"
          >
            <!-- Tab 页签 -->
            <div
              class="flex space-x-6 border-b pb-3 flex-shrink-0 select-none transition-colors duration-500"
              :class="isDark ? 'border-zinc-800/60' : 'border-primary/10'"
            >
              <button
                @click="showCommentsTab = false"
                class="text-xs font-black transition-all cursor-pointer pb-1.5 focus:outline-none"
                :class="
                  !showCommentsTab
                    ? isDark
                      ? 'text-emerald-400 border-b-2 border-emerald-400 scale-105'
                      : 'text-primary border-b-2 border-primary scale-105'
                    : isDark
                      ? 'text-zinc-500 hover:text-zinc-300'
                      : 'text-on-surface-variant/60 hover:text-on-surface'
                "
              >
                歌词展示
              </button>
              <button
                @click="showCommentsTab = true"
                class="text-xs font-black transition-all cursor-pointer pb-1.5 focus:outline-none"
                :class="
                  showCommentsTab
                    ? isDark
                      ? 'text-emerald-400 border-b-2 border-emerald-400 scale-105'
                      : 'text-primary border-b-2 border-primary scale-105'
                    : isDark
                      ? 'text-zinc-500 hover:text-zinc-300'
                      : 'text-on-surface-variant/60 hover:text-on-surface'
                "
              >
                精选评论 ({{ musicStore.state.commentsTotal }})
              </button>
            </div>

            <!-- 页签内容区 -->
            <div class="flex-1 overflow-hidden min-h-0 mt-6">
              <!-- 1. 歌词滚动页 -->
              <div
                v-if="!showCommentsTab"
                ref="lyricContainerRef"
                class="h-full overflow-y-auto pr-6 space-y-4 text-center scroll-smooth scrollbar-thin"
              >
                <div
                  v-if="musicStore.state.lyricLines.length === 0"
                  class="py-24 text-sm select-none transition-colors duration-500"
                  :class="isDark ? 'text-zinc-500' : 'text-on-surface-variant/50'"
                >
                  歌词加载中...
                </div>
                <div
                  v-else
                  v-for="(line, idx) in musicStore.state.lyricLines"
                  :key="idx"
                  class="transition-all duration-300 py-1"
                  :class="
                    musicStore.state.currentLyricIndex === idx
                      ? isDark
                        ? 'lyric-line-active text-emerald-400 text-base font-black scale-105 drop-shadow-[0_0_10px_rgba(78,222,163,0.4)]'
                        : 'lyric-line-active text-primary text-base font-black scale-105 drop-shadow-[0_0_10px_rgba(70,72,212,0.35)]'
                      : isDark
                        ? 'text-zinc-500 text-xs font-medium'
                        : 'text-on-surface-variant/40 text-xs font-medium'
                  "
                >
                  {{ line.text }}
                  <!-- 对应的翻译歌词 -->
                  <div v-if="musicStore.state.tlyricLines.length > 0" class="text-[10px] mt-1 font-normal opacity-60">
                    {{ musicStore.state.tlyricLines.find(tl => Math.abs(tl.time - line.time) < 0.5)?.text }}
                  </div>
                </div>
              </div>

              <!-- 2. 精选评论滚动页 -->
              <div
                v-else
                class="h-full overflow-y-auto pr-4 space-y-4"
                @scroll="
                  e => {
                    const el = e.currentTarget as HTMLElement;
                    if (el.scrollHeight - el.scrollTop - el.clientHeight < 20) {
                      musicStore.loadMoreComments();
                    }
                  }
                "
              >
                <div
                  v-if="musicStore.state.commentsLoading && musicStore.state.comments.length === 0"
                  class="py-24 text-center text-xs select-none transition-colors duration-500"
                  :class="isDark ? 'text-zinc-500' : 'text-on-surface-variant/50'"
                >
                  评论加载中...
                </div>
                <div
                  v-else-if="musicStore.state.comments.length === 0"
                  class="py-24 text-center text-xs select-none transition-colors duration-500"
                  :class="isDark ? 'text-zinc-500' : 'text-on-surface-variant/50'"
                >
                  本歌曲暂无热门评论 🐾
                </div>
                <div v-else class="space-y-4 pb-12">
                  <div
                    v-for="c in musicStore.state.comments"
                    :key="c.id"
                    class="flex items-start space-x-3.5 p-4 rounded-2xl border transition-all duration-300 shadow-sm"
                    :class="
                      isDark
                        ? 'bg-white/[0.02] border-white/[0.03] hover:bg-white/[0.05] hover:border-white/[0.06]'
                        : 'bg-white/30 border-primary/5 hover:bg-white/60 hover:border-primary/10'
                    "
                  >
                    <div
                      class="w-8 h-8 rounded-xl overflow-hidden flex-shrink-0 border transition-colors duration-500"
                      :class="isDark ? 'bg-zinc-800 border-zinc-700/60' : 'bg-white border-primary/10'"
                    >
                      <img :src="c.avatar" class="w-full h-full object-cover" />
                    </div>
                    <div class="flex-1 min-w-0">
                      <div class="flex items-center justify-between select-none">
                        <span
                          class="text-xs font-bold truncate transition-colors duration-500"
                          :class="isDark ? 'text-zinc-200' : 'text-on-surface'"
                        >
                          {{ c.userName }}
                        </span>
                        <span
                          class="text-[9px] font-mono transition-colors duration-500"
                          :class="isDark ? 'text-zinc-500' : 'text-on-surface-variant/50'"
                        >
                          {{ c.timeStr }}
                        </span>
                      </div>
                      <p
                        class="text-[11px] mt-1.5 leading-relaxed pr-2 font-medium transition-colors duration-500"
                        :class="isDark ? 'text-zinc-300' : 'text-on-surface/85'"
                      >
                        {{ c.content }}
                      </p>
                      <div
                        class="flex items-center justify-end text-[9px] select-none mt-2 font-bold font-mono transition-colors duration-500"
                        :class="isDark ? 'text-zinc-500' : 'text-on-surface-variant/60'"
                      >
                        <span>👍</span> <span class="ml-1">{{ c.likedCount }}</span>
                      </div>
                    </div>
                  </div>

                  <div
                    v-if="musicStore.state.commentsLoading"
                    class="py-3 text-center text-[10px] animate-pulse transition-colors duration-500"
                    :class="isDark ? 'text-zinc-500' : 'text-on-surface-variant/50'"
                  >
                    正在拼命拉取更多评论...
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>

        <!-- 底部控制栏 -->
        <footer
          class="h-24 border-t z-10 px-8 flex items-center justify-between select-none flex-shrink-0 backdrop-blur-md transition-all duration-500"
          :class="isDark ? 'bg-[#0a0a0a]/60 border-white/[0.04]' : 'bg-white/40 border-primary/5'"
        >
          <div class="w-1/4"></div>

          <!-- 大控制播放器 -->
          <div class="flex-1 flex flex-col items-center max-w-xl">
            <!-- 播放进度 -->
            <div class="w-full flex items-center space-x-3 select-none">
              <span
                class="text-[10px] font-mono transition-colors duration-500"
                :class="isDark ? 'text-zinc-500' : 'text-on-surface-variant/60'"
              >
                {{ formatDuration(musicStore.state.currentTime) }}
              </span>
              <div
                class="flex-1 h-1 rounded-full relative group cursor-pointer transition-colors duration-500"
                :class="isDark ? 'bg-white/10 hover:h-1.5' : 'bg-primary/10 hover:h-1.5'"
                @click="
                  e => {
                    if (musicStore.audio) {
                      const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
                      const percent = (e.clientX - rect.left) / rect.width;
                      musicStore.audio.currentTime = percent * musicStore.state.duration;
                    }
                  }
                "
              >
                <div
                  class="h-full rounded-full transition-all duration-75 relative"
                  :class="isDark ? 'bg-emerald-400' : 'bg-primary'"
                  :style="{ width: (musicStore.state.currentTime / (musicStore.state.duration || 1)) * 100 + '%' }"
                >
                  <span
                    class="w-2.5 h-2.5 border-2 rounded-full absolute -right-1.25 -top-0.75 shadow opacity-0 group-hover:opacity-100 transition-opacity"
                    :class="isDark ? 'bg-emerald-400 border-zinc-900' : 'bg-primary border-white'"
                  ></span>
                </div>
              </div>
              <span
                class="text-[10px] font-mono transition-colors duration-500"
                :class="isDark ? 'text-zinc-500' : 'text-on-surface-variant/60'"
              >
                {{ formatDuration(musicStore.state.duration) }}
              </span>
            </div>

            <!-- 控制按钮 -->
            <div class="flex items-center space-x-8 mt-3">
              <!-- 循环模式 -->
              <button
                @click="
                  musicStore.state.loopMode =
                    musicStore.state.loopMode === 'listLoop'
                      ? 'random'
                      : musicStore.state.loopMode === 'random'
                        ? 'singleLoop'
                        : 'listLoop'
                "
                class="p-1 transition-all duration-300 cursor-pointer focus:outline-none"
                :class="isDark ? 'text-zinc-400 hover:text-white' : 'text-on-surface-variant/70 hover:text-primary'"
                :title="
                  musicStore.state.loopMode === 'listLoop'
                    ? '列表循环'
                    : musicStore.state.loopMode === 'random'
                      ? '随机播放'
                      : '单曲循环'
                "
              >
                <RepeatIcon
                  v-if="musicStore.state.loopMode === 'listLoop'"
                  class="w-4 h-4"
                  :class="isDark ? 'text-emerald-400' : 'text-primary'"
                />
                <ShuffleIcon
                  v-else-if="musicStore.state.loopMode === 'random'"
                  class="w-4 h-4"
                  :class="isDark ? 'text-emerald-400' : 'text-primary'"
                />
                <Repeat1Icon v-else class="w-4 h-4" :class="isDark ? 'text-emerald-400' : 'text-primary'" />
              </button>

              <!-- 上一首 -->
              <button
                @click="musicStore.playPrev()"
                class="p-1.5 rounded-lg transition-all active:scale-95 cursor-pointer focus:outline-none"
                :class="
                  isDark
                    ? 'text-zinc-400 hover:text-white hover:bg-white/5'
                    : 'text-on-surface-variant/70 hover:text-primary hover:bg-primary/5'
                "
              >
                <SkipBackIcon class="w-4.5 h-4.5" />
              </button>

              <!-- 播放/暂停 -->
              <button
                @click="musicStore.togglePlay()"
                class="w-12 h-12 rounded-full flex items-center justify-center hover:scale-105 active:scale-95 shadow-lg transition-all cursor-pointer focus:outline-none"
                :class="
                  isDark
                    ? 'bg-emerald-400 text-zinc-950 hover:bg-emerald-300 shadow-[0_4px_20px_rgba(78,222,163,0.3)]'
                    : 'bg-primary text-white hover:bg-primary-container shadow-[0_4px_20px_rgba(70,72,212,0.3)]'
                "
              >
                <PauseIcon v-if="musicStore.state.isPlaying" class="w-5 h-5" />
                <PlayIcon
                  v-else
                  class="w-5 h-5 ml-0.5"
                  :class="isDark ? 'fill-zinc-950 text-zinc-950' : 'fill-white text-white'"
                />
              </button>

              <!-- 下一首 -->
              <button
                @click="musicStore.playNext()"
                class="p-1.5 rounded-lg transition-all active:scale-95 cursor-pointer focus:outline-none"
                :class="
                  isDark
                    ? 'text-zinc-400 hover:text-white hover:bg-white/5'
                    : 'text-on-surface-variant/70 hover:text-primary hover:bg-primary/5'
                "
              >
                <SkipForwardIcon class="w-4.5 h-4.5" />
              </button>

              <!-- 红心收藏 -->
              <button
                @click="musicStore.toggleFavorite(musicStore.state.currentSong)"
                class="p-1 transition-all active:scale-90 cursor-pointer focus:outline-none"
                :class="isDark ? 'text-zinc-400 hover:text-red-500' : 'text-on-surface-variant/70 hover:text-red-500'"
              >
                <HeartIcon
                  class="w-4.5 h-4.5"
                  :class="
                    musicStore.isFavorited(musicStore.state.currentSong.songmid)
                      ? 'fill-red-500 text-red-500 scale-110'
                      : 'scale-100'
                  "
                />
              </button>
            </div>
          </div>

          <div class="w-1/4"></div>
        </footer>
      </div>
    </transition>

    <!-- ====== 模态框 Modals ====== -->
    <!-- 1. 新建播放列表弹窗 -->
    <div
      v-if="showCreatePlaylistModal"
      class="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-fade-in select-text"
    >
      <div
        class="w-[340px] bg-surface rounded-3xl border border-outline-variant/70 shadow-2xl flex flex-col overflow-hidden animate-scale-in"
      >
        <header
          class="p-5 border-b border-outline-variant/40 bg-surface flex items-center justify-between flex-shrink-0 select-none"
        >
          <span class="text-xs font-extrabold text-on-surface tracking-wide">新建播放列表</span>
          <button
            @click="showCreatePlaylistModal = false"
            class="p-1.5 rounded-full hover:bg-surface-high text-on-surface-variant hover:text-on-surface transition-colors cursor-pointer select-none"
          >
            <XIcon class="w-4 h-4" />
          </button>
        </header>
        <div class="p-5 space-y-4 select-none">
          <div class="space-y-1.5">
            <label class="text-[10px] font-bold text-on-surface-variant uppercase tracking-wider">列表名称</label>
            <input
              v-model="newPlaylistName"
              type="text"
              placeholder="请输入新列表的精美名字..."
              class="w-full px-3 py-2 bg-surface-low border border-outline-variant rounded-xl text-xs focus:outline-none focus:border-primary text-on-surface"
              @keyup.enter="triggerCreatePlaylist"
            />
          </div>
        </div>
        <footer
          class="p-4 bg-surface border-t border-outline-variant/60 flex justify-end space-x-2 cursor-pointer select-none"
        >
          <button
            @click="showCreatePlaylistModal = false"
            class="px-3.5 py-1.5 rounded-xl border border-outline-variant hover:bg-surface-high text-xs font-bold text-on-surface transition-colors"
          >
            取消
          </button>
          <button
            @click="triggerCreatePlaylist"
            :disabled="!newPlaylistName.trim()"
            class="px-4 py-1.5 rounded-xl bg-primary hover:bg-primary-high text-xs font-bold text-white shadow-md disabled:opacity-40"
          >
            确认创建
          </button>
        </footer>
      </div>
    </div>

    <!-- 2. 歌单导入弹窗 -->
    <div
      v-if="showImportPlaylistModal"
      class="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-fade-in select-text"
    >
      <div
        class="w-[420px] bg-surface rounded-3xl border border-outline-variant/70 shadow-2xl flex flex-col overflow-hidden animate-scale-in"
      >
        <header
          class="p-5 border-b border-outline-variant/40 bg-surface flex items-center justify-between flex-shrink-0 select-none"
        >
          <span class="text-xs font-extrabold text-on-surface tracking-wide">一键导入网易云歌单</span>
          <button
            @click="showImportPlaylistModal = false"
            class="p-1.5 rounded-full hover:bg-surface-high text-on-surface-variant hover:text-on-surface transition-colors cursor-pointer select-none"
          >
            <XIcon class="w-4 h-4" />
          </button>
        </header>
        <div class="p-5 space-y-4">
          <div class="space-y-1.5 select-none">
            <label class="text-[10px] font-bold text-on-surface-variant uppercase tracking-wider"
              >歌单网页链接或分享短链</label
            >
            <textarea
              v-model="importPlaylistLink"
              placeholder="请粘贴网易云官方歌单链接，如：https://music.163.com/playlist?id=123456...  或者移动端的分享短链"
              class="w-full h-24 p-3 bg-surface-low border border-outline-variant rounded-xl text-xs focus:outline-none focus:border-primary text-on-surface resize-none leading-relaxed"
            ></textarea>
          </div>
          <div class="text-[9px] text-on-surface-variant/50 font-bold select-none leading-relaxed">
            🐾 导入说明：系统会自动分析并跟随重定向解析出真正的网易云歌单 ID，拉取其下多达 300
            首单曲，并一键导入落库到当前选中的本地自建列表中。
          </div>
        </div>
        <footer
          class="p-4 bg-surface border-t border-outline-variant/60 flex justify-end space-x-2 cursor-pointer select-none"
        >
          <button
            @click="showImportPlaylistModal = false"
            class="px-3.5 py-1.5 rounded-xl border border-outline-variant hover:bg-surface-high text-xs font-bold text-on-surface transition-colors"
          >
            取消
          </button>
          <button
            @click="triggerImportPlaylist"
            :disabled="!importPlaylistLink.trim() || isImportingPlaylist"
            class="px-4 py-1.5 rounded-xl bg-primary hover:bg-primary-high text-xs font-bold text-white shadow-md disabled:opacity-40 flex items-center space-x-1"
          >
            <Loader2Icon v-if="isImportingPlaylist" class="w-3 h-3 animate-spin text-white" />
            <span>✓ 开始导入</span>
          </button>
        </footer>
      </div>
    </div>

    <!-- 3. 添加到播放列表弹窗 (高颜值磨砂高透玻璃升级版) -->
    <div
      v-if="showAddToPlaylistModal && songToAddToPlaylist"
      class="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-fade-in select-text"
    >
      <div
        class="w-[360px] rounded-3xl border shadow-2xl flex flex-col overflow-hidden animate-scale-in backdrop-blur-md transition-all duration-300"
        :class="
          isDark
            ? 'bg-zinc-900/95 border-zinc-800 text-zinc-100 shadow-[0_20px_50px_rgba(0,0,0,0.5)]'
            : 'bg-white/95 border-zinc-200/80 text-zinc-800 shadow-[0_20px_40px_rgba(0,0,0,0.08)]'
        "
      >
        <header
          class="p-5 border-b flex items-center justify-between flex-shrink-0 select-none"
          :class="isDark ? 'border-zinc-800/60' : 'border-zinc-200/50'"
        >
          <div class="flex flex-col">
            <span class="text-xs font-extrabold tracking-wide" :class="isDark ? 'text-zinc-100' : 'text-zinc-800'"
              >添加到播放列表</span
            >
            <span
              class="text-[9px] mt-0.5 truncate max-w-[260px] font-medium"
              :class="isDark ? 'text-zinc-400' : 'text-zinc-500'"
              >歌曲：{{ songToAddToPlaylist.name }}</span
            >
          </div>
          <button
            @click="showAddToPlaylistModal = false"
            class="p-1.5 rounded-full hover:bg-surface-high transition-colors cursor-pointer select-none"
            :class="
              isDark
                ? 'hover:bg-zinc-800 text-zinc-400 hover:text-zinc-200'
                : 'hover:bg-zinc-100 text-zinc-500 hover:text-zinc-800'
            "
          >
            <XIcon class="w-4 h-4" />
          </button>
        </header>

        <!-- 播放列表供选区 -->
        <div class="p-4 max-h-[220px] overflow-y-auto space-y-1.5 select-none scrollbar-thin">
          <!-- A. 我的收藏项 -->
          <div
            @click="addSongToPlaylist('love')"
            class="flex items-center px-4 py-2.5 rounded-2xl border transition-all cursor-pointer group"
            :class="
              isDark
                ? 'bg-zinc-800/30 border-zinc-800/80 hover:border-emerald-400/40 hover:bg-emerald-400/5'
                : 'bg-zinc-50 border-zinc-200/60 hover:border-primary/30 hover:bg-primary/5'
            "
          >
            <div
              class="w-8 h-8 rounded-xl bg-red-500/10 text-red-500 flex items-center justify-center mr-3 group-hover:scale-105 transition-transform"
            >
              <HeartIcon class="w-4 h-4 fill-red-500 text-red-500" />
            </div>
            <div class="flex-1 min-w-0">
              <div class="text-xs font-bold">我的收藏</div>
              <div class="text-[9px] mt-0.5" :class="isDark ? 'text-zinc-500' : 'text-zinc-400'">系统默认收藏夹</div>
            </div>
          </div>

          <!-- B. 用户自定义列表 -->
          <div
            v-for="p in musicStore.state.playlists"
            :key="p.id"
            @click="addSongToPlaylist(p.id)"
            class="flex items-center px-4 py-2.5 rounded-2xl border transition-all cursor-pointer group"
            :class="
              isDark
                ? 'bg-zinc-800/30 border-zinc-800/80 hover:border-emerald-400/40 hover:bg-emerald-400/5'
                : 'bg-zinc-50 border-zinc-200/60 hover:border-primary/30 hover:bg-primary/5'
            "
          >
            <div
              class="w-8 h-8 rounded-xl flex items-center justify-center mr-3 group-hover:scale-105 transition-transform"
              :class="isDark ? 'bg-emerald-400/10 text-emerald-400' : 'bg-primary/10 text-primary'"
            >
              <ListMusicIcon class="w-4 h-4" />
            </div>
            <div class="flex-1 min-w-0">
              <div class="text-xs font-bold truncate">{{ p.name }}</div>
              <div class="text-[9px] mt-0.5" :class="isDark ? 'text-zinc-500' : 'text-zinc-400'">用户创建列表</div>
            </div>
          </div>

          <!-- 空白占位 -->
          <div
            v-if="!musicStore.state.playlists.length"
            class="text-center py-4 text-[10px]"
            :class="isDark ? 'text-zinc-600' : 'text-zinc-400'"
          >
            暂无自定义播放列表，可在下方快速创建
          </div>
        </div>

        <!-- 底部：快捷新建歌单并添加 -->
        <div
          class="p-4 border-t flex flex-col space-y-2 select-none"
          :class="isDark ? 'bg-zinc-950/20 border-zinc-800/80' : 'bg-zinc-50/60 border-zinc-200/50'"
        >
          <div
            class="text-[9px] font-bold uppercase tracking-wider pl-1"
            :class="isDark ? 'text-zinc-500' : 'text-zinc-400'"
          >
            快速创建新列表并加入
          </div>
          <div class="flex items-center space-x-2">
            <input
              v-model="quickNewPlaylistName"
              type="text"
              placeholder="新歌单名称..."
              class="flex-1 px-3 py-2 border rounded-xl text-xs focus:outline-none transition-all font-sans select-text"
              :class="
                isDark
                  ? 'bg-zinc-800/80 border-zinc-700 text-zinc-100 focus:border-emerald-400 focus:bg-zinc-800/50 placeholder-zinc-600'
                  : 'bg-white border-zinc-200 text-zinc-800 focus:border-primary placeholder-zinc-400'
              "
              @keyup.enter="triggerQuickCreatePlaylistAndAdd"
            />
            <button
              @click="triggerQuickCreatePlaylistAndAdd"
              :disabled="!quickNewPlaylistName.trim()"
              class="px-4 py-2 rounded-xl text-xs font-bold shadow-md transition-all whitespace-nowrap"
              :class="
                isDark
                  ? 'bg-emerald-400 hover:bg-emerald-300 text-zinc-950 disabled:opacity-40 disabled:scale-100 active:scale-95 shadow-[0_0_12px_rgba(52,211,153,0.15)] cursor-pointer'
                  : 'bg-primary hover:bg-primary-high text-white disabled:opacity-40 disabled:scale-100 active:scale-95 cursor-pointer'
              "
            >
              创建并添加
            </button>
          </div>
        </div>
      </div>
    </div>

    <!-- 移动端精致底部导航栏 -->
    <div
      v-if="isMobile"
      :class="
        isInputFocused
          ? 'opacity-0 translate-y-full h-0 border-t-0 pointer-events-none py-0'
          : 'opacity-100 translate-y-0 h-16 border-t border-sidebar-border/30 py-1'
      "
      class="flex md:hidden w-full bg-sidebar/85 backdrop-blur-xl flex-shrink-0 items-center justify-around px-1 z-40 select-none pb-safe transition-all duration-300 ease-in-out"
    >
      <!-- 1. 对话 -->
      <button
        @click="
          sideView = 'chat';
          selectedCharacterId = null;
          activeView = 'chat';
        "
        class="flex flex-col items-center justify-center space-y-0.5 py-1 w-[42px] px-0.5 text-on-surface-variant hover:text-primary transition-all active:scale-90"
        :class="{ 'text-primary font-bold': sideView === 'chat' }"
      >
        <MessageSquareIcon class="w-5 h-5" />
        <span class="text-[9px] scale-90 font-semibold tracking-tighter">对话</span>
      </button>

      <!-- 2. 通讯录 -->
      <button
        @click="
          sideView = 'contacts';
          selectedContactId = null;
        "
        class="flex flex-col items-center justify-center space-y-0.5 py-1 w-[42px] px-0.5 text-on-surface-variant hover:text-primary transition-all active:scale-90"
        :class="{ 'text-primary font-bold': sideView === 'contacts' }"
      >
        <UsersIcon class="w-5 h-5" />
        <span class="text-[9px] scale-90 font-semibold tracking-tighter">通讯录</span>
      </button>

      <!-- 3. 朋友圈 -->
      <button
        @click="
          sideView = 'moments';
          loadMomentsList();
        "
        class="flex flex-col items-center justify-center space-y-0.5 py-1 w-[42px] px-0.5 text-on-surface-variant hover:text-primary relative transition-all active:scale-90"
        :class="{ 'text-primary font-bold': sideView === 'moments' }"
      >
        <GlobeIcon class="w-5 h-5" />
        <span
          v-if="unreadMomentsCount > 0"
          class="absolute top-1.5 right-1.5 w-2 h-2 bg-red-500 rounded-full shadow-sm"
        ></span>
        <span class="text-[9px] scale-90 font-semibold tracking-tighter">朋友圈</span>
      </button>

      <!-- 4. 论坛 -->
      <button
        @click="
          sideView = 'forum';
          selectBoard('all');
          selectedForumPost = null;
        "
        class="flex flex-col items-center justify-center space-y-0.5 py-1 w-[42px] px-0.5 text-on-surface-variant hover:text-primary relative transition-all active:scale-90"
        :class="{ 'text-primary font-bold': sideView === 'forum' }"
      >
        <ScrollIcon class="w-5 h-5" />
        <span
          v-if="unreadForumCount > 0"
          class="absolute top-1.5 right-1.5 w-2 h-2 bg-red-500 rounded-full shadow-sm"
        ></span>
        <span class="text-[9px] scale-90 font-semibold tracking-tighter">论坛</span>
      </button>

      <!-- 5. 更多 -->
      <button
        @click="showMobileMoreDrawer = true"
        class="flex flex-col items-center justify-center space-y-0.5 py-1 w-[42px] px-0.5 text-on-surface-variant hover:text-primary relative transition-all active:scale-90"
        :class="{ 'text-primary font-bold': ['favorites', 'bookshelf', 'settings'].includes(sideView) }"
      >
        <MenuIcon class="w-5 h-5" />
        <!-- 如果小说有新章节，红点提醒 -->
        <span
          v-if="Object.values(novelNewChapterBadges).reduce((a, b) => a + b, 0) > 0"
          class="absolute top-1.5 right-1.5 w-2 h-2 bg-red-500 rounded-full shadow-sm"
        ></span>
        <span class="text-[9px] scale-90 font-semibold tracking-tighter">更多</span>
      </button>
    </div>

    <!-- 移动端“更多”遮罩抽屉 (Bottom Drawer) -->
    <div
      v-if="isMobile && showMobileMoreDrawer"
      class="fixed inset-0 z-50 flex flex-col justify-end"
      @click.self="showMobileMoreDrawer = false"
    >
      <!-- 遮罩背景 -->
      <div class="absolute inset-0 bg-black/40 backdrop-blur-sm transition-opacity duration-300"></div>

      <!-- 抽屉主体面板 -->
      <div
        class="relative bg-surface-low border-t border-outline-variant/30 rounded-t-[32px] px-5 pb-8 pt-5 flex flex-col space-y-5 animate-in slide-in-from-bottom duration-300 select-none"
      >
        <!-- 抽屉顶部小提手 -->
        <div class="w-12 h-1 bg-outline-variant/60 rounded-full mx-auto mb-2"></div>

        <div class="text-xs font-bold text-on-surface-variant/60 px-1">更多功能</div>

        <div class="grid grid-cols-3 gap-3">
          <!-- 1. 书架 -->
          <button
            @click="
              sideView = 'bookshelf';
              showMobileMoreDrawer = false;
              mobileReadLayer = 'shelf';
              loadBookshelf();
            "
            class="flex flex-col items-center justify-center p-4 rounded-2xl border transition-all active:scale-95"
            :class="
              sideView === 'bookshelf'
                ? 'border-primary bg-primary/5 text-primary'
                : 'border-outline-variant/20 bg-surface text-on-surface'
            "
          >
            <div class="relative">
              <LibraryIcon class="w-6 h-6 mb-1.5" />
              <span
                v-if="Object.values(novelNewChapterBadges).reduce((a, b) => a + b, 0) > 0"
                class="absolute -top-1 -right-2 bg-red-500 text-[8px] text-white px-1.5 py-0.5 rounded-full font-bold leading-none scale-75"
              >
                {{ Object.values(novelNewChapterBadges).reduce((a, b) => a + b, 0) }}
              </span>
            </div>
            <span class="text-[10px] font-bold">小说书架</span>
          </button>

          <!-- 2. 收藏 -->
          <button
            @click="
              sideView = 'favorites';
              loadFavoritesList();
              selectedFavorite = null;
              showMobileMoreDrawer = false;
            "
            class="flex flex-col items-center justify-center p-4 rounded-2xl border transition-all active:scale-95"
            :class="
              sideView === 'favorites'
                ? 'border-primary bg-primary/5 text-primary'
                : 'border-outline-variant/20 bg-surface text-on-surface'
            "
          >
            <BookmarkIcon class="w-6 h-6 mb-1.5" />
            <span class="text-[10px] font-bold">我的收藏</span>
          </button>

          <!-- 3. 设置 -->
          <button
            @click="
              sideView = 'settings';
              isMobileSettingsActive = false;
              showMobileMoreDrawer = false;
            "
            class="flex flex-col items-center justify-center p-4 rounded-2xl border transition-all active:scale-95"
            :class="
              sideView === 'settings'
                ? 'border-primary bg-primary/5 text-primary'
                : 'border-outline-variant/20 bg-surface text-on-surface'
            "
          >
            <SettingsIcon class="w-6 h-6 mb-1.5" />
            <span class="text-[10px] font-bold">系统设置</span>
          </button>
        </div>

        <!-- 关闭按钮 -->
        <button
          @click="showMobileMoreDrawer = false"
          class="w-full py-3 bg-surface-high/40 hover:bg-surface-high/60 active:scale-98 rounded-2xl text-xs font-bold text-on-surface transition-all"
        >
          关闭
        </button>
      </div>
    </div>

    <!-- 转发消息好友选择弹窗 (iOS/WeChat 同款高颜值磨砂升级版) -->
    <div
      v-if="showForwardModal"
      class="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-fade-in select-text"
    >
      <div
        class="w-[360px] bg-surface rounded-3xl border border-outline-variant/70 shadow-2xl flex flex-col max-h-[75vh] overflow-hidden select-text animate-scale-in"
      >
        <header
          class="p-5 border-b border-outline-variant/40 bg-surface flex items-center justify-between flex-shrink-0 select-none"
        >
          <div class="flex items-center space-x-2.5">
            <Share2Icon class="w-4.5 h-4.5 text-primary animate-pulse" />
            <span class="text-xs font-extrabold text-on-surface tracking-wide">转发消息至...</span>
          </div>
          <button
            @click="showForwardModal = false"
            class="p-1.5 rounded-full hover:bg-surface-high text-on-surface-variant hover:text-on-surface transition-colors cursor-pointer select-none"
          >
            <XIcon class="w-4 h-4" />
          </button>
        </header>

        <!-- 搜索输入框 -->
        <div class="p-3 bg-surface-low border-b border-outline-variant/10 flex-shrink-0 select-none">
          <div class="relative">
            <SearchIcon class="absolute left-3 top-3 w-3.5 h-3.5 text-on-surface-variant/40" />
            <input
              v-model="forwardQuery"
              type="text"
              placeholder="搜索联系人名字..."
              class="w-full pl-9 pr-4 py-2 rounded-xl bg-surface border border-outline-variant/50 text-[11px] text-on-surface placeholder-on-surface-variant/30 focus:outline-none focus:border-primary transition-all shadow-inner"
            />
          </div>
        </div>

        <!-- 好友列表 -->
        <div class="flex-1 overflow-y-auto p-3.5 space-y-2 min-h-0 select-none max-h-[380px]">
          <div
            v-if="filteredCharacters.length === 0"
            class="text-center py-12 text-[10.5px] text-on-surface-variant/40"
          >
            没有匹配社区角色 🐾
          </div>
          <button
            v-for="char in filteredCharacters"
            :key="char.id"
            @click="forwardMessageToCharacter(char)"
            class="w-full flex items-center space-x-3 p-3 rounded-2xl bg-surface-low/50 hover:bg-primary/5 active:bg-primary/10 transition-all text-left cursor-pointer border border-outline-variant/30 hover:border-primary/20 shadow-sm"
          >
            <div
              class="w-8 h-8 rounded-xl overflow-hidden border border-outline-variant shadow-sm flex-shrink-0 bg-surface-low flex items-center justify-center"
            >
              <img
                v-if="characterAvatars[char.id]"
                :src="characterAvatars[char.id]"
                class="w-full h-full object-cover"
              />
              <UserIcon v-else class="w-4 h-4 text-on-surface-variant m-auto" />
            </div>
            <div class="flex-1 min-w-0">
              <h5 class="text-xs font-black text-on-surface truncate">{{ char.name }}</h5>
              <p class="text-[9px] text-on-surface-variant/60 truncate mt-0.5">{{ char.folder_name }}</p>
            </div>
          </button>
        </div>
      </div>
    </div>

    <!-- 🚀 手机端消息“选择复制”专用弹窗（毛玻璃拟真大字阅读与局部选择模式） -->
    <div
      v-if="showSelectCopyModal"
      class="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-md p-4 animate-fade-in select-text"
    >
      <div
        class="w-full max-w-[340px] bg-surface rounded-3xl border border-outline-variant/70 shadow-2xl flex flex-col max-h-[70vh] overflow-hidden select-text animate-scale-in"
      >
        <!-- 头部 -->
        <header
          class="p-4 border-b border-outline-variant/40 bg-surface flex items-center justify-between flex-shrink-0 select-none"
        >
          <div class="flex items-center space-x-2">
            <ScissorsIcon class="w-4 h-4 text-primary animate-pulse" />
            <span class="text-xs font-black text-on-surface tracking-wide">选择复制（长按拖拽局部文字）</span>
          </div>
          <button
            @click="showSelectCopyModal = false"
            class="p-1.5 rounded-full hover:bg-surface-high text-on-surface-variant hover:text-on-surface transition-colors cursor-pointer select-none"
          >
            <XIcon class="w-4 h-4" />
          </button>
        </header>

        <!-- 卡片内容区域：在这个大框框里，正文强制开启选择！ -->
        <div class="flex-1 overflow-y-auto p-5 select-text min-h-0 bg-surface-low">
          <div class="p-4 rounded-2xl bg-surface border border-outline-variant/50 shadow-inner select-text">
            <p
              class="select-text text-sm leading-relaxed text-on-surface whitespace-pre-wrap break-all mobile-select-text"
            >
              {{ selectCopyText }}
            </p>
          </div>
        </div>

        <!-- 底部操作按钮 -->
        <footer
          class="p-4 border-t border-outline-variant/30 bg-surface flex items-center space-x-3 flex-shrink-0 select-none"
        >
          <button
            @click="selectCopyAll"
            class="flex-1 py-2.5 rounded-xl bg-primary text-white text-xs font-bold shadow-md active:scale-95 transition-all hover:bg-primary-container flex items-center justify-center space-x-1.5"
          >
            <CopyIcon class="w-3.5 h-3.5" />
            <span>复制全文</span>
          </button>
          <button
            @click="showSelectCopyModal = false"
            class="px-5 py-2.5 rounded-xl bg-surface-high border border-outline-variant/60 text-on-surface-variant text-xs font-bold active:scale-95 transition-all"
          >
            关闭
          </button>
        </footer>
      </div>
    </div>

    <!-- 🚀 浮动用户协议只读回看 Modal（用于同意协议后在关于页面中随时无感唤起） -->
    <div
      v-if="showAgreementModal && isAgreementViewMode"
      class="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-fade-in select-text"
    >
      <div
        class="w-full max-w-[500px] h-[80vh] bg-surface rounded-[24px] border border-outline-variant shadow-2xl flex flex-col overflow-hidden animate-scale-in relative select-text"
      >
        <header
          class="p-5 border-b border-outline-variant/30 flex items-center justify-between select-none flex-shrink-0 bg-surface"
        >
          <div class="flex items-center space-x-3">
            <BookOpenIcon class="w-4.5 h-4.5 text-primary animate-pulse" />
            <h3 class="text-xs font-black text-on-surface tracking-wide">用户协议与免责声明</h3>
          </div>
          <button
            @click="showAgreementModal = false"
            class="p-1.5 rounded-full hover:bg-surface-high text-on-surface-variant hover:text-on-surface transition-colors cursor-pointer"
          >
            <XIcon class="w-4 h-4" />
          </button>
        </header>

        <!-- 🚀 纯 Markdown 条款排版区 -->
        <div
          class="flex-1 overflow-y-auto p-5 select-text bg-surface-low border-b border-outline-variant/20 mobile-select-text leading-relaxed markdown-body"
          v-html="renderMarkdown(agreementText)"
        ></div>

        <footer
          class="p-4 flex items-center justify-end bg-surface select-none flex-shrink-0 border-t border-outline-variant/10"
        >
          <button
            @click="showAgreementModal = false"
            class="px-8 py-2.5 rounded-xl bg-primary text-white text-xs font-bold hover:bg-primary-container active:scale-95 transition-all shadow-md cursor-pointer"
          >
            确定
          </button>
        </footer>
      </div>
    </div>

    <!-- 🚀 全局版本升级就绪高级拟真自适应 Modal -->
    <div
      v-if="showUpdateModal"
      class="fixed inset-0 z-[1000] flex items-center justify-center p-4 bg-black/30 dark:bg-black/75 backdrop-blur-[16px] animate-fade-in select-text"
    >
      <div
        class="w-full max-w-[420px] bg-white/95 dark:bg-[#0c0c0d] border border-white/60 dark:border-[#202022] shadow-[0_24px_60px_-15px_rgba(0,0,0,0.12)] dark:shadow-[0_30px_70px_-15px_rgba(0,0,0,0.7)] flex flex-col overflow-hidden animate-scale-in relative rounded-[28px] dark:rounded-[12px] select-text"
      >
        <!-- 亮色模式下的背景微弱七彩流光模糊晕染 -->
        <div
          class="absolute -top-32 -left-32 w-64 h-64 rounded-full bg-gradient-to-tr from-primary/8 via-secondary/4 to-transparent blur-3xl pointer-events-none"
        ></div>
        <div
          class="absolute -bottom-32 -right-32 w-64 h-64 rounded-full bg-gradient-to-tr from-secondary/5 via-primary/5 to-transparent blur-3xl pointer-events-none"
        ></div>

        <!-- 🚀 暗色模式专用：极其克制的“翠绿激光二极管”极细发光线条 -->
        <div
          class="absolute top-0 left-1/2 -translate-x-1/2 w-32 h-[2px] bg-gradient-to-r from-transparent via-[#4edea3] to-transparent blur-[0.5px] dark:opacity-90 pointer-events-none"
        ></div>

        <!-- 头部设计：极精致云端升级图标与标题 -->
        <header class="pt-8 pb-3 px-6 flex flex-col items-center select-none flex-shrink-0 relative">
          <!-- 升级指示图标：极简高保真云端同步徽章 -->
          <div
            class="w-12 h-12 rounded-2xl dark:rounded-[8px] bg-primary/10 dark:bg-primary/20 flex items-center justify-center text-primary dark:text-[#4edea3] mb-3.5 shadow-inner"
          >
            <svg
              class="w-6 h-6 animate-pulse"
              style="animation-duration: 2s"
              fill="none"
              stroke="currentColor"
              stroke-width="2"
              viewBox="0 0 24 24"
            >
              <path
                stroke-linecap="round"
                stroke-linejoin="round"
                d="M12 16.5V9.75m0 0l3 3m-3-3l-3 3M6.75 19.5a4.5 4.5 0 01-1.41-8.775 5.25 5.25 0 0110.233-2.33 3 3 0 013.758 3.848A3.752 3.752 0 0118 19.5H6.75z"
              />
            </svg>
          </div>

          <h3 class="text-base font-extrabold text-on-surface tracking-tight text-center dark:text-[#e5e2e1]">
            {{ isDockerUpdate ? '新版本回音已就绪' : '发现新版本回音' }}
          </h3>
          <p
            class="text-[10px] text-on-surface-variant/60 dark:text-[#bbcabf]/50 mt-1 select-none font-sans dark:font-mono"
          >
            数字生命扮演系统 · 精益升级
          </p>
        </header>

        <!-- 🚀 版本比对卡片组件 (Version Comparison Widget - 极简极奢款) -->
        <div class="px-6 pb-2 flex-shrink-0 select-none">
          <div
            class="flex items-center justify-center space-x-3.5 py-2 px-4 bg-surface-low/30 dark:bg-[#1a1a1a]/30 border border-outline-variant/10 dark:border-[#202022] rounded-[18px] dark:rounded-[6px] max-w-[290px] mx-auto shadow-sm"
          >
            <div class="flex flex-col items-center">
              <span
                class="text-[8px] text-on-surface-variant/40 dark:text-[#bbcabf]/30 font-bold tracking-wider uppercase font-mono"
                >Current</span
              >
              <span
                class="text-[11px] font-bold text-on-surface-variant/70 dark:text-[#c6c6c6] font-mono select-text mt-0.5"
                >v{{ appVersion }}</span
              >
            </div>

            <!-- 指示箭头带极精密虚线 -->
            <div
              class="flex-1 flex items-center justify-center text-primary/30 dark:text-[#4edea3]/30 min-w-[60px] relative"
            >
              <div class="w-full border-t border-dashed border-current scale-y-[0.5] opacity-40"></div>
              <div
                class="absolute p-0.5 rounded-full bg-white dark:bg-[#121214] border border-outline-variant/5 dark:border-[#202022]"
              >
                <ChevronRightIcon class="w-3.5 h-3.5 text-primary dark:text-[#4edea3]" />
              </div>
            </div>

            <div class="flex flex-col items-center">
              <span
                class="text-[8px] text-primary/60 dark:text-[#4edea3]/60 font-bold tracking-wider uppercase font-mono"
                >Latest</span
              >
              <span class="text-[11px] font-extrabold text-primary dark:text-[#4edea3] font-mono select-text mt-0.5"
                >v{{ latestVersion }}</span
              >
            </div>
          </div>
        </div>

        <!-- 更新日志区域 (空气感无界面板) -->
        <div class="flex-1 overflow-y-auto pt-3 pb-5 px-6 select-text max-h-[220px] leading-relaxed">
          <h4 class="text-[11px] font-bold text-on-surface/80 dark:text-[#e5e2e1]/80 mb-2.5 select-none tracking-wide">
            本次升级内容：
          </h4>

          <div class="space-y-3 px-1">
            <div
              v-for="(item, index) in parsedChangelog"
              :key="index"
              class="flex items-start space-x-3 text-left animate-fade-in"
              :style="{ animationDelay: `${index * 50}ms` }"
            >
              <!-- 精致微型高光图标前置点缀 -->
              <div
                class="w-4.5 h-4.5 rounded-full bg-primary/8 dark:bg-[#4edea3]/10 flex items-center justify-center text-primary dark:text-[#4edea3] flex-shrink-0 mt-0.5"
              >
                <CheckIcon class="w-2.5 h-2.5 stroke-[3]" />
              </div>
              <span
                class="text-[11px] text-on-surface-variant/90 dark:text-[#bbcabf]/90 leading-relaxed font-sans dark:font-mono select-text"
              >
                {{ item.replace(/^\d+[\.\s、]+/, '') }}
              </span>
            </div>
          </div>
        </div>

        <!-- 底部控制栏：右侧高保真高度对称排列，无生硬线 -->
        <footer class="pb-6 pt-2 px-6 flex items-center justify-end space-x-3 select-none flex-shrink-0 bg-transparent">
          <!-- A. 稍后更新幽灵按钮 (解决 Tailwind 编译透明度失效 Bug，高宽圆角完全对称) -->
          <button
            @click="showUpdateModal = false"
            class="px-6 py-2.5 rounded-xl dark:rounded-[4px] bg-surface-low hover:bg-surface-high text-xs font-bold text-on-surface-variant/80 dark:text-[#e5e2e1] transition-all duration-200 hover:-translate-y-[1px] active:translate-y-0 cursor-pointer text-center font-sans dark:font-mono"
          >
            {{ isDockerUpdate ? '稍后更新' : '稍后安装' }}
          </button>

          <!-- B. Docker 专属一键极速复制指令按钮 -->
          <button
            v-if="isDockerUpdate"
            @click="handleCopyDockerCommand"
            :class="[
              'px-6 py-2.5 rounded-xl dark:rounded-[4px] text-xs font-bold transition-all duration-200 hover:-translate-y-[1px] active:translate-y-0 shadow-sm flex items-center justify-center space-x-1.5 cursor-pointer relative overflow-hidden group font-sans dark:font-mono',
              copiedDockerCmd
                ? 'bg-emerald-600 dark:bg-[#4edea3] text-white dark:text-[#050505] shadow-[0_4px_12px_rgba(16,185,129,0.2)] dark:shadow-[0_0_12px_var(--primary)]'
                : 'bg-primary dark:bg-[#e5e5e5] text-white dark:text-[#050505] hover:brightness-105 shadow-sm dark:hover:shadow-[0_0_12px_var(--primary)]',
            ]"
          >
            <!-- 闪光特效 -->
            <div
              class="absolute inset-0 w-1/2 h-full bg-white/15 dark:bg-black/10 skew-x-12 -translate-x-full group-hover:animate-shine"
            ></div>
            <CheckIcon v-if="copiedDockerCmd" class="w-3.5 h-3.5" />
            <CopyIcon v-else class="w-3.5 h-3.5" />
            <span>{{ copiedDockerCmd ? '指令已复制！' : '复制 Docker 更新指令' }}</span>
          </button>

          <!-- C. 常规电脑客户端重启安装按钮 -->
          <template v-else>
            <button
              v-if="isElectron"
              @click="handleRestartAndInstall"
              class="px-6 py-2.5 rounded-xl dark:rounded-[4px] bg-gradient-to-r from-primary to-[#6063ee] dark:bg-none dark:bg-[#e5e5e5] text-white dark:text-[#050505] hover:brightness-105 hover:shadow-[0_6px_18px_rgba(70,72,212,0.25)] hover:-translate-y-[1px] active:translate-y-0 transition-all duration-200 flex items-center justify-center space-x-1.5 cursor-pointer relative overflow-hidden group font-sans dark:font-mono dark:hover:shadow-[0_0_12px_var(--primary)]"
            >
              <!-- 闪光特效 -->
              <div
                class="absolute inset-0 w-1/2 h-full bg-white/15 dark:bg-black/10 skew-x-12 -translate-x-full group-hover:animate-shine"
              ></div>
              <RefreshCwIcon class="w-3.5 h-3.5 animate-spin-slow" />
              <span>重启并升级</span>
            </button>
            <div
              v-else
              class="px-4 py-2 rounded-xl dark:rounded-[4px] bg-primary/10 dark:bg-primary/20 text-xs font-semibold text-primary dark:text-[#4edea3] text-center border border-primary/20 dark:border-[#4edea3]/20 shadow-sm font-sans dark:font-mono select-none"
            >
              🐾 请前往您的电脑端客户端点击重启升级
            </div>
          </template>
        </footer>
      </div>
    </div>
  </div>

  <!-- ========================= 多端复用单例全局表情包/Emoji面板 ========================= -->
  <div
    v-if="showGlobalEmojiPanel"
    @click.stop
    :style="globalEmojiPanelStyle"
    class="fixed z-[999] p-3 flex flex-col w-[260px] h-[220px] justify-between animate-scale-in select-none glass-panel shadow-[0_12px_40px_-6px_rgba(0,0,0,0.3)] rounded-2xl border border-outline-variant/30 backdrop-blur-2xl bg-surface/85"
  >
    <!-- A. 默认表情 -->
    <div
      v-if="emojiActiveTab === 'default'"
      class="flex flex-wrap gap-1.5 overflow-y-auto flex-1 select-none pr-1 py-1"
    >
      <button
        v-for="emoji in emojiList"
        :key="emoji"
        class="w-6 h-6 flex items-center justify-center text-lg hover:scale-125 hover:bg-surface-high/60 rounded transition-all cursor-pointer"
        @click="handleGlobalEmojiSelect(emoji)"
      >
        {{ emoji }}
      </button>
    </div>

    <!-- B. 自定义表情 (Stickers) -->
    <div v-else class="grid grid-cols-5 gap-1.5 overflow-y-auto flex-1 select-none pr-1 py-1 min-h-0">
      <div
        v-if="customEmojiList.length === 0"
        class="col-span-5 flex flex-col items-center justify-center text-[10px] text-on-surface-variant/40 py-8"
      >
        <HeartIcon class="w-8 h-8 opacity-25 mb-1.5" />
        <span>暂无收藏表情包</span>
      </div>
      <div
        v-for="emoji in customEmojiList"
        :key="emoji.id"
        @click="handleGlobalStickerSelect(emoji)"
        class="aspect-square rounded-lg overflow-hidden border border-outline-variant/60 hover:border-primary bg-surface flex items-center justify-center p-0.5 cursor-pointer hover:scale-105 active:scale-95 transition-all relative shadow-sm"
        :title="emoji.meaning"
      >
        <img :src="emoji.base64" class="w-full h-full object-contain select-none" />
      </div>
    </div>

    <!-- 页签切换 -->
    <div class="flex items-center space-x-2 pt-2 border-t border-outline-variant/20 mt-1.5 flex-shrink-0 select-none">
      <button
        @click="emojiActiveTab = 'default'"
        class="w-6 h-6 rounded flex items-center justify-center transition-all cursor-pointer border"
        :class="
          emojiActiveTab === 'default'
            ? 'bg-surface text-primary border-primary/20 shadow-sm'
            : 'bg-surface-high/40 text-on-surface-variant border-transparent'
        "
        title="默认表情"
      >
        <SmileIcon class="w-3.5 h-3.5" />
      </button>
      <button
        @click="emojiActiveTab = 'favorites'"
        class="w-6 h-6 rounded flex items-center justify-center transition-all cursor-pointer border"
        :class="
          emojiActiveTab === 'favorites'
            ? 'bg-surface text-[#ff4b72] border-[#ff4b72]/20 shadow-sm'
            : 'bg-surface-high/40 text-on-surface-variant border-transparent'
        "
        title="自定义表情"
      >
        <HeartIcon class="w-3.5 h-3.5" />
      </button>
    </div>
  </div>

  <!-- 精美全局 Toast 通知的浮动 UI 气泡 (苹果极简毛玻璃药丸微图标升级版) -->
  <div
    v-if="toastVisible"
    class="fixed top-8 left-1/2 -translate-x-1/2 z-[9999] px-6 py-3 bg-slate-900/90 dark:bg-slate-950/95 text-white text-[12px] font-semibold rounded-full shadow-[0_12px_40px_-6px_rgba(0,0,0,0.6)] backdrop-blur-xl flex items-center space-x-3 border border-white/10 animate-fade-in select-none tracking-wide"
  >
    <SparklesIcon class="w-3.5 h-3.5 text-amber-400 animate-spin" style="animation-duration: 4s" />
    <span>{{ toastMessage }}</span>
  </div>

  <!-- A. AI 绘图场景 Prompt 预览与微调确认 Modal -->
  <div
    v-if="showPromptConfirmModal"
    class="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200 select-none"
    @click.self="showPromptConfirmModal = false"
  >
    <div
      class="max-w-md w-full bg-surface-low border border-outline-variant/20 rounded-2xl p-6 shadow-2xl space-y-5 animate-in zoom-in-95 duration-200 text-on-surface"
    >
      <div class="flex items-center space-x-2.5 border-b border-outline-variant/20 pb-3">
        <div
          class="w-8 h-8 rounded-xl bg-primary/10 border border-primary/20 flex items-center justify-center text-primary"
        >
          <SparklesIcon class="w-4 h-4" />
        </div>
        <div>
          <h3 class="text-xs font-bold">微调绘图场景设计</h3>
          <p class="text-[9px] text-on-surface-variant mt-0.5">确认或修改当前场景生成的绘图细节与尺寸</p>
        </div>
      </div>

      <!-- 场景简述展示 -->
      <div class="space-y-1 bg-surface-high/30 p-3 rounded-xl border border-outline-variant/10">
        <span class="text-[9px] font-bold text-on-surface-variant uppercase tracking-wider font-mono"
          >场景中文设计构想</span
        >
        <p class="text-xs text-on-surface leading-relaxed select-text">{{ confirmedDescription }}</p>
      </div>

      <!-- Prompt Tags 编辑框 -->
      <div class="space-y-1.5">
        <label class="text-[10px] font-bold text-on-surface-variant uppercase tracking-wider font-mono"
          >生图 Prompt (Tags) - 支持自由微调</label
        >
        <textarea
          v-model="confirmedPrompt"
          rows="4"
          class="form-input font-mono text-[10px] leading-relaxed resize-none bg-surface p-3"
          placeholder="1girl, detailed background..."
        ></textarea>
        <p class="text-[9px] text-on-surface-variant leading-normal">
          注：绘图时，系统会自动将您在角色物理目录中提炼的 Appearance
          专属外貌特征标签合并在最前面，以确保五官和形象不偏离。
        </p>
      </div>

      <!-- 尺寸长宽比选择 -->
      <div class="space-y-2">
        <label class="text-[10px] font-bold text-on-surface-variant uppercase tracking-wider font-mono"
          >长宽比尺寸选择</label
        >
        <div class="grid grid-cols-4 gap-2">
          <button
            type="button"
            @click="confirmedDimensions = 'portrait'"
            class="p-2 rounded-xl border-2 flex flex-col items-center justify-center transition-all bg-surface hover:border-primary active:scale-95 text-on-surface-variant"
            :class="
              confirmedDimensions === 'portrait'
                ? 'border-primary bg-primary/5 text-primary'
                : 'border-outline-variant/60 text-on-surface-variant'
            "
          >
            <div class="w-3 h-5 border border-current rounded-sm mb-1 opacity-70"></div>
            <span class="text-[9px] font-bold">纵向 832x1216</span>
          </button>
          <button
            type="button"
            @click="confirmedDimensions = 'landscape'"
            class="p-2 rounded-xl border-2 flex flex-col items-center justify-center transition-all bg-surface hover:border-primary active:scale-95 text-on-surface-variant"
            :class="
              confirmedDimensions === 'landscape'
                ? 'border-primary bg-primary/5 text-primary'
                : 'border-outline-variant/60 text-on-surface-variant'
            "
          >
            <div class="w-5 h-3 border border-current rounded-sm mb-1 opacity-70"></div>
            <span class="text-[9px] font-bold">横向 1216x832</span>
          </button>
          <button
            type="button"
            @click="confirmedDimensions = 'square'"
            class="p-2 rounded-xl border-2 flex flex-col items-center justify-center transition-all bg-surface hover:border-primary active:scale-95 text-on-surface-variant"
            :class="
              confirmedDimensions === 'square'
                ? 'border-primary bg-primary/5 text-primary'
                : 'border-outline-variant/60 text-on-surface-variant'
            "
          >
            <div class="w-4 h-4 border border-current rounded-sm mb-1.5 opacity-70"></div>
            <span class="text-[9px] font-bold">正方 1024x1024</span>
          </button>
          <button
            type="button"
            @click="confirmedDimensions = 'custom'"
            class="p-2 rounded-xl border-2 flex flex-col items-center justify-center transition-all bg-surface hover:border-primary active:scale-95 text-on-surface-variant"
            :class="
              confirmedDimensions === 'custom'
                ? 'border-primary bg-primary/5 text-primary'
                : 'border-outline-variant/60 text-on-surface-variant'
            "
          >
            <div
              class="w-4 h-4 border-2 border-dashed border-current rounded-sm mb-1.5 opacity-70 flex items-center justify-center text-[7px] font-black"
            >
              ⚙️
            </div>
            <span class="text-[9px] font-bold">自定义尺寸</span>
          </button>
        </div>
      </div>

      <!-- 自定义尺寸高宽输入框 -->
      <div
        v-if="confirmedDimensions === 'custom'"
        class="space-y-2 p-3 bg-surface-high/30 rounded-xl border border-outline-variant/10 animate-in fade-in slide-in-from-top-2 duration-200"
      >
        <label class="text-[10px] font-bold text-on-surface-variant uppercase tracking-wider font-mono"
          >自定义尺寸 (必须为 64 的倍数)</label
        >
        <div class="flex items-center space-x-3">
          <div class="flex-1 flex items-center bg-surface border border-outline-variant/50 rounded-lg px-3 py-1.5">
            <span class="text-[10px] text-on-surface-variant mr-2 select-none shrink-0 whitespace-nowrap">宽度:</span>
            <input
              v-model.number="customWidth"
              type="number"
              step="64"
              min="256"
              max="2560"
              @blur="customWidth = Math.max(256, Math.min(2560, Math.round(customWidth / 64) * 64))"
              class="w-full text-xs font-mono bg-transparent text-on-surface focus:outline-none"
            />
          </div>
          <span class="text-xs text-on-surface-variant font-bold">×</span>
          <div class="flex-1 flex items-center bg-surface border border-outline-variant/50 rounded-lg px-3 py-1.5">
            <span class="text-[10px] text-on-surface-variant mr-2 select-none shrink-0 whitespace-nowrap">高度:</span>
            <input
              v-model.number="customHeight"
              type="number"
              step="64"
              min="256"
              max="2560"
              @blur="customHeight = Math.max(256, Math.min(2560, Math.round(customHeight / 64) * 64))"
              class="w-full text-xs font-mono bg-transparent text-on-surface focus:outline-none"
            />
          </div>
        </div>
        <p class="text-[9px] text-on-surface-variant/70 leading-normal">
          说明：尺寸越大会消耗越多的 Anlas 算力点数。超出 1024 x 1024 面积将扣除额外点数。
        </p>
      </div>

      <!-- 操作按钮 -->
      <div class="flex space-x-3 pt-2">
        <button @click="showPromptConfirmModal = false" class="btn-secondary flex-1 text-xs py-2 rounded-xl">
          取消
        </button>
        <button
          @click="handleConfirmModalImageGeneration"
          class="btn-primary flex-1 text-xs py-2 rounded-xl flex items-center justify-center space-x-1"
        >
          <SparklesIcon class="w-3.5 h-3.5" />
          <span>确定绘制场景</span>
        </button>
      </div>
    </div>
  </div>

  <!-- B. 大图预览毛玻璃 Modal -->
  <div
    v-if="showBigImageModal"
    class="fixed inset-0 z-[1000] flex items-center justify-center p-4 bg-black/80 backdrop-blur-md animate-in fade-in duration-200 select-none"
    @click.self="showBigImageModal = false"
  >
    <!-- 会话内生图预览：只显示干净图片，底部显示控制条 -->
    <div
      v-if="
        (bigImageInfo?.prefixType === 'chat' ||
          bigImageInfo?.prefixType === 'proactive' ||
          bigImageInfo?.prefixType === 'drawing') &&
        !bigImageInfo?.fromGallery
      "
      class="flex flex-col items-center max-w-4xl w-full max-h-[85vh] animate-in zoom-in-95 duration-200"
    >
      <!-- 关闭按钮 -->
      <button
        @click="showBigImageModal = false"
        class="absolute right-4 top-4 z-10 p-2 rounded-full bg-black/40 hover:bg-black/60 text-white transition-all cursor-pointer border border-white/10"
      >
        <XIcon class="w-4 h-4" />
      </button>

      <!-- 图片展示区（纯净，无框，无底色） -->
      <div class="flex items-center justify-center overflow-hidden mb-6">
        <img :src="bigImageUrl" class="max-w-full max-h-[70vh] object-contain rounded-lg shadow-2xl" />
      </div>

      <!-- 底部居中控制条 -->
      <div
