// 物理清洗大模型前缀缓存时注入的动态状态/记忆，防止在 UI 和列表渲染时残留系统提示词
function cleanUserContentForUI(content: string): string {
  if (typeof content !== 'string') return content || '';
  return content.replace(/^\[System Dynamic Context Update\][\s\S]*?---\n\n/, '');
}

// 判断内容是否仅包含表情包
function isEmojiOnly(content?: string): boolean {
  if (!content) return false;
  const cleaned = cleanUserContentForUI(content);
  const trimmed = cleaned.trim();
  if (!trimmed) return false;
  // 确认至少包含一个表情包占位符
  if (!/\[表情:\s*(.*?)\s*\]/.test(trimmed)) return false;
  // 移除所有表情包标签后，剩下的必须全是空白字符
  const remaining = trimmed.replace(/\[表情:\s*(.*?)\s*\]/g, '').trim();
  return remaining === '';
}

// 优雅的 window.api Polyfill 局域网桥接垫片
if (typeof window !== 'undefined' && !(window as any).api) {
  const listeners: Record<string, ((data: any) => void)[]> = {};

  // 🚀 自适应端口计算：开发环境（5173 等端口）下默认穿透到 3000 网关；
  // 生产/Docker 部署（6868 端口）下走同源同端口（即 window.location.port 比如 6868），消除多端口暴露与跨域
  const hostname = window.location.hostname || 'localhost';
  const currentPort = window.location.port || '80';
  const isDevPort = ['5173', '5174', '5175'].includes(currentPort);
  const targetPort = isDevPort ? '3000' : currentPort;
  const baseUrl = `http://${hostname}${targetPort ? `:${targetPort}` : ''}`;

  (window as any).api = {
    isIpcBridge: true,
    invoke: async (channel: string, payload?: any) => {
      try {
        const response = await fetch(`${baseUrl}/api/ipc`, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({ channel, payload }),
        });
        return await response.json();
      } catch (e: any) {
        console.error(`[Polyfill IPC Network Error]`, e);
        return { success: false, error: e.message || String(e) };
      }
    },
    receive: (channel: string, callback: (data: any) => void) => {
      if (!listeners[channel]) {
        listeners[channel] = [];
      }
      listeners[channel].push(callback);
      return () => {
        listeners[channel] = listeners[channel].filter(cb => cb !== callback);
      };
    },
  };

  // 在局域网手机端初始化 SSE 双向主动推送连接
  try {
    const lastId = localStorage.getItem('last_sse_event_id') || '-1';
    const eventSource = new EventSource(`${baseUrl}/api/events?lastEventId=${lastId}&clientId=${myClientId.value}`);

    // SseManager 发送带 event: 类型的 SSE 帧（`event: echo:message`），
    // 必须用 addEventListener 才能接收，onmessage 只接收无类型的默认帧
    const handleSseEvent = (event: MessageEvent) => {
      if (event.lastEventId) {
        localStorage.setItem('last_sse_event_id', event.lastEventId);
      }
      try {
        const payload = JSON.parse(event.data);
        // SseManager 格式：{ eventType, data, sseSeq }
        const channel = payload.eventType;
        const data = payload.data;
        if (payload.sseSeq) {
          localStorage.setItem('last_sse_event_id', String(payload.sseSeq));
        }
        if (channel && listeners[channel]) {
          listeners[channel].forEach((callback: (d: any) => void) => callback(data));
        }
      } catch (err) {
        // 忽略非 JSON 数据（如 `: ping` 心跳或连接确认帧）
      }
    };

    // 监听所有业务事件类型
    eventSource.addEventListener('echo:message', handleSseEvent);
    eventSource.addEventListener('echo:unread-update', handleSseEvent);
    eventSource.addEventListener('chat-chunk', handleSseEvent);
    eventSource.addEventListener('social-moment-updated', handleSseEvent);
    eventSource.addEventListener('social-forum-updated', handleSseEvent);
    eventSource.addEventListener('social-moment-liked-broadcast', handleSseEvent);
    eventSource.addEventListener('social-moment-comment-added', handleSseEvent);
    eventSource.addEventListener('social-forum-comment-added', handleSseEvent);

    // 🚀 监听群聊变更相关的 SSE 事件，以便多端实时同步
    eventSource.addEventListener('group-chat-created', handleSseEvent);
    eventSource.addEventListener('group-chat-updated', handleSseEvent);
    eventSource.addEventListener('group-chat-deleted', handleSseEvent);

    // 🚀 监听创角 Bot 过程消息和新角色导入成功的广播，打通多端联动
    eventSource.addEventListener('creator-bot-message', handleSseEvent);
    eventSource.addEventListener('character-imported', handleSseEvent);

    // 🚀 监听运行日志实时广播，打通局域网手机端多端同步
    eventSource.addEventListener('new-log-broadcast', handleSseEvent);

    // 🚀 监听小说 AI 写手事件，使局域网/移动端接收到红点和进程变更广播
    eventSource.addEventListener('novel-chapter-added', handleSseEvent);
    eventSource.addEventListener('novel-chapter-rewritten', handleSseEvent);
    eventSource.addEventListener('novel-continue-done', handleSseEvent);
    eventSource.addEventListener('novel-generation-state-changed', handleSseEvent);
    eventSource.addEventListener('novel-unread-count-changed', handleSseEvent);
    eventSource.addEventListener('novel-bookshelf-updated', handleSseEvent);

    // 🚀 补全缺失的局域网/多端强同步 SSE 事件订阅，打通删除、已读、状态及设置全通路即时同步
    eventSource.addEventListener('conversation-meta-updated', handleSseEvent);
    eventSource.addEventListener('message-deleted', handleSseEvent);
    eventSource.addEventListener('message-content-edited', handleSseEvent);
    eventSource.addEventListener('chat-window-cleared', handleSseEvent);
    eventSource.addEventListener('history-memory-cleared', handleSseEvent);
    eventSource.addEventListener('character-chat-mode-changed', handleSseEvent);
    eventSource.addEventListener('character-state-updated', handleSseEvent);
    eventSource.addEventListener('user-profile-updated', handleSseEvent);
    eventSource.addEventListener('character-settings-updated', handleSseEvent);
    eventSource.addEventListener('character-file-updated', handleSseEvent);
    eventSource.addEventListener('custom-emojis-updated', handleSseEvent);
    eventSource.addEventListener('update-check-status', handleSseEvent);
    eventSource.addEventListener('update-download-progress', handleSseEvent);
    eventSource.addEventListener('update-download-status', handleSseEvent);

    eventSource.onerror = err => {
      console.warn('[Polyfill SSE Connect Error] SSE 连接异常中断，正在自动重连...', err);
    };
  } catch (sseErr) {
    console.error('[Polyfill SSE Init Error] 初始化 SSE 长连接失败:', sseErr);
  }

  // ── iOS 后台保活：无声音频 Audio Session 技术 ──────────────────────────
  // iOS Safari 在标签页有活跃 AudioContext（哪怕完全静音）时，不会将其挂起。
  // 我们用 Web Audio API 生成一段 0.5 秒的全静音缓冲区循环播放，用户完全听不到，
  // 但 iOS 系统会把该标签页视为"正在播放音频"，从而保持 SSE 连接活跃。
  // 注意：AudioContext 必须在用户交互（触摸/点击）后才能启动（浏览器自动播放策略）。
  (function initSilentAudioKeepAlive() {
    // 仅在移动端 iOS/Android 上启用（桌面端无此问题）
    const isIos = /iphone|ipad|ipod/i.test(navigator.userAgent);
    const isAndroid = /android/i.test(navigator.userAgent);
    if (!isIos && !isAndroid) return;
    if (typeof AudioContext === 'undefined' && typeof (window as any).webkitAudioContext === 'undefined') return;

    let audioCtx: AudioContext | null = null;
    let silentSource: AudioBufferSourceNode | null = null;
    let isRunning = false;

    function startSilentLoop() {
      if (isRunning) return;
      try {
        const Ctx = (window.AudioContext || (window as any).webkitAudioContext) as typeof AudioContext;
        audioCtx = new Ctx();

        // 创建 1.0 秒长度的静音缓冲区（全零样本，100% 无声）
        const bufferSize = audioCtx.sampleRate * 1.0;
        const silentBuffer = audioCtx.createBuffer(1, bufferSize, audioCtx.sampleRate);
        // createBuffer 默认已填充零，无需额外操作

        // 仅需创建一次音频源节点，开启原生硬件级循环 (loop = true)，杜绝高频 JS 闭包执行与垃圾回收泄露
        silentSource = audioCtx.createBufferSource();
        silentSource.buffer = silentBuffer;
        silentSource.loop = true;
        silentSource.connect(audioCtx.destination);
        silentSource.start();

        isRunning = true;
        console.log('[SilentAudio] iOS 后台保活硬件级无声音频循环已启动 🔇');
      } catch (e) {
        console.warn('[SilentAudio] 无声音频保活启动失败:', e);
      }
    }

    // 等待用户第一次触摸，激活 AudioContext（一次性）
    document.addEventListener(
      'touchstart',
      function onFirstTouch() {
        document.removeEventListener('touchstart', onFirstTouch);
        startSilentLoop();
      },
      { once: true, passive: true },
    );

    // 兜底：用户点击也可以触发
    document.addEventListener(
      'click',
      function onFirstClick() {
        document.removeEventListener('click', onFirstClick);
        startSilentLoop();
      },
      { once: true },
    );
  })();
}

const md = new MarkdownIt({
  html: true,
  linkify: true,
  typographer: true,
  breaks: true, // 允许将单个换行符渲染为 <br>
});

// 自定义 link_open 规则，使所有渲染出来的链接在新窗口（即系统默认浏览器）中打开
const defaultLinkRender =
  md.renderer.rules.link_open ||
  function (tokens, idx, options, env, self) {
    return self.renderToken(tokens, idx, options);
  };
md.renderer.rules.link_open = function (tokens, idx, options, env, self) {
  const token = tokens[idx];
  const aIndex = token.attrIndex('target');
  if (aIndex < 0) {
    token.attrPush(['target', '_blank']);
  } else if (token.attrs) {
    token.attrs[aIndex][1] = '_blank';
  }
  return defaultLinkRender(tokens, idx, options, env, self);
};

function renderMarkdown(content: string) {
  if (!content) return '';
  const html = md.render(content);

  // 识别并包裹非对话内容（中英文括号与中括号里的动作或内心描写），物理防误伤 HTML 标签内部结构
  const processed = html.replace(/(<[^>]+>)|([^<]+)/g, (_, tag, text) => {
    if (tag) return tag;

    let temp = text;
    // 1. 替换中文括号 （...）
    temp = temp.replace(/（([\s\S]*?)）/g, "<span class='narrative-bracket'>（$1）</span>");
    // 2. 替换英文括号 (...)
    temp = temp.replace(/\(([\s\S]*?)\)/g, "<span class='narrative-bracket'>($1)</span>");
    // 3. 替换中文中括号 【...】
    temp = temp.replace(/【([\s\S]*?)】/g, "<span class='narrative-bracket'>【$1】</span>");
    // 4. 替换英文中括号 [...]，避开表情包标记 [表情: xxx]
    temp = temp.replace(/\[(?!表情:\s*)([\s\S]*?)\]/g, "<span class='narrative-bracket'>[$1]</span>");
    // 5. 替换中文双引号 “...” (使用单引号属性且限定内部无HTML标签，防范二次吞噬)
    temp = temp.replace(/“([^”<>]*?)”/g, "<span class='dialogue-quote'>“$1”</span>");
    // 6. 替换英文双引号 "..." (使用单引号属性且限定内部无HTML标签，物理隔绝二次吞噬)
    temp = temp.replace(/"([^"<>]*?)"/g, '<span class=\'dialogue-quote\'>"$1"</span>');

    return temp;
  });

  // 🚀 将 [表情: 含义] 替换为真实的微信表情包图片
  return replaceStickersOnly(processed);
}

function renderTextWithStickers(text: string) {
  if (!text) return '';
  // 物理剔除隐藏的配图与描述注释，防止其在 HTML 转义时溢出在正文可见
  const cleanText = text
    .replace(/<!--\s*\[wechat_image_media\]:[\s\S]*?\s*-->/gi, '')
    .replace(/<!--\s*\[image_desc\]:[\s\S]*?\s*-->/gi, '')
    .trim();

  let escaped = cleanText
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');

  const regex = /\[表情:\s*(.*?)\]/g;
  return escaped.replace(regex, (match, meaning) => {
    const matchedEmoji = customEmojiList.value.find(e => e.meaning === meaning);
    if (matchedEmoji) {
      return `<img src="${matchedEmoji.base64}" class="w-12 h-12 inline-block object-contain my-1 select-none animate-scale-in align-bottom" title="${meaning}" />`;
    }
    return match;
  });
}

function replaceStickersOnly(html: string) {
  if (!html) return '';
  const regex = /\[表情:\s*(.*?)\]/g;
  return html.replace(regex, (match, meaning) => {
    const matchedEmoji = customEmojiList.value.find(e => e.meaning === meaning);
    if (matchedEmoji) {
      return `<img src="${matchedEmoji.base64}" class="w-12 h-12 inline-block object-contain my-1 select-none animate-scale-in align-bottom" title="${meaning}" />`;
    }
    return match;
  });
}

