// ===================== 微信个人号接入专属 Vue3 响应式状态机 =====================
const wechatState = ref({
  enabled: false,
  connected: false,
  accountId: null as string | null,
  qrcodeUrl: null as string | null,
  mappings: {} as Record<string, string>,
});
const isRequestingQR = ref(false);

async function fetchWeChatStatus() {
  try {
    const res = await window.api.invoke('wechat-get-status');
    if (res && res.success && res.status) {
      wechatState.value = res.status;
    }
  } catch (err) {
    console.error('[WeChat UI] 获取微信状态失败:', err);
  }
}

async function triggerWeChatLogin() {
  if (isRequestingQR.value) return;
  isRequestingQR.value = true;
  try {
    const res = await window.api.invoke('wechat-start-login');
    if (res && res.success && res.qrcodeUrl) {
      wechatState.value.qrcodeUrl = res.qrcodeUrl;
      wechatState.value.connected = false;
      showCustomAlert('二维码已生成', '请使用手机微信扫码进行官方安全绑定授权，限接入一个账号哦！', 'info');
    } else {
      showCustomAlert('生成失败', (res && res.error) || '获取微信扫码二维码失败', 'error');
    }
  } catch (err: any) {
    showCustomAlert('物理故障', err.message || err, 'error');
  } finally {
    isRequestingQR.value = false;
  }
}

async function handleWeChatUnbind() {
  try {
    const res = await window.api.invoke('wechat-unbind');
    if (res && res.success && res.status) {
      wechatState.value = res.status;
      showCustomAlert('解绑成功', '微信接入凭证与好友映射字典已安全物理清除！', 'success');
    } else {
      showCustomAlert('解绑失败', (res && res.error) || '注销微信绑定失败', 'error');
    }
  } catch (err: any) {
    showCustomAlert('注销错误', err.message || err, 'error');
  }
}

async function updateFriendMapping(friendId: string, characterId: string) {
  try {
    const res = await window.api.invoke('wechat-update-mapping', { friendId, characterId });
    if (res && res.success && res.status) {
      wechatState.value = res.status;
    }
  } catch (err: any) {
    showCustomAlert('绑定切换失败', err.message || err, 'error');
  }
}

function onFriendMappingChange(friendId: string, event: Event) {
  const target = event.target as HTMLSelectElement;
  if (target) {
    updateFriendMapping(friendId, target.value);
  }
}

function onQRCodeLoadError() {
  wechatState.value.qrcodeUrl = null;
  showCustomAlert('加载失败', '扫码二维码加载或解析失败，请检查您的网络连接并重新生成！🐾', 'error');
}

const mappedFriends = computed(() => {
  return Object.entries(wechatState.value.mappings).map(([friendId, characterId]) => ({
    friendId,
    characterId,
  }));
});

