function checkIfMobile() {
  isMobile.value = window.innerWidth < 768;
}

function updateViewportHeight() {
  if (window.visualViewport) {
    // 🔒 关键修复：使用 offsetTop + height 而非单纯 height 作为根容器高度。
    // iOS 键盘弹出时会自动将页面向上滚动（visualViewport.offsetTop 增大），
    // 若只用 height，根容器会偏短，每次键盘弹出/收回循环导致空白累积增大。
    // offsetTop + height = 页面顶部到键盘顶部的完整距离，确保输入框始终紧贴键盘上方。
    // Android 上 offsetTop 始终为 0，该公式对两端均正确。
    const vv = window.visualViewport;
    viewportHeight.value = `${vv.offsetTop + vv.height}px`;
    // 只有键盘未弹出时（未聚焦），才重置页面滚动，防止聚焦期间调用 scrollTo 导致键盘收回
    if (!isInputFocused.value) {
      window.scrollTo(0, 0);
      document.body.scrollTop = 0;
      document.documentElement.scrollTop = 0;
    }
    // 软键盘弹起时自动滚动到底部，保证极致流畅体验
    if (sideView.value === 'chat' && selectedCharacterId.value) {
      nextTick(() => {
        scrollToBottom('auto');
      });
    }
  }
}

function handleTextareaFocus() {
  isInputFocused.value = true;
  if (isMobile.value) {
    // 极其关键：瞬间强行重置 iOS 因软键盘聚焦弹出导致的 html/body 默认全局滚动
    nextTick(() => {
      window.scrollTo(0, 0);
      document.body.scrollTop = 0;
      document.documentElement.scrollTop = 0;
      scrollToBottom('auto', true);
    });
    // 60ms 和 150ms 再次进行多重保险触底锁定，防止移动端键盘弹出动画导致的滚动条滞后与消息遮挡！
    setTimeout(() => {
      window.scrollTo(0, 0);
      document.body.scrollTop = 0;
      document.documentElement.scrollTop = 0;
      scrollToBottom('auto', true);
    }, 60);
    setTimeout(() => {
      scrollToBottom('auto', true);
    }, 150);
  } else {
    nextTick(() => scrollToBottom('auto'));
  }
}

