// 钱包定期自动发薪响应式变量与读取辅助函数
const tempSalaryBase = ref<number>(0.00);
const tempSalaryPeriod = ref<string>('none');
const tempSalaryDesc = ref<string>('不定期自动增资');

const getSalaryBaseVal = () => {
  if (!activeCharacter.value) return '0.00';
  const items = characterStates.value[activeCharacter.value.id]?.items || [];
  const item = items.find(i => i.key === 'salary_base');
  return item ? Number(item.value).toFixed(2) : '0.00';
};
const getSalaryPeriodVal = () => {
  if (!activeCharacter.value) return 'none';
  const items = characterStates.value[activeCharacter.value.id]?.items || [];
  const item = items.find(i => i.key === 'salary_period');
  return item ? String(item.value).trim().toLowerCase() : 'none';
};
const getSalaryPeriodText = () => {
  const val = getSalaryPeriodVal();
  if (val === 'daily') return '天';
  if (val === 'weekly') return '周一';
  if (val === 'monthly') return '月1号';
  return '';
};
const getSalaryDescVal = () => {
  if (!activeCharacter.value) return '不定期自动增资';
  const items = characterStates.value[activeCharacter.value.id]?.items || [];
  const item = items.find(i => i.key === 'salary_desc');
  return item ? String(item.value).trim() : '不定期自动增资';
};

// 态度映射文本
function getIntimacyPhaseText(val: number | string): string {
  const v = Number(val);
  if (v >= 0 && v < 20) return '陌生';
  if (v >= 20 && v < 40) return '客套';
  if (v >= 40 && v < 60) return '好友';
  if (v >= 60 && v < 80) return '亲密';
  return '羁绊';
}

