// ===================== 聊天输入 =====================
const chatInputText = ref('');
const chatTextarea = ref<HTMLTextAreaElement | null>(null);
const chatContainer = ref<HTMLElement | null>(null);
// 每个角色独立的流式状态集合，允许多角色并发对话互不阻塞
const streamingCharsSet = reactive(new Set<string>());
const streamingCharacterId = ref<string | null>(null);
// isCurrentCharStreaming：当前选中角色是否正在流式回复（不阻塞其他角色的发送按钮）
const isCurrentCharStreaming = computed(() => streamingCharsSet.has(selectedCharacterId.value || ''));

// 🚀 角色流式回复超时保护机制 (30秒超时自愈防线)
let replyTimeoutTimer: any = null;

function clearReplyTimeout() {
  if (replyTimeoutTimer) {
    clearTimeout(replyTimeoutTimer);
    replyTimeoutTimer = null;
  }
}

function startReplyTimeout(charId: string) {
  clearReplyTimeout();
  replyTimeoutTimer = setTimeout(() => {
    handleReplyTimeout(charId);
  }, 600000); // 600秒(10分钟)超时自愈防线
}

function handleReplyTimeout(charId: string) {
  streamingCharsSet.delete(charId);
  streamingCharacterId.value = null;

  const msgs = allMessages[charId] || [];
  if (msgs.length > 0) {
    const last = msgs[msgs.length - 1];
    if (last.role === 'assistant') {
      last.isError = true;
      if (!last.content) {
        last.content = '[连接超时，回复失败]';
      } else {
        last.content += '\n\n[连接超时，回复中断]';
      }
    } else {
      msgs.push({
        id: 'msg_err_' + Date.now(),
        role: 'assistant',
        content: '[连接超时，回复失败]',
        isError: true,
        created_at: new Date().toISOString(),
        timestamp: Date.now(),
      });
    }
  } else {
    msgs.push({
      id: 'msg_err_' + Date.now(),
      role: 'assistant',
      content: '[连接超时，回复失败]',
      isError: true,
      created_at: new Date().toISOString(),
      timestamp: Date.now(),
    });
  }

  nextTick(() => scrollToBottom());
}

const pastedImageBase64 = ref('');
const lastUserMsgId = ref('');
const isDraggingFile = ref(false);
const inputHeight = ref(Number(localStorage.getItem('echo_input_height') || '160'));

// 多消息延时聚合防抖状态（分角色独立隔离，防范跨窗口时序冲突与串台 Bug）
const pendingUserMessagesMap = reactive<
  Record<
    string,
    Array<{
      content: string;
      imageBase64?: string;
      redPacketPayload?: { amount: number; title: string; userMsgId: string; targetId?: string; targetName?: string };
      userMsgId?: string;
      timestamp?: number;
    }>
  >
>({});
const messageMergeTimersMap = reactive<Record<string, any>>({});

// 监听用户输入框内容改变，实现极其智能的“打字感知防抖”与“输入删空自愈恢复”：
// 1. 只要用户在输入框内打字（输入了有效非空字符），立刻清除当前聚焦角色的聚合定时器，防范 AI 在用户打字思索中途抢话！
// 2. 如果用户在打字中途删除、清空了输入框，且后台队列有之前发送的积压消息，说明用户放弃了继续补充，自动延时 2.5 秒后恢复角色回复！
watch(chatInputText, newVal => {
  const trimmed = newVal.trim();
  const charId = selectedCharacterId.value;
  if (!charId) return;

  // 🚀 如果是正在执行发送产生的清空，直接拦截，避开干扰
  if (isSendingChatMessage) return;

  if (trimmed.length > 0 || isComposing.value) {
    // 🚀 清除删空确认定时器，代表这只是瞬间过渡态，用户仍在打字中
    if (inputEmptyTimersMap[charId]) {
      clearTimeout(inputEmptyTimersMap[charId]);
      inputEmptyTimersMap[charId] = null;
    }

    if (messageMergeTimersMap[charId]) {
      clearTimeout(messageMergeTimersMap[charId]);
      messageMergeTimersMap[charId] = null;
    }
  } else {
    // 🚀 用户输入框变空：不立刻执行自愈，而是设立 500ms 缓冲确认期，以彻底过滤输入法上屏或秒删退格的抖动
    if (inputEmptyTimersMap[charId]) {
      clearTimeout(inputEmptyTimersMap[charId]);
    }

    inputEmptyTimersMap[charId] = setTimeout(() => {
      // 500ms 确认期满，若输入框仍为空，则认定为真实清空
      inputEmptyTimersMap[charId] = null;

      const pendingQueue = pendingUserMessagesMap[charId] || [];
      if (pendingQueue.length > 0 && !messageMergeTimersMap[charId] && !streamingCharsSet.has(charId)) {
        const mergeDelay = isMobile.value ? 4500 : 2500;
        console.log(
          `[Typing reconciliation] 500ms 确认期满，用户确实删空了输入框，将在 ${mergeDelay / 1000} 秒后恢复角色回复...`,
        );
        const char = characterList.value.find(c => c.id === charId);
        if (char) {
          messageMergeTimersMap[charId] = setTimeout(async () => {
            await triggerMergedAiResponse(char);
          }, mergeDelay);
        }
      } else if (pendingQueue.length === 0) {
        // 🚀 极致自愈保障：当消息框清空，且后台没有任何待回复的积压消息时，
        // 任何遗留的"对方正在输入..."或 streamingCharsSet 锁定状态绝对属于异常死锁，必须无条件强力释放！
        if (streamingCharsSet.has(charId)) {
          console.warn(
            `[Typing Safety] 消息框已清空且无挂起积压消息，但角色仍在 streamingCharsSet 中，触发强力自愈解锁！`,
          );
          streamingCharsSet.delete(charId);
          streamingCharacterId.value = '';
          clearReplyTimeout();
        }
      }
    }, 500);
  }
});

