// ===================== 搜索功能 =====================
const searchContactResults = computed(() => {
  if (!searchQuery.value) return [];
  const q = searchQuery.value.toLowerCase();
  return characterList.value.filter(c => c.name.toLowerCase().includes(q));
});

const searchMessageResults = computed(() => {
  if (!searchQuery.value) return [];
  const q = searchQuery.value.toLowerCase();
  const results: any[] = [];
  for (const char of characterList.value) {
    const msgs = allMessages[char.id] || [];
    for (const msg of msgs) {
      if (msg.content && msg.content.toLowerCase().includes(q)) {
        results.push({
          id: `${char.id}-${msg.content}`,
          characterId: char.id,
          charName: char.name,
          content: msg.content,
        });
      }
    }
  }
  return results.slice(0, 10);
});

function highlightSearch(text: string): string {
  if (!searchQuery.value) return text;
  const escaped = searchQuery.value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  return text.replace(new RegExp(escaped, 'gi'), match => `<mark>${match}</mark>`);
}

// ===================== 最后一条消息（用于会话列表预览） =====================
function getLastMessage(charId: string) {
  const msgs = allMessages[charId] || [];
  for (let i = msgs.length - 1; i >= 0; i--) {
    if (!msgs[i].isSystem && (msgs[i].role === 'user' || msgs[i].role === 'assistant')) {
      return msgs[i];
    }
  }
  return null;
}

function splitAssistantContent(content: string): string[] {
  if (!content || !content.trim()) return [];
  const paragraphs: string[] = [];
  const lines = content
    .split('\n')
    .map(l => l.trim())
    .filter(Boolean);
  for (const line of lines) {
    if (line.length <= 25) {
      paragraphs.push(line);
      continue;
    }
    const sentences = line
      .split(/(?<=[。；！？!?])\s*/)
      .map(s => s.trim())
      .filter(Boolean);
    let currentTemp = '';
    for (const s of sentences) {
      if (currentTemp.length === 0) {
        currentTemp = s;
      } else {
        if (currentTemp.length + s.length <= 15 || s.length < 4) {
          currentTemp += s;
        } else {
          paragraphs.push(currentTemp);
          currentTemp = s;
        }
      }
    }
    if (currentTemp) {
      paragraphs.push(currentTemp);
    }
  }
  return paragraphs;
}

// 怎么存就怎么显示：后端对话模式已按句分条存储，描写模式整段存储，DB 格式即为正确的显示格式
// 无需前端二次拆分，直接透传原始消息列表
function flattenMessages(historyMessages: any[], _charId: string): any[] {
  return historyMessages;
}

function restoreMessageProps(m: any) {
  const ts = m.timestamp !== undefined && m.timestamp !== null ? m.timestamp : (m.created_at ? new Date(m.created_at).getTime() : Date.now());
  const result: any = {
    id: m.id,
    role: m.role,
    content: m.content,
    character_id: m.character_id,
    isSystem: m.role === 'system',
    timestamp: ts,
    created_at: ts,
    prompt_tokens: m.prompt_tokens,
    completion_tokens: m.completion_tokens,
    cached_tokens: m.cached_tokens,
    imageBase64: m.imageBase64 || '',
    imageMeta: m.imageMeta || null,
    sender_id: m.sender_id || m.character_id,
    inner_thought: m.inner_thought, // 🚀 映射并保留从 SQLite 读出来的心声字段
  };

  if (m.content) {
    // 自动清洗历史记录中可能残存的红包控制字符，确保绝不显露代码
    if (typeof m.content === 'string') {
      // 🚀 升级为超强容错全局正则，支持全半角冒号/逗号、反单引号包裹、忽略大小写
      const sendReg = /`?\s*\[SEND_RED_PACKET[:：]\s*(\d+(\.\d+)?)\s*[,，]\s*([\s\S]+?)\]\s*`?/gi;
      result.content = m.content
        .replace(/\[RECEIVE_RED_PACKET\]/g, '')
        .replace(/\[RETURN_RED_PACKET\]/g, '')
        .replace(sendReg, '')
        .trim();
    }

    if (m.content.startsWith('[character_diary]:')) {
      try {
        const jsonStr = m.content.replace('[character_diary]:', '');
        const diaryObj = JSON.parse(jsonStr);
        result.diary = diaryObj;
        result.content = `[日记: ${diaryObj.date}]`;
      } catch (_) {}
    } else if (m.content.startsWith('[wechat_red_packet]:')) {
      try {
        const jsonStr = m.content.replace('[wechat_red_packet]:', '');
        const redPacket = JSON.parse(jsonStr);
        result.redPacket = redPacket;
        result.content = `[发送红包: ${redPacket.amount} 元, 附言: ${redPacket.title}]`;
      } catch (_) {}
    } else if (m.content.startsWith('[wechat_custom_emoji]:')) {
      try {
        const jsonStr = m.content.replace('[wechat_custom_emoji]:', '');
        const emoji = JSON.parse(jsonStr);
        result.content = `[表情: ${emoji.meaning}]`;
        result.customEmojiUrl = '';
        if (emoji.base64) {
          result.customEmojiUrl = emoji.base64;
        } else if (emoji.id) {
          window.api.invoke('read-custom-emoji-file', { id: emoji.id, ext: emoji.ext }).then(res => {
            if (res.success) {
              result.customEmojiUrl = res.base64;
            }
          });
        }
      } catch (_) {}
    } else if (m.content.startsWith('[wechat_image_media]:')) {
      let mediaPath = m.content.replace('[wechat_image_media]:', '');
      if (mediaPath.includes('[image_desc:')) {
        mediaPath = mediaPath.split('[image_desc:')[0];
      }
      result.content = '';
      result.imageBase64 = ''; // 初始占位，待异步读取填充
      result.imageMeta = null; // 元数据初始占位
      result.isImage = true; // 同步标记为图片消息，便于会话中栏列表即时显示为 [图片消息]
      const char = characterList.value.find(c => c.id === m.character_id);
      if (char) {
        window.api.invoke('read-image-media', { folderName: char.folder_name, mediaPath }).then(res => {
          if (res.success) {
            result.imageBase64 = res.base64;
            if (res.meta) {
              result.imageMeta = res.meta;
            }
          }
        });
      }
    }
  }

  return result;
}

// ===================== 加载角色列表 =====================
async function loadCharacters() {
  try {
    const res = await window.api.invoke('get-characters');
    if (res.success && res.characters) {
      const rawChars = res.characters;

      // 先将基础角色列表提早赋值，这极度关键！它保证了并发并发消息拉取/解析 (restoreMessageProps) 时能够查到 folder_name 以加载本地资源
      characterList.value = rawChars;

      // 声明临时“离屏”装载对象，防范 Vue 响应式多频重拍抖动
      const tempAvatars: Record<string, string> = {};
      const tempMeta: Record<string, any> = {};
      const tempAllMessages: Record<string, any[]> = {};
      const tempActiveTimes: Record<string, number> = {};

      // 并发并行批量预拉取，极速减少网络等待
      await Promise.all(
        rawChars.map(async (char: any) => {
          // A. 头像
          const avatarData = await window.api.invoke('get-character-avatar', char.folder_name);
          tempAvatars[char.id] = avatarData;

          // B. 会话元数据初始化与读取
          tempMeta[char.id] = { pinned: false, unread: 0, muted: false, hidden: false };
          const metaRes = await window.api.invoke('get-conversation-meta', { characterId: char.id });
          if (metaRes.success && metaRes.meta) {
            Object.assign(tempMeta[char.id], metaRes.meta);
          }

          // C. 先加载该角色的聊天模式写入缓存，确保后面 flattenMessages 能读到正确的值
          const modeRes = await window.api.invoke('get-character-chat-mode', { characterId: char.id });
          if (modeRes.success && modeRes.mode) {
            characterChatModeCache[char.id] = modeRes.mode;
          } else {
            characterChatModeCache[char.id] = 'descriptive'; // 默认描写模式（更安全，不会错误拆分）
          }

          // D. 历史消息懒加载：此时 cache 已就绪，flattenMessages 能正确按角色自身模式拆分
          const histRes = await window.api.invoke('get-chat-history', { characterId: char.id, limit: 50 });
          if (histRes.success && histRes.history) {
            const restored = histRes.history.map((m: any) => restoreMessageProps(m));
            tempAllMessages[char.id] = flattenMessages(restored, char.id);
            // 获取最后一条非系统活跃消息时间戳，作为会话的最新活跃时间。若无消息，以创建时间兜底，使其默认排在侧栏最前
            const lastMsg = restored
              .filter((m: any) => !m.isSystem && (m.role === 'user' || m.role === 'assistant'))
              .pop();
            tempActiveTimes[char.id] = lastMsg?.timestamp || char.created_at || 0;
          } else {
            tempAllMessages[char.id] = [];
            tempActiveTimes[char.id] = char.created_at || 0;
          }
        }),
      );

      // 一次性批量覆盖提交，避免 DOM 发生 Layout Shift
      Object.assign(characterAvatars.value, tempAvatars);
      Object.assign(conversationMeta, tempMeta);
      Object.assign(allMessages, tempAllMessages);
      Object.assign(conversationActiveTimes, tempActiveTimes);

      // ===================== 前端群聊会话批量预拉取与合并 =====================
      try {
        const groupRes = await window.api.invoke('get-group-chats');
        if (groupRes.success && groupRes.groups) {
          const rawGroups = groupRes.groups;
          groupChats.value = rawGroups;

          const tempGroupAvatars: Record<string, string> = {};
          const tempMeta: Record<string, any> = {};
          const tempAllMessages: Record<string, any[]> = {};
          const tempActiveTimes: Record<string, number> = {};

          await Promise.all(
            rawGroups.map(async (group: any) => {
              // A. 群聊头像
              const avatarData = await window.api.invoke('get-group-avatar', group.id);
              tempGroupAvatars[group.id] = avatarData;

              // B. 会话元数据初始化与读取
              tempMeta[group.id] = { pinned: false, unread: 0, muted: false, hidden: false };
              const metaRes = await window.api.invoke('get-conversation-meta', { characterId: group.id });
              if (metaRes.success && metaRes.meta) {
                Object.assign(tempMeta[group.id], metaRes.meta);
              }

              // 🚀 预载群聊专属聊天模式并写入缓存，根治重启后重置为“包含描写”的 Bug
              if (group.chat_mode) {
                characterChatModeCache[group.id] = group.chat_mode;
              } else {
                characterChatModeCache[group.id] = 'descriptive';
              }

              // C. 历史消息加载
              const histRes = await window.api.invoke('get-chat-history', { characterId: group.id, limit: 50 });
              if (histRes.success && histRes.history) {
                const restored = histRes.history.map((m: any) => restoreMessageProps(m));
                tempAllMessages[group.id] = restored;
                // 若无历史消息，以群聊创建时间兜底，使其默认排在侧栏最前
                const lastMsg = restored
                  .filter((m: any) => !m.isSystem && (m.role === 'user' || m.role === 'assistant'))
                  .pop();
                tempActiveTimes[group.id] = lastMsg?.timestamp || group.created_at || 0;
              } else {
                tempAllMessages[group.id] = [];
                tempActiveTimes[group.id] = group.created_at || 0;
              }
            }),
          );

          Object.assign(groupAvatars.value, tempGroupAvatars);
          Object.assign(characterAvatars.value, tempGroupAvatars);
          Object.assign(conversationMeta, tempMeta);
          Object.assign(allMessages, tempAllMessages);
          Object.assign(conversationActiveTimes, tempActiveTimes);
        }
      } catch (groupError) {
        console.error('加载群聊库异常:', groupError);
      }
    }
  } catch (error) {
    console.error('加载角色库异常:', error);
  }
}

// ===================== 设置当前角色聊天模式 =====================
// 核心隔离约束：只写当前打开角色的 chat_mode_{charId}，不影响任何其他角色
async function setChatMode(mode: 'dialogue' | 'descriptive' | 'director') {
  if (!selectedCharacterId.value) return;
  if (isGroupActive.value && mode === 'director') return; // 群聊不允许选择导演模式
  const charId = selectedCharacterId.value;
  // 直接写入 characterChatModeCache（reactive），currentChatMode computed 自动响应，UI 即时刷新
  characterChatModeCache[charId] = mode;
  // 2. 持久化到 DB 并通过 SSE 广播
  await window.api.invoke('set-character-chat-mode', { characterId: charId, mode });
  // 3. 关闭弹窗
  showChatModeModal.value = false;
}

// ===================== 选中角色 =====================
async function selectCharacter(charId: string) {
  activeInnerThoughtMsgId.value = null;
  const oldCharId = selectedCharacterId.value;
  if (oldCharId && pendingCleanedContentMap[oldCharId]) {
    const msgs = allMessages[oldCharId] || [];
    if (msgs.length > 0) {
      const last = msgs[msgs.length - 1];
      if (last.role === 'assistant') {
        last.content = pendingCleanedContentMap[oldCharId];
      }
    }
    delete pendingCleanedContentMap[oldCharId];
  }

  selectedCharacterId.value = charId;
  activeView.value = 'chat';
  sideView.value = 'chat';

  // 🚀 核心：切换聊天角色时无条件等待最新用户人设列表，然后再拉取数据库中该会话绑定的用户人设 ID 并同步状态
  currentChatBindingProfileId.value = '';
  if (charId && charId !== creatorBotId) {
    try {
      await loadUserProfilesList();
      if (selectedCharacterId.value === charId) {
        const bindingRes = await window.api.invoke('get-profile-binding', charId);
        if (selectedCharacterId.value === charId && bindingRes.success && bindingRes.profileId) {
          // 检查该绑定的 profileId 是否在当前人设列表中真实存在
          const exists = userProfilesList.value.some(p => p.profileId === bindingRes.profileId);
          if (exists) {
            currentChatBindingProfileId.value = bindingRes.profileId;
          } else {
            // 如果绑定的 profileId 是无效的（例如是不存在的人设或历史残留'default'），则重置为空以触发自愈或重新选择
            currentChatBindingProfileId.value = '';
          }
        }

        // 🚀 预判当前会话是否是拥有历史聊天记录的老会话
        let hasHistory = false;
        if (allMessages[charId] && allMessages[charId].length > 0) {
          hasHistory = true;
        } else {
          const historyCheck = await window.api.invoke('get-chat-history', { characterId: charId, limit: 1 });
          if (historyCheck.success && historyCheck.history && historyCheck.history.length > 0) {
            hasHistory = true;
          }
        }

        // 🚀 核心自愈：若该会话有历史消息，但数据库中缺失用户人设绑定关系，则静默绑定由 USER.md 转化的主人设卡
        if (!currentChatBindingProfileId.value && hasHistory && userProfilesList.value.length > 0) {
          const defaultProfileId = findLegacyUserProfileId();
          if (defaultProfileId) {
            await window.api.invoke('set-profile-binding', {
              targetId: charId,
              profileId: defaultProfileId,
            });
            if (selectedCharacterId.value === charId) {
              currentChatBindingProfileId.value = defaultProfileId;
            }
          }
        }

        // 🚀 终极防护拦截：若当前会话既无绑定，也无法成功自愈绑定（例如全新会话，或者没有静默成功），则必须拦截输入并呼出配置弹窗
        if (!currentChatBindingProfileId.value) {
          hasConfiguredFirstChatMap.value[charId] = false;
          openFirstChatConfig();
        } else {
          hasConfiguredFirstChatMap.value[charId] = true;
        }
      }
    } catch (e) {
      console.error('同步加载用户人设绑定关系失败:', e);
      hasConfiguredFirstChatMap.value[charId] = true;
    }
  } else {
    hasConfiguredFirstChatMap.value[charId] = true;
  }

  // ===================== 角色专属聊天模式加载（非阻塞 UI，但发消息时会等待） =====================
  const isGroup = groupChats.value.some(g => g.id === charId);
  pendingChatModeLoad = window.api
    .invoke('get-character-chat-mode', { characterId: charId })
    .then((modeRes: any) => {
      if (modeRes.success && modeRes.mode) {
        characterChatModeCache[charId] = modeRes.mode;
      } else if (isGroup) {
        characterChatModeCache[charId] = 'descriptive'; // 群聊兜底
      }
    })
    .catch(() => {
      if (isGroup && !characterChatModeCache[charId]) {
        characterChatModeCache[charId] = 'descriptive';
      }
    })
    .finally(() => {
      pendingChatModeLoad = null;
    });

  // 预检性格进化草案（非阻塞，不卡切换）：先清空横幅，草案加载完后再显示
  activeEvolutionCharId.value = '';
  activeEvolutionDraft.value = null;
  if (!isGroup) {
    window.api
      .invoke('get-soul-draft', { characterId: charId })
      .then((draftRes: any) => {
        // charId 守卫：只更新当前仍处于该角色会话的横幅
        if (selectedCharacterId.value !== charId) return;
        if (draftRes.success && draftRes.hasDraft) {
          activeEvolutionCharId.value = charId;
          activeEvolutionDraft.value = draftRes.draft;
        }
      })
      .catch(() => {
        /* 保持清空状态 */
      });
  }

  // 微信级细节：如果该会话曾经被删除/隐藏，在再次发起会话时，100% 自动恢复其在列表中的可见性
  if (!conversationMeta[charId]) {
    conversationMeta[charId] = { pinned: false, unread: 0, muted: false, hidden: false };
  } else {
    conversationMeta[charId].hidden = false;
  }

  // 清零未读，并同步反向写盘保存至 SQLite，确保重启后红点不复现
  if (conversationMeta[charId]) {
    conversationMeta[charId].unread = 0;
    window.api.invoke('save-conversation-meta', { characterId: charId, ...conversationMeta[charId] });
  }

  // 重置输入状态
  chatInputText.value = '';
  pastedImageBase64.value = '';
  typingQueue.value = [];
  if (typingTimer) {
    clearInterval(typingTimer);
    typingTimer = null;
  }

  // 读取最新历史
  if (charId === creatorBotId) {
    if (!allMessages[charId] || allMessages[charId].length === 0) {
      allMessages[charId] = [
        {
          role: 'assistant',
          content:
            '欢迎使用角色卡创建Bot，请描述您想要创建的角色信息，请包含角色姓名。您也可以通过 [✨ **MOI（https://moi.jiuwo.me）**](https://moi.jiuwo.me) 工具来创建角色卡。',
        },
      ];
    }
    nextTick(() => {
      scrollToBottom('auto', true);
      setTimeout(() => scrollToBottom('auto', true), 50);
      setTimeout(() => scrollToBottom('auto', true), 150);
      setTimeout(() => scrollToBottom('auto', true), 350);
      setTimeout(() => scrollToBottom('auto', true), 600);
    });
    return;
  }

  // 🚀 核心优化：若内存中已有该角色的聊天历史（说明之前已加载过），则无需重复去数据库拉取覆盖，防范在合并防抖期或 AI 生成中切换导致消息消息丢失，并能带来极其顺畅的零卡顿体验！
  if (allMessages[charId] && allMessages[charId].length > 0) {
    // 🚀 向前自愈：如果内存里已有聊天消息（说明是老会话），且数据库没有用户人设绑定，则静默绑定由 USER.md 转化来的主人设卡
    if (!currentChatBindingProfileId.value && userProfilesList.value.length > 0) {
      const defaultProfileId = findLegacyUserProfileId();
      if (defaultProfileId) {
        window.api
          .invoke('set-profile-binding', {
            targetId: charId,
            profileId: defaultProfileId,
          })
          .then(() => {
            if (selectedCharacterId.value === charId) {
              currentChatBindingProfileId.value = defaultProfileId;
            }
          })
          .catch(() => {});
      }
    }
    nextTick(() => {
      scrollToBottom('auto', true);
      setTimeout(() => scrollToBottom('auto', true), 50);
      setTimeout(() => scrollToBottom('auto', true), 150);
      setTimeout(() => scrollToBottom('auto', true), 350);
      setTimeout(() => scrollToBottom('auto', true), 600);
    });
    return;
  }

  // 首次进入该角色会话：先显示空列表让 UI 立即响应，后台加载历史消息
  allMessages[charId] = [];
  hasMoreHistoryMap[charId] = true;
  isLoadingMore.value = false;

  window.api
    .invoke('get-chat-history', { characterId: charId, limit: 100 })
    .then((chatHistoryRes: any) => {
      // charId 守卫：如果用户已切换到其他角色，丢弃结果
      if (selectedCharacterId.value !== charId) return;
      if (chatHistoryRes.success && chatHistoryRes.history) {
        const restored = chatHistoryRes.history.map((m: any) => restoreMessageProps(m));
        allMessages[charId] = flattenMessages(restored, charId);
        if (chatHistoryRes.history.length < 100) {
          hasMoreHistoryMap[charId] = false;
        }

        // 🚀 核心判定：以最终是否绑定用户人设作为拦截状态的唯一标准，杜绝重复库查询与竞态条件
        if (charId === creatorBotId) {
          hasConfiguredFirstChatMap.value[charId] = true;
        } else {
          if (currentChatBindingProfileId.value) {
            hasConfiguredFirstChatMap.value[charId] = true;
          } else {
            hasConfiguredFirstChatMap.value[charId] = false;
            if (selectedCharacterId.value === charId) {
              openFirstChatConfig();
            }
          }
        }
      } else {
        allMessages[charId] = [];
        hasMoreHistoryMap[charId] = false;
        hasConfiguredFirstChatMap.value[charId] = currentChatBindingProfileId.value ? true : false;
      }
      nextTick(() => {
        scrollToBottom('auto', true);
        setTimeout(() => scrollToBottom('auto', true), 50);
        setTimeout(() => scrollToBottom('auto', true), 150);
        setTimeout(() => scrollToBottom('auto', true), 350);
        setTimeout(() => scrollToBottom('auto', true), 600);
      });
    })
    .catch((error: any) => {
      console.error('读取聊天历史异常:', error);
    });
}

async function selectCharacterFromContacts(charId: string) {
