const creatorBotId = 'character_creator_bot';
async function triggerCreateNewCharacter() {
  showAddMenu.value = false;

  // 强力重置后端创角会话状态机，保证为 step 1
  try {
    await window.api.invoke('reset-creator-bot');
  } catch (err) {
    console.error('重置后端创角会话失败:', err);
  }

  // 检查当前角色列表中是否已有这个虚拟 Bot，如果没有则推入
  if (!characterList.value.some(c => c.id === creatorBotId)) {
    // 插入到最前面，给用户最直接的即时反馈！
    characterList.value.unshift({
      id: creatorBotId,
      name: '角色卡创建Bot',
      first_mes:
        '欢迎使用角色卡创建Bot，请描述您想要创建的角色信息，请包含角色姓名。您也可以通过 [✨ **MOI（https://moi.jiuwo.me）**](https://moi.jiuwo.me) 工具来创建角色卡。',
      created_at: Date.now(),
    });
  }

  // 无论如何覆盖清空该Bot的消息历史，彻底清除上一次对话痕迹
  allMessages[creatorBotId] = [
    {
      role: 'assistant',
      content:
        '欢迎使用角色卡创建Bot，请描述您想要创建的角色信息，请包含角色姓名。您也可以通过 [✨ **MOI（https://moi.jiuwo.me）**](https://moi.jiuwo.me) 工具来创建角色卡。',
      created_at: Date.now(),
    },
  ];

  // 选中并开始对话
  selectCharacter(creatorBotId);
  sideView.value = 'chat';
  activeView.value = 'chat';
}

// ===================== 导入角色 =====================
function openImportView() {
  activeView.value = 'import';
  selectedCharacterId.value = null;
}

function triggerFileInput() {
  fileInput.value?.click();
}

async function handleFileSelect(e: Event) {
  const files = (e.target as HTMLInputElement).files;
  if (files && files.length > 0) await processUploadedFile(files[0]);
}

async function handleCardDrop(e: DragEvent) {
  dragOver.value = false;
  const files = e.dataTransfer?.files;
  if (files && files.length > 0) {
    const file = files[0];
    const isPng = file.type === 'image/png' || file.name.endsWith('.png');
    const isJson = file.type === 'application/json' || file.name.endsWith('.json');
    if (!isPng && !isJson) {
      parseError.value = '文件格式不正确，只支持 PNG 格式或 JSON 格式的角色卡！';
      return;
    }
    await processUploadedFile(file);
  }
}

async function processUploadedFile(file: File) {
  uploading.value = true;
  uploadStep.value = 'parsing';
  parseError.value = null;
  isPreviewOpen.value = false;

  // 如果是 JSON 规格角色卡，由于没有图像二进制数据，不读取 Base64 头像，直接触发系统默认高保真文字头像
  const isJson = file.type === 'application/json' || file.name.endsWith('.json');
  if (isJson) {
    uploadedAvatarUrl.value = '';
  } else {
    const localReader = new FileReader();
    localReader.onload = () => {
      uploadedAvatarUrl.value = localReader.result as string;
    };
    localReader.readAsDataURL(file);
  }

  const arrayReader = new FileReader();
  arrayReader.onload = async () => {
    try {
      const arrayBuffer = arrayReader.result as ArrayBuffer;
      const rawBytes = Array.from(new Uint8Array(arrayBuffer));
      uploadedRawBytes.value = rawBytes;

      const parseRes = await window.api.invoke('parse-character-card', rawBytes);
      if (!parseRes.success) throw new Error(parseRes.error || '解析失败');

      uploadedRawData.value = parseRes.data;
      uploadStep.value = 'summarizing';

      const summarizeRes = await window.api.invoke('summarize-character', JSON.parse(JSON.stringify(parseRes.data)));
      if (!summarizeRes.success) throw new Error(summarizeRes.error || 'AI 提炼失败');

      const pinyinRes = await window.api.invoke('get-pinyin-name', parseRes.data.name);
      previewPinyinName.value = pinyinRes.success ? pinyinRes.uniqueFolderName : '';
      previewSoul.value = summarizeRes.summary.soul;
      previewWorld.value = summarizeRes.summary.world;

      uploading.value = false;
      uploadStep.value = 'idle';
      isPreviewOpen.value = true;
    } catch (e: any) {
      parseError.value = e.message || '导入异常';
      uploading.value = false;
      uploadStep.value = 'idle';
    }
  };
  arrayReader.readAsArrayBuffer(file);
}

async function onImportConfirm(data: { folderName: string; name: string; soul: string; world: string }) {
  isPreviewOpen.value = false;
  try {
    const res = await window.api.invoke('import-character', {
      folderName: data.folderName,
      name: data.name,
      cardData: JSON.parse(JSON.stringify(uploadedRawData.value)),
      soul: data.soul,
      world: data.world,
      uint8ArrayData: JSON.parse(JSON.stringify(uploadedRawBytes.value)),
    });
    if (res.success && res.character) {
      await loadCharacters();
      await selectCharacter(res.character.id);
      activeView.value = 'chat';
    } else {
      showCustomAlert('导入失败', `角色导入失败: ${res.error || '文件保存失败'}`, 'error');
    }
  } catch (error: any) {
    showCustomAlert('导入异常', `${error.message || error}`, 'error');
  }
}

function onImportCancel() {
  isPreviewOpen.value = false;
}

// 重新提炼：携带用户修正要求，重新调用后端进行 AI 提炼
async function onReSummarize(userInstruction: string) {
  try {
    const cardDataForSummarize = JSON.parse(JSON.stringify(uploadedRawData.value));
    const summarizeRes = await window.api.invoke('summarize-character', cardDataForSummarize, userInstruction);
    if (!summarizeRes.success) throw new Error(summarizeRes.error || 'AI 重新提炼失败');
    previewSoul.value = summarizeRes.summary.soul;
    previewWorld.value = summarizeRes.summary.world;
  } catch (e: any) {
    showCustomAlert('重新提炼失败', e.message || '发生未知错误', 'error');
  } finally {
    // 无论成功或失败，都恢复弹窗内的按钮状态
    characterPreviewModalRef.value?.onReSummarizeDone();
  }
}

// ===================== 发送消息 =====================
async function sendChatMessage() {
  activeInnerThoughtMsgId.value = null;
  const char = activeCharacter.value || activeGroupChat.value;
  // 安全拦截：当 AI 正在回复当前角色（streamingCharsSet 中）或者输入与图片均为空时，拦截不予发送
  if (!char || streamingCharsSet.has(char.id) || (!chatInputText.value.trim() && !pastedImageBase64.value)) return;

  // 如果模式还未从 DB 加载完成，等它（通常 < 20ms，不影响体验）
  if (pendingChatModeLoad) await pendingChatModeLoad;

  isSendingChatMessage = true; // 🚀 开启发送清空锁，通知 watch 拦截

  const userMsg = chatInputText.value.trim();
  const imageBase64 = pastedImageBase64.value;

  chatInputText.value = '';
  pastedImageBase64.value = '';

  // 🚀 在下一 tick 释放标志位并强力重新聚焦，确保当前微任务/同步清空产生的 watch 触发已被 100% 物理拦截且输入法一直常驻不折叠
  nextTick(() => {
    isSendingChatMessage = false;
    chatTextarea.value?.focus();
  });

  // 智能重置多端所有可能挂载的 textarea 高度为舒适的 40px
  const textareas = document.querySelectorAll('textarea');
  textareas.forEach(el => {
    if (el.placeholder && el.placeholder.includes('发送消息')) {
      (el as HTMLTextAreaElement).style.height = '40px';
    }
  });

  showEmojiPanel.value = false;

  // 生成唯一的消息ID，用于在 SQLite 数据库中独立持久化该条消息气泡
  const userMsgId = 'msg_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
  lastUserMsgId.value = userMsgId;

  // 🚀 $admin 命令早期拦截：不显示气泡、不入 pending 队列、不存 DB
  // 直接调用 chat-stream（主进程会通过 isSystem chat-chunk 返回文字提示）
  if (userMsg.startsWith('$admin')) {
    // 标记当前角色为流式交互中，避免重复发送
    streamingCharsSet.add(char.id);
    streamingCharacterId.value = char.id;
    try {
      await window.api.invoke('chat-stream', {
        characterId: char.id,
        folderName: (char as any).folder_name || '',
        userMessage: userMsg,
      });
    } catch (e) {
      console.warn('[Admin] IPC 调用失败:', e);
    } finally {
      streamingCharsSet.delete(char.id);
      streamingCharacterId.value = null;
    }
    return;
  }

  // 1. 立即在聊天列表追加该用户消息的绿色气泡进行渲染展示，提供最顺畅的即发即现体验
  if (!allMessages[char.id]) allMessages[char.id] = [];
  const timestamp = Date.now();
  conversationActiveTimes[char.id] = timestamp;
  allMessages[char.id].push({
    id: userMsgId,
    role: 'user',
    content: userMsg,
    imageBase64: imageBase64 || undefined,
    created_at: new Date().toISOString(),
    timestamp: timestamp,
    sender_id: 'user',
  });
  nextTick(() => scrollToBottom('smooth', true));

  // 2. 物理落盘已完全移交给后台 3 秒合并时唯一落盘，从而解除重复产生的双条消息 Bug

  // 3. 将本条消息推入延时合并队列中，准备进行 3 秒内的多消息聚合
  const charId = char.id;
  if (!pendingUserMessagesMap[charId]) {
    pendingUserMessagesMap[charId] = [];
  }
  pendingUserMessagesMap[charId].push({
    content: userMsg,
    imageBase64: imageBase64 || undefined,
    userMsgId: userMsgId, // 每条消息携带自己的唯一 ID
    timestamp: timestamp, // 每条消息携带自己的时间戳
  });

  // 4. 重置并刷新 3 秒延时聚合防抖定时器
  const isSlashStart = currentChatMode.value === 'director' && (userMsg === '/开始' || userMsg === '/开始剧情');

  if (isSlashStart) {
    // 🚀 如果是导演模式下的开场白斜杠指令，立即清除聚合防抖定时器并瞬间发起调用，提供 0 延迟交互
    if (messageMergeTimersMap[charId]) {
      clearTimeout(messageMergeTimersMap[charId]);
      messageMergeTimersMap[charId] = null;
    }
    nextTick(async () => {
      await triggerMergedAiResponse(char);
    });
  } else {
    if (messageMergeTimersMap[charId]) {
      clearTimeout(messageMergeTimersMap[charId]);
    }

    messageMergeTimersMap[charId] = setTimeout(async () => {
      await triggerMergedAiResponse(char);
    }, 3000);
  }
}

// 聚合期满，向 AI 发起真正的回复请求
async function triggerMergedAiResponse(char: any, overrideText?: string, isRegenerate = false) {
  const charId = char.id;
  const pendingQueue = pendingUserMessagesMap[charId] || [];
  if (!overrideText && pendingQueue.length === 0) return;

  const currentRoundId = `round_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;

  // 1. 合并 3 秒内的所有用户短消息（换行符拼接）
  // 特殊：如果是发红包消息，要把文字和红包做微信级合流拼接
  const rpPayload = pendingQueue.find(m => m.redPacketPayload)?.redPacketPayload;

  // 过滤剔除红包本身系统占位词 content，只提取用户发送的文字消息
  const textLines = pendingQueue
    .filter(m => !m.redPacketPayload)
    .map(m => m.content)
    .filter(Boolean);
  const chatInputTextMerged = textLines.join('\n');

  let finalUserMessage = overrideText || chatInputTextMerged;
  let finalDbMessage = overrideText || chatInputTextMerged;
  let finalUserMsgId = overrideText ? `msg_override_${Date.now()}` : lastUserMsgId.value || 'msg_merged_' + Date.now();

  // 🚀 多条消息各自落盘：若 pending 队列有多条消息，把除最后一条以外的所有消息
  // await 存入 DB，必须在 chat-stream 调用（getChatHistory 读 DB）之前完成，
  // 否则 getChatHistory 读不到这些消息。
  // 最后一条由 chat-stream 在主进程侧存盘（finalUserMsgId 对应最后一条）。
  // ⚠️ 同时只将最后一条消息作为 finalUserMessage 传给 AI：
  //    前面的消息已经进 DB 历史，会自然出现在 history 上下文里，
  //    如果再放进 finalUserMessage 就会造成上下文双重污染（重复出现）。
  const nonRpMessages = pendingQueue.filter(m => !m.redPacketPayload);
  if (!overrideText && !isRegenerate && nonRpMessages.length > 1) {
    const extraMessages = nonRpMessages.slice(0, nonRpMessages.length - 1); // 除最后一条
    const savePromises = extraMessages
      .filter(m => m.userMsgId && m.content)
      .map(m =>
        window.api
          .invoke('save-message', {
            id: m.userMsgId!,
            character_id: charId,
            role: 'user',
            content: m.content,
            timestamp: m.timestamp || Date.now(),
            msg_type: 'text',
            round_id: currentRoundId,
          })
          .catch((e: any) => console.warn('[MultiMsg] 独立存盘失败:', e)),
      );
    // await 确保 DB 写入完成，再让 chat-stream 读取 getChatHistory
    await Promise.all(savePromises);

    // 只用最后一条文本消息作为当前轮输入，避免与已存 DB 的前置消息产生上下文重复
    const lastNonRp = nonRpMessages[nonRpMessages.length - 1];
    finalUserMessage = lastNonRp.content || finalUserMessage;
    finalDbMessage = lastNonRp.content || finalDbMessage;
    finalUserMsgId = lastNonRp.userMsgId || finalUserMsgId;
  }

  if (!overrideText && rpPayload) {
    const isGroup = groupChats.value.some(g => g.id === charId);
    const greetings = finalUserMessage ? `在发红包的同时，用户对你们说道：“${finalUserMessage}”\n` : '';

    if (isGroup) {
      const isExclusive = !!rpPayload.targetId;
      if (isExclusive) {
        finalUserMessage = `${greetings}[USER_EXCLUSIVE_RED_ENVELOPE: ${rpPayload.amount}元, 给: ${rpPayload.targetName}, 祝福语: "${rpPayload.title}"] 用户在群里给 ${rpPayload.targetName} 发了一个专属红包，金额为 ${rpPayload.amount} 元，附言：“${rpPayload.title}”。其他 AI 成员绝对不能领用（请选择拒收或保持沉默）。

请 ${rpPayload.targetName} 决定是否“领取”或“退回/拒收”这个专属红包：
- 如果你决定【领取专属红包】：请务必在你的回复的【最开始】加入一行控制符：[RECEIVE_RED_PACKET] ，并符合性格地感谢用户！
- 如果你决定【退回专属红包】：请务必在你的回复的【最开始】加入一行控制符：[RETURN_RED_PACKET] ，并符合性格地拒绝。

其他非指定的 AI 角色如果发言，请在发言中表现出对专属红包的吐槽、羡慕或无视，但绝不能加入控制符 [RECEIVE_RED_PACKET]。`;

        finalDbMessage = `[wechat_red_packet]:${JSON.stringify({
          amount: rpPayload.amount,
          title: rpPayload.title,
          status: 'waiting',
          targetId: rpPayload.targetId,
          targetName: rpPayload.targetName,
        })}`;
      } else {
        finalUserMessage = `${greetings}[USER_GROUP_RED_ENVELOPE: ${rpPayload.amount}元, 祝福语: "${rpPayload.title}"] 用户在群里发了一个普通群红包，金额为 ${rpPayload.amount} 元，群内每个 AI 角色均可分得 ${rpPayload.amount} 元，附言：“${rpPayload.title}”。

请各自以你们的 AI 角色性格和设定，独立决定是否“领取”或“退回/拒收”这个红包：
- 如果你根据性格和设定决定【领取红包】：请务必在你的回复的【最开始】加入一行控制符：[RECEIVE_RED_PACKET] ，并以角色性格表示感谢！
- 如果你根据性格和设定决定【退回红包】：请务必在你的回复的【最开始】加入一行控制符：[RETURN_RED_PACKET] ，并以角色性格拒绝。`;

        finalDbMessage = `[wechat_red_packet]:${JSON.stringify({
          amount: rpPayload.amount,
          title: rpPayload.title,
          status: 'waiting',
        })}`;
      }
    } else {
      finalUserMessage = `${greetings}[USER_RED_ENVELOPE: ${rpPayload.amount}元, 祝福语: "${rpPayload.title}"] 用户给你发了 ${rpPayload.amount} 元的红包，附言：“${rpPayload.title}”。

请以你当前的 AI 角色性格和设定，独立决定是否“领取”或“退回”这个红包：
- 如果你根据性格和设定决定【领取红包】：请你务必在你的回复的【最开始】加入一行控制符：[RECEIVE_RED_PACKET] ，并以角色的性格热情或符合人设地感谢用户！
- 如果你根据性格和设定决定【退回红包】（拒收）：请你务必在你的回复的【最开始】加入一行控制符：[RETURN_RED_PACKET] ，以你的性格傲娇、委婉或符合设定地拒绝红包并说明缘由。

请直接开始你符合人设 of 自然对话回复，不要向用户暴露控制符的存在。`;

      finalDbMessage = `[wechat_red_packet]:${JSON.stringify({ amount: rpPayload.amount, title: rpPayload.title, status: 'waiting' })}`;
    }
    finalUserMsgId = rpPayload.userMsgId;
  }

  const lastImage = overrideText ? undefined : pendingQueue.find(m => m.imageBase64)?.imageBase64;

  // 2. 清空该角色的缓存队列与合并定时器
  if (!overrideText) {
    pendingUserMessagesMap[charId] = [];
    if (messageMergeTimersMap[charId]) {
      clearTimeout(messageMergeTimersMap[charId]);
      messageMergeTimersMap[charId] = null;
    }
  }

  // 不再提前推送助理空白气泡，仅通过 isCurrentCharStreaming 激活顶部"对方正在输入..."状态
  streamingCharsSet.add(char.id);
  streamingCharacterId.value = char.id;
  scrubber.reset();

  // 🚀 如果是导演模式下的开场白斜杠指令，启动 scrubber 的特化 <content> 提取模式
  const isSlashStart =
    currentChatMode.value === 'director' && pendingQueue.some(m => m.content === '/开始' || m.content === '/开始剧情');
  if (isSlashStart) {
    scrubber.setExtractMode(true);
  }

  typingQueue.value = [];
  nextTick(() => scrollToBottom());

  // 🚀 启动 30 秒超时自愈定时器保护
  startReplyTimeout(char.id);

  try {
    const isGroup = groupChats.value.some(g => g.id === charId);
    // 4. 发起大模型一次性返回调用
    const res = await window.api.invoke('chat-stream', {
      characterId: char.id,
      folderName: char.folder_name || 'groups',
      userMessage: finalUserMessage || '（用户发来了一张图片）',
      chatMode: currentChatMode.value,
      imageBase64: lastImage || undefined,
      userMsgId: finalUserMsgId,
      dbMessage: finalDbMessage,
      roundId: !isRegenerate ? currentRoundId : undefined,
      isGroup: isGroup,
      isRegenerate: isRegenerate, // 🚀 传入重新回复标识，避开用户消息的二次重复保存
    });

    if (!res.success) throw new Error(res.error || '连接断开');

    // 🚀 局域网 Web 双通道分流拦截：
    // 在任何局域网连入的 Web 客户端上（含手机、平板及电脑浏览器），为了彻底杜绝局域网 fetch 回调延迟返回与 SSE 广播撞车造成的双份消息 BUG，
    // 发送端的 fetch 回调直接静默 return 拦截，100% 交由绝对不超时、高保真 SSE done / receive-message 接收器去触发唯一一次的分段仿真渲染！
    if (!window.electron || (window.api && (window.api as any).isIpcBridge)) {
      clearReplyTimeout(); // 局域网端交由 SSE 保活，此处清除 fetch 定时器

      // 🚀 4 秒保底自愈：防止大模型生成期间局域网 SSE 遭遇瞬断丢包
      // 必须同时满足三个条件才触发保底：
      // 1. 消息 ID 还未进入 allMessages（未渲染完成）
      // 2. 消息 ID 不在 pendingPlaybackMessageIds 中（echo:message 路径没有接管）
      // 3. 仍处于等待流式状态（streamingCharsSet 中有该角色）
      // 条件 2 是关键：dialogue 模式下打字机动画耗时可能超过 1.5s，若 echo:message 已接管
      // 则 pendingPlaybackMessageIds.has(msgId) === true，保底绝对不触发
      if (res.content && res.messageId) {
        const webMsgId = res.messageId;
        setTimeout(async () => {
          const msgs = allMessages[char.id] || [];
          const hasReceived = msgs.some(m => m.id === webMsgId);
          const isBeingHandled = pendingPlaybackMessageIds.has(webMsgId);
          if (!hasReceived && !isBeingHandled && streamingCharsSet.has(char.id)) {
            console.warn('[Sync Gate Fetch Recovery] 检测到局域网 SSE 丢失广播，触发 fetch 保底自愈渲染！');
            streamingCharsSet.delete(char.id);
            streamingCharacterId.value = '';
            await handleAssistantResponse(
              char,
              res.content,
              res.redPacketAction,
              res.prompt_tokens,
              res.completion_tokens,
              res.cached_tokens,
              webMsgId,
              undefined,
              res.inner_thought,
            );
          }
        }, 4000);
      }
      return;
    }

    // 5. Electron 端：res.content 作为保底自愈渲染（与 Web SSE 端逻辑对齐）
    // 主渲染路径为：MessageBusService.publishBatch → echo:message → handleEchoMessage
    // 只有当 echo:message 完全未被接管时，才由此处兜底
    // 必须同时满足三个条件才触发保底：
    // 1. 消息 ID 还未进入 allMessages（未渲染完成）
    // 2. 消息 ID 不在 pendingPlaybackMessageIds 中（echo:message 路径没有接管）
    // 3. 仍处于等待流式状态（streamingCharsSet 中有该角色）
    // 条件 2 是关键：dialogue 模式下打字机动画耗时可能超过 500ms，若 echo:message 已接管
    // 则 pendingPlaybackMessageIds.has(msgId) === true，保底绝对不触发
    if (res.content && res.messageId) {
      const msgId = res.messageId;
      setTimeout(async () => {
        const msgs = allMessages[char.id] || [];
        const hasReceived = msgs.some(m => m.id === msgId);
        const isBeingHandled = pendingPlaybackMessageIds.has(msgId);
        if (!hasReceived && !isBeingHandled && streamingCharsSet.has(char.id)) {
          console.warn('[Sync Gate Electron Recovery] echo:message 未被接管，触发 res.content 保底自愈！');
          streamingCharsSet.delete(char.id);
          streamingCharacterId.value = null;
          clearReplyTimeout();
          await handleAssistantResponse(
            char,
            res.content,
            res.redPacketAction,
            res.prompt_tokens,
            res.completion_tokens,
            res.cached_tokens,
            msgId,
            undefined,
            res.inner_thought,
          );
        }
      }, 3000);
    }

    // 红包渲染已完全移交 echo:message → handleEchoMessage 标准路径：
    // MessageBusService.publishBatch 会广播一条 msg_type='red_packet' 的消息，
    // handleEchoMessage 收到后通过 restoreMessageProps 正确解析并渲染红包卡片。
    // 不再在此手动 push 临时红包气泡，避免时序差导致去重失败造成重复。
  } catch (err: any) {
    clearReplyTimeout(); // 🚀 发生异常，物理清除 30秒 超时定时器
    // 局域网 Web 客户端静默忽略 fetch 超时断连报错，因为后台大模型依然在完美生成，且 100% 最终会由 SSE 强力救活！
    if (!window.electron || (window.api && (window.api as any).isIpcBridge)) {
      console.warn(
        '[Web Bridge Fetch Handshake Disconnect] 局域网 Web 客户端管手超时/断开（属正常自愈范畴），静默移交 SSE 保活接管。',
      );
      // 🚀 核心修复：局域网端虽然依赖 SSE，但如果是真实接口报错（非握手断连），必须释放正在输入锁定，杜绝卡死，并追加报错提示气泡
      if (err && err.message && !err.message.includes('handshake')) {
        streamingCharsSet.delete(char.id);
        streamingCharacterId.value = '';

        const msgs = allMessages[char.id] || [];
        msgs.push({
          id: 'msg_error_' + Date.now(),
          role: 'assistant',
          content: `[网络或系统异常]: 发送消息失败，请检查 Docker / 局域网连接。详细错误: ${err.message || err}`,
          created_at: new Date().toISOString(),
          timestamp: Date.now(),
          sender_id: char.id,
        });
        nextTick(() => scrollToBottom());
      }
      return;
    }
    streamingCharsSet.delete(char.id);
    const msgs = allMessages[char.id] || [];
    if (msgs.length > 0) {
      const last = msgs[msgs.length - 1];
      if (last.role === 'assistant') last.content += `\n[系统异常]: ${err.message || err}`;
    }
  }
}

// 微信级分段打字仿真播放器
async function handleAssistantResponse(
  char: any,
  content: string,
  redPacketAction: string | null,
  promptTokens?: number,
  completionTokens?: number,
  cachedTokens?: number,
  messageId?: string,
  senderId?: string, // 🚀 新增可选参数：指示真正的发言人角色 ID（用于群聊）
  innerThought?: string | null, // 💡 新增参数：角色心声潜台词
) {
  const sessionId = char.id;
  const actualSenderId = senderId || char.id;

  // 极致物理防重锁：物理清洗掉一切可能因中英文标点、特殊标记、空格或换行等差异引起的误伤，取正文前 30 字紧凑串作为唯一比对锁
  const cleanLockStr = content
    .replace(/\s+/g, '')
    .replace(/[\[\]\(\)\s［］（）:：,，\/]/g, '')
    .slice(0, 30);
  if (cleanLockStr) {
    const lockKey = sessionId + '_' + cleanLockStr;
    if (activeTypingLocks.has(lockKey)) {
      console.warn('[Sync Gate] 拦截到并发打字弹射冲突，此内容正在播放中，静默丢弃：', cleanLockStr);
      return;
    }
    activeTypingLocks.add(lockKey);
  }

  const sessionKey = sessionId + '_' + content.slice(0, 15);
  activeTypingSessions.add(sessionKey);
  // 获取该会话自身的聊天模式：优先读缓存（启动时已全量预加载），缓存未命中时直接查 DB 并回写缓存
  // 完全不依赖全局 chatMode.value，确保非当前选中角色的消息不会被错误分段
  let charChatMode = characterChatModeCache[sessionId];
  if (!charChatMode) {
    try {
      const modeRes = await window.api.invoke('get-character-chat-mode', { characterId: sessionId });
      charChatMode = modeRes.success && modeRes.mode ? modeRes.mode : 'descriptive';
    } catch {
      charChatMode = 'descriptive';
    }
    characterChatModeCache[sessionId] = charChatMode;
  }
  // 在 dialogue 模式下，记录当前正在弹射的内容，供 receive-message 精确去重
  if (charChatMode === 'dialogue') {
    pendingDialogueContents.add(content.replace(/\s+/g, '').slice(0, 80));
  }

  try {
    // 未读数由 MessageBusService → echo:unread-update 权威驱动，此处不再手动自增

    // A. 处理红包决策状态更新与返款
    if (redPacketAction) {
      const msgs = allMessages[sessionId] || [];
      const isReceive = redPacketAction === 'receive';
      const isReturn = redPacketAction === 'return';

      // 逆序寻找最近一封等待处理的红包消息进行物理状态更新与退款提示
      for (let i = msgs.length - 1; i >= 0; i--) {
        const msg = msgs[i];
        if (msg.role === 'user' && msg.redPacket && (!msg.redPacket.status || msg.redPacket.status === 'waiting')) {
          if (isReceive) {
            msg.redPacket.status = 'received';
          } else if (isReturn) {
            msg.redPacket.status = 'returned';
            const amount = parseFloat(msg.redPacket.amount);
            if (!isNaN(amount) && amount > 0) {
              userProfile.walletBalance += amount;
              saveUserProfileLocal();
              showCustomAlert(
                '红包被退回',
                `角色退回了你的红包，金额 ${amount.toFixed(2)} 元已全额退回您的虚拟钱包！`,
                'info',
              );
            }
          }

          // 物理保存红包的最新状态到 SQLite
          if (msg.id) {
            const updatedPayload = {
              ...msg.redPacket,
              status: msg.redPacket.status,
            };
            const updatedDbMessage = `[wechat_red_packet]:${JSON.stringify(updatedPayload)}`;
            window.api.invoke('update-message-content', {
              characterId: sessionId,
              messageId: msg.id,
              content: updatedDbMessage,
            });
          }
          break;
        }
      }
    }

    // B. 根据该角色的聊天模式分发渲染（使用 charChatMode 而非全局 chatMode.value，防止非当前角色的消息被错误分段）
    const msgs = allMessages[sessionId] || [];

    if (charChatMode === 'descriptive' || charChatMode === 'director') {
      // B.1 包含描写模式/导演模式：直接向会话追加或更新助理回复气泡，瞬间呈现

      // 🚀 流式自愈复用防线：如果最后一条消息是流式临时气泡，我们直接将其 id 与内容更新为物理权威数据，彻底杜绝重复生成 Bug
      const lastMsg = msgs.length > 0 ? msgs[msgs.length - 1] : null;
      if (lastMsg && lastMsg.role === 'assistant' && lastMsg.id && String(lastMsg.id).startsWith('msg_stream_')) {
        console.log(`[Sync Gate] 流式气泡复用更新，覆盖 ID: ${messageId}`);
        lastMsg.id = messageId;
        lastMsg.content = content;
        if (promptTokens !== undefined) lastMsg.prompt_tokens = promptTokens;
        if (completionTokens !== undefined) lastMsg.completion_tokens = completionTokens;
        if (cachedTokens !== undefined) lastMsg.cached_tokens = cachedTokens;
        streamingCharsSet.delete(sessionId);
        nextTick(() => scrollToBottom('smooth', true));
      } else {
        // 🚀 核心自愈去重：检查本地 msgs 中是否由于 receive-message 提前到达而已经存在了相同 id 或高度相同内容的消息！
        const isAlreadyExist = msgs.some(m => m.id === messageId || (m.role === 'assistant' && m.content === content));
        if (isAlreadyExist) {
          console.log(`[Sync Gate] 瞬间呈现模式：本地已被 receive-message 提前写入，不再重复 push`);
          streamingCharsSet.delete(sessionId);
          nextTick(() => scrollToBottom());
        } else {
          msgs.push({
            role: 'assistant',
            content: content,
            id: messageId, // 🚀 瞬间呈现直接绑定真实物理 ID
            sender_id: actualSenderId, // 🚀 补全发送人 ID
            character_id: sessionId, // 🚀 补全会话 ID
            created_at: new Date().toISOString(),
            prompt_tokens: promptTokens,
            completion_tokens: completionTokens,
            cached_tokens: cachedTokens,
          });
          streamingCharsSet.delete(sessionId);
          nextTick(() => {
            scrollToBottom('smooth', true);
            setTimeout(() => scrollToBottom('smooth', true), 80);
          });
        }
      }
    } else {
      // B.2 纯对话模式：采用高维微信级智能分句重组算法，进行有节奏的逐句打字弹射播放

      const isSpecialMsg =
        content &&
        (content.startsWith('[character_diary]:') ||
          content.startsWith('[wechat_red_packet]:') ||
          content.startsWith('[wechat_custom_emoji]:') ||
          content.startsWith('[wechat_image_media]:'));

      if (isSpecialMsg) {
        // 🚀 特殊卡片消息（红包/表情包/图片/日记等）在仅对话模式下的串行排队弹射
        streamingCharsSet.add(sessionId);

        // 拟真网络传输缓冲小延迟
        await new Promise(resolve => setTimeout(resolve, 800));

        const currentMsgs = allMessages[sessionId] || [];
        let insertAt = currentMsgs.length;
        const safeInsertAt = Math.min(insertAt, currentMsgs.length);

        const rawMsg = {
          role: 'assistant',
          content: content,
          id: messageId || 'msg_special_' + Math.random().toString(36).substr(2, 9),
          sender_id: actualSenderId,
          character_id: sessionId,
          created_at: new Date().toISOString(),
          prompt_tokens: promptTokens,
          completion_tokens: completionTokens,
          cached_tokens: cachedTokens,
        };

        // 使用 restoreMessageProps 补全解析后的渲染字段（如红包对象等）
        const restored = restoreMessageProps(rawMsg);
        currentMsgs.splice(safeInsertAt, 0, restored);

        streamingCharsSet.delete(sessionId);
        nextTick(() => {
          scrollToBottom('smooth', true);
        });
        return;
      }

      const paragraphs: string[] = [];
      const lines = content
        .split('\n')
        .map(l => l.trim())
        .filter(Boolean);

      for (const line of lines) {
        if (line.length <= 25) {
          paragraphs.push(line);
          continue;
        }

        // 基于标准句尾标点进行高精度二次拆分
        const sentences = line
          .split(/(?<=[。；！？!?])\s*/)
          .map(s => s.trim())
          .filter(Boolean);

        let currentTemp = '';
        for (const s of sentences) {
          if (currentTemp.length === 0) {
            currentTemp = s;
          } else {
            // 合并过短的断句片段，防止显示太细造成刷屏
            if (currentTemp.length + s.length <= 15 || s.length < 4) {
              currentTemp += s;
            } else {
              paragraphs.push(currentTemp);
              currentTemp = s;
            }
          }
        }
        if (currentTemp) {
          paragraphs.push(currentTemp);
        }
      }

      if (paragraphs.length === 0) {
        streamingCharsSet.delete(sessionId);
        return;
      }

      // 开启串行异步微信分段打字发送模拟
      // 🔒 修复气泡顺序 Bug：在弹射开始前锁定插入位置（当前消息数组末尾）。
      let insertAt = allMessages[sessionId].length;

      for (let idx = 0; idx < paragraphs.length; idx++) {
        const text = paragraphs[idx];

        // 在顶部标题栏显示"对方正在输入..."
        streamingCharsSet.add(sessionId);

        // 根据每句话 of 字数拟真思考打字的时长
        const typeDelay = Math.min(Math.max(text.length * 100, 1000), 2800);
        await new Promise(resolve => setTimeout(resolve, typeDelay));

        // 延迟结束，该句段瞬间作为独立的微信助理气泡弹射展示出来！
        const isLast = idx === paragraphs.length - 1;
        const currentMsgs = allMessages[sessionId];
        // 安全边界：insertAt 不能超过数组当前长度
        const safeInsertAt = Math.min(insertAt, currentMsgs.length);
        currentMsgs.splice(safeInsertAt, 0, {
          role: 'assistant',
          content: text,
          id: isLast && messageId ? messageId : 'msg_part_' + Math.random().toString(36).substr(2, 9), // 🚀 最后一句绑定真实物理 ID，前几段用临时唯一 ID！
          sender_id: actualSenderId, // 🚀 补全发送人 ID
          character_id: sessionId, // 🚀 补全会话 ID
          created_at: new Date().toISOString(),
          prompt_tokens: isLast ? promptTokens : undefined,
          completion_tokens: isLast ? completionTokens : undefined,
          cached_tokens: isLast ? cachedTokens : undefined,
          inner_thought: isLast ? innerThought : null, // 💡 只有最后一句绑定心声
        });
        insertAt = safeInsertAt + 1; // 下一句插入到本句之后
        nextTick(() => scrollToBottom());

        // 如果有下一句，微等 500ms 作为大脑思考打字间隔空隙，随后再次进入"对方正在输入"状态
        if (idx < paragraphs.length - 1) {
          streamingCharsSet.delete(sessionId);
          await new Promise(resolve => setTimeout(resolve, 500));
        }
      }

      streamingCharsSet.delete(sessionId);
      nextTick(() => {
        scrollToBottom('smooth', true);
        setTimeout(() => scrollToBottom('smooth', true), 80);
      });
    }

    // 刷新记忆与日记视图
    setTimeout(async () => {
      const memRes = await window.api.invoke('read-character-file', {
        folderName: char.folder_name,
        fileName: 'Memory.md',
      });
      if (memRes.success) activeMemory.value = memRes.content;
      const diaryRes = await window.api.invoke('read-character-file', {
        folderName: char.folder_name,
        fileName: 'Diary.md',
      });
      if (diaryRes.success) activeDiary.value = diaryRes.content;
    }, 1500);
  } finally {
    if (cleanLockStr) {
      activeTypingLocks.delete(char.id + '_' + cleanLockStr);
    }
    pendingDialogueContents.delete(content.replace(/\s+/g, '').slice(0, 80));
    activeTypingSessions.delete(sessionKey);
  }
}

function handleKeyDown(e: KeyboardEvent) {
  if (showAtMentionModal.value) {
    const list = filteredAtMentionMembers.value;
    if (list.length > 0) {
      if (e.key === 'ArrowDown') {
        e.preventDefault();
        activeAtMentionSelectIndex.value = (activeAtMentionSelectIndex.value + 1) % list.length;
        return;
      } else if (e.key === 'ArrowUp') {
        e.preventDefault();
        activeAtMentionSelectIndex.value = (activeAtMentionSelectIndex.value - 1 + list.length) % list.length;
        return;
      } else if (e.key === 'Enter') {
        e.preventDefault();
        insertAtMention(list[activeAtMentionSelectIndex.value].name);
        return;
      }
    }
    if (e.key === 'Escape') {
      e.preventDefault();
      showAtMentionModal.value = false;
      return;
    }
  }

  if (e.key === 'Enter' && !e.shiftKey) {
    if (isMobile.value) {
      // 手机端回车仅作换行，不发送消息
      return;
    }
    e.preventDefault();
    sendChatMessage();
  }
}

// 粘贴图片处理
function handlePaste(e: ClipboardEvent) {
  const items = e.clipboardData?.items;
  if (!items) return;
  for (let i = 0; i < items.length; i++) {
    if (items[i].type.startsWith('image/')) {
      e.preventDefault();
      const file = items[i].getAsFile();
      if (!file) continue;
      const reader = new FileReader();
      reader.onload = () => {
        pastedImageBase64.value = reader.result as string;
      };
      reader.readAsDataURL(file);
      break;
    }
  }
}

// 拖拽文件进入与悬停处理器
function handleDragEnter(e: DragEvent) {
  if (!isChattingActive.value) return;
  if (e.dataTransfer?.types.includes('Files')) {
    isDraggingFile.value = true;
  }
}

function handleDragOver(e: DragEvent) {
  if (!isChattingActive.value) return;
  if (e.dataTransfer?.types.includes('Files')) {
    isDraggingFile.value = true;
  }
}

function handleDragLeave() {
  isDraggingFile.value = false;
}

// 释放拖拽文件处理器
function handleDrop(e: DragEvent) {
  if (!isChattingActive.value) {
    isDraggingFile.value = false;
    return;
  }
  isDraggingFile.value = false;
  const files = e.dataTransfer?.files;
  if (!files || files.length === 0) return;

  // 仅截取并解析拖拽列表中的第一张图片
  for (let i = 0; i < files.length; i++) {
    if (files[i].type.startsWith('image/')) {
      const file = files[i];
      const reader = new FileReader();
      reader.onload = () => {
        pastedImageBase64.value = reader.result as string;
      };
      reader.readAsDataURL(file);
      break;
    }
  }
}

// ===================== 滚动到底部 =====================
function scrollToBottom(behavior: 'auto' | 'smooth' = 'smooth', force = false) {
  if (chatContainer.value) {
    const container = chatContainer.value;
    const diff = container.scrollHeight - container.scrollTop - container.clientHeight;

    // 🚀 黄金防抖自愈避让机制：
    // 如果不是强制置底（例如用户自己发消息或点了回底按钮），且当前滚动条距离底部已经超过了 50px（约两行字高度），
    // 说明用户明显在向上滑动或停留在上方阅读历史。此时必须直接避让 return，绝对不要强行置底拉回，
    // 从而完美终结流式输出打字机高频置底导致的剧烈上下拉扯与回弹，给用户最丝滑、无阻力的历史翻阅体验！
    if (!force && diff > 50) {
      return;
    }
    container.scrollTo({ top: container.scrollHeight, behavior });
  }
}

// ===================== 滚动触顶分页拉取历史消息 =====================
async function handleChatScroll(e: Event) {
  const container = e.target as HTMLElement;
  if (!container || !selectedCharacterId.value) return;

  // 实时检测滚动条当前是否不在最底部以控制回底悬浮按钮的显隐
  // 容差值设为 120px：只要距离底部超出 120px，就算“不在最底部”
  const isAtBottom = container.scrollHeight - container.scrollTop - container.clientHeight <= 120;
  showScrollToBottomBtn.value = !isAtBottom;

  const charId = selectedCharacterId.value;

  // 仅在滚动触顶（留出 5px 物理容差）、未处于流式加载、且该会话还有更早历史时触发
  if (container.scrollTop <= 5 && !isLoadingMore.value && hasMoreHistoryMap[charId] !== false) {
    const currentMsgs = allMessages[charId] || [];
    if (currentMsgs.length === 0) return;

    // 提取当前对话列表最前端（时间戳最老）且具有有效时间戳的消息作为游标
    const validMsgs = currentMsgs.filter(m => m.timestamp !== undefined && m.timestamp !== null);
    if (validMsgs.length === 0) return;
    const beforeTimestamp = validMsgs[0].timestamp;

    console.log(
      `[handleChatScroll] 准备加载更早历史。当前队列长度: ${currentMsgs.length}, 最老游标 beforeTimestamp: ${beforeTimestamp}, 消息片断: "${validMsgs[0].content?.slice(0, 15)}"`,
    );

    isLoadingMore.value = true;

    try {
      // 记录追加消息前容器的 scrollHeight 物理高度，用于锁定滚动视野
      const prevScrollHeight = container.scrollHeight;

      // 向主进程请求在此时间戳之前的 100 条消息（50 轮）
      const res = await window.api.invoke('get-chat-history', {
        characterId: charId,
        limit: 100,
        beforeTimestamp,
      });

      if (res.success && res.history && res.history.length > 0) {
        console.log(
          `[handleChatScroll] 成功拉取到历史。条数: ${res.history.length}, 返回消息最老一条时间戳: ${res.history[0].timestamp}, 最新一条时间戳: ${res.history[res.history.length - 1].timestamp}`,
        );

        const restored = res.history.map((m: any) => restoreMessageProps(m));
        const olderMsgs = flattenMessages(restored, charId); // 🚀 翻页加载的历史记录也在前端进行 flatten 拆分铺平！

        // 🚀 核心自愈优化：通过 ID 强效去重过滤，100% 根除快速连续滚动、并发拉取可能造成的历史消息重复显示 Bug
        const filteredOlder = olderMsgs.filter((om: any) => !currentMsgs.some((cm: any) => cm.id === om.id));
        if (filteredOlder.length > 0) {
          currentMsgs.unshift(...filteredOlder);
        }

        // 如果拉取的历史条数不足 100 条，说明已达数据库消息起点，标记为无更多
        if (res.history.length < 100) {
          hasMoreHistoryMap[charId] = false;
          console.log(`[handleChatScroll] 历史消息已全部加载完毕，触及数据库起点。`);
        }

        // 极其惊艳的物理滚动补偿对齐，保证视野内消息纹丝不动，彻底免除画面抖动
        nextTick(() => {
          container.scrollTop = container.scrollHeight - prevScrollHeight;
          isLoadingMore.value = false;
        });
      } else {
        // 无数据，则标记已加载到尽头
        console.log(`[handleChatScroll] 未拉取到更早消息，标记为无更多历史。`);
        hasMoreHistoryMap[charId] = false;
        isLoadingMore.value = false;
      }
    } catch (err) {
      console.error('拉取分页聊天历史异常:', err);
      isLoadingMore.value = false;
    }
  }
}

// ===================== 底部输入区高度拖拽 =====================
function startInputResize(e: MouseEvent) {
  e.preventDefault();
  const startY = e.clientY;
  const startHeight = inputHeight.value;

  const onMouseMove = (ev: MouseEvent) => {
    const deltaY = ev.clientY - startY;
    const newHeight = startHeight - deltaY;
    inputHeight.value = Math.max(110, Math.min(350, newHeight));
  };

  const onMouseUp = () => {
    localStorage.setItem('echo_input_height', inputHeight.value.toString());
    window.removeEventListener('mousemove', onMouseMove);
    window.removeEventListener('mouseup', onMouseUp);
  };

  window.addEventListener('mousemove', onMouseMove);
  window.addEventListener('mouseup', onMouseUp);
}

// ===================== 打字机效果 =====================
function startTypingEffect() {
  if (typingTimer) return;
  typingTimer = setInterval(() => {
    if (typingQueue.value.length > 0) {
      const ch = typingQueue.value.shift();
      const msgs = allMessages[selectedCharacterId.value || ''] || [];
      if (msgs.length > 0) {
        const last = msgs[msgs.length - 1];
        if (last.role === 'assistant') last.content += ch;
      }
      scrollToBottom();
    } else if (!streamingCharsSet.has(selectedCharacterId.value || '')) {
      clearInterval(typingTimer);
      typingTimer = null;

      // 当打字机动画播放完成，且流式已结束时，应用保留的完美换行权威全文
      const charId = selectedCharacterId.value;
      if (charId && pendingCleanedContentMap[charId]) {
        const msgs = allMessages[charId] || [];
        if (msgs.length > 0) {
          const last = msgs[msgs.length - 1];
          if (last.role === 'assistant') {
            last.content = pendingCleanedContentMap[charId];
          }
        }
        delete pendingCleanedContentMap[charId];
      }

      handleRedPacketStatusOnDone();
    }
  }, 30);
}

function scrubRedPacketFromQueue() {
  const queueText = typingQueue.value.join('');

  // 🚀 前端 done 兜底：强力抹杀 typingQueue 里面残存的任何主动发红包控制符 [SEND_RED_PACKET: ...]
  // 🚀 升级为超强容错全局正则，支持全半角冒号/逗号、反单引号包裹、忽略大小写
  const sendReg = /`?\s*\[SEND_RED_PACKET[:：]\s*(\d+(\.\d+)?)\s*[,，]\s*([\s\S]+?)\]\s*`?/gi;
  let updatedText = queueText.replace(sendReg, '').trim();

  let isReceive = false;
  let isReturn = false;

  if (updatedText.includes('[RECEIVE_RED_PACKET]')) {
    isReceive = true;
  } else if (updatedText.includes('[RETURN_RED_PACKET]')) {
    isReturn = true;
  }

  const targetTag = isReceive ? '[RECEIVE_RED_PACKET]' : '[RETURN_RED_PACKET]';
  updatedText = updatedText.replace(targetTag, '').trim();

  // 🚀 进一步清除未闭合的小说动作半截括号残余（如：“(红”）
  const halfBracketReg = /[（(][^）)]*$/g;

  updatedText = updatedText.replace(halfBracketReg, '').trim();

  typingQueue.value = updatedText.split('');

  const charId = selectedCharacterId.value;
  if (charId && allMessages[charId]) {
    const msgs = allMessages[charId];
    for (let i = msgs.length - 1; i >= 0; i--) {
      const msg = msgs[i];
      if (msg.role === 'user' && msg.redPacket && (!msg.redPacket.status || msg.redPacket.status === 'waiting')) {
        if (isReceive) {
          msg.redPacket.status = 'received';
        } else if (isReturn) {
          msg.redPacket.status = 'returned';
          const amount = parseFloat(msg.redPacket.amount);
          if (!isNaN(amount) && amount > 0) {
            userProfile.walletBalance += amount;
            saveUserProfileLocal();
            showCustomAlert(
              '红包被退回',
              `角色退回了你的红包，金额 ${amount.toFixed(2)} 元已全额退回您的虚拟钱包！`,
              'info',
            );
          }
        }

        // 物理保存红包的最新状态更新到 SQLite 数据库中，防止退出后状态丢失
        if (msg.id) {
          const updatedDbMessage = `[wechat_red_packet]:${JSON.stringify({
            amount: msg.redPacket.amount,
            title: msg.redPacket.title,
            status: msg.redPacket.status,
          })}`;
          window.api.invoke('update-message-content', {
            messageId: msg.id,
            content: updatedDbMessage,
          });
        }
        break;
      }
    }
  }
}

function handleRedPacketStatusOnDone() {
  const charId = selectedCharacterId.value;
  if (!charId || !allMessages[charId]) return;

  const msgs = allMessages[charId];
  if (msgs.length === 0) return;

  const lastAssistant = msgs[msgs.length - 1];
  if (lastAssistant.role !== 'assistant') return;

  let isReceive = false;
  let isReturn = false;

  if (lastAssistant.content.includes('[RECEIVE_RED_PACKET]')) {
    isReceive = true;
    lastAssistant.content = lastAssistant.content.replace(/\[RECEIVE_RED_PACKET\]/g, '').trim();
  } else if (lastAssistant.content.includes('[RETURN_RED_PACKET]')) {
    isReturn = true;
    lastAssistant.content = lastAssistant.content.replace(/\[RETURN_RED_PACKET\]/g, '').trim();
  }

  if (!isReceive && !isReturn) return;

  // 逆序寻找最近一封等待处理的红包消息
  for (let i = msgs.length - 1; i >= 0; i--) {
    const msg = msgs[i];
    if (msg.role === 'user' && msg.redPacket) {
      if (isReceive) {
        msg.redPacket.status = 'received';
      } else if (isReturn) {
        msg.redPacket.status = 'returned';
        const amount = parseFloat(msg.redPacket.amount);
        if (!isNaN(amount) && amount > 0) {
          userProfile.walletBalance += amount;
          saveUserProfileLocal();
          showCustomAlert(
            '红包被退回',
            `角色退回了你的红包，金额 ${amount.toFixed(2)} 元已全额退回您的虚拟钱包！`,
            'info',
          );
        }
      }

      // 物理保存红包的最新状态更新到 SQLite 数据库中，防止退出后状态丢失
      if (msg.id) {
        const updatedDbMessage = `[wechat_red_packet]:${JSON.stringify({
          amount: msg.redPacket.amount,
          title: msg.redPacket.title,
          status: msg.redPacket.status,
        })}`;
        window.api.invoke('update-message-content', {
          messageId: msg.id,
          content: updatedDbMessage,
        });
      }
      break;
    }
  }
}

