}

async function sendCustomEmoji(emoji: { base64: string; meaning: string }) {
  const char = activeCharacter.value || activeGroupChat.value;
  if (!char) return;

  showEmojiPanel.value = false;

  if (!allMessages[char.id]) allMessages[char.id] = [];

  // 生成唯一的 userMsgId，用于物理保存与定位消息
  const userMsgId = 'msg_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);

  const contentText = `[表情: ${emoji.meaning}]`;
  const timestamp = Date.now();
  conversationActiveTimes[char.id] = timestamp;
  allMessages[char.id].push({
    id: userMsgId,
    role: 'user',
    content: contentText,
    customEmojiUrl: emoji.base64,
    created_at: new Date().toISOString(),
    timestamp: timestamp,
  });

  streamingCharsSet.add(char.id);
  streamingCharacterId.value = char.id;
  startReplyTimeout(char.id); // 10 分钟超时兜底，防止网络异常导致"正在输入..."永久卡死
  scrubber.reset();
  typingQueue.value = [];
  nextTick(() => scrollToBottom());

  try {
    const res = await window.api.invoke('chat-stream', {
      characterId: char.id,
      folderName: char.folder_name,
      userMessage: `[表情: ${emoji.meaning}]`,
      chatMode: characterChatModeCache[char.id] ?? 'descriptive',
      userMsgId: userMsgId,
      dbMessage: `[wechat_custom_emoji]:${JSON.stringify({ meaning: emoji.meaning, base64: emoji.base64 })}`,
    });
    if (!res.success) throw new Error(res.error || '连接断开');

    // 与 triggerMergedAiResponse 保持一致：
    // 主渲染路径为 publishBatch → echo:message → handleEchoMessage
    // 此处只做 safety-net 保底，不立即调用 handleAssistantResponse（防止与 echo:message 路径竞争）
    if (res.content && res.messageId) {
      const safetyMsgId = res.messageId;
      const safetyDelay = !window.electron || (window.api && (window.api as any).isIpcBridge) ? 4000 : 3000;
      setTimeout(async () => {
        const msgs = allMessages[char.id] || [];
        const hasReceived = msgs.some(m => m.id === safetyMsgId);
        const isBeingHandled = pendingPlaybackMessageIds.has(safetyMsgId);
        if (!hasReceived && !isBeingHandled && streamingCharsSet.has(char.id)) {
          console.warn('[sendCustomEmoji Safety] echo:message 未被接管，触发保底渲染！');
          streamingCharsSet.delete(char.id);
          streamingCharacterId.value = null;
          clearReplyTimeout();
          await handleAssistantResponse(
            char,
            res.content,
            res.redPacketAction,
            res.prompt_tokens,
            res.completion_tokens,
            res.cached_tokens,
            safetyMsgId,
            undefined,
            res.inner_thought,
          );
        }
      }, safetyDelay);
    }

    // Web 端清除计时器，交由 SSE 保活
    if (!window.electron || (window.api && (window.api as any).isIpcBridge)) {
      clearReplyTimeout();
    }
  } catch (err: any) {
    streamingCharsSet.delete(char.id);
    streamingCharacterId.value = null;
    clearReplyTimeout();
    const msgs = allMessages[char.id] || [];
    if (msgs.length > 0) {
      const last = msgs[msgs.length - 1];
      if (last.role === 'assistant') last.content += `\n[系统异常]: ${err.message || err}`;
    }
  }
}

// ===================== 红包 =====================
const showReceiveRedPacketModal = ref(false);
const activeReceivingRedPacketMsg = ref<any>(null);
const redPacketSender = computed(() => {
  const msg = activeReceivingRedPacketMsg.value;
  if (!msg) return null;
  const senderId = msg.sender_id || msg.character_id;
  if (senderId) {
    const char = characterList.value.find(c => c.id === senderId);
    if (char) return char;
    if (senderId === 'user') {
      return { id: 'user', name: userProfile.nickname || '我', avatar: userProfile.avatarUrl };
    }
  }
  return activeCharacter.value || { id: 'unknown', name: '神秘成员' };
});
const isOpeningRedPacket = ref(false);

function openRedPacket() {
  showRedPacketModal.value = true;
}

function handleReceiveCharacterRedPacket(msg: any) {
  if (!msg.redPacket || msg.redPacket.status === 'received') return;
  activeReceivingRedPacketMsg.value = msg;
  showReceiveRedPacketModal.value = true;
  isOpeningRedPacket.value = false;
}

async function openCharacterRedPacket() {
  const msg = activeReceivingRedPacketMsg.value;
  if (!msg || isOpeningRedPacket.value) return;

  isOpeningRedPacket.value = true;

  // 微信级极高拟真度 1 秒金币旋转缓冲延迟
  await new Promise(resolve => setTimeout(resolve, 1000));

  try {
    const amount = parseFloat(msg.redPacket.amount);
    if (!isNaN(amount) && amount > 0) {
      userProfile.walletBalance += amount;
      saveUserProfileLocal();

      // 更新本条红包卡片的物理状态并物理同步更新 SQLite
      msg.redPacket.status = 'received';
      if (msg.id) {
        const updatedDbMessage = `[wechat_red_packet]:${JSON.stringify({
          amount: msg.redPacket.amount,
          title: msg.redPacket.title,
          status: 'received',
        })}`;
        await window.api.invoke('update-message-content', {
          messageId: msg.id,
          content: updatedDbMessage,
        });
      }

      showCustomAlert(
        '领受成功',
        `成功领受了角色发给你的回音红包，金额 ${amount.toFixed(2)} 元已实时存入您的钱包！`,
        'success',
      );
    }
  } catch (err: any) {
    showCustomAlert('领取失败', `发生异常：${err.message || err}`, 'error');
  } finally {
    showReceiveRedPacketModal.value = false;
    isOpeningRedPacket.value = false;
    activeReceivingRedPacketMsg.value = null;
  }
}

