async function saveUserProfile() {
  // 根据当前所在的页签，决定保存的源头
  const source = userProfileActiveTab.value === 'profile' ? 'profile' : 'markdown';

  saveUserProfileLocal();

  // 保存全局 USER.md 且同步写回姓名
  const syncRes = await window.api.invoke('save-global-user-md', {
    content: globalUserMdContent.value,
    nickname: userProfile.nickname,
    source: source,
  });
  if (syncRes?.success) {
    if (syncRes.updatedContent !== undefined) {
      globalUserMdContent.value = syncRes.updatedContent;
    }
    // 只有当物理文件逆向解析出的姓名非空时，才同步并覆盖前端缓存，防止零占位物理清空将已有姓名抹杀
    if (syncRes.nickname !== undefined && syncRes.nickname.trim() !== '') {
      userProfile.nickname = syncRes.nickname;
      saveUserProfileLocal();
    }
    showCustomAlert('个人中心保存成功', '个人中心基础资料与全局用户画像已成功保存并实时生效。', 'success');
    fetchRealtimeWeather();
  } else {
    showCustomAlert('保存失败', `${syncRes?.error || '物理写盘失败'}`, 'error');
  }
  showUserProfileModal.value = false;
}

function saveUserProfileLocal(syncToBackend = true) {
  const profileData = {
    appAvatarUrl: '', // 🚀 缓存绝不存放庞大的 Base64 头像数据，避免超出 LocalStorage 的 5MB 配额导致异常中断
    avatarUrl: userProfile.avatarUrl,
    nickname: userProfile.nickname,
    signature: userProfile.signature,
    location: userProfile.location,
    walletBalance: userProfile.walletBalance,
  };

  try {
    localStorage.setItem('echo_user_profile', JSON.stringify(profileData));
  } catch (err) {
    console.warn('[LocalStorage] 写入用户配置缓存失败，可能超出配额:', err);
  }

  if (syncToBackend) {
    // 物理写盘必须带上 appAvatarUrl 原始数据
    const backendData = {
      ...profileData,
      appAvatarUrl: userProfile.appAvatarUrl,
    };
    window.api.invoke('save-user-profile', backendData).catch(err => {
      console.error('[saveUserProfileLocal] 同步个人配置到后端失败:', err);
    });
  }
}

function loadUserProfileLocal() {
  try {
    const stored = localStorage.getItem('echo_user_profile');
    if (stored) {
      const data = JSON.parse(stored);
      // 🚀 注意：appAvatarUrl 由后端的物理文件读写托管读取，此处只加载除头像外的配置项
      userProfile.avatarUrl = data.avatarUrl || '';
      userProfile.nickname = data.nickname || '';
      userProfile.signature = data.signature || '';
      userProfile.location = data.location || '';
      userProfile.walletBalance = data.walletBalance ?? 1000;
    } else {
      userProfile.nickname = '';
    }
  } catch (_) {
    userProfile.nickname = '';
  }
}

