async function refreshDeepSeekBalance() {
  if (!hasDeepSeek.value) return;

  isBalanceLoading.value = true;
  // 核心：彻底消除闪烁！刷新时绝不将 deepseekBalance.value 设为 null，以保留先前的稳定渲染和数值！
  try {
