  } finally {
    saving.value = false;
  }
}

// ===================== NovelAI 绘图前端交互逻辑 =====================
const showApiKey = ref(false);

async function saveNovelAiConfig() {
  saving.value = true;
  try {
    // ⚡️ 兼容同步自愈：如果 artistStringList 存在，自动同步当前 Pin 锁定项的提示词内容到旧有的单 artistString 字段中
    if (Array.isArray(novelai.artistStringList) && novelai.artistStringList.length > 0) {
      const idx = novelai.fixedArtistIndex || 0;
      if (novelai.artistStringList[idx]) {
        novelai.artistString = novelai.artistStringList[idx].value || '';
      } else {
        // 如果越界则兜底使用第一项
        novelai.artistString = novelai.artistStringList[0].value || '';
      }
    }

    // ⚡️ 验证并规整自定义默认高宽分辨率为数字且是 64 的倍数，防止输入非法内容导致生图错误
    if (novelai.defaultDimensions === 'custom') {
      const w = Math.round((Number(novelai.defaultWidth) || 832) / 64) * 64;
      const h = Math.round((Number(novelai.defaultHeight) || 1216) / 64) * 64;
      novelai.defaultWidth = Math.max(256, Math.min(2560, w));
      novelai.defaultHeight = Math.max(256, Math.min(2560, h));
    }

    const res = await window.api.invoke('save-novelai-config', toRaw(novelai));
    if (res.success) {
      // 同时同步更新当前自定义分辨率输入框的默认初始值
      customWidth.value = novelai.defaultWidth || 832;
      customHeight.value = novelai.defaultHeight || 1216;
      showSettingsModal.value = false;
      showCustomAlert('配置保存成功', 'NovelAI 绘图配置已成功写入本地 SQLite，并已实时生效！', 'success');
    } else {
      showCustomAlert('保存失败', `${res.error || '未知错误'}`, 'error');
    }
  } catch (error: any) {
    showCustomAlert('保存异常', `${error.message}`, 'error');
  } finally {
    saving.value = false;
  }
}

