function openAdjustPromptModal() {
  if (!bigImageInfo.value) return;

  // 提取原始字符 ID 并进行 Ref 解包处理
  let targetCharId = bigImageInfo.value.characterId;
  if (targetCharId && typeof targetCharId === 'object' && 'value' in targetCharId) {
    targetCharId = (targetCharId as any).value;
  }
  if (!targetCharId) {
    targetCharId = selectedCharacterId.value || '';
  }

  // 增加防重复绘图限制
  if (targetCharId && isDrawingImageMap[targetCharId]) {
    showToast('该角色正在绘图中，请稍候... 🎨');
    return;
  }

  showBigImageModal.value = false;

  // 提取轮次 ID 并进行 Ref 解包处理
  let targetRoundId = bigImageInfo.value.round_id;
  if (targetRoundId && typeof targetRoundId === 'object' && 'value' in targetRoundId) {
    targetRoundId = (targetRoundId as any).value;
  }
  if (!targetRoundId) {
    targetRoundId = '';
  }

  adjustPromptData.value = {
    characterId: targetCharId,
    folderName: '',
    prompt: bigImageInfo.value.prompt || '',
    negativePrompt: bigImageInfo.value.negativePrompt || '',
    dimensions: 'portrait',
    customWidth: 1024,
    customHeight: 1024,
    filename: bigImageInfo.value.filename || '',
    prefixType: bigImageInfo.value.prefixType || 'chat',
    parentRoundId: targetRoundId,
    isRegenerating: false,
  };

  const dims = bigImageInfo.value.dimensions;
  if (typeof dims === 'object' && dims) {
    adjustPromptData.value.dimensions = 'custom';
    adjustPromptData.value.customWidth = dims.width || 1024;
    adjustPromptData.value.customHeight = dims.height || 1024;
  } else if (dims === 'landscape') {
    adjustPromptData.value.dimensions = 'landscape';
  } else if (dims === 'square') {
    adjustPromptData.value.dimensions = 'square';
  } else {
    adjustPromptData.value.dimensions = 'portrait';
  }

  const char = characterList.value.find(c => c.id === adjustPromptData.value.characterId);
  if (char) {
    adjustPromptData.value.folderName = char.folder_name;
  }

  showAdjustPromptModal.value = true;
}

async function startRegeneratingImage() {
  if (adjustPromptData.value.isRegenerating) return;

  let finalDimensions: any = adjustPromptData.value.dimensions;
  if (adjustPromptData.value.dimensions === 'custom') {
    let w = Number(adjustPromptData.value.customWidth);
    let h = Number(adjustPromptData.value.customHeight);

    if (isNaN(w) || w < 256 || w > 2560 || isNaN(h) || h < 256 || h > 2560) {
      showToast('尺寸范围必须在 256 ~ 2560 像素之间');
      return;
    }

    w = Math.round(w / 64) * 64;
    h = Math.round(h / 64) * 64;

    w = Math.max(256, Math.min(2560, w));
    h = Math.max(256, Math.min(2560, h));

    finalDimensions = { width: w, height: h };
  }

  const charId = adjustPromptData.value.characterId;

  // 1. 立刻关闭微调提示词弹窗，交还聊天界面焦点
  showAdjustPromptModal.value = false;

  // 2. 立即将对应角色的“AI绘图”按钮激活为 loading 状态
  if (charId) {
    isDrawingImageMap[charId] = true;
  }

  adjustPromptData.value.isRegenerating = true;
  try {
    const res = await window.api.invoke('regenerate-novelai-image', {
      characterId: adjustPromptData.value.characterId,
      folderName: adjustPromptData.value.folderName,
      prompt: adjustPromptData.value.prompt,
      negativePrompt: adjustPromptData.value.negativePrompt,
      dimensions: finalDimensions,
      filename: adjustPromptData.value.filename,
      prefixType: adjustPromptData.value.prefixType,
      parentRoundId: adjustPromptData.value.parentRoundId,
    });

    if (res.success) {
      showToast('生图成功，新照片已推送到会话最下方 ✨');
    } else {
      showCustomAlert('重新绘制失败', `异常错误: ${res.error}`, 'error');
    }
  } catch (error: any) {
    showCustomAlert('重新绘制异常', `${error.message || error}`, 'error');
  } finally {
    adjustPromptData.value.isRegenerating = false;
    // 3. 生图过程结束（成功或失败），将该角色的绘图 loading 状态设为 false 恢复原状
    if (charId) {
      isDrawingImageMap[charId] = false;
    }
  }
}

async function triggerDeleteGalleryImage(img: any, fromModal: boolean = false) {
  if (!img) return;
  const charId = img.characterId || selectedCharacterId.value || selectedContactId.value;
  if (!charId) return;
  const char = characterList.value.find(c => c.id === charId);
  if (!char) return;

  showCustomConfirm(
    '物理硬删除确认',
    '您确定要从本地磁盘物理硬删除这张图片吗？\n警告：此操作为物理硬抹除，彻底且不可恢复！',
    async () => {
      try {
        const res = await window.api.invoke('delete-gallery-image', {
          folderName: char.folder_name,
          filename: img.filename,
        });

        if (res.success) {
          showToast('影像已从本地磁盘中硬删除 🗑️');

          const idx = contactGalleryImages.value.findIndex(item => item.filename === img.filename);
          if (idx !== -1) {
            contactGalleryImages.value.splice(idx, 1);
          }

          if (fromModal) {
            showBigImageModal.value = false;
          }
        } else {
          showCustomAlert('删除失败', `硬删除失败: ${res.error}`, 'error');
        }
      } catch (err: any) {
        showCustomAlert('删除异常', `${err.message || String(err)}`, 'error');
      }
    },
  );
}

function formatGalleryTime(timestamp: number) {
  if (!timestamp) return '';
  const date = new Date(timestamp);
  return `${date.getMonth() + 1}/${date.getDate()} ${date.getHours().toString().padStart(2, '0')}:${date.getMinutes().toString().padStart(2, '0')}`;
}

function formatGalleryFullTime(timestamp: number) {
  if (!timestamp) return '';
  const date = new Date(timestamp);
  return `${date.getFullYear()}-${(date.getMonth() + 1).toString().padStart(2, '0')}-${date.getDate().toString().padStart(2, '0')} ${date.getHours().toString().padStart(2, '0')}:${date.getMinutes().toString().padStart(2, '0')}:${date.getSeconds().toString().padStart(2, '0')}`;
}

// ===================== 聊天框 AI 绘图交互逻辑 =====================
const showPromptConfirmModal = ref(false);
// 🚀 角色提示词分析状态隔离机制，防止跨角色串台与禁用共享
const isAnalyzingPromptMap = reactive<Record<string, boolean>>({});
const isAnalyzingPrompt = computed(() => {
  return selectedCharacterId.value ? !!isAnalyzingPromptMap[selectedCharacterId.value] : false;
});
// 🚀 角色绘图状态隔离机制，防止跨角色串台与禁用共享
const isDrawingImageMap = reactive<Record<string, boolean>>({});
const isDrawingImage = computed(() => {
  return selectedCharacterId.value ? !!isDrawingImageMap[selectedCharacterId.value] : false;
});

// 🚀 核心上下文隔离：实现生图提示词、描述和尺寸参数在角色维度的物理隔离，杜绝异步切换会话时的数据覆盖与污染
const activeDrawingContextMap = reactive<
  Record<
    string,
    {
      prompt: string;
      description: string;
      dimensions: 'portrait' | 'landscape' | 'square' | 'custom' | { width: number; height: number };
    }
  >
>({});
// 锚定当前弹出的确认框所属的角色 ID
const confirmModalCharacterId = ref<string>('');

// 自定义高宽分辨率响应式状态定义
const customWidth = ref<number>(832);
const customHeight = ref<number>(1216);

// 🚀 桥接 computed：为了零改动 Vue 模版并实现 100% 编译安全，使用 computed 将旧的 confirmed 变量智能路由到当前选中的确认框角色专属 Map
const confirmedPrompt = computed({
  get: () =>
    confirmModalCharacterId.value ? activeDrawingContextMap[confirmModalCharacterId.value]?.prompt || '' : '',
  set: val => {
    if (confirmModalCharacterId.value) {
      if (!activeDrawingContextMap[confirmModalCharacterId.value]) {
        activeDrawingContextMap[confirmModalCharacterId.value] = {
          prompt: '',
          description: '',
          dimensions: 'portrait',
        };
      }
      activeDrawingContextMap[confirmModalCharacterId.value].prompt = val;
    }
  },
});
const confirmedDescription = computed(() => {
  return confirmModalCharacterId.value ? activeDrawingContextMap[confirmModalCharacterId.value]?.description || '' : '';
});
const confirmedDimensions = computed({
  get: () =>
    confirmModalCharacterId.value
      ? activeDrawingContextMap[confirmModalCharacterId.value]?.dimensions || 'portrait'
      : 'portrait',
  set: (val: 'portrait' | 'landscape' | 'square' | 'custom') => {
    if (confirmModalCharacterId.value) {
      if (!activeDrawingContextMap[confirmModalCharacterId.value]) {
        activeDrawingContextMap[confirmModalCharacterId.value] = {
          prompt: '',
          description: '',
          dimensions: 'portrait',
        };
      }
      activeDrawingContextMap[confirmModalCharacterId.value].dimensions = val;
      // ⚡️ 当用户在弹窗中点选或切换到“自定义尺寸”时，如果全局有配置自定义默认高宽，则将弹窗输入框默认值初始化为全局默认值
      if (val === 'custom') {
        customWidth.value = novelai.defaultWidth || 832;
        customHeight.value = novelai.defaultHeight || 1216;
      }
    }
  },
});

async function triggerChatImageGeneration() {
  if (!activeCharacter.value) return;
  if (!novelai.apiKey) {
    showCustomAlert('未配置绘图', '您尚未配置 NovelAI API Key，请前往「设置 - AI 绘图」进行配置。', 'info');
    return;
  }

  const charId = activeCharacter.value.id;
  const folderName = activeCharacter.value.folder_name;
  isAnalyzingPromptMap[charId] = true;

  try {
    const recentMsgs = (allMessages[charId] || []).slice(-20);
    showToast('AI 正在深度领悟上下文气氛中... 🔮');

    const res = await window.api.invoke('analyze-chat-image-prompt', {
      characterId: charId,
      folderName: folderName,
      recentMessages: JSON.parse(JSON.stringify(recentMsgs)),
    });

    if (res.success) {
      // 🚀 局部状态锁定：将当前角色分析出来的参数直接物理绑定，隔离全局
      activeDrawingContextMap[charId] = {
        prompt: res.prompt,
        description: res.description,
        dimensions: (novelai.defaultDimensions as any) || 'portrait',
      };

      // ⚡️ 若默认生图尺寸为自定义，则把 customWidth / customHeight 状态初始化为全局自定义默认高宽
      if (novelai.defaultDimensions === 'custom') {
        customWidth.value = novelai.defaultWidth || 832;
        customHeight.value = novelai.defaultHeight || 1216;
      }

      if (novelai.confirmMode) {
        confirmModalCharacterId.value = charId;
        showPromptConfirmModal.value = true;
      } else {
        await executeNovelAiImageGeneration(charId, folderName);
      }
    } else {
      showCustomAlert('分析场景失败', `${res.error || 'AI 分析上下文场景失败，请重试。'}`, 'error');
    }
  } catch (err: any) {
    showCustomAlert('分析场景异常', `${err.message || String(err)}`, 'error');
  } finally {
    isAnalyzingPromptMap[charId] = false;
  }
}

// 确认框中点击“确定绘制场景”时触发的物理锁定处理器，彻底摆脱全局 activeCharacter 漂移影响
async function handleConfirmModalImageGeneration() {
  const charId = confirmModalCharacterId.value;
  if (!charId) return;
  const char = characterList.value.find(c => c.id === charId);
  const folderName = char ? char.folder_name : '';
  if (!folderName) return;

  await executeNovelAiImageGeneration(charId, folderName);
}

async function executeNovelAiImageGeneration(targetCharId?: string, targetFolderName?: string) {
  // 🚀 核心去状态化传参机制：优先使用显式注入的角色 ID 与文件夹，从根本上解决异步生图时切换会话的串台问题！
  const charId = targetCharId || (activeCharacter.value ? activeCharacter.value.id : '');
  const folderName = targetFolderName || (activeCharacter.value ? activeCharacter.value.folder_name : '');
  if (!charId || !folderName) return;

  const context = activeDrawingContextMap[charId];
  if (!context) return;

  isDrawingImageMap[charId] = true;
  showPromptConfirmModal.value = false;

  showToast('AI 画笔绘制中，预计需要 3~8 秒... 🎨');

  try {
    const res = await window.api.invoke('generate-novelai-image', {
      characterId: charId,
      folderName: folderName,
      prompt: context.prompt,
      dimensions:
        context.dimensions === 'custom' ? { width: customWidth.value, height: customHeight.value } : context.dimensions,
      prefixType: 'drawing',
    });

    if (res.success) {
      showToast('画卷落笔成功！🎉');

      const imgMsgId = `chat_img_${charId}_${Date.now()}`;
      const imgTimestamp = Date.now();

      // 🚀 通过 MessageBusService 广播图片消息：
      // 1. 存入 DB
      // 2. Electron IPC echo:message 推送 → handleEchoMessage → restoreMessageProps 异步加载图片 base64
      // 3. SSE 广播 → 手机端实时同步
      // 这样图片气泡不会显示为空白气泡，刷新后也能正常显示。
      const saveRes = await window.api.invoke('save-message', {
        id: imgMsgId,
        character_id: charId,
        role: 'assistant',
        content: `[wechat_image_media]:${res.relativePath}`,
        timestamp: imgTimestamp,
        token_usage: 0,
        msg_type: 'image',
        broadcast: true, // 触发 MessageBusService 存盘 + 双路广播
      });

      if (!saveRes.success) {
        showCustomAlert('生图存盘失败', `${saveRes.error || '存入消息失败'}`, 'error');
      }
      // 不需要手动 push 到 allMessages：
      // echo:message 广播 → handleEchoMessage → restoreMessageProps 异步加载图片后自动渲染
    } else {
      showCustomAlert('生图失败', `${res.error || '绘图引擎出错了，请检查设置。'}`, 'error');
    }
  } catch (err: any) {
    showCustomAlert('生图异常', `${err.message || String(err)}`, 'error');
  } finally {
    isDrawingImageMap[charId] = false;
  }
}

function copyText(text: string) {
  if (!text) return;

  // 1. 优先尝试现代 clipboard API
  if (navigator.clipboard && navigator.clipboard.writeText) {
    navigator.clipboard
      .writeText(text)
      .then(() => {
        showToast('已成功复制到剪贴板！📋');
      })
      .catch(() => {
        // 降级到 execCommand 物理复制
        fallbackCopy(text);
      });
  } else {
    // 降级到 execCommand 物理复制
    fallbackCopy(text);
  }
}

// 物理降级复制辅助函数，无 Secure Context 限制，局域网全平台通用
function fallbackCopy(text: string) {
  try {
    const textarea = document.createElement('textarea');
    textarea.value = text;
    textarea.style.position = 'fixed';
    textarea.style.top = '-9999px';
    textarea.style.left = '-9999px';
    textarea.style.opacity = '0';
    document.body.appendChild(textarea);

    textarea.select();
    textarea.setSelectionRange(0, 99999); // 兼容 iOS 选区
    const success = document.execCommand('copy');
    document.body.removeChild(textarea);

    if (success) {
      showToast('已成功复制到剪贴板！📋');
    } else {
      showToast('复制失败，请手动长按选区复制 😢');
    }
  } catch (err) {
    console.error('[Fallback Copy Error] 复制异常:', err);
    showToast('复制失败，请手动长按选区复制 😢');
  }
}

