async function triggerImportPlaylist() {
  const link = importPlaylistLink.value.trim();
  if (!link) return;
  isImportingPlaylist.value = true;
  try {
    const res = await window.api.invoke('music-import-playlist', link);
    if (res.success) {
      const playlistId = musicStore.state.activePlaylistId;
      if (playlistId === 'love') {
        alert('请先在左侧选择或创建一个您的自建列表，不能直接导入到收藏夹中哦 🐾');
        return;
      }

      let importedCount = 0;
      for (const song of res.songs) {
        await musicStore.addSongToCustomPlaylist(playlistId, song);
        importedCount++;
      }

      await musicStore.loadPlaylistSongs(playlistId);
      alert(`成功解析歌单《${res.playlistName}》，已一键为您导入 ${importedCount} 首歌曲！🎉`);
      importPlaylistLink.value = '';
      showImportPlaylistModal.value = false;
    } else {
      alert(res.error || '歌单导入解析失败，请检查链接');
    }
  } catch (err) {
    console.error('导入歌单发生异常:', err);
  } finally {
    isImportingPlaylist.value = false;
  }
}

watch(
  () => musicStore.state.currentLyricIndex,
  newIdx => {
    if (newIdx >= 0 && lyricContainerRef.value) {
      nextTick(() => {
        const container = lyricContainerRef.value;
        if (container) {
          const activeEl = container.querySelector('.lyric-line-active') as HTMLElement;
          if (activeEl) {
            const containerHeight = container.clientHeight;
            const offsetTop = activeEl.offsetTop;
            const itemHeight = activeEl.clientHeight;
            container.scrollTo({
              top: offsetTop - containerHeight / 2 + itemHeight / 2,
              behavior: 'smooth',
            });
          }
        }
      });
    }
  },
);

// ===================== 生命周期 =====================
// 🚀 核心数据资产加载主函数（唯独在同意用户协议后，才允许被执行载入挂载，实行物理阻断）
async function initializeCoreApp() {
  fetchStatePresets();
  // 提前加载通用常规设置，以获取音乐模块的启用状态
  try {
    const genRes = await window.api.invoke('get-general-settings');
    if (genRes.success && genRes.config) {
      generalConfig.value = genRes.config;
      if (generalConfig.value.enable_music === undefined) {
        generalConfig.value.enable_music = false;
      }
      if (generalConfig.value.lan_mapping_enabled === undefined) {
        generalConfig.value.lan_mapping_enabled = false;
      }
      if (generalConfig.value.lan_mapping_port === undefined) {
        generalConfig.value.lan_mapping_port = 6868;
      }
      if (generalConfig.value.enable_token_stats === undefined) {
        generalConfig.value.enable_token_stats = true;
      }
      if (generalConfig.value.enable_nsfw === undefined) {
        generalConfig.value.enable_nsfw = false;
      }
      if (generalConfig.value.descriptive_min_words === undefined) {
        generalConfig.value.descriptive_min_words = 500;
      }
      if (generalConfig.value.director_min_words === undefined) {
        generalConfig.value.director_min_words = 800;
      }
    }
  } catch (e) {
    console.error('加载通用设置异常:', e);
  }

  // 仅在开启了音乐功能时，才执行音乐相关初始化操作
  if (generalConfig.value.enable_music) {
    // 同步桌面歌词自定义底色和文字颜色
    try {
      await window.api.invoke('lyric-window-update-theme', {
        bgColor: lyricBgColor.value,
        textColor: lyricTextColor.value,
      });
    } catch (_) {}

    // 同步加载所有导入的自定义音源到主进程沙箱中
    await syncCustomSources();

    // 加载音乐模块数据
    loadRecommendPlaylists();
    loadLeaderboardList(activeBangId.value);
  }

  // 加载社媒朋友圈与论坛列表
  loadMomentsList();
  loadForumPostsList();

  // 加载用户个人信息并通过 IPC 向主进程同步画像权威数据
  loadUserProfileLocal();
  window.api.invoke('get-user-profile').then((pRes: any) => {
    if (pRes.success && pRes.profile) {
      Object.assign(userProfile, pRes.profile);
      saveUserProfileLocal(false); // 仅更新本地，防循环写入
    }
    fetchRealtimeWeather();
    // 异步加载大模型自省解析的 USER.md 以保持姓名覆盖和预检
    window.api.invoke('read-global-user-md').then((res: any) => {
      if (res.success) {
        globalUserMdContent.value = res.content;
        if (res.nickname !== undefined && res.nickname.trim() !== '') {
          userProfile.nickname = res.nickname;
          saveUserProfileLocal(true); // 姓名权威解析可以物理回写同步
        }
      }
    });
  });

  // 加载自定义表情
  try {
    const stored = localStorage.getItem('echo_custom_emojis');
    if (stored) {
      customEmojiList.value = JSON.parse(stored);
    }
  } catch (_) {}
  window.api.invoke('get-custom-emojis').then((eRes: any) => {
    if (eRes.success && eRes.emojis) {
      customEmojiList.value = eRes.emojis;
      saveCustomEmojis(false); // 仅更新本地，防循环写入
    }
  });

  // 加载角色列表
  await loadCharacters();

  // 加载大模型配置
  try {
    const result = await window.api.invoke('get-settings');
    if (result?.success && result.config) {
      const {
        primaryConfigs: savedPrimaryConfigs,
        secondaryConfigs: savedSecondaryConfigs,
        primaryProvider,
        secondaryProvider,
        enableSecondary: savedEnableSecondary,
        globalPrompt: savedGlobalPrompt,
      } = result.config;

      // 1. 恢复各大渠道独立配置库
      if (savedPrimaryConfigs) {
        Object.assign(primaryConfigs, savedPrimaryConfigs);
      }
      if (savedSecondaryConfigs) {
        Object.assign(secondaryConfigs, savedSecondaryConfigs);
      }

      // 2. 恢复启用的渠道类型
      const activePrimaryProvider = primaryProvider || 'openai';
      const activeSecondaryProvider = secondaryProvider || 'openai';

      primary.provider = activePrimaryProvider;
      secondary.provider = activeSecondaryProvider;
      lastPrimaryProvider.value = activePrimaryProvider;
      lastSecondaryProvider.value = activeSecondaryProvider;

      // 3. 将对应渠道的具体内容覆写到当前主/副模型配置
      const activePrimary = primaryConfigs[activePrimaryProvider];
      if (activePrimary) {
        Object.assign(primary, activePrimary);
        primary.provider = activePrimaryProvider;
      }

      const activeSecondary = secondaryConfigs[activeSecondaryProvider];
      if (activeSecondary) {
        Object.assign(secondary, activeSecondary);
        secondary.provider = activeSecondaryProvider;
      }

      enableSecondary.value = !!savedEnableSecondary;
      // 注意：chatMode 已改为角色专属，在 selectCharacter 时从 DB 读取，不在全局设置中保存/恢复
      if (savedGlobalPrompt !== undefined) globalPrompt.value = savedGlobalPrompt;

      console.log('[App] 大模型配置恢复完成，当前提供商:', primary.provider);
    } else {
      lastPrimaryProvider.value = primary.provider;
      lastSecondaryProvider.value = secondary.provider;
    }
  } catch (error) {
    console.error('加载大模型设置异常:', error);
  }

  // 加载 NovelAI 绘图配置
  try {
    const naiRes = await window.api.invoke('get-novelai-config');
    if (naiRes.success && naiRes.config) {
      Object.assign(novelai, naiRes.config);

      // ⚡️ 老配置迁移自愈：如果 artistStringList 为空或不是数组，将其自愈为含有一个对象的数组
      if (!Array.isArray(novelai.artistStringList) || novelai.artistStringList.length === 0) {
        novelai.artistStringList = [{ name: '', value: novelai.artistString || '' }];
      } else {
        // 如果是老版本里保存的旧字符串数组，自愈转换为对象数组
        novelai.artistStringList = novelai.artistStringList.map((item: any) => {
          if (typeof item === 'string') {
            return { name: '', value: item };
          }
          return { name: item.name || '', value: item.value || '' };
        });
      }

      // 📌 锁定指针自愈防空与防越界
      novelai.fixedArtistIndex = typeof novelai.fixedArtistIndex === 'number' ? novelai.fixedArtistIndex : 0;
      if (novelai.fixedArtistIndex >= novelai.artistStringList.length || novelai.fixedArtistIndex < 0) {
        novelai.fixedArtistIndex = 0;
      }

      // ⚡️ 初始化自定义高宽输入框初始值，同步使用全局配置中的默认尺寸
      customWidth.value = novelai.defaultWidth || 832;
      customHeight.value = novelai.defaultHeight || 1216;
    }
  } catch (e) {
    console.error('加载 NovelAI 配置异常:', e);
  }

  // 加载自主生命配置
  await loadProactiveConfig();
}

// 🚀 用户协议 15 秒倒计时启动器
function startAgreementCountdown() {
  if (agreementTimer) {
    clearInterval(agreementTimer);
  }
  agreementCountdown.value = 15;
  agreementTimer = setInterval(() => {
    if (agreementCountdown.value > 0) {
      agreementCountdown.value--;
    } else {
      clearInterval(agreementTimer);
      agreementTimer = null;
    }
  }, 1000);
}

// 🚀 同意用户协议存盘并解锁加载
async function acceptAgreement() {
  try {
    const res = await window.api.invoke('save-agreement-status');
    if (res.success) {
      showAgreementModal.value = false;
      hasAcceptedAgreement.value = true;
      // 🚀 正式解除阻断，加载大模型、角色卡等全部资产
      await initializeCoreApp();
    } else {
      showToast('保存协议同意状态失败，请稍后重试 🐾');
    }
  } catch (e: any) {
    showToast(`同意协议发生异常: ${e.message || e}`);
  }
}

// 🚀 不同意用户协议物理彻底关闭程序进程
function rejectAgreement() {
  window.api.invoke('exit-app');
}

// 🚀 全局网页文字字号大小调节支持
const globalFontSize = ref(16);

function initFontSize() {
  const saved = localStorage.getItem('user_font_size');
  if (saved) {
    const size = parseInt(saved, 10);
    if (!isNaN(size) && size >= 10 && size <= 32) {
      globalFontSize.value = size;
    }
  }
  applyFontSize();
}

function applyFontSize() {
  document.documentElement.style.setProperty('--global-font-size', `${globalFontSize.value}px`);
}

function changeFontSize(delta: number) {
  const newSize = globalFontSize.value + delta;
  if (newSize >= 10 && newSize <= 32) {
    globalFontSize.value = newSize;
    localStorage.setItem('user_font_size', newSize.toString());
    applyFontSize();
  }
}

function resetFontSize() {
  globalFontSize.value = 16;
  localStorage.removeItem('user_font_size');
  applyFontSize();
}

// ===================== 生命周期 =====================
onMounted(async () => {
  // 初始化全局网页字体大小
  initFontSize();

  // 获取实际应用版本号
  try {
    const version = await window.api.invoke('get-app-version');
    if (version && typeof version === 'string') {
      appVersion.value = version;
    }
  } catch (err) {
    console.error('获取应用版本号失败:', err);
  }

  // 检查小说可用状态
  await checkGlobalNovelStatus();

  // ══════════════════════════════════════════════════════════
  // 初始化 MessageQueueManager（新一代消息接收核心）
  // 统一接管 echo:message（来自 Electron IPC）和 SSE 的 echo:message
  // 实现精确一次去重 + 有序分发
  // ══════════════════════════════════════════════════════════
  MessageQueueManager.getInstance().init({
    // echo:message 处理：转发给原有的 receive-message 处理函数
    onMessage: (msg: EchoMessage) => {
      // 将 EchoMessage 转换为 receive-message 原有 msg 格式，复用现有处理逻辑
      // 此处直接触发原有 receive-message 处理函数的主体逻辑（通过合成事件）
      handleEchoMessage(msg);
    },
    // echo:unread-update 处理：直接更新前端 conversationMeta
    onUnreadUpdate: (characterId: string, unread: number) => {
      if (!conversationMeta[characterId]) {
        conversationMeta[characterId] = { pinned: false, unread: 0, muted: false, hidden: false };
      }
      // 如果用户正在查看该会话，维持未读=0，不展示红点
      if (selectedCharacterId.value === characterId && isChattingActive.value) {
        conversationMeta[characterId].unread = 0;
      } else {
        // 数据库端权威值：直接覆盖（不累加）
        conversationMeta[characterId].unread = unread;
      }
    },
  });

  // 微信个人号状态自愈与登录事件广播接入
  if (window.api && window.api.receive) {
    window.api.receive('wechat-status-updated', (status: any) => {
      wechatState.value = status;
    });
    window.api.receive('wechat-login-confirmed', (status: any) => {
      wechatState.value = status;
      showCustomAlert('绑定成功', '您的微信个人号已成功安全托管并上线就绪！🐾', 'success');
    });
    // AI小说写手广播事件监听
    window.api.receive(
      'novel-chapter-added',
      (data: { characterId: string; novelId: string; chapterId: string; chapterIndex: number; title: string }) => {
        checkGlobalNovelStatus();
        if (selectedCharacterId.value === data.characterId) {
          loadNovelChapters(data.characterId);
        }
        if (!novelNewChapterBadges[data.novelId]) {
          novelNewChapterBadges[data.novelId] = 0;
        }
        novelNewChapterBadges[data.novelId]++;

        // 热刷新书架与当前阅读的书籍目录
        if (sideView.value === 'bookshelf') {
          loadBookshelf();
          if (selectedBookId.value === data.novelId) {
            // 静默重新加载目录，不打扰阅读
            window.api.invoke('novel-get-chapters', { novelId: data.novelId }).then((res: any) => {
              if (res.success && res.chapters) {
                bookChapters.value = res.chapters;
              }
            });
          }
        }
        fetchNovelProgress(data.characterId);
      },
    );
    window.api.receive(
      'novel-chapter-rewritten',
      (data: { characterId: string; novelId: string; chapterId: string }) => {
        if (selectedCharacterId.value === data.characterId) {
          loadNovelChapters(data.characterId);
        }
        // 热刷新当前重写后章节的内容
        if (selectedBookId.value === data.novelId) {
          window.api.invoke('novel-get-chapters', { novelId: data.novelId }).then((res: any) => {
            if (res.success && res.chapters) {
              bookChapters.value = res.chapters;
              if (selectedBookChapterId.value) {
                loadChapterContent(selectedBookChapterId.value);
              }
            }
          });
        }
        fetchNovelProgress(data.characterId);
      },
    );
    // 续写任务完成/失败的通知
    window.api.receive('novel-continue-done', (data: { characterId: string; success: boolean; error?: string }) => {
      if (data.characterId) {
        novelContinuingMap.value[data.characterId] = false;
      }
      if (data.success) {
        if (selectedCharacterId.value === data.characterId) {
          loadNovelChapters(data.characterId);
        }
        // novel-chapter-added 事件会在同一次任务中触发，不再重复弹窗
      } else {
        showCustomAlert('续写失败', data.error || '后台续写任务失败，请检查模型设置。', 'error');
      }
    });
    // 监听后台小说生成状态变更广播，秒级联动按钮禁用状态与进度条
    window.api.receive('novel-generation-state-changed', (data: { characterId: string; generating: boolean }) => {
      if (data.characterId) {
        novelContinuingMap.value[data.characterId] = data.generating;
        fetchNovelProgress(data.characterId);
      }
    });
    // 监听后台已读状态变更广播，多窗口秒级同步小红点状态
    window.api.receive(
      'novel-unread-count-changed',
      (data: { characterId: string; novelId?: string; unreadCount: number }) => {
        if (data.characterId) {
          novelNewChapterBadges[data.characterId] = data.unreadCount;
        }
        if (data.novelId) {
          novelNewChapterBadges[data.novelId] = data.unreadCount;
        }
      },
    );
    // 监听后台书架被修改广播（如删除小说），热刷新书架列表
    window.api.receive('novel-bookshelf-updated', () => {
      loadBookshelf();
    });
  }
  fetchWeChatStatus();
  loadNovelStyles();
  loadBookshelf(); // 启动时立即拉取书架以显示最新的小说红点角标
  loadUserProfilesList(); // 🚀 启动时立即拉取所有用户人设列表，供聊天界面渲染人设与头像

  // 🚀 手机端输入法物理折叠状态高度精密监测与 Done 自愈解锁防线
  if (window.visualViewport) {
    let baseHeight = window.visualViewport.height;
    let keyboardHasOpened = false; // 🚀 状态机核心：键盘成功弹起的物理标记，阻断弹起瞬时过渡态误杀

    // 监听窗口尺寸变化，动态修正基准视口高度（优雅适配手机横竖屏切换）
    window.addEventListener('resize', () => {
      if (!isInputFocused.value && window.visualViewport) {
        baseHeight = window.visualViewport.height;
      }
    });

    window.visualViewport.addEventListener('resize', () => {
      if (!isMobile.value || !window.visualViewport) return;

      const currentHeight = window.visualViewport.height;
      // 🚀 键盘收起判定：只有当键盘曾成功弹起过（keyboardHasOpened 为 true），且当前可视区域高度恢复到基准高度 80px 以内时，才认定为真正的收起！
      if (currentHeight >= baseHeight - 80) {
        if (keyboardHasOpened) {
          keyboardHasOpened = false;
          isInputFocused.value = false;
          // 🚀 核心自愈：主动让输入框失焦，完美干掉 iOS 点击 Done/完成 键盘收起后输入框光标残留与不触发 blur 的 Bug！
          if (
            document.activeElement &&
            (document.activeElement === chatTextarea.value || document.activeElement.tagName === 'TEXTAREA')
          ) {
            (document.activeElement as HTMLElement)?.blur();
          }

          // 键盘收起后立即恢复根容器高度（isInputFocused 已置为 false，updateViewportHeight 会正常执行）
          updateViewportHeight();

          // 🚀 黄金微操：手机键盘彻底折叠收起后，立即触发平滑向下滚动到底部，消息气泡像流水般优美沉底，绝不留出大片空白！
          nextTick(() => {
            scrollToBottom('smooth', true);
            // 多重防抖延迟：iOS/Android 系统级软键盘折叠可能有物理动画过渡，额外加上微小延迟强力锚定触底
            setTimeout(() => scrollToBottom('smooth', true), 80);
            setTimeout(() => scrollToBottom('smooth', true), 220);
          });
        }
      } else if (currentHeight < baseHeight - 120) {
        // 🚀 键盘弹起判定：可视高度比基准骤降 120px 以上，说明软件盘已真实弹起！
        keyboardHasOpened = true;
        isInputFocused.value = true;

        // 🚀 黄金微操：软键盘成功弹出、视口高度骤缩的瞬间，立即强力瞬间将消息气泡推向最底部，最后一条消息绝不被键盘遮挡！
        nextTick(() => {
          scrollToBottom('auto', true);
          // 物理动画过渡期多重延迟兜底
          setTimeout(() => scrollToBottom('auto', true), 60);
          setTimeout(() => scrollToBottom('auto', true), 150);
        });
      }
    });
  }

  // 注册客户端版本更新通知监听
  if (window.electron && window.electron.ipcRenderer) {
    unlistenUpdateStatus = window.electron.ipcRenderer.on('update-check-status', handleUpdateCheckStatus);
    unlistenDownloadProgress = window.electron.ipcRenderer.on('update-download-progress', handleUpdateDownloadProgress);
    unlistenDownloadStatus = window.electron.ipcRenderer.on('update-download-status', handleUpdateDownloadStatus);
  } else if (window.api && window.api.receive) {
    const r1 = window.api.receive('update-check-status', handleUpdateCheckStatus);
    unlistenUpdateStatus = typeof r1 === 'function' ? (r1 as any) : null;
    const r2 = window.api.receive('update-download-progress', handleUpdateDownloadProgress);
    unlistenDownloadProgress = typeof r2 === 'function' ? (r2 as any) : null;
    const r3 = window.api.receive('update-download-status', handleUpdateDownloadStatus);
    unlistenDownloadStatus = typeof r3 === 'function' ? (r3 as any) : null;
  }

  checkIfMobile();
  window.addEventListener('resize', checkIfMobile);

  if (window.visualViewport) {
    window.visualViewport.addEventListener('resize', updateViewportHeight);
    window.visualViewport.addEventListener('scroll', updateViewportHeight);
    updateViewportHeight();
  }

  // 加载主题
  const savedTheme = localStorage.getItem('echo_theme');
  if (savedTheme === 'dark') {
    isDark.value = true;
    document.documentElement.classList.add('dark');
  } else {
    document.documentElement.classList.remove('dark');
  }

  // 🚀 最前置的物理级用户协议拦截锁
  try {
    const agreeRes = await window.api.invoke('get-agreement-status');
    isAgreementChecking.value = false;
    if (agreeRes.success && agreeRes.accepted) {
      hasAcceptedAgreement.value = true;
      // 已同意协议，顺畅载入大模型与角色列表
      await initializeCoreApp();
    } else {
      // 未同意协议，强行激活磨砂弹窗与 15 秒强制倒计时
      hasAcceptedAgreement.value = false;
      showAgreementModal.value = true;
      isAgreementViewMode.value = false;
      startAgreementCountdown();
    }
  } catch (e) {
    console.error('[Agreement Gate] 获取协议同意状态发生异常:', e);
    isAgreementChecking.value = false;
    hasAcceptedAgreement.value = true;
    await initializeCoreApp();
  }

  // 监听局域网多端同步角色设定（性格/世界观）更新广播
  window.api.receive('character-settings-updated', (data: { folderName: string; soul?: string; world?: string }) => {
    console.log('[Sync Gate] 收到角色人设/世界观更新广播，执行多端数据同步自愈:', data.folderName);
    // 重新拉取角色列表以刷新所有缓存及左侧状态
    loadCharacters();

    // 如果当前打开的就是该被修改的角色，且正在右侧面板/大脑面板里查看其设定，静默重新读取其内容以刷新当前视图
    if (
      activeCharacter.value &&
      (activeCharacter.value.folder_name || '').toLowerCase() === data.folderName.toLowerCase()
    ) {
      if (showBrainPanel.value) {
        openBrainPanel(); // 自动重拉并渲染最新人设
      }
    }
  });

  // 监听局域网多端同步角色文件（如 Memory.md/Appearance.md）更新广播
  window.api.receive('character-file-updated', (data: { folderName: string; fileName: string; content: string }) => {
    console.log(`[Sync Gate] 收到角色文件 [${data.fileName}] 物理更新广播，触发局域网数据自愈:`, data.folderName);
    // 如果当前打开的就是该被修改的角色
    if (
      activeCharacter.value &&
      (activeCharacter.value.folder_name || '').toLowerCase() === data.folderName.toLowerCase()
    ) {
      if (data.fileName === 'Memory.md') {
        // 如果当前大脑面板开着，重新读取长期记忆以更新视图
        if (showBrainPanel.value) {
          openBrainPanel();
        }
      } else if (data.fileName === 'Appearance.md') {
        // 如果当前正好在绘图设置 Tab 中，静默刷新外貌提示词文本框
        if (showSettingsModal.value && activeSettingsTab.value === 'drawing') {
          window.api.invoke('read-appearance-file', { folderName: data.folderName }).then(res => {
            if (res.success && res.content) {
              contactAppearanceContent.value = res.content;
            }
          });
        }
      }
    }
  });

  // 监听后台自省与用户手动修改状态增量更新广播
  window.api.receive('character-state-updated', (data: { characterId: string; updates: any[] }) => {
    if (activeCharacter.value) {
      const activeFolder = (activeCharacter.value.folder_name || '').toLowerCase();
      const activeId = (activeCharacter.value.id || '').toLowerCase();
      const targetId = (data.characterId || '').toLowerCase();
      if (activeFolder === targetId || activeId === targetId) {
        fetchActiveCharacterStates();
      }
    }
  });

  // 🚀 监听群聊变更广播，打通多端群聊增删改同步机制
  window.api.receive('group-chat-created', async (data: { groupId: string; name: string; memberIds: string[] }) => {
    console.log('[IPC] ➜ 收到创建群聊广播通知，正在刷新角色与群聊列表...', data);
    await loadCharacters();
  });

  window.api.receive('group-chat-updated', async (data: { groupId: string; name: string }) => {
    console.log('[IPC] ➜ 收到群名更新广播通知，正在刷新角色与群聊列表...', data);
    await loadCharacters();
  });

  window.api.receive('group-chat-deleted', async (data: { groupId: string }) => {
    console.log('[IPC] ➜ 收到删除群聊广播通知，正在刷新列表并检查当前选中状态...', data);
    if (selectedCharacterId.value === data.groupId) {
      selectedCharacterId.value = null;
      activeView.value = 'chat';
    }
    await loadCharacters();
  });

  // 🚀 监听创角 Bot 过程消息广播，打通多端同步对话
  window.api.receive('creator-bot-message', (data: { characterId: string; message: any }) => {
    const charId = data.characterId;
    if (!allMessages[charId]) allMessages[charId] = [];
    const msgs = allMessages[charId];

    // 防重复检查与推入
    const cleanContent = data.message.content.trim();
    const exists = msgs.some(m => m.role === data.message.role && m.content.trim() === cleanContent);
    if (!exists) {
      msgs.push({
        ...data.message,
        timestamp: data.message.timestamp || Date.now(),
      });
      nextTick(() => scrollToBottom());
    }
  });

  // 🚀 监听角色导入/诞生成功广播，刷新多端角色列表以同步呈现新生命
  window.api.receive('character-imported', async (data: any) => {
    console.log('[IPC] ➜ 收到新角色导入/创建成功广播通知，正在刷新角色列表...', data);
    await loadCharacters();
  });

  // 监听角色专属聊天模式变更广播（多端同步）
  // 核心隔离约束：只有当 characterId 与当前打开的角色完全一致时，才更新 chatMode.value，
  // 其他角色的模式变更广播会被完全忽略，确保互不影响
  window.api.receive('character-chat-mode-changed', (data: { characterId: string; mode: string }) => {
    // 所有角色的 mode 变更都写入缓存（多端同步）
    // 写入 characterChatModeCache（reactive），currentChatMode computed 自动响应，UI 即时刷新
    characterChatModeCache[data.characterId] = data.mode as 'dialogue' | 'descriptive' | 'director';
  });

  // 监听角色专属用户人设绑定变更广播（多端同步）
  window.api.receive('profile-binding-changed', (data: { targetId: string; profileId: string | null }) => {
    if (selectedCharacterId.value === data.targetId) {
      selectedContactBindingProfileId.value = data.profileId || '';
      currentChatBindingProfileId.value = data.profileId || ''; // 🚀 即时同步更新当前聊天界面绑定的用户人设 ID
      if (data.profileId) {
        hasConfiguredFirstChatMap.value[data.targetId] = true;
        showFirstChatConfigModal.value = false;
      } else {
        hasConfiguredFirstChatMap.value[data.targetId] = false;
      }
    }
  });

  // 监听小说写手设置变更广播（多设备同步）
  window.api.receive('novel-settings-changed', (data: { characterId: string; enabled: boolean }) => {
    if (selectedCharacterId.value === data.characterId) {
      novelEnabled.value = data.enabled;
    }
  });

  // 🚀 核心修复：监听局域网与物理删除广播，打通多端秒级删除自愈同步机制，根治电脑缓存残留 Bug
  window.api.receive('message-deleted', (data: { characterId: string; messageId: string }) => {
    const msgs = allMessages[data.characterId];
    if (msgs) {
      const idx = msgs.findIndex(m => m.id === data.messageId);
      if (idx !== -1) {
        msgs.splice(idx, 1);
      }
    }
  });

  // 监听多端/局域网消息内容修改广播
  window.api.receive('message-content-edited', (data: { characterId: string; messageId: string; content: string }) => {
    const msgs = allMessages[data.characterId];
    if (msgs) {
      const target = msgs.find(m => m.id === data.messageId);
      if (target) {
        target.content = data.content;
        // 🚀 重新解析状态，更新红包、表情包等附加渲染属性，保障界面响应式更新！
        if (data.content.startsWith('[wechat_red_packet]:')) {
          try {
            const jsonStr = data.content.replace('[wechat_red_packet]:', '');
            target.redPacket = JSON.parse(jsonStr);
          } catch (_) {}
        } else if (data.content.startsWith('[wechat_custom_emoji]:')) {
          try {
            const jsonStr = data.content.replace('[wechat_custom_emoji]:', '');
            const emoji = JSON.parse(jsonStr);
            target.customEmojiUrl = emoji.base64;
          } catch (_) {}
        }
      }
    }
  });

  window.api.receive('chat-window-cleared', (data: { characterId: string }) => {
    allMessages[data.characterId] = [];
  });

  window.api.receive('history-memory-cleared', (data: { characterId: string }) => {
    allMessages[data.characterId] = [];
    if (activeCharacter.value && activeCharacter.value.id === data.characterId && showBrainPanel.value) {
      openBrainPanel();
