  window.api.receive('custom-emojis-updated', (emojis: any[]) => {
    if (emojis) {
      customEmojiList.value = emojis;
      saveCustomEmojis(false); // 仅写入本地，防止循环广播
    }
  });

  // 监听流式 chunk
  window.api.receive(
    'chat-chunk',
    (data: { characterId: string; content: string; done: boolean; isSystem?: boolean }) => {
      // 🚀 $admin 系统提示快速通道：在所有流式逻辑之前优先处理，无视 done 状态
      if (data.isSystem) {
        const sysCharId = data.characterId;
        if (!sysCharId) return; // 物理隔离：无明确 characterId 的系统提示不予分发，防止串窗口显示
        if (!allMessages[sysCharId]) allMessages[sysCharId] = [];

        // 防止同一条系统提示被重复 push (例如 electron 本地和广播通道重复触发)
        const isDuplicate = allMessages[sysCharId].some(m => m.isSystem && m.content === data.content);
        if (!isDuplicate) {
          allMessages[sysCharId].push({ role: 'system', content: data.content, isSystem: true });
        }

        if (sysCharId === selectedCharacterId.value) {
          nextTick(() => scrollToBottom());
        }
        return;
      }

      const chunkCharId = data.characterId || streamingCharacterId.value || selectedCharacterId.value || '';

      // 🚀 核心修复：创角 Bot 专属快速处理通道，不参与下面的单聊过滤与群聊流式追加，从源头避免被误伤过滤
      if (chunkCharId === creatorBotId) {
        if (data.content && data.content.includes('[SUCCESS_CREATION_JUMP]:')) {
          const parts = data.content.split('[SUCCESS_CREATION_JUMP]:');
          const folderName = parts[1].trim();

          // 立即重置流式标志，确保新创建出来的角色对话框发送按钮立即可用，避免卡死
          streamingCharsSet.delete(chunkCharId);
          streamingCharacterId.value = null;

          // 延迟 3.5 秒跳转，让用户看清成功提示
          setTimeout(async () => {
            // 从左侧列表中移除临时虚拟创角 Bot
            characterList.value = characterList.value.filter(c => c.id !== creatorBotId);
            delete allMessages[creatorBotId];

            // 重新加载正式角色列表并选中跳转到新鲜出炉的角色
            await loadCharacters();
            selectCharacter(folderName);
          }, 3500);

          return;
        }

        // 接收创角普通问答气泡或系统异常报错气泡，去重推入
        if (data.content && data.content.trim()) {
          if (!allMessages[creatorBotId]) allMessages[creatorBotId] = [];
          const msgs = allMessages[creatorBotId];

          const cleanInputContent = data.content.trim();
          const exists = msgs.some(m => m.role === 'assistant' && m.content.trim() === cleanInputContent);
          if (!exists) {
            msgs.push({
              role: 'assistant',
              content: data.content,
              timestamp: Date.now(),
            });
            nextTick(() => scrollToBottom());
          }
        }

        if (data.done) {
          // 创角 Bot 的流程 done 时清除流式等待标志，避免按钮与输入框卡死，使用户可以重新尝试或继续步骤
          streamingCharsSet.delete(chunkCharId);
          if (streamingCharacterId.value === chunkCharId) {
            streamingCharacterId.value = null;
          }
        }
        return;
      }

      // 🚀 只要流式吐字或处于流式交互中，就重置/清除超时定时器，只在真正停滞 10分钟 以上时才超时自愈
      if (data.done) {
        clearReplyTimeout();
      } else {
        // 🚀 彻底去流式：如果是单聊（包括创角 Bot），直接屏蔽 done 为 false 的所有流式碎片，不进行追加渲染，瞬间回执
        const isGroup = groupChats.value.some(g => g.id === chunkCharId);
        if (!isGroup) {
          // 🚀 单聊流式期间也有有效吐字，刷新超时定时器，防范超长回复误判超时
          if (data.content) {
            startReplyTimeout(chunkCharId);
          }
          return;
        }
        if (data.content) {
          startReplyTimeout(chunkCharId);
        }
      }

      if (data.content && data.content.includes('[SUCCESS_CREATION_JUMP]:')) {
        const parts = data.content.split('[SUCCESS_CREATION_JUMP]:');
        const folderName = parts[1].trim();

        // 立即重置流式标志，确保新创建出来的角色对话框发送按钮立即可用，避免卡死
        streamingCharsSet.delete(chunkCharId);
        streamingCharacterId.value = null;

        // 延迟 3.5 秒跳转，让用户看清成功提示
        setTimeout(async () => {
          // 从左侧列表中移除临时虚拟创角 Bot
          characterList.value = characterList.value.filter(c => c.id !== creatorBotId);
          delete allMessages[creatorBotId];

          // 重新加载正式角色列表并选中跳转到新鲜出炉的角色
          await loadCharacters();
          selectCharacter(folderName);
        }, 3500);

        return;
      }

      if (data.done) {
        // 创角 Bot 的流程 done 时清除流式等待标志，避免按钮卡死锁死
        if (chunkCharId === creatorBotId) {
          streamingCharsSet.delete(chunkCharId);
          if (streamingCharacterId.value === chunkCharId) {
            streamingCharacterId.value = null;
          }
        }
        return;
      }

      // 🚀 响应取消流式诉求：如果当前不是群聊，或者处于纯文字对话（dialogue）模式，直接拦截并静默丢弃流式消息（含创角 Bot 文本），全部交由 Promise 决议和广播接管，从根本上消灭重复气泡！
      // 🔒 修复：使用消息归属角色（chunkCharId）的真实 chatMode，而非当前 UI 选中角色的 chatMode
      const isGroupChat = groupChats.value.some(g => g.id === chunkCharId);
      const chunkCharModeForStream = characterChatModeCache[chunkCharId] ?? 'descriptive';
      if (!isGroupChat || chunkCharModeForStream === 'dialogue') {
        return;
      }

      const cleanContent = scrubber.scrub(data.content);
      if (cleanContent) {
        conversationActiveTimes[chunkCharId] = Date.now();
        const msgs = allMessages[chunkCharId];

        // ===================== 群聊模式流式文本追加 =====================
        const isGroupChat = groupChats.value.some(g => g.id === chunkCharId);
        const senderId = (data as any).senderId;
        if (isGroupChat && senderId) {
          if (msgs) {
            if (
              msgs.length === 0 ||
              msgs[msgs.length - 1].role !== 'assistant' ||
              msgs[msgs.length - 1].sender_id !== senderId
            ) {
              msgs.push({
                role: 'assistant',
                sender_id: senderId,
                content: '',
                created_at: new Date().toISOString(),
                timestamp: Date.now(),
              });
              if (chunkCharId === selectedCharacterId.value) {
                nextTick(() => scrollToBottom());
              }
            }

            const last = msgs[msgs.length - 1];
            if (last.role === 'assistant' && last.sender_id === senderId) {
              last.content += cleanContent;
              if (chunkCharId === selectedCharacterId.value) {
                nextTick(() => scrollToBottom());
              }
            }
          }
          return;
        }

        // 确保消息列表末尾有 assistant 气泡容器，Creator Bot 流式推送时不会预先 push 空气泡
        // 若最后一条不是 assistant，则自动插入一条，供 startTypingEffect 逐字追加
        if (msgs && (msgs.length === 0 || msgs[msgs.length - 1].role !== 'assistant')) {
          msgs.push({ role: 'assistant', content: '', created_at: new Date().toISOString() });
          if (chunkCharId === selectedCharacterId.value) {
            nextTick(() => scrollToBottom());
          }
        }

        if (chunkCharId === selectedCharacterId.value) {
          pushToTypingQueue(cleanContent);
        } else {
          // 如果是后台角色，直接将内容追加到最后一条 assistant 消息的 content 中，不做打字动画，避免污染全局 typingQueue
          if (msgs && msgs.length > 0) {
            const last = msgs[msgs.length - 1];
            if (last.role === 'assistant') {
              last.content += cleanContent;
            }
          }
        }
      }
    },
  );

  // 监听朋友圈动态和论坛帖子的后台实时更新以点亮 Badge 气泡
  window.api.receive('social-moment-updated', () => {
    if (sideView.value !== 'moments') {
      unreadMomentsCount.value += 1;
    }
  });

  window.api.receive('social-forum-updated', () => {
    if (sideView.value !== 'forum') {
      unreadForumCount.value += 1;
    }
  });

  // 监听 sideView 的变化，切入时实时清空未读数并自动拉取对应数据
  watch(sideView, async newVal => {
    if (newVal === 'moments') {
      unreadMomentsCount.value = 0;
      hasNewMomentNotification.value = false;
      await loadMomentsList();
    } else if (newVal === 'forum') {
      unreadForumCount.value = 0;
      unreadForumPostIds.value = [];
      await selectBoard('all');
    } else if (newVal === 'favorites') {
      await loadFavoritesList();
    } else if (newVal === 'chat') {
      // 切回会话页时，强制将消息滚到底部（force=true 跳过防抖，确保不被"用户在上方阅读"条件拦截）
      if (selectedCharacterId.value) {
        nextTick(() => {
          scrollToBottom('auto', true);
          // DOM 渲染可能有延迟，增加 150ms 和 400ms 双重保险
          setTimeout(() => scrollToBottom('auto', true), 150);
          setTimeout(() => scrollToBottom('auto', true), 400);
        });
      }
    }
  });

  // 监听多端会话元数据（置顶/免打扰/已读未读状态）变更广播，实现多端强同步
  window.api.receive(
    'conversation-meta-updated',
    (data: { characterId: string; pinned?: boolean; unread?: number; muted?: boolean; hidden?: boolean }) => {
      const { characterId, pinned, unread, muted, hidden } = data;
      if (!characterId) return;

      // 如果本地不存在此元数据，则进行初始化
      if (!conversationMeta[characterId]) {
        conversationMeta[characterId] = { pinned: false, unread: 0, muted: false, hidden: false };
      }

      // 同步基础元数据属性
      if (pinned !== undefined) conversationMeta[characterId].pinned = pinned;
      if (muted !== undefined) conversationMeta[characterId].muted = muted;
      if (hidden !== undefined) conversationMeta[characterId].hidden = hidden;

      // 竞态自愈正反馈逻辑：同步已读未读状态
      if (unread !== undefined) {
        if (selectedCharacterId.value === characterId && isChattingActive.value) {
          conversationMeta[characterId].unread = 0;
        } else {
          // 非活跃页面，直接同步接收到的未读数
          conversationMeta[characterId].unread = unread;
        }
      }
    },
  );

  // 注意：proactive-chat-message 旧通道已废弃。
  // AgentLifeEngine / trigger-diary 均已迁移到 MessageBusService.publish，
  // 统一走 echo:message IPC → handleEchoMessage → MessageQueueManager 去重分发。
  // 未读计数由 MessageBusService → echo:unread-update → onUnreadUpdate 回调权威维护。

  // 🚀 全图模式自动生图判定与触发函数
  async function checkAndTriggerAutoNai(charId: string, content: string, msg: any) {
    try {
      const naiModeRes = await window.api.invoke('get-setting', { key: 'admin_nai_auto_mode' });
      if (naiModeRes?.value === '1' && novelai.apiKey) {
        // 确保当前消息是有实质内容的文字消息，排除图片、表情、红包及日记，规避死循环
        if (
          !content ||
          content.startsWith('[wechat_image_media]:') ||
          content.startsWith('[wechat_custom_emoji]:') ||
          content.startsWith('[wechat_red_packet]:') ||
          content.startsWith('[character_diary]:')
        ) {
          return;
        }

        if (msg.role !== 'assistant') {
          return;
        }

        // 限制每轮对话（同一个 round_id）只触发一次生图，防止多分段/多广播时重复生成
        if (msg.round_id) {
          if (autoNaiTriggeredRounds.has(msg.round_id)) {
            console.log(`[NAI Auto Mode] 轮次 ${msg.round_id} 已触发过生图，本次跳过。`);
            return;
          }
          autoNaiTriggeredRounds.add(msg.round_id);
        }

        const char = characterList.value.find(c => c.id === charId);
        if (!char) return;

        let recentMsgs = (allMessages[charId] || []).slice(-20);
        // 确保最新收到且正在处理的消息包含在上下文中，供 LLM 准确构图
        if (!recentMsgs.some(m => m.id === msg.id)) {
          recentMsgs = [...recentMsgs, msg];
        }

        const promptRes = await window.api.invoke('analyze-chat-image-prompt', {
          characterId: charId,
          folderName: char.folder_name,
          recentMessages: JSON.parse(JSON.stringify(recentMsgs)),
        });
        if (promptRes.success && promptRes.prompt) {
          // 直接写入上下文，强制自动执行 NovelAI 生图流程并推入会话中
          activeDrawingContextMap[charId] = {
            prompt: promptRes.prompt,
            description: promptRes.description || '',
            dimensions: (novelai.defaultDimensions as any) || 'portrait',
          };
          // ⚡️ 若默认生图尺寸为自定义，则把 customWidth / customHeight 状态初始化为全局自定义默认高宽
          if (novelai.defaultDimensions === 'custom') {
            customWidth.value = novelai.defaultWidth || 832;
            customHeight.value = novelai.defaultHeight || 1216;
          }
          await executeNovelAiImageGeneration(charId, char.folder_name);
        }
      }
    } catch (e) {
      console.warn('[NAI Auto Mode] 全图模式自动生图异常:', e);
    }
  }

  // ────────────────────────────────────────────────────────
  // handleEchoMessage：接收并处理来自任意端（Electron IPC / SSE）的 echo:message
  // 由 MessageQueueManager 调用（已在 init 时注册），MessageQueueManager 负责去重
  // 使用 function 声明以获得变量提升（hoisting），允许在文件中任意位置调用
  // ────────────────────────────────────────────────────────
  function handleEchoMessage(msg: any) {
    if (msg.msg_type === 'roast') {
      // 吐槽消息属于演员戏外吐槽，在此默默拦截，绝不混入主聊天界面
      return;
    }
    // 包装为 async IIFE，允许内部 await（不阻塞其他消息接收）
    (async () => {
      const charId = msg.character_id;
      if (!charId) return;

      // 🚀 红包状态即时同步与存盘（支持单聊与群聊）：无论是否为重复气泡，只要大模型返回了红包处理动作（领取/退回），就应立即触发钱包和数据库同步
      if (msg.role === 'assistant' && msg.redPacketAction && msg.redPacketAction !== 'send') {
        const isGroup = groupChats.value.some(g => g.id === charId);
        const senderId = msg.sender_id;
        const act = msg.redPacketAction;
        const charMsgs = allMessages[charId] || [];

        for (let i = charMsgs.length - 1; i >= 0; i--) {
          const m = charMsgs[i];
          if (m.role === 'user' && m.redPacket && (!m.redPacket.status || m.redPacket.status === 'waiting')) {
            if (isGroup) {
              if (m.redPacket.targetId && m.redPacket.targetId !== senderId) {
                continue;
              }
            }
            if (act === 'receive') {
              m.redPacket.status = 'received';
            } else if (act === 'return') {
              m.redPacket.status = 'returned';
              const amt = parseFloat(m.redPacket.amount);
              if (!isNaN(amt) && amt > 0) {
                userProfile.walletBalance += amt;
                saveUserProfileLocal();
                showCustomAlert(
                  '红包被退回',
                  `${isGroup ? '群成员' : '角色'}退回了你的红包，金额 ${amt.toFixed(2)} 元已退回您的钱包！`,
                  'info',
                );
              }
            }
            if (m.id) {
              const updatedPayload = {
                amount: m.redPacket.amount,
                title: m.redPacket.title,
                status: m.redPacket.status,
              } as any;
              if (isGroup) {
                updatedPayload.targetId = m.redPacket.targetId;
                updatedPayload.targetName = m.redPacket.targetName;
              }
              window.api.invoke('update-message-content', {
                messageId: m.id,
                content: `[wechat_red_packet]:${JSON.stringify(updatedPayload)}`,
              });
            }
            break;
          }
        }
      }

      // 更新对应会话的活跃时间戳
      conversationActiveTimes[charId] = msg.timestamp || Date.now();
      // 将消息追加到对应缓存
      if (!allMessages[charId]) allMessages[charId] = [];
      const msgs = allMessages[charId];

      // 1. 智能去重自愈：采用顶级空白忽略与分段合并自适应比对门禁，完美兼容 PC 端自己发自己收的去重以及复杂的微信级分段回复去重
      let isDuplicate = false;

      // 🚀 最优先：直接 ID 存在检查（最快路径，async IIFE 延迟后 handleAssistantResponse 可能已将气泡替换为真实 ID）
      if (msg.id && msgs.some(m => m.id === msg.id)) {
        isDuplicate = true;
      }

      if (!isDuplicate && msg.id && pendingPlaybackMessageIds.has(msg.id)) {
        isDuplicate = true;
      }

      // 物理去除内容中的所有换行、空白字符、特有标签用于高精准比对
      const cleanStr = (s: string) => {
        let temp = s || '';
        if (temp.startsWith('[wechat_image_media]:')) {
          temp = temp.split('[image_desc:')[0];
        }
        return temp.replace(/\s+/g, '');
      };

      if (msg.role === 'assistant') {
        const normBroadcast = cleanStr(msg.content);

        // 🚀 物理级红包特征精准去重：从广播消息内容中提取金额与附言，实现以金额与附言为准的红包特征去重，免疫任何微观字符串格式或 JSON 属性顺序差异！
        let broadcastRp: any = null;
        if (msg.content && msg.content.startsWith('[wechat_red_packet]:')) {
          try {
            const jsonStr = msg.content.replace('[wechat_red_packet]:', '');
            broadcastRp = JSON.parse(jsonStr);
          } catch (_) {}
        }

        // 🚀 物理级自定义表情包强力特征去重：从广播消息中提取表情包特征，防止临时追加的表情包与数据库落盘广播重复渲染
        let broadcastEmoji: any = null;
        if (msg.content && msg.content.startsWith('[wechat_custom_emoji]:')) {
          try {
            const jsonStr = msg.content.replace('[wechat_custom_emoji]:', '');
            broadcastEmoji = JSON.parse(jsonStr);
          } catch (_) {}
        }

        // 首先检查是否有 ID、原始物理内容、或红包、表情包属性直接相存的重复项
        for (let i = msgs.length - 1; i >= Math.max(0, msgs.length - 15); i--) {
          if (msgs[i].role === 'assistant') {
            // 🚀 流式临时气泡前置匹配去重：如果本地存在 msg_stream_ 临时气泡，且内容高度重合，我们提前将其 id 修正为真正的物理 id 从而完美拦截广播
            if (String(msgs[i].id).startsWith('msg_stream_')) {
              const localClean = cleanStr(msgs[i].content);
              if (
                localClean === normBroadcast ||
                localClean.includes(normBroadcast) ||
                normBroadcast.includes(localClean)
              ) {
                isDuplicate = true;
                msgs[i].id = msg.id; // 提前原子替换为正式 ID，使之后 handleAssistantResponse 的 check 拦截达到 100% 精确度
                break;
              }
            }

            // A. 物理 ID 精确匹配（MessageQueueManager 已在上游做了 ID 去重，此处兜底 msgs 层面的 ID 二次检查）
            // 注意：不再做内容字符串匹配，避免 AI 连续发相同内容时第二条被误判丢弃
            if (msgs[i].id === msg.id) {
              isDuplicate = true;
              break;
            }
            // B. 红包强力特征去重
            if (broadcastRp && msgs[i].redPacket) {
              const localAmount = parseFloat(msgs[i].redPacket.amount);
              const broadcastAmount = parseFloat(broadcastRp.amount);
              if (localAmount === broadcastAmount && msgs[i].redPacket.title === broadcastRp.title) {
                isDuplicate = true;
                msgs[i].id = msg.id; // 顺便原子修正临时红包卡片的 ID 为物理正式 ID
                break;
              }
            }
            // C. 表情包强力特征去重：完美解决群发表情卡片后 receive-message 二次广播重叠导致的重复渲染 Bug
            if (broadcastEmoji && msgs[i].customEmojiUrl && msgs[i].content) {
              if (msgs[i].content.includes(broadcastEmoji.meaning.trim())) {
                isDuplicate = true;
                msgs[i].id = msg.id; // 原子修正临时表情卡片的 ID 为物理正式 ID
                break;
              }
            }
          }
        }

        // 🚀 仅对话模式精确去重：必须在 await 之前同步检查 pendingDialogueContents！
        // 读取该角色的真实 chatMode（从缓存；cache miss 时查 DB 并回写，彻底不依赖全局 chatMode.value）
        let charModeForDedup = characterChatModeCache[charId];
        if (!charModeForDedup) {
          try {
            const mr = await window.api.invoke('get-character-chat-mode', { characterId: charId });
            charModeForDedup = mr.success && mr.mode ? mr.mode : 'descriptive';
          } catch {
            charModeForDedup = 'descriptive';
          }
          characterChatModeCache[charId] = charModeForDedup;
        }
        if (!isDuplicate && charModeForDedup === 'dialogue') {
          const normBroadcastShort = normBroadcast.slice(0, 80);
          for (const pending of pendingDialogueContents) {
            // 🔒 修复：只有当 pending 与 broadcast 内容精确相等（去空白后），才判定为重复广播。
            // 原来用 pending.includes(normBroadcastShort) 会误拦截"你好"这样的短气泡，
            // 因为"你好"是"你好你想要点什么"的子串，导致 receive-message 把合法分段气泡丢弃。
            // 分段气泡的显示由 playbackChain 串行弹射负责，receive-message 不应该干涉。
            if (pending === normBroadcastShort || normBroadcast === pending.slice(0, normBroadcast.length)) {
              isDuplicate = true;
              console.log('[Sync Gate] dialogue pendingContent 精确匹配，拦截完整回复广播重复。');
              break;
            }
          }
        }

        // await chatMode 加载（仅用于后续渲染路径判断，不再用于去重）
        if (charId === selectedCharacterId.value && pendingChatModeLoad) {
          await pendingChatModeLoad;
        }

        // 🚀 分段合并去重兜底：弹射已完成（pendingDialogueContents 已清除）时，通过拼合本地分段比对
        if (!isDuplicate) {
          const recentAssistants = msgs.slice(-15).filter(m => m.role === 'assistant' && m.content);
          if (recentAssistants.length >= 1) {
            let combined = '';
            for (let i = recentAssistants.length - 1; i >= 0; i--) {
              combined = cleanStr(recentAssistants[i].content) + combined;
              if (combined === normBroadcast) {
                isDuplicate = true;
                break;
              }
            }
          }
        }
      } else if (msg.role === 'user') {
        // 用户消息去重：优先按 ID 精确匹配，内容匹配仅在本端 500ms 内刚 push 的消息上生效
        // 防止另一端（手机/桌面）发来相同内容被误判为重复而漏显
        const normBroadcast = cleanStr(msg.content);
        const now = Date.now();
        for (let i = msgs.length - 1; i >= Math.max(0, msgs.length - 15); i--) {
          if (msgs[i].role === 'user') {
            // ID 精确匹配：必定是重复
            if (msgs[i].id === msg.id) {
              isDuplicate = true;
              break;
            }
            // 内容匹配：仅限本端 500ms 内刚发出的消息（自己发自己收的去重）
            if (cleanStr(msgs[i].content) === normBroadcast && now - (msgs[i].timestamp || 0) < 500) {
              isDuplicate = true;
              break;
            }
          }
        }
      }

      const isWaitingResponse = streamingCharsSet.has(charId);

      if (isDuplicate) {
        console.log(`[Sync Gate] 拦截到重复气泡广播，予以丢弃过滤，安全避开双气泡。`);

        // 顺便在这里帮已有气泡（包括可能被分段的最后一个气泡或者匹配气泡）补全一下 ID 和 Token 元数据
        if (msg.role === 'assistant') {
          const normBroadcast = cleanStr(msg.content);
          for (let i = msgs.length - 1; i >= Math.max(0, msgs.length - 4); i--) {
            if (
              msgs[i].role === 'assistant' &&
              (msgs[i].id === msg.id || normBroadcast.includes(cleanStr(msgs[i].content)))
            ) {
              msgs[i].id = msg.id;
              if (msg.prompt_tokens) msgs[i].prompt_tokens = msg.prompt_tokens;
              if (msg.completion_tokens) msgs[i].completion_tokens = msg.completion_tokens;
              if (msg.cached_tokens) msgs[i].cached_tokens = msg.cached_tokens;
              break;
            }
          }
        }
        return;
      } else {
        // 🚀 如果并非重复消息，但本地仍处于等待该角色的流式回复状态，说明本地流式通道（SSE/Fetch）遭遇了严重的网络瞬断或丢包死锁
        // 此时我们绝对不能过滤丢弃它，而是将其作为保底救命消息渲染出来，并立刻自动重置卡死状态，解除死锁！
        if (isWaitingResponse && msg.role === 'assistant') {
          console.warn(
            `[Sync Gate Self-Cure] 发现本地卡在等待状态，但从未收到此消息。判定流式信道丢包，触发保底自愈！`,
          );
          streamingCharsSet.delete(charId);
          streamingCharacterId.value = '';
          clearReplyTimeout();
        }
      }

      const isSpecialMsg =
        msg.content &&
        (msg.content.startsWith('[character_diary]:') ||
          msg.content.startsWith('[wechat_red_packet]:') ||
          msg.content.startsWith('[wechat_custom_emoji]:') ||
          msg.content.startsWith('[wechat_image_media]:'));

      if (!isDuplicate && !msgs.some(m => m.id === msg.id)) {
        if (msg.role === 'assistant') {
          // 🚀 立刻并行的在后台触发全图模式自动分析与生图检测，无需等待拟真打字播放结束（解决从落盘到生图的延迟过长问题）
          checkAndTriggerAutoNai(charId, msg.content, msg);
        }

        // 读取该消息所属角色的真实 chatMode（优先缓存，未命中则查 DB 并回写）
        let msgCharMode = characterChatModeCache[charId];
        if (!msgCharMode) {
          try {
            const mr = await window.api.invoke('get-character-chat-mode', { characterId: charId });
            msgCharMode = mr.success && mr.mode ? mr.mode : 'descriptive';
          } catch {
            msgCharMode = 'descriptive';
          }
          characterChatModeCache[charId] = msgCharMode;
        }

        if (msgCharMode === 'dialogue' && msg.role === 'assistant') {
          // 🚀 仅对话模式下，收到 AI 回复（无论是否是红包、表情包等特殊卡片，为防插队乱序）均通过播放器进行排队！
          const isGroup = groupChats.value.some(g => g.id === charId);
          const char = isGroup
            ? groupChats.value.find(g => g.id === charId)
            : characterList.value.find(c => c.id === charId);
          if (char) {
            // Web 端 and Electron 端现在路径完全一致：通过 playbackChain 串行化播放
            // Electron 端的 chat-stream 路径已改为 500ms 保底检查，主渲染路径统一走此处
            const msgId = msg.id;
            pendingPlaybackMessageIds.add(msgId);
            // 使用该角色独立的播放链，不同角色互不阻塞
            const nextStep = getPlaybackChain(charId).then(async () => {
              try {
                const senderId = msg.sender_id || (isGroup ? '' : charId);
                await handleAssistantResponse(
                  char,
                  msg.content,
                  msg.redPacketAction ?? null, // 传递红包动作（领取/退回），驱动钱包状态更新
                  msg.prompt_tokens,
                  msg.completion_tokens,
                  msg.cached_tokens,
                  msg.id,
                  senderId,
                  msg.inner_thought,
                );
              } catch (err) {
                console.error(`[playbackChain] handleAssistantResponse 异常 (charId=${charId}):`, err);
              } finally {
                pendingPlaybackMessageIds.delete(msgId);
              }
            });
            // 更新该角色的链（收割旧链，防止内存泄漏）
            playbackChains.set(charId, nextStep);
          } else {
            // 极致兜底降级处理：找不到角色元数据时直接扁平化渲染
            const flattened = flattenMessages([msg], charId);
            msgs.push(...flattened.map(m => restoreMessageProps(m)));
          }
        } else {
          const flattened = flattenMessages([msg], charId);
          const restoredMsgs = flattened.map(m => restoreMessageProps(m));
          // 防空气泡：非特殊消息（文字消息）如果内容被清洗后为空，不 push
          const validMsgs = restoredMsgs.filter(
            m => isSpecialMsg || (m.content && m.content.trim()) || m.imageBase64 || m.customEmojiUrl || m.redPacket,
          );
          msgs.push(...validMsgs);
          // 非 dialogue 模式的 assistant 消息到达
          if (msg.role === 'assistant') {
            // 清除流式等待状态（"正在输入..."）
            streamingCharsSet.delete(charId);
            if (streamingCharacterId.value === charId) {
              streamingCharacterId.value = null;
            }
            clearReplyTimeout();

            // 🚀 刷新记忆与日记视图 (非 dialogue 模式自愈)
            setTimeout(async () => {
              const char = characterList.value.find(c => c.id === charId);
              if (char) {
                const memRes = await window.api.invoke('read-character-file', {
                  folderName: char.folder_name,
                  fileName: 'Memory.md',
                });
                if (memRes.success && charId === selectedCharacterId.value) activeMemory.value = memRes.content;
                const diaryRes = await window.api.invoke('read-character-file', {
                  folderName: char.folder_name,
                  fileName: 'Diary.md',
                });
                if (diaryRes.success && charId === selectedCharacterId.value) activeDiary.value = diaryRes.content;
              }
            }, 1500);

            // 若携带红包动作（AI 领取/退回用户红包），触发钱包状态更新
            // dialogue 模式由 handleAssistantResponse 内部处理；descriptive/director 需在此处额外触发
            // ⚠️ 注意：redPacketAction='send' 是 AI 主动发红包，气泡已由 restoreMessageProps 正确渲染为红包卡片，
            // 不需要再调用 handleAssistantResponse（否则会把 '[wechat_red_packet]:...' 再次 push 成空气泡）。
            // 只有 receive/return（AI 响应用户红包）才需要调用 handleAssistantResponse 更新钱包状态。
            if (msg.redPacketAction && msg.redPacketAction !== 'send') {
              const char = characterList.value.find(c => c.id === charId);
              if (char) {
                handleAssistantResponse(
                  char,
                  msg.content,
                  msg.redPacketAction,
                  msg.prompt_tokens,
                  msg.completion_tokens,
                  msg.cached_tokens,
                  msg.id,
                  undefined,
                  msg.inner_thought,
                );
              }
            }
          }
        }

        // 未读数由 MessageBusService → echo:unread-update 推送，前端 onUnreadUpdate 权威更新
        // 不在此处手动自增，避免双重计数
        if (selectedCharacterId.value === charId && isChattingActive.value) {
          // 当前正在查看该会话，强制置底
          nextTick(() => scrollToBottom('smooth', true));
        }
      }
    })();
  } // end handleEchoMessage

  // 注意：receive-message 旧通道已在 AgentLifeEngine/WeChatService 等迁移到
  // MessageBusService.publish 后废弃。MessageBusService 统一走 echo:message IPC，
  // 不再重复监听 receive-message，避免双路推送造成消息重复。

  // 监听朋友圈点赞广播，实时更新点赞数和点赞者列表头像，并处理未读通知
  window.api.receive(
    'social-moment-liked-broadcast',
    (data: {
      momentId: string;
      characterId: string;
      authorName: string;
      authorAvatar?: string;
      targetAuthorId?: string;
    }) => {
      // 实时更新内存中对应 moment 的点赞数和点赞者列表
      const targetMoment = momentsList.value.find((m: any) => m.id === data.momentId);
      if (targetMoment) {
        targetMoment.likes = (targetMoment.likes || 0) + 1;
        if (!targetMoment.likes_list) targetMoment.likes_list = [];
        // 避免重复追加
        const alreadyLiked = targetMoment.likes_list.some((l: any) => l.character_id === data.characterId);
        if (!alreadyLiked) {
          targetMoment.likes_list.push({
            moment_id: data.momentId,
            character_id: data.characterId,
            author_name: data.authorName,
            timestamp: Date.now(),
          });
        }
      }
      // 如果是针对用户发的朋友圈，点亮通知
      if (data.targetAuthorId === 'user') {
        if (sideView.value !== 'moments') {
          unreadMomentsCount.value += 1;
        }
        hasNewMomentNotification.value = true;
        newMomentTargetId.value = data.momentId;
      }
    },
  );

  // 监听朋友圈评论广播：实时追加评论到对应moment，并处理通知
  window.api.receive('social-moment-comment-added', (comment: any) => {
    // 实时将评论追加到内存中对应 moment 的 comments 数组
    const targetMoment = momentsList.value.find((m: any) => m.id === comment.moment_id);
    if (targetMoment) {
      if (!targetMoment.comments) targetMoment.comments = [];
      // 避免重复追加
      const alreadyExists = targetMoment.comments.some((c: any) => c.id === comment.id);
      if (!alreadyExists) {
        targetMoment.comments.push(comment);
      }
    }
    // 如果是针对用户朋友圈的评论或回复，点亮通知
    if (comment.target_author_id === 'user') {
      if (sideView.value !== 'moments') {
        unreadMomentsCount.value += 1;
      }
      hasNewMomentNotification.value = true;
      newMomentTargetId.value = comment.moment_id;
    }
  });

  // 监听论坛评论广播，如果是针对用户的回复，点亮最左侧论坛导航按钮的未读红点及对应帖子的红点
  window.api.receive('social-forum-comment-added', (comment: any) => {
    // 1. 如果当前正在详细阅读这个帖子，实时追加评论到当前评论列表中
    if (selectedForumPost.value && selectedForumPost.value.id === comment.post_id) {
      if (!forumCommentsList.value.some(c => c.id === comment.id)) {
        forumCommentsList.value.push(comment);
      }
    }

    // 2. 更新未读状态与红点
    if (comment.target_author_id === 'user') {
      if (sideView.value !== 'forum') {
        unreadForumCount.value += 1;
      }
      // 如果当前没有正在详细阅读这个帖子，加入帖子未读列表以点亮帖子卡片红点
      if (selectedForumPost.value?.id !== comment.post_id) {
        if (!unreadForumPostIds.value.includes(comment.post_id)) {
          unreadForumPostIds.value.push(comment.post_id);
        }
      }
    }
  });

  // 全局点击事件（关闭菜单）
  document.addEventListener('click', handleGlobalClick);

  // =================== 新增社媒与性格人设进化 IPC 监听器 ===================
  // 1. 监听状态 delta 更新以触发前端飞入动效
  window.api.receive(
    'character-state-updated',
    (data: { characterId: string; updates: { key: string; delta?: number; value?: any }[] }) => {
      const char = characterList.value.find(c => {
        const folder = (c.folder_name || '').toLowerCase();
        const cid = (c.id || '').toLowerCase();
        const target = (data.characterId || '').toLowerCase();
        return folder === target || cid === target;
      });
      if (!char) return;
      const charId = char.id;

      if (!stateDeltas.value[charId]) stateDeltas.value[charId] = {};
      for (const update of data.updates) {
        if (characterStates.value[charId]) {
          const item = characterStates.value[charId].items.find((i: any) => i.key === update.key);
          if (item) {
            if (item.type === 'text') {
              // 文本型状态：同时兼容 update.value 与 update.delta，只要有更新字串就进行合并与动效飞入
              const txtVal = update.value !== undefined ? update.value : update.delta;
              if (txtVal !== undefined && txtVal !== null) {
                const strVal = String(txtVal).trim();
                item.value = strVal;
                stateDeltas.value[charId][update.key] = `➔ ${strVal}`;
              }
            } else {
              // 数值型状态：智能兼顾绝对值 value 覆盖与相对值 delta 累加
              const minVal = item.min ?? 0;
              const maxVal = item.max ?? 100;
              const numericVal = typeof item.value === 'number' ? item.value : Number(item.value) || 0;

              if (update.value !== undefined && update.value !== null && update.value !== '') {
                // 绝对值更新模式
                const targetVal = Number(update.value);
                if (!isNaN(targetVal)) {
                  const newVal = Math.max(minVal, Math.min(maxVal, targetVal));
                  const diff = newVal - numericVal;
                  stateDeltas.value[charId][update.key] = diff >= 0 ? `+${diff}` : diff;
                  item.value = newVal;
                }
              } else if (update.delta !== undefined && update.delta !== null) {
                // 相对值更新模式
                const deltaVal = Number(update.delta);
                if (!isNaN(deltaVal)) {
                  const newVal = Math.max(minVal, Math.min(maxVal, numericVal + deltaVal));
                  stateDeltas.value[charId][update.key] = deltaVal >= 0 ? `+${deltaVal}` : deltaVal;
                  item.value = newVal;
                }
              }
            }
          }
        }
      }

      // 3秒后淡出更新标志
      setTimeout(() => {
        if (stateDeltas.value[charId]) {
          for (const update of data.updates) {
            delete stateDeltas.value[charId][update.key];
          }
        }
      }, 3000);
    },
  );

  // 2. 监听性格进化草案生成通知
  window.api.receive('soul-evolution-proposed', (data: { characterId: string; draft: any }) => {
    activeEvolutionCharId.value = data.characterId;
    activeEvolutionDraft.value = data.draft;
    showToast(`🌱 检测到 ${characterList.value.find(c => c.id === data.characterId)?.name} 产生了人设性格演化提案！`);
  });

  // ===================== 本地向量模型下载与写入 IPC 广播监听 =====================
  if (window.api && window.api.receive) {
    // 监听模型下载进度
    const rVectorDlProg = window.api.receive('vector-model-download-progress', (data: { pct: number; fileName: string }) => {
      isDownloadingModel.value = true;
      downloadProgress.value = data.pct;
      downloadingFileName.value = data.fileName;
    });
    unlistenVectorDownloadProgress = typeof rVectorDlProg === 'function' ? (rVectorDlProg as any) : null;

    // 监听模型下载结束
    const rVectorDlDone = window.api.receive('vector-model-download-done', (data: { success: boolean; error?: string }) => {
      isDownloadingModel.value = false;
      if (data.success) {
        showToast('🎉 本地向量模型下载完成并加载成功！');
      } else {
        showCustomAlert('模型下载失败', data.error || '未知网络问题，请重试', 'error');
      }
      refreshVectorModelStatus();
    });
    unlistenVectorDownloadDone = typeof rVectorDlDone === 'function' ? (rVectorDlDone as any) : null;

    // 监听历史存量向量化进度
    const rVectorBfProg = window.api.receive('vector-backfill-progress', (data: { characterId: string; done: number; total: number }) => {
      isBackfilling.value = true;
      if (data.characterId === 'all' || selectedCharacterId.value === data.characterId) {
        vectorProgress.value = {
          done: data.done,
          total: data.total
        };
      }
    });
    unlistenVectorBackfillProgress = typeof rVectorBfProg === 'function' ? (rVectorBfProg as any) : null;

    // 监听历史存量向量化结束
    const rVectorBfDone = window.api.receive('vector-backfill-done', (data: { characterId: string; done: boolean }) => {
      isBackfilling.value = false;
      if (data.done) {
        if (data.characterId === 'all') {
          showToast('🎉 全量历史对话向量化补录已全部完成！');
        } else {
          showToast('🎉 该角色的历史对话向量化补录已全部完成！');
        }
      }
      refreshVectorProgress('all');
    });
    unlistenVectorBackfillDone = typeof rVectorBfDone === 'function' ? (rVectorBfDone as any) : null;
  }
});

// ===================== 朋友圈 & 论坛 & 状态 & 成长线交互方法 =====================
// 点击朋友圈新动态提醒条，优雅滚动到对应的卡片位置，并附加精美的高亮闪烁边框效果
function scrollToNewMoment() {
  hasNewMomentNotification.value = false;
  unreadMomentsCount.value = 0;

  if (!newMomentTargetId.value) return;

  const targetId = newMomentTargetId.value;
  newMomentTargetId.value = null; // 消费后即时重置

  nextTick(() => {
    const el = document.getElementById(`moment-item-${targetId}`);
    if (el) {
      el.scrollIntoView({ behavior: 'smooth', block: 'center' });
      el.classList.add('ring-2', 'ring-primary', 'ring-offset-2', 'scale-[1.01]');
      setTimeout(() => {
        el.classList.remove('ring-2', 'ring-primary', 'ring-offset-2', 'scale-[1.01]');
      }, 2000);
    }
  });
}

function getMomentImage(content: string) {
  if (!content) return null;
  const match = content.match(/<!--\s*\[wechat_image_media\]:(.*?)\s*-->/);
  return match ? match[1].trim() : null;
}

// 1. 加载朋友圈和论坛
async function loadMomentsList() {
  const res = await window.api.invoke('fetch-moments', { limit: 50 });
  if (res.success) {
    momentsList.value = res.moments.map((m: any) => reactive({ ...m, imageBase64: '', imageMeta: null }));

    // 异步拉取朋友圈配图及元数据
    momentsList.value.forEach(async (moment: any) => {
      const imgPath = getMomentImage(moment.content);
      if (imgPath) {
        const char = characterList.value.find(c => c.id === moment.character_id);
        if (char) {
          try {
            const readRes = await window.api.invoke('read-image-media', {
              folderName: char.folder_name,
              mediaPath: imgPath,
            });
            if (readRes.success) {
              moment.imageBase64 = readRes.base64;
              if (readRes.meta) {
                moment.imageMeta = readRes.meta;
              }
            }
          } catch (e) {
            console.error('加载朋友圈图片失败:', e);
          }
        }
      }
    });
  }
}

async function loadForumPostsList() {
  const res = await window.api.invoke('fetch-forum-posts', { limit: 50 });
  if (res.success) {
    forumPostsList.value = res.posts.map((p: any) => ({
      ...p,
      imageBase64: p.imageBase64 || '',
      imageMeta: p.imageMeta || null,
    }));
  }
}

// 手动物理删除朋友圈动态
