    async () => {
      const res = await window.api.invoke('delete-moment', { momentId: moment.id });
      if (res.success) {
        showToast('朋友圈动态已成功删除 ✨');
        await loadMomentsList();
      } else {
        showToast(`删除失败: ${res.error || '未知错误'}`);
