    showSelectCopyModal.value = false; // 复制成功后，顺便优雅关闭弹窗
  }
}

async function ctxFavoriteMessage() {
  const msg = contextMenu.message;
  const char = contextMenu.char;
  if (!msg || !char) return;

  const res = await window.api.invoke('add-favorite', {
    type: 'chat',
    targetId: msg.id || `msg_${msg.timestamp || Date.now()}`,
    characterId: char.id,
    authorName: char.name,
    authorAvatar: char.avatar || '',
    title: `与 ${char.name} 的对话`,
    content: msg.content,
  });
  if (res.success) {
    showToast('对话气泡成功收藏！🔖');
  } else {
    showToast(`收藏失败: ${res.error}`);
  }
  contextMenu.visible = false;
}

function ctxDeleteMessage() {
  const msg = contextMenu.message;
  const char = contextMenu.char;
  if (!msg || !char) return;

  if (streamingCharsSet.has(contextMenu.char?.id || '')) {
    showToast('AI 正在回复中，暂时无法删除消息！ ⏳');
    return;
  }

  contextMenu.visible = false;

  showCustomConfirm(
    '确认删除消息',
    '您确定要彻底物理删除此条聊天记录吗？\n\n注意：此操作将永久从本地数据库与上下文记忆中抹去，无法撤销。',
    async () => {
      const res = await window.api.invoke('delete-message', { messageId: msg.id });
      if (res.success) {
        const msgs = allMessages[char.id];
        if (msgs) {
          const idx = msgs.findIndex(m => m.id === msg.id);
          if (idx !== -1) {
            msgs.splice(idx, 1);
          }
        }
        showToast('消息记录已成功物理擦除！🗑️');
      } else {
        showToast(`删除失败: ${res.error}`);
      }
    },
  );
}

// ===================== 多选删除功能 =====================

// 是否处于多选模式
const isMultiSelectMode = ref(false);
// 当前已选中的消息 ID 集合
const selectedMessageIds = ref<Set<string>>(new Set());

// 从右键菜单进入多选模式，并默认选中当前消息
function ctxEnterMultiSelect() {
  const msg = contextMenu.message;
  contextMenu.visible = false;
  isMultiSelectMode.value = true;
  selectedMessageIds.value = new Set();
  if (msg?.id) {
    selectedMessageIds.value.add(msg.id);
  }
}

// 退出多选模式，清空选中
function exitMultiSelect() {
  isMultiSelectMode.value = false;
  selectedMessageIds.value = new Set();
}

// 切换某条消息的选中状态
function toggleMessageSelect(id: string) {
  const s = selectedMessageIds.value;
  if (s.has(id)) {
    s.delete(id);
  } else {
    s.add(id);
  }
  // 触发响应式更新（Set 变更需要重新赋值）
  selectedMessageIds.value = new Set(s);
}

// 批量删除已选消息
async function confirmBatchDelete() {
  const char = activeCharacter.value || activeGroupChat.value;
  if (!char || selectedMessageIds.value.size === 0) return;

  if (streamingCharsSet.has(char.id)) {
    showToast('AI 正在回复中，暂时无法删除消息！ ⏳');
    return;
  }

  const count = selectedMessageIds.value.size;

  showCustomConfirm(
    '确认批量删除',
    `您确定要彻底物理删除选中的 ${count} 条聊天记录吗？\n\n此操作将从数据库、上下文历史、记忆草稿与缓存中永久抹去，无法撤销。`,
    async () => {
      const ids = [...selectedMessageIds.value];
      let successCount = 0;

      for (const msgId of ids) {
        const res = await window.api.invoke('delete-message', { messageId: msgId });
        if (res.success) {
          // 同步从前端消息列表移除
          const msgs = allMessages[char.id];
          if (msgs) {
            const idx = msgs.findIndex((m: any) => m.id === msgId);
            if (idx !== -1) msgs.splice(idx, 1);
          }
          successCount++;
        }
      }

      exitMultiSelect();
      showToast(`已成功删除 ${successCount} 条消息记录 🗑️`);

      // 超过 2 条时展示记忆提醒横幅
      if (successCount > 2) {
        showMemoryWarningBanner.value = true;
        if (memoryWarningTimer) clearTimeout(memoryWarningTimer);
        memoryWarningTimer = setTimeout(() => {
          showMemoryWarningBanner.value = false;
        }, 8000);
      }
    },
  );
}

// 记忆提醒横幅状态
const showMemoryWarningBanner = ref(false);
let memoryWarningTimer: any = null;

async function ctxRegenerateMessage() {
  const char = contextMenu.char;
  if (!char || streamingCharsSet.has(char.id)) return;
  contextMenu.visible = false;

  showCustomConfirm(
    '重新回复消息',
    `您确定要删除此条旧回复，并要求 [${char.name}] 重新回复吗？\n\n注意：如果角色有连续多段气泡，它们将被同时统一抹去并由 AI 重新接管渲染。`,
    async () => {
      activeInnerThoughtMsgId.value = null;
      const res = await window.api.invoke('regenerate-reply', { characterId: char.id });
      if (res.success) {
        // 1. 前端物理擦除 Messages 里的旧助理回复气泡
        const msgs = allMessages[char.id];
        if (msgs) {
          // pop 掉尾部连续的所有 role === 'assistant' 气泡
          while (msgs.length > 0 && msgs[msgs.length - 1].role === 'assistant') {
            msgs.pop();
          }
        }

        // 2. 找到倒数第一条用户的消息内容作为大模型的 userMessage 输入
        const userMsgs = msgs.filter(m => m.role === 'user');
        if (userMsgs.length === 0) {
          showToast('没有找到可以用来重新触发的历史消息！');
          return;
        }
        const lastUserMsg = userMsgs[userMsgs.length - 1];

        // 3. 触发重答流
        await triggerMergedAiResponse(char, lastUserMsg.content, true);
      } else {
        showToast(`重新回复触发失败: ${res.error}`);
      }
    },
  );
}

function ctxForwardMessage() {
  const msg = contextMenu.message;
  if (!msg) return;

  messageToForward.value = msg;
  forwardQuery.value = '';
  showForwardModal.value = true;
  contextMenu.visible = false;
}

async function forwardMessageToCharacter(targetChar: any) {
  const msg = messageToForward.value;
  if (!msg || !targetChar) return;

  showForwardModal.value = false;
  showToast(`正在将消息转发给 [${targetChar.name}]... 🚀`);

  // 对转发消息内容进行前缀清洗，防止残留“转发自其他频道的消息”字样
  let cleanContent = msg.content || '';
  cleanContent = cleanContent.replace(/^\[?转发自其他频道的消息\]?\s*[:：]?\s*/g, '').trim();

  // 1. 物理插入转发的 user 消息到目标角色的 Messages 表中
  const userMsg = {
    id: `msg_user_${Date.now()}_forward`,
    character_id: targetChar.id,
    role: 'user' as const,
    content: cleanContent,
    timestamp: Date.now(),
    token_usage: 0,
  };

  // 保存到数据库
  await window.api.invoke('save-message', userMsg);

  // 2. 如果当前正处于该角色的聊天，或前端已缓存，联动插入
  if (!allMessages[targetChar.id]) {
    allMessages[targetChar.id] = [];
  }
  // 🚀 时序防重自愈：防止主进程存盘广播抢先追加导致双气泡
  if (!allMessages[targetChar.id].some(m => m.id === userMsg.id)) {
    allMessages[targetChar.id].push(restoreMessageProps(userMsg));
  }

  // 3. 自动跳转到该角色的聊天页！
  await selectCharacter(targetChar.folder_name);
  sideView.value = 'chat';

  // 4. 发送一个空包来触发该角色的 AI 针对该转发话题做出聊天响应！
  await triggerMergedAiResponse(targetChar, userMsg.content);
}

// 6. 保存通用常规设置
async function saveGeneralSettings() {
  // 🚀 至尊级局域网受限端口防呆校验与自愈重置过滤器
  let port = Number(generalConfig.value.lan_mapping_port) || 6868;
  const restrictedPorts = [
    1, 7, 9, 11, 13, 15, 17, 19, 20, 21, 22, 23, 25, 37, 42, 43, 53, 77, 79, 87, 95, 101, 102, 103, 104, 109, 110, 111,
    113, 115, 117, 119, 123, 135, 137, 139, 143, 179, 389, 465, 512, 513, 514, 515, 526, 530, 531, 532, 540, 556, 563,
    587, 601, 636, 993, 995, 2049, 3659, 4045, 6000, 6665, 6666, 6667, 6668, 6669, 6697,
  ];
  if (restrictedPorts.includes(port)) {
    showToast(`为了您的访问安全，浏览器默认禁用了 ${port} 等受限端口。系统已自动为您重置为安全的 6868 端口！🐾`);
    generalConfig.value.lan_mapping_port = 6868;
    port = 6868;
  }

  const res = await window.api.invoke('save-general-settings', {
    show_schedule: generalConfig.value.show_schedule,
    show_goals: generalConfig.value.show_goals,
    cron_frequency: generalConfig.value.cron_frequency,
    enable_music: generalConfig.value.enable_music,
    lan_mapping_enabled: generalConfig.value.lan_mapping_enabled,
    lan_mapping_port: port,
    enable_token_stats: generalConfig.value.enable_token_stats,
    enable_nsfw: generalConfig.value.enable_nsfw,
    descriptive_min_words: Number(generalConfig.value.descriptive_min_words) || 500,
    director_min_words: Number(generalConfig.value.director_min_words) || 800,
  });
  if (!res.success) {
    showToast(`保存失败: ${res.error}`);
  } else {
    // 物理防呆拦截：如果关闭了音乐功能，直接强行物理停播音乐，并退回侧边栏
    if (!generalConfig.value.enable_music) {
      if (sideView.value === 'music') {
        sideView.value = 'chat';
      }
      musicStore.stop();
    }
  }
}

// 7. 打开状态自定义配置弹窗
function openCustomizeStatesModal() {
  const charId = selectedContactId.value;
  if (!charId || !characterStates.value[charId]) return;
  editingStatesString.value = JSON.stringify(characterStates.value[charId], null, 2);
  showCustomizeStatesModal.value = true;
}

// 保存自定义状态
async function saveCustomizedStates() {
  const charId = selectedContactId.value;
  const char = characterList.value.find(c => c.id === charId);
  if (!charId || !char) return;

  try {
    const parsed = JSON.parse(editingStatesString.value);
    if (!parsed.items || !parsed.items.length) {
      throw new Error('缺少 items 数组状态项描述。');
    }

    const res = await window.api.invoke('write-character-state', {
      folderName: char.folder_name,
      state: parsed,
    });

    if (res.success) {
      characterStates.value[charId] = parsed;
      showCustomizeStatesModal.value = false;
      showToast('角色状态指标配置成功！🛠️');
    } else {
      showToast(`写入失败: ${res.error}`);
    }
  } catch (err: any) {
    showToast(`格式解析失败: ${err.message}`);
  }
}

// 8. 审批性格演变
async function approveSoulEvolution() {
  if (!activeEvolutionCharId.value) return;
  const charId = activeEvolutionCharId.value;
  const res = await window.api.invoke('approve-soul-draft', { characterId: charId });
  if (res.success) {
    if (selectedContactId.value === charId) {
      await selectCharacterForContactDetails(charId);
    }
    showEvolutionModal.value = false;
    activeEvolutionDraft.value = null;
    activeEvolutionCharId.value = '';
    showToast('性格人设升级进化应用成功！🌱');
  } else {
    showToast('批准应用演化修改失败。');
  }
}

async function rejectSoulEvolution() {
  if (!activeEvolutionCharId.value) return;
  const charId = activeEvolutionCharId.value;
  await window.api.invoke('reject-soul-draft', { characterId: charId });
  showEvolutionModal.value = false;
  activeEvolutionDraft.value = null;
  activeEvolutionCharId.value = '';
